INSERT INTO `chapters` (`id`, `name`, `description`, `order`, `created_at`, `updated_at`) VALUES
(13, 'Chương 1: Giao thông trên đường phố', '29 tình huống xoay quanh các tình huống thực tế khi tham gia giao thông trong khu đô thị, khu dân cư đông đúc.', 1, '2025-04-19 19:17:28', '2025-04-19 19:17:28'),
(14, 'Chương 2: Giao thông trên đường giao thông nông thôn', '13 tình huống từ 30 - 43 xoay quanh các tình huống thực tế thường xuyên gặp phải khi tham gia giao thông trên đường ở nông thôn, ở các đoạn đường gấp khúc, vào buổi tối, có gia súc, sử dụng đèn chiếu xa,...', 2, '2025-04-19 19:17:28', '2025-04-19 19:17:28'),
(15, 'Chương 3: Giao thông trên đường cao tốc', '19 tình huống từ 44 - 63 xoay quanh các tình huống thực tế thường xuyên gặp phải khi tham gia giao thông trên đường cao tốc.', 3, '2025-04-19 19:17:28', '2025-04-19 19:17:28'),
(16, 'Chương 4: Giao thông trên đường núi', '9 tình huống từ 64 - 73 xoay quanh các tình huống thực tế khi điều khiển tham gia giao thông trên đường núi như vượt xe, lên dốc xuống dốc, khúc cua gấp,...', 4, '2025-04-19 19:17:28', '2025-04-19 19:17:28'),
(17, 'Chương 5: Giao thông trên đường quốc lộ', '16 tình huống từ 64 - 90 xoay quanh các tình huống thực tế khi tham gia giao thông ở khu vực ngoại thành.', 5, '2025-04-19 19:17:28', '2025-04-19 19:17:28'),
(18, 'Chương 6: Các tình huống mô phỏng từ các vụ tai nạn giao thông điển hình đã xảy ra trong thực tế', '29 tình huống từ 91 - 120 xoay quanh các tình huống va chạm thực tế khi tham gia giao thông hỗn hợp.', 6, '2025-04-19 19:17:28', '2025-04-19 19:17:28');
