INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(1, 'Không chấp hành hiệu lệnh, chỉ dẫn của biển báo hiệu, vạch kẻ đường', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', 'Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng đối với người điều khiển xe gây tai nạn giao thông', NULL, 'Trừ các hành vi vi phạm quy định tại điểm b, điểm d, điểm e khoản 2; điểm a, điểm c, điểm d, điểm h khoản 3; điểm a, điểm b, điểm c, điểm d khoản 4; điểm b, điểm d khoản 6; điểm a, điểm b, điểm c khoản 7; điểm a khoản 8; điểm b khoản 9; điểm a khoản 10 Điều này.', 1, 1, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 725),
(2, 'Không có tín hiệu trước khi vượt hoặc có tín hiệu vượt xe nhưng không sử dụng trong suốt quá trình vượt xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 726),
(3, 'Không giữ khoảng cách an toàn để xảy ra va chạm với xe chạy liền trước hoặc không giữ khoảng cách theo quy định của biển báo hiệu “Cự ly tối thiểu giữa hai xe”', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 1, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 727),
(4, 'Chuyển hướng không nhường quyền đi trước cho người đi bộ, xe lăn của người khuyết tật qua đường tại nơi có vạch kẻ đường dành cho người đi bộ', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 728),
(5, 'Chuyển hướng không nhường quyền đi trước cho xe thô sơ đang đi trên phần đường dành cho xe thô sơ', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 729),
(6, 'Chuyển hướng không nhường đường cho các xe đi ngược chiều', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 730),
(7, 'Chuyển hướng không nhường đường cho người đi bộ, xe thô sơ đang qua đường tại nơi không có vạch kẻ đường cho người đi bộ', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 731),
(8, 'Lùi xe mô tô ba bánh không quan sát hai bên, phía sau xe hoặc không có tín hiệu lùi xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 732),
(9, 'Chở người ngồi trên xe sử dụng ô (dù)', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng', NULL, NULL, NULL, 1, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 733),
(10, 'Không tuân thủ các quy định về nhường đường tại nơi đường giao nhau', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm c, điểm d khoản 6 Điều 7 Nghi định 168/2024/NĐ-CP.', 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 734),
(11, 'Chuyển làn đường không đúng nơi cho phép hoặc không có tín hiệu báo trước hoặc chuyển làn đường không đúng quy định', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, 'Mỗi lần chuyển làn đường chỉ được phép chuyển sang một làn đường liền kề.', 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 735),
(12, 'Điều khiển xe chạy dàn hàng ngang từ 3 xe trở lên', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', 'Nếu gây tai nạn giao thông thì bị tước quyền sử dụng Giấy phép lái xe từ 02 tháng đến 04 tháng.', NULL, 'Điều khiển xe chạy dàn hàng ngang từ 3 xe trở lên mà gây tai nạn giao thông thì phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng và bị trừ điểm giấy phép lái xe 10 điểm', 1, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 736),
(13, 'Không sử dụng đèn chiếu sáng trong thời gian từ 18 giờ ngày hôm trước đến 06 giờ ngày hôm sau hoặc khi có sương mù, khói, bụi, trời mưa, thời tiết xấu làm hạn chế tầm nhìn', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 737),
(14, 'Tránh xe không đúng quy định', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 738),
(15, 'Sử dụng đèn chiếu xa khi gặp xe đi ngược chiều', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 739),
(16, 'Không nhường đường cho xe đi ngược chiều theo quy định tại nơi đường hẹp, đường dốc, nơi có chướng ngại vật', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 740),
(17, 'Sử dụng còi trong thời gian từ 22 giờ ngày hôm trước đến 05 giờ ngày hôm sau trong khu đông dân cư, khu vực cơ sở khám bệnh, chữa bệnh', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng', '- Gây tai nạn giao thông: Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng', NULL, 'Trường hợp này không áp dụng đối với các xe ưu tiên đang đi làm nhiệm vụ theo quy định.', 1, 4, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 741),
(18, 'Xe được quyền ưu tiên lắp đặt, sử dụng thiết bị phát tín hiệu ưu tiên không đúng quy định hoặc sử dụng thiết bị phát tín hiệu ưu tiên mà không có giấy phép của cơ quan có thẩm quyền cấp hoặc có giấy phép của cơ quan có thẩm quyền cấp nhưng không còn giá trị sử dụng theo quy định.', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 1, 4, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 742),
(19, 'Quay đầu xe tại nơi không được quay đầu xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, 'Trường hợp này không áp dụng đối với hành vi vi phạm quy định tại điểm d khoản 4 Điều 7 Nghị định 168/2024/NĐ-CP.', 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 743),
(20, 'Điều khiển xe chạy dưới tốc độ tối thiểu trên đoạn đường bộ có quy định tốc độ tối thiểu cho phép', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng', NULL, NULL, NULL, 1, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 744),
(21, 'Dừng xe, đỗ xe trên phần đường xe chạy ở đoạn đường ngoài đô thị nơi có lề đường', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 745),
(22, 'Không giảm tốc độ (hoặc dừng lại) và nhường đường khi điều khiển xe đi từ đường không ưu tiên ra đường ưu tiên, từ đường nhánh ra đường chính', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 746),
(23, 'Điều khiển xe chạy quá tốc độ quy định từ 05 km/h đến dưới 10 km/h', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 1, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 747),
(24, 'Điều khiển xe chạy tốc độ thấp mà không đi bên phải phần đường xe chạy gây cản trở giao thông', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', 'Gây tai nạn giao thông phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng', NULL, NULL, 1, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 748),
(25, 'Dừng xe, đỗ xe ở lòng đường gây cản trở giao thông', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 749),
(26, 'Tụ tập từ 03 xe trở lên ở lòng đường, trong hầm đường bộ', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 750),
