(88, 'Không tuân thủ các quy định về nhường đường tại nơi đường bộ giao nhau', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng với các hành vi vi phạm quy định tại điểm n, điểm o khoản 5 Điều 6 Nghị định 168/2024/NĐ-CP', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 817),
(89, 'Chuyển hướng không nhường quyền đi trước cho: người đi bộ, xe lăn của người khuyết tật qua đường tại nơi có vạch kẻ đường dành cho người đi bộ', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 818),
(90, 'Điều khiển xe ô tô chở hành khách, ô tô chở người thực hiện hành vi vi phạm chở quá số người quy định được phép chở của phương tiện', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng trên mỗi người vượt quá quy định được phép chở của phương tiện (Tổng mức phạt tiền tối đa không vượt quá 75.000.000 đồng)', 'Trường hợp vượt trên 100% số người quy định được phép chở của phương tiện bị trừ điểm giấy phép lái xe 10 điểm.', NULL, '- Trường hợp này không áp dụng với xe buýt.\r\n-  Trừ các hành vi vi phạm quy định tại khoản 4 Điều 20 Nghị định 168/2024/NĐ-CP.', 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 820),
(91, 'Chuyển hướng không nhường quyền đi trước cho: người đi bộ, xe lăn của người khuyết tật qua đường tại nơi có vạch kẻ đường dành cho người đi bộ; xe thô sơ đang đi trên phần đường dành cho xe thô sơ', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 822),
(92, 'Điều khiển xe có liên quan trực tiếp đến vụ tai nạn giao thông mà không dừng ngay phương tiện, không giữ nguyên hiện trường, không trợ giúp người bị nạn', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trừ hành vi vi phạm gây tai nạn giao thông không dừng ngay phương tiện, không giữ nguyên hiện trường, không trợ giúp người bị nạn, không ở lại hiện trường hoặc không đến trình báo ngay với cơ quan công an, Ủy ban nhân dân nơi gần nhất.', 2, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 823),
(93, 'Điều khiển xe ô tô chở hành khách (kinh doanh vận tải hành khách theo tuyến cố định, hợp đồng) chạy tuyến có cự ly lớn hơn 300 km thực hiện hành vi vi phạm chở quá số người quy định được phép chở của phương tiện', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng trên mỗi người vượt quá quy định được phép chở của phương tiện nhưng tổng mức phạt tiền tối đa không vượt quá 75.000.000 đồng', '- Trường hợp vượt trên 50% đến 100% số người quy định được phép chở của phương tiện bị trừ điểm giấy phép lái xe 04 điểm\r\n- Trường hợp vượt trên 100% số người quy định được phép chở của phương tiện bị trừ điểm giấy phép lái xe 10 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 824),
(94, 'Chuyển hướng không nhường đường cho: các xe đi ngược chiều; người đi bộ, xe thô sơ đang qua đường tại nơi không có vạch kẻ đường cho người đi bộ.', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 825),
(95, 'Xe được quyền ưu tiên lắp đặt, sử dụng thiết bị phát tín hiệu ưu tiên không đúng quy định hoặc sử dụng thiết bị phát tín hiệu ưu tiên mà không có giấy phép của cơ quan có thẩm quyền cấp hoặc có giấy phép của cơ quan có thẩm quyền cấp nhưng không còn giá trị sử dụng theo quy định', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, NULL, 2, 4, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 826),
(96, 'Cắt, hàn, tẩy xoá, đục sửa, đóng lại trái phép số khung, số động cơ (số máy)', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Tịch thu phương tiện', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 827),
(97, 'Điều khiển xe trên đường mà trong máu hoặc hơi thở có nồng độ cồn nhưng chưa vượt quá 50 miligam/100 mililít máu hoặc chưa vượt quá 0,25 miligam/1 lít khí thở', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 9, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 828),
(98, 'Đưa phương tiện đã bị cắt, hàn, tẩy xoá, đục sửa, đóng lại trái phép số khung, số động cơ (số máy) tham gia giao thông;', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Tịch thu phương tiện', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 829),
(99, 'Dừng xe, đỗ xe trên phần đường xe chạy ở đoạn đường ngoài đô thị nơi có lề đường rộng', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 830),
(100, 'Chuyển hướng không nhường đường cho người đi bộ, xe lăn của người khuyết tật đang qua đường tại nơi không có vạch kẻ đường cho người đi bộ', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 832),
(101, 'Tẩy xóa, sửa chữa hoặc giả mạo hồ sơ đăng ký xe ô tô và các loại xe tương tự xe ô tô nhưng chưa đến mức truy cứu trách nhiệm hình sự', 'Chủ phương tiện', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Bị thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 833),
(102, 'Không chấp hành hiệu lệnh của đèn tín hiệu giao thông', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng', NULL, NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 834),
(103, 'Dừng xe, đỗ xe không sát mép đường phía bên phải theo chiều đi ở nơi đường có lề đường hẹp hoặc không có lề đường', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 835),
(104, 'Không làm thủ tục thu hồi chứng nhận đăng ký xe', 'Chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện).', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 836),
(105, 'Quay đầu xe ở phần đường dành cho người đi bộ qua đường, trên cầu, đầu cầu, ngầm, gầm cầu vượt', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với trường hợp tổ chức giao thông tại những khu vực này có bố trí nơi quay đầu xe.', 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 838),
(106, 'Dừng xe, đỗ xe ngược với chiều lưu thông của làn đường', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 839),
(107, 'Không làm thủ tục thu hồi biển số xe xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô.', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô.', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải làm thủ tục thu hồi biển số xe theo quy định.', 'Trừ trường hợp bị tịch thu phương tiện.', 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 841),
(108, 'Dừng xe, đỗ xe trên dải phân cách cố định ở giữa hai phần đường xe chạy', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 842),
(109, 'Lùi xe ở đường một chiều, đường có biển Cấm đi ngược chiều, khu vực cấm dừng, trên phần đường dành cho người đi bộ qua đường, nơi đường bộ giao nhau, nơi đường bộ giao nhau cùng mức với đường sắt, nơi tầm nhìn bị che khuất', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 845),
(110, 'Không làm thủ tục thu hồi giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định', 'Chủ phương tiện', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện)', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 846),
