(117, 'Điều khiển xe đạp, xe đạp máy buông cả hai tay', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng.', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 854),
(118, 'Dừng xe trên đường dành riêng cho xe buýt', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 855),
