(120, 'Dừng xe trên miệng cống thoát nước, miệng hầm của đường điện thoại, điện cao thế, chỗ dành riêng cho xe chữa cháy lấy nước', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 857),
(121, 'Rời vị trí lái, tắt máy khi dừng xe (trừ trường hợp rời khỏi vị trí lái để đóng, mở cửa xe, xếp dỡ hàng hóa, kiểm tra kỹ thuật xe) hoặc rời vị trí lái khi dừng xe nhưng không sử dụng phanh đỗ xe (hoặc thực hiện biện pháp an toàn khác)', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'trừ trường hợp rời khỏi vị trí lái để đóng, mở cửa xe, xếp dỡ hàng hóa, kiểm tra kỹ thuật xe', 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 858),
(122, 'Dừng xe, đỗ xe không sát mép đường phía bên phải theo chiều đi ở nơi đường có lề đường hẹp hoặc không có lề đường', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 859),
(123, 'Không thực hiện đúng quy định về biển số, quy định về kẻ chữ trên thành xe và cửa xe ô tô và các loại xe tương tự xe ô tô', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc thực hiện đúng quy định về biển số xe, quy định về kẻ hoặc dán chữ, số biển số, thông tin trên thành xe, cửa xe.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 861),
(124, 'Dừng xe, đỗ xe không đúng vị trí quy định ở những đoạn có bố trí nơi dừng xe, đỗ xe', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 862),
(125, 'Chuyển hướng đột ngột trước đầu xe cơ giới đang chạy', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 863),
(126, 'Dừng xe, đỗ xe ngược với chiều lưu thông của làn đường', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 864);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(127, 'Dừng xe, đỗ xe trên phần đường dành cho người đi bộ qua đường', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 866),
(128, 'Khai báo không đúng sự thật hoặc sử dụng các giấy tờ, tài liệu giả để được cấp lại biển số, Giấy đăng ký xe, Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường xe ô tô và các loại xe tương tự xe ô tô nhưng chưa đến mức bị truy cứu trách nhiệm hình sự', 'Chủ phương tiện', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo; giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 867),
(129, 'Dùng chân điều khiển xe đạp, xe đạp máy', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 868),
(130, 'Dừng xe nơi có biển “Cấm dừng xe và đỗ xe”', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'trừ hành vi vi phạm quy định tại điểm đ khoản 4, điểm c khoản 7 Điều 6 Nghị định 168/2024/NĐ-CP', 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 869),
(131, 'Dừng xe, đỗ xe trên dải phân cách cố định ở giữa hai phần đường xe chạy', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 871),
(132, 'Không chấp hành hiệu lệnh, chỉ dẫn của người điều khiển giao thông hoặc người kiểm soát giao thông', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng', NULL, NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 872),
(133, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện hoặc trực tiếp điều khiển phương tiện thực hiện hành vi chở hành lý, hàng hóa vượt quá kích thước bao ngoài của xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 873),
(134, 'Dừng xe, đỗ xe không đúng vị trí quy định ở những đoạn đường đã có bố trí nơi dừng xe, đỗ xe', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 875),
(135, 'Người đang điều khiển xe hoặc chở người ngồi trên xe bám, kéo, đẩy xe khác, vật khác, mang vác vật cồng kềnh', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 876),
(136, 'Quay đầu xe ở phần đường dành cho người đi bộ qua đường, trên cầu, đầu cầu, ngầm, gầm cầu vượt', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trừ khi có hiệu lệnh của người điều khiển giao thông hoặc chỉ dẫn của biển báo hiệu tạm thời hoặc tổ chức giao thông tại những khu vực này có bố trí nơi quay đầu xe', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 877),
(137, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện hoặc trực tiếp điều khiển phương tiện chở hành lý, hàng hóa vượt quá trọng tải theo thiết kế của xe', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 878),
(138, 'Đỗ xe trên dốc không chèn bánh', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 880),
(139, 'Điều khiển xe chạy quá tốc độ quy định từ 05 km/h đến dưới 10 km/h', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 881),
(140, 'Điều khiển xe kéo theo xe khác, vật khác', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 882),
(141, 'Người đang điều khiển xe hoặc chở người ngồi trên xe bám, kéo, đẩy xe khác, vật khác, mang vác vật cồng kềnh', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 150.000 đồng đến 250.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 883),
(142, 'Dừng xe nơi có biển Cấm dừng xe và đỗ xe', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 884),
(143, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30% (trừ xe xi téc chở chất lỏng), trên 20% đến 30% đối với xe xi téc chở chất lỏng.', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) và các loại xe tương tự xe ô tô.', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n-  Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 885),
(144, 'Sử dụng còi, rú ga liên tục', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'Ngoại trừ trường hợp các xe ưu tiên đang đi làm nhiệm vụ theo quy định', 2, 4, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 886),
(145, 'Điều khiển xe lạng lách, đánh võng', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 887),
(146, 'Đỗ xe nơi có biển Cấm đỗ xe hoặc biển Cấm dừng xe và đỗ xe', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với hành vi vi phạm quy định tại điểm a khoản 6 Điều 7 Nghị định 100/2019/NĐ-CP.', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 888),
(147, 'Sử dụng còi hơi, sử dụng đèn chiếu xa khi gặp người đi bộ qua đường hoặc khi đi trên đoạn đường qua khu dân cư có hệ thống chiếu sáng đang hoạt động hoặc khi gặp xe đi ngược chiều hoặc khi chuyển hướng xe tại nơi đường giao nhau', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng với dải phân cách có khả năng chống chói và các xe ưu tiên đang đi làm nhiệm vụ theo quy định', 2, 4, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 890),
(148, 'Đuổi nhau trên đường', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 891),
(149, 'Dừng xe, đỗ xe tại bên trái đường một chiều hoặc bên trái (theo hướng lưu thông) của đường đôi', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 893),
(150, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30%.', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) và các loại xe tương tự xe ô tô.', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n-  Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 894),
(151, 'Chuyển hướng không quan sát hoặc không bảo đảm khoảng cách an toàn với xe phía sau hoặc không giảm tốc độ hoặc không có tín hiệu báo hướng rẽ hoặc có tín hiệu báo hướng rẽ nhưng không sử dụng liên tục trong quá trình chuyển hướng', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'trừ trường hợp điều khiển xe đi theo hướng cong của đoạn đường bộ ở nơi đường không giao nhau cùng mức', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 895),
