(174, 'Dừng xe, đỗ xe che khuất biển báo hiệu đường bộ, đèn tín hiệu giao thông', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 924),
(175, 'Điều khiển xe trên đường mà trong máu hoặc hơi thở có nồng độ cồn vượt quá 50 miligam đến 80 miligam/100 mililít máu hoặc vượt quá 0,25 miligam đến 0,4 miligam/1 lít khí thở', 'Người điều khiển xe đạp, xe đạp máy (kể cả xe đạp điện), người điều khiển xe thô sơ khác', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 9, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 925),
(176, 'Dừng xe, đỗ xe nơi mở dải phân cách giữa', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 926),
(177, 'Dừng xe, đỗ xe tại nơi mở dải phân cách giữa', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 928),
(178, 'Đỗ xe không sát theo lề đường, vỉa hè phía bên phải theo chiều đi hoặc bánh xe gần nhất cách lề đường, vỉa hè quá 0,25 m', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 929),
(179, 'Điều khiển xe trên đường mà trong máu hoặc hơi thở có nồng độ cồn vượt quá 80 miligam/100 mililít máu hoặc vượt quá 0,4 miligam/1 lít khí thở', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 9, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 930),
(180, 'Không làm thủ tục cấp chứng nhận đăng ký xe, biển số xe trong trường hợp thay đổi chủ xe theo quy định', 'Chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng', NULL, 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện)', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 931),
(181, 'Đỗ xe trên đường dành riêng cho xe buýt', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 932),
(182, 'Đỗ xe trên miệng cống thoát nước, miệng hầm của đường điện thoại, điện cao thế, chỗ dành riêng cho xe chữa cháy lấy nước', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 933),
(183, 'Đỗ, để xe ở vỉa hè trái quy định của pháp luật', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 934),
(184, 'Không chấp hành yêu cầu kiểm tra về nồng độ cồn của người thi hành công vụ', 'Người điều khiển  xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', NULL, 3, 9, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 935),
(185, 'Đỗ xe nơi có biển “Cấm đỗ xe” hoặc biển “Cấm dừng xe và đỗ xe”', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'trừ hành vi vi phạm quy định tại điểm đ khoản 4, điểm c khoản 7 Điều 6 Nghị định 168/2024/NĐ-CP', 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 936),
(186, 'Đi vào khu vực cấm', 'Người điều khiển xe đạp, xe đạp máy (kể cả xe đạp điện), người điều khiển xe thô sơ khác', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 937),
(187, 'Dừng xe, đỗ xe ở lòng đường trái quy định', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 939),
(188, 'Không sử dụng hoặc sử dụng không đủ đèn chiếu sáng trong thời gian từ 18 giờ ngày hôm trước đến 06 giờ ngày hôm sau hoặc khi có sương mù, khói, bụi, trời mưa, thời tiết xấu làm hạn chế tầm nhìn', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 940),
(189, 'Đi vào đường có biển báo hiệu nội dung cấm đi vào đối với loại phương tiện đang điều khiển', 'Người điều khiển xe đạp, xe đạp máy (kể cả xe đạp điện), người điều khiển xe thô sơ khác', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 941),
(190, 'Đi ngược chiều đường của đường một chiều, đường có biển cấm đi ngược chiều', 'Người điều khiển xe đạp, xe đạp máy (kể cả xe đạp điện), người điều khiển xe thô sơ khác', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 943),
(191, 'Sử dụng đèn chiếu xa khi tránh xe đi ngược chiều', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'Trừ trường hợp dải phân cách có khả năng chống chói.', 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 944),
(192, 'Dừng xe, đỗ xe trên đường dành riêng cho xe buýt, trên miệng cống thoát nước, miệng hầm của đường điện thoại, điện cao thế, chỗ dành riêng cho xe chữa cháy lấy nước, trên phần đường dành cho người đi bộ qua đường', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 945),
(193, 'Điều khiển xe ô tô kéo theo xe khác, vật khác', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trừ trường hợp kéo theo một rơ moóc, sơ mi rơ moóc hoặc một xe ô tô, xe máy chuyên dùng khác khi xe này không tự chạy được', 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 946),
(194, 'Điều khiển xe đi vào đường cao tốc', 'Người điều khiển xe đạp, xe đạp máy (kể cả xe đạp điện), người điều khiển xe thô sơ khác', 'Phạt tiền từ 800.000 đồng đến 1.200.000 đồng.', NULL, NULL, 'Trường hợp này không áp dụng với phương tiện phục vụ việc quản lý, bảo trì đường cao tốc.\r\nTrường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 947),
(195, 'Rời vị trí lái, tắt máy khi dừng xe', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ trường hợp rời khỏi vị trí lái để đóng, mở cửa xe, xếp dỡ hàng hóa, kiểm tra kỹ thuật xe', 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 949),
(196, 'Đưa xe ô tô và các loại xe tương tự xe ô tô có chứng nhận đăng ký xe tạm thời, phương tiện có phạm vi hoạt động hạn chế tham gia giao thông quá thời hạn, tuyến đường, phạm vi cho phép', 'Chủ phương tiện', 'Phạt tiền từ 16.000.000 đồng đến 18.000.000 đồng đối với cá nhân, từ 32.000.000 đồng đến 36.000.000 đồng đối với tổ chức', 'Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện).', 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 950),
(197, 'Điều khiển xe ô tô đẩy xe khác, vật khác', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Nếu gây tai nạn giao thông thì bị tước quyền sử dụng Giấy phép lái xe từ 02 tháng đến 04 tháng', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 951),
(198, 'Người được chở trên xe đạp, xe đạp máy sử dụng ô (dù)', 'Người được chở trên xe đạp, xe đạp máy', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 952),
(199, 'Thuê, mượn linh kiện, phụ kiện của xe ô tô khi kiểm định', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô.', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 953),
(200, 'Mở cửa xe, để cửa xe mở không bảo đảm an toàn', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng', 'Thực hiện hành vi quy định tại một trong các điểm, khoản sau của Điều này mà gây tai nạn giao thông thì bị tước quyền sử dụng Giấy phép lái xe (khi điều khiển máy kéo), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 02 tháng đến 04 tháng.', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 955),
(201, 'Điều khiển xe kéo rơ moóc, sơ mi rơ moóc kéo thêm rơ moóc hoặc xe khác, vật khác', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 956),
(202, 'Tụ tập để cổ vũ, giúp sức, xúi giục hành vi điều khiển xe chạy quá tốc độ quy định, lạng lách, đánh võng, đuổi nhau trên đường hoặc đua xe trái phép', 'Người đua xe trái phép, tổ chức đua xe, xúi giục, cổ vũ đua xe trái phép', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 957),
(203, 'Đưa xe cơ giới, xe máy chuyên dùng có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường (đối với loại xe có quy định phải kiểm định) nhưng đã hết hiệu lực (hạn sử dụng) dưới 01 tháng (kể cả rơ moóc và sơ mi rơ moóc) tham gia giao thông', 'Chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với chủ xe là cá nhân. Phạt tiền từ  8.000.000 đồng đến 12.000.000 đồng đối với chủ xe là tổ chức.', 'Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 958),
(204, 'Khi ra, vào vị trí dừng xe, đỗ xe không có tín hiệu báo cho người điều khiển phương tiện khác biết', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 959),
(205, 'Đua xe đạp, đua xe đạp máy, đua xe xích lô, đua xe súc vật kéo, cưỡi súc vật chạy đua trái phép trên đường giao thông', 'Người đua xe đạp, đua xe đạp máy, đua xe xích lô, đua xe súc vật kéo, cưỡi súc vật', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Tịch thu phương tiện (trừ súc vật kéo, cưỡi).', NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 960),
(206, 'Không nối chắc chắn, an toàn giữa xe kéo và xe được kéo khi kéo nhau', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 961),
(207, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện hoặc trực tiếp điều khiển phương tiện chở hàng vượt quá chiều cao xếp hàng cho phép đối với xe ô tô tải (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe ô tô tải', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 962),
(208, 'Chở người trên xe được kéo', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp này không áp dụng với người điều khiển', 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 963),
(209, 'Không chấp hành hiệu lệnh, chỉ dẫn của biển báo hiệu, vạch kẻ đường khi đi qua đường ngang, cầu chung', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ', 'Phạt tiền từ 80.000 đồng đến 100.000 đồng.', NULL, NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 964),
(210, 'Quay đầu xe tại nơi đường bộ giao nhau cùng mức với đường sắt', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, 'trừ khi có hiệu lệnh của người điều khiển giao thông hoặc chỉ dẫn của biển báo hiệu tạm thời hoặc tổ chức giao thông tại những khu vực này có bố trí nơi quay đầu xe', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 965),
(211, 'Dừng xe, đỗ xe trong phạm vi an toàn đường ngang, cầu chung', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 967),
(212, 'Quay đầu xe tại nơi đường hẹp, đường dốc, đoạn đường cong tầm nhìn bị che khuất, trên đường một chiều', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, 'trừ khi có hiệu lệnh của người điều khiển giao thông hoặc chỉ dẫn của biển báo hiệu tạm thời hoặc tổ chức giao thông tại những khu vực này có bố trí nơi quay đầu xe', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 968),
(213, 'Vượt rào chắn đường ngang, cầu chung khi chắn đang dịch chuyển', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 969),
(214, 'Không giữ khoảng cách an toàn để xảy ra va chạm với xe chạy liền trước hoặc không giữ khoảng cách theo quy định của biển báo hiệu “Cự ly tối thiểu giữa hai xe”', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, 'Trừ các hành vi vi phạm quy định tại điểm d khoản 5 Điều này', 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 970),
(215, 'Vượt đường ngang, cầu chung khi đèn đỏ đã bật sáng', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 971),
(216, 'Đưa xe ô tô và các loại xe tương tự xe ô tô quá niên hạn sử dụng tham gia giao thông', 'Chủ phương tiện', 'Tịch thu phương tiện', NULL, NULL, '- Trường hợp này không áp dụng đối với hành vi vi phạm quy định tại điểm i khoản 7 Điều 26 Nghị định 168/2024/NĐ-CP\r\n- Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 972),
(217, 'Không giảm tốc độ (hoặc dừng lại) và nhường đường khi điều khiển xe đi từ đường không ưu tiên ra đường ưu tiên, từ đường nhánh ra đường chính', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 973),
(218, 'Không chấp hành hiệu lệnh, chỉ dẫn của nhân viên gác đường ngang, cầu chung khi đi qua đường ngang, cầu chung', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 974),
(219, 'Không tuân thủ các quy định về nhường đường tại nơi đường bộ giao nhau', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'trừ các hành vi vi phạm quy định tại điểm n, điểm o khoản 5 Điều 6 Nghị định 168/2024/NĐ-CP', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 975),
(220, 'Đưa xe ô tô và các loại xe tương tự xe ô tô có Giấy đăng ký xe, Giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe nhưng không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa tham gia giao thông', 'Chủ phương tiện', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Tịch thu phương tiện trong trường hợp có chứng nhận đăng ký xe nhưng không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa (kể cả rơ moóc và sơ mi rơ moóc) mà không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng nhận nguồn gốc xe, chứng nhận quyền sở hữu hợp pháp)\r\n- Bị thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo; giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường; chứng nhận đăng ký xe không do cơ quan có thẩm quyền cấp; giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe không do cơ quan có thẩm quyền cấp.\r\n- Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', '- Buộc nộp lại chứng nhận đăng ký xe, giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe bị tẩy xóa', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 976),
(221, 'Lùi xe ở đường một chiều, đường có biển “Cấm đi ngược chiều”, khu vực cấm dừng, trên phần đường dành cho người đi bộ qua đường, nơi đường bộ giao nhau, đường bộ giao nhau cùng mức với đường sắt, nơi tầm nhìn bị che khuất', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, 'Quy định này không áp dụng đối với hành vi vi phạm quy định tại điểm đ khoản 11 Điều 6 Nghị định 168/2024/NĐ-CP', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 977),
(222, 'Điều khiển xe không gắn biển số', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'Trường hợp này chỉ áp dụng với loại xe có quy định phải gắn biển số', 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 980),
(223, 'Lùi xe không quan sát hai bên, phía sau xe hoặc không có tín hiệu lùi xe', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ  2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng với  các hành vi vi phạm quy định tại điểm đ khoản 11 Điều 6 Nghị định 168/2024NĐ-CP', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 981),
(224, 'Chạy quá tốc độ quy định từ 05 km/h đến dưới 10 km/h', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 982),
(225, 'Không thắt dây đai an toàn khi điều khiển xe chạy trên đường', 'Người điều khiển xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 983),
(226, 'Đưa xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe nhưng không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa tham gia giao thông; đưa phương tiện có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) nhưng không đúng với số khung, số động cơ (số máy) của xe (kể cả rơ moóc và sơ mi rơ moóc) tham gia giao thông;', 'Chủ phương tiện', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Tịch thu phương tiện\r\n- Bị thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo; giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường; chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc không đúng với số khung, số động cơ (số máy); giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe không do cơ quan có thẩm quyền cấp.\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', '- Buộc nộp lại chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe bị tẩy xóa;', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 984),
(227, 'Đi vào khu vực cấm, đường có biển báo hiệu có nội dung cấm đi vào đối với loại phương tiện đang điều khiển', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', 'Tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng.', NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm a, điểm b khoản 7 Điều 7 Nghị định 168/2024/NĐ-CP và các trường hợp xe ưu tiên đang đi làm nhiệm vụ khẩn cấp theo quy định', 1, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 985),
(228, 'Không thực hiện đúng quy định về biển số, quy định về kẻ hoặc dán chữ, số biển số, thông tin trên thành xe, cửa xe (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc thực hiện đúng quy định về biển số xe, quy định về kẻ hoặc dán chữ, số biển số, thông tin trên thành xe, cửa xe.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 986),
(229, 'Đi vào khu vực cấm, đường có biển báo hiệu có nội dung cấm đi vào đối với loại phương tiện đang điều khiển', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm d khoản 7, điểm đ khoản 9 Điều này và các trường hợp xe ưu tiên đang đi làm nhiệm vụ khẩn cấp theo quy định.', 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 987),
(230, 'Chở người trên xe ô tô không thắt dây đai an toàn (tại vị trí có trang bị dây đai an toàn) khi xe đang chạy', 'Người điều khiển xe', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 988),
(231, 'Chạy trong hầm đường bộ không sử dụng đèn chiếu sáng gần', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 989);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(232, 'Không đi bên phải theo chiều đi của mình', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, 'trừ các hành vi vi phạm quy định tại điểm e khoản 6, điểm d khoản 7, điểm đ khoản 9 Điều 8 Nghị định 168/2024/NĐ-CP', 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 990),
(233, 'Điều khiển xe chạy dưới tốc độ tối thiểu trên những đoạn đường bộ có quy định tốc độ tối thiểu cho phép', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', '- Nếu gây tai nạn giao thông thì bị tước quyền sử dụng Giấy phép lái xe từ 02 tháng đến 04 tháng', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 992),
(234, 'Không thực hiện đúng quy định về biển số, quy định về kẻ hoặc dán chữ, số biển số, thông tin trên thành xe, cửa xe (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc thực hiện đúng quy định về biển số xe, quy định về kẻ hoặc dán chữ, số biển số, thông tin trên thành xe, cửa xe.', 'Trừ các hành vi vi phạm quy định tại điểm b, điểm c khoản 12; điểm d khoản 13 Điều 32 và các hành vi vi phạm quy định tại điểm b khoản 3 Điều 39 của Nghị định 168/2024/NĐ-CP.', 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 993),
(235, 'Đi không đúng phần đường hoặc làn đường quy định (làn cùng chiều hoặc làn ngược chiều)', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 995),
(236, 'Dùng tay cầm và sử dụng điện thoại hoặc các thiết bị điện tử khác khi điều khiển phương tiện tham gia giao thông đang di chuyển trên đường bộ;', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 996),
(237, 'Giao xe hoặc để cho người không đủ điều kiện theo quy định tại khoản 1 Điều 56 (đối với xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô) của Luật Trật tự, an toàn giao thông đường bộ điều khiển xe tham gia giao thông (bao gồm cả trường hợp người điều khiển phương tiện có giấy phép lái xe nhưng đã hết hạn sử dụng hoặc đang trong thời gian bị tước quyền sử dụng; chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ bị tước quyền sử dụng trước ngày 01/01/2025 và đang trong thời gian bị tước).', 'Chủ phương tiện', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 997),
(238, 'Chở người đứng trên yên, giá đèo hàng hoặc ngồi trên tay lái của xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 1, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 998),
(239, 'Lắp đặt, sử dụng thiết bị thay đổi biển số trên xe ô tô trái quy định (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô, phương tiện giao thông thông minh.', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với chủ xe là cá nhân. Phạt tiền từ 8.000.000 đồng đến 12.000.000 đồng đối với chủ xe là tổ chức.', '- Tịch thu thiết bị thay đổi biển số.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 999),
(240, 'Lắp đặt, sử dụng thiết bị thay đổi biển số trên xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, và các loại xe tương tự xe ô tô trái quy định (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, và các loại xe tương tự xe ô tô', 'Phạt tiền từ 16.000.000 đồng đến 18.000.000 đồng đối với cá nhân, từ 32.000.000 đồng đến 36.000.000 đồng đối với tổ chức', 'Tịch thu biển số, thiết bị thay đổi biển số.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1000),
(241, 'Đi vào khu vực cấm, đường có biển báo hiệu có nội dung cấm đi vào đối với loại phương tiện đang điều khiển', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trừ các hành vi vi phạm quy định tại điểm d khoản 9, điểm đ khoản 11 Điều 6 Nghị định 168-2024/NĐ-CP, hành vi bị cấm đi vào công trình thủy lợi và các trường hợp xe ưu tiên đang đi làm nhiệm vụ khẩn cấp theo quy định;', 2, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1001),
(242, 'Điều khiển xe đi qua dải phân cách cố định ở giữa hai phần đường xe chạy', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm e khoản 6, điểm d khoản 7, điểm đ khoản 9 Điều 8 Nghị định 168/2024/NĐ-CP.', 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1002),
(243, 'Điều khiển xe đi qua dải phân cách cố định ở giữa hai phần đường xe chạy', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm e khoản 6, điểm d khoản 7, điểm đ khoản 9 Điều 8 Nghị định 168/2024/NĐ-CP', 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1003),
(244, 'Xếp hàng hóa trên xe vượt quá giới hạn quy định', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', 'Nếu gây tai nạn giao thông thì bị tước quyền sử dụng Giấy phép lái xe từ 02 tháng đến 04 tháng.', NULL, NULL, 1, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1004),
(245, 'Điều khiển xe không đủ điều kiện đã thu phí theo hình thức điện tử tự động không dừng (xe không gắn thẻ đầu cuối) đi vào làn đường dành riêng thu phí theo hình thức điện tử tự động không dừng tại các trạm thu phí', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1005),
(246, 'Điều khiển xe không có hệ thống (bộ phận) hãm hoặc có nhưng không có hiệu lực (đối với loại xe quy định phải có hệ thống (bộ phận) này)', 'Người điều khiển xe thô sơ', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1006),
(247, 'Tự ý thay đổi tổng thành khung, tổng thành máy (động cơ), hệ thống phanh, hệ thống truyền động (truyền lực), hệ thống chuyển động hoặc tự ý cải tạo kết cấu, hình dáng, kích thước của xe không đúng thiết kế của nhà sản xuất hoặc thiết kế trong hồ sơ đã nộp cho cơ quan đăng ký xe hoặc thiết kế cải tạo đã được cơ quan có thẩm quyền phê duyệt; tự ý thay đổi tính năng sử dụng của xe hoặc tự ý lắp đặt thêm cơ cấu nâng hạ thùng xe, nâng hạ công-ten-nơ trên xe (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng', 'Bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.', 'Buộc khôi phục lại hình dáng, kích thước, tình trạng an toàn kỹ thuật ban đầu của xe và đăng kiểm lại trước khi đưa phương tiện ra tham gia giao thông.', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1007),
(248, 'Điều khiển xe kéo theo xe khác, vật khác', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng đối với người điều khiển xe gây tai nạn giao thông', 1, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1008),
