(268, 'Không nhường đường cho xe xin vượt khi có đủ điều kiện an toàn', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', '- Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1031),
(269, 'Không sử dụng hoặc sử dụng không đủ đèn chiếu sáng trong thời gian từ 18 giờ ngày hôm trước đến 06 giờ ngày hôm sau hoặc khi có sương mù, khói, bụi, trời mưa, thời tiết xấu làm hạn chế tầm nhìn', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1032),
(270, 'Đu, bám vào phương tiện giao thông đang chạy', 'Người đi bộ', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1033),
(271, 'Lùi xe, quay đầu xe trong hầm đường bộ', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1034),
(272, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô và các loại xe tương tự xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Tổ chức cá nhân là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', '- Trường hợp phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có);\r\n- Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm.', '- Trường hợp phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông;\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1035),
(273, 'Sử dụng đèn chiếu xa khi gặp xe đi ngược chiều (trừ trường hợp dải phân cách có khả năng chống chói)', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với xe ưu tiên đang làm nhiệm vụ theo quy định.', 3, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1036),
