(298, 'Đi vào đường cao tốc trái quy định', 'Người điều khiển, dẫn dắt vật nuôi, điều khiển xe vật nuôi kéo', 'Phạt tiền từ 100.000 đồng đến 2.000.000 đồng.', NULL, NULL, NULL, 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1063),
(299, 'Vượt xe trong những trường hợp không được vượt, vượt xe tại đoạn đường có biển báo hiệu có nội dung cấm vượt (đối với loại phương tiện đang điều khiển)', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, 'bị trừ điểm giấy phép lái xe 02 điểm', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1064),
(300, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô và các loại xe tương tự xe ô tô mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 20% đến 50%', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\n- Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1065),
(301, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 20% đến 50%', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với xe có Giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1066),
(302, 'Vượt rào chắn đường ngang, cầu chung khi chắn đang dịch chuyển hoặc đã đóng', 'Người đi bộ', 'Phạt tiền từ 60.000 đồng đến 100.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1068),
(303, 'Vượt xe không có tín hiệu trước khi vượt hoặc có tín hiệu vượt xe nhưng không sử dụng trong suốt quá trình vượt xe', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, 'bị trừ điểm giấy phép lái xe 02 điểm', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1069),
(304, 'Đưa xe ô tô tải (kể cả rơ moóc và sơ mi rơ moóc) có kích thước thùng xe không đúng với thông số kỹ thuật được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe tham gia giao thông', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', '- Bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n- Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm.', 'Buộc khôi phục lại hình dáng, kích thước, tình trạng an toàn kỹ thuật ban đầu của xe và đăng kiểm lại trước khi đưa phương tiện ra tham gia giao thông', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1070),
(305, 'Vượt qua đường ngang khi đèn đỏ đã bật sáng', 'Người đi bộ', 'Phạt tiền từ 60.000 đồng đến 100.000 đồng.', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1071),
(306, 'Vượt bên phải xe khác trong trường hợp không được phép', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1073),
(307, 'Không chấp hành hiệu lệnh, chỉ dẫn của biển báo hiệu, vạch kẻ đường hoặc hướng dẫn của nhân viên gác đường ngang, cầu chung, hầm khi đi qua đường ngang, cầu chung, hầm', 'Người đi bộ', 'Phạt tiền từ 60.000 đồng đến 100.000 đồng.', NULL, NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1074),
(308, 'Đưa xe ô tô kinh doanh vận tải hành khách lắp thêm hoặc tháo bớt ghế, giường nằm hoặc có kích thước khoang chở hành lý (hầm xe) không đúng với thông số kỹ thuật được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe tham gia giao thông', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và Tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.', 'Buộc khôi phục lại hình dáng, kích thước, tình trạng an toàn kỹ thuật ban đầu của xe và đăng kiểm lại trước khi đưa phương tiện ra tham gia giao thông', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1075),
(309, 'Điều khiển xe không đi bên phải theo chiều đi của mình', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1076),
(310, 'Không chấp hành hiệu lệnh, hướng dẫn của người điều khiển giao thông hoặc người kiểm soát giao thông', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 1, 1, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1078),
(311, 'Đi không đúng phần đường hoặc làn đường quy định (làn cùng chiều hoặc làn ngược chiều)', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'trừ hành vi quy định tại điểm a khoản 4 Điều 6 Nghị định 168/2024/NĐ-CP', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1079),
(312, 'Người đang điều khiển xe sử dụng ô (dù), thiết bị âm thanh, dùng tay cầm và sử dụng điện thoại hoặc các thiết bị điện tử khác', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, 'Trừ thiết bị trợ thính', 1, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1080),
(313, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hoặc trực tiếp điều khiển phương tiện thực hiện hành vi điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe vượt quá tải trọng cho phép của đường bộ trên 10% đến 20%, trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra;', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1081),
(314, 'Điều khiển xe kinh doanh vận tải hàng hóa không có hoặc không mang theo giấy vận tải bằng văn bản giấy theo quy định hoặc không có thiết bị để truy cập vào được phần mềm thể hiện nội dung của giấy vận tải theo quy định hoặc có thiết bị để truy cập nhưng không cung cấp cho lực lượng chức năng khi có yêu cầu.', 'Người điều khiển xe ô tô tả và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1082),
(315, 'Đi ngược chiều của đường một chiều, đi ngược chiều trên đường có biển “Cấm đi ngược chiều”', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', NULL, NULL, '- Trừ hành vi vi phạm quy định tại điểm b khoản 7 Điều 7 Nghị định 168/2024/NĐ-CP và các trường hợp xe ưu tiên đang đi làm nhiệm vụ khẩn cấp theo quy định.', 1, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1083),
(316, 'Điều khiển xe đi qua dải phân cách cố định ở giữa hai phần đường xe chạy', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1084),
(317, 'Điều khiển xe đi trên vỉa hè', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'bị trừ điểm giấy phép lái xe 04 điểm', NULL, 'trừ trường hợp điều khiển xe đi qua vỉa hè để vào nhà, cơ quan', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1085),
(318, 'Sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', '- Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng đối với người điều khiển xe gây tai nạn giao thông.\r\n- Tịch thu phương tiện đối với người điều khiển xe tái phạm.\r\n- Bị tước quyền sử dụng giấy phép lái xe từ 10 tháng đến 12 tháng.', NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1086),
(319, 'Tránh xe đi ngược chiều không đúng quy định', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'trừ hành vi vi phạm sử dụng đèn chiếu xa khi tránh xe đi ngược chiều quy định tại điểm b khoản 3 Điều 6 Nghị định 168/2024/NĐ-CP', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1087),
(320, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hành vi vi phạm quy định tại điểm a, điểm b khoản 6 Điều 24 Nghị định này hoặc trực tiếp điều khiển phương tiện thực hiện hành vi vi phạm quy định tại điểm a, điểm b khoản 6 Điều 24 Nghị định này;', 'Tổ chức, cá nhân là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ  14.000.000 đồng đến 16.000.000 đồng đối với chủ xe là cá nhân. Phạt tiền từ  28.000.000 đồng đến 32.000.000 đồng đối với chủ xe là tổ chức.', '- Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng. \r\n- Tước quyền sử dụng Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và Tem kiểm định của phương tiện từ 01 tháng đến 03 tháng nếu phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành.\r\n- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có).', '- Phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc phải thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1088),
(321, 'Không nhường đường cho xe đi ngược chiều theo quy định tại nơi đường hẹp, đường dốc, nơi có chướng ngại vật', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1089),
(322, 'Điều khiển xe đi vào đường cao tốc', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', 'Tước quyền sử dụng Giấy phép lái xe từ 03 tháng đến 05 tháng.', NULL, '- Trường hợp này không áp dụng đối với xe phục vụ việc quản lý, bảo trì đường cao tốc.\r\n- Tạm giữ phương tiện tối đa đến 07 ngày trước khi ra quyết định xử phạt.', 1, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1090),
(323, 'Không tuân thủ các quy định khi vào hoặc ra đường cao tốc', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1091),
(324, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện hoặc trực tiếp điều khiển phương tiện thực hiện hành vi điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 50% đến 100%', 'Cá nhân, tổ chức là chủ xe ô tô, và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng', '- Trường hợp phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 04 điểm.', '- Trường hợp phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông;', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1092),
(325, 'Điều khiển xe chạy ở làn dừng xe khẩn cấp hoặc phần lề đường của đường cao tốc', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1093),
(326, 'Chuyển làn đường không đúng nơi cho phép hoặc không có tín hiệu báo trước khi chạy trên đường cao tốc', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1094),
(327, 'Không tuân thủ quy định về khoảng cách an toàn đối với xe chạy liền trước khi chạy trên đường cao tốc', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1095),
(328, 'Không nhường đường hoặc gây cản trở xe được quyền ưu tiên đang phát tín hiệu ưu tiên đi làm nhiệm vụ', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'bị trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1096),
(329, 'Điều khiển xe chạy quá tốc độ quy định từ 10 km/h đến 20 km/h', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1097),
(330, 'Điều khiển xe trên đường mà trong máu hoặc hơi thở có nồng độ cồn nhưng chưa vượt quá 50 miligam/100 mililít máu hoặc chưa vượt quá 0,25 miligam/1 lít khí thở', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', 'Trừ điểm giấy phép lái xe 04 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 9, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1098),
(331, 'Điều khiển xe chạy quá tốc độ quy định trên 20 km/h đến 35 km/h', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1099),
(332, 'Đỗ xe trên đường cao tốc không đúng nơi quy định', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 12.000.000 đồng đến 14.000.000 đồng', 'bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1100);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(333, 'Điều khiển xe chạy quá tốc độ quy định trên 20 km/h', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', '- Trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 1, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1101),
(334, 'Không nhường đường hoặc gây cản trở xe được quyền ưu tiên đang phát tín hiệu ưu tiên đi làm nhiệm vụ', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 2, 4, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1102),
(335, 'Quay đầu xe trên đường cao tốc', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 30.000.000 đồng đến 40.000.000 đồng', '- Bị trừ điểm giấy phép lái xe 10 điểm', NULL, 'trừ các xe ưu tiên đang đi làm nhiệm vụ khẩn cấp theo quy định', 2, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1103),
(336, 'Điều khiển xe trên đường mà trong máu hoặc hơi thở có nồng độ cồn nhưng chưa vượt quá 50 miligam/100 mililít máu hoặc chưa vượt quá 0,25 miligam/1 lít khí thở', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 9, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1104),
(337, 'Điều khiển xe chạy quá tốc độ quy định gây tai nạn giao thông', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 22.000.000 đồng', 'Trừ điểm giấy phép lái xe 10 điểm', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1105),
(338, 'Điều khiển xe có liên quan trực tiếp đến vụ tai nạn giao thông mà không dừng ngay phương tiện, không giữ nguyên hiện trường, không trợ giúp người bị nạn', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với hành vi vi phạm quy định tại điểm c khoản 8 Điều 8 Nghị định 168/2024/NĐ-CP.', 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1108),
(339, 'Tránh xe, vượt xe không đúng quy định', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1109),
(340, 'Điều khiển xe không quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn theo quy định mà gây tai nạn giao thông; điều khiển xe chạy quá tốc độ quy định gây tai nạn giao thông', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng', '- Trừ điểm giấy phép lái xe 10 điểm.', NULL, NULL, 1, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1110),
(341, 'Đi vào đường cao tốc, dừng xe, đỗ xe, quay đầu xe, lùi xe, vượt xe, chuyển hướng, chuyển làn đường không đúng quy định gây tai nạn giao thông', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 10 điểm.', NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1111),
(342, 'Không nhường đường cho xe đi ngược chiều theo quy định tại nơi đường hẹp, đường dốc, nơi có chướng ngại vật', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1112),
(343, 'Không đi đúng phần đường, làn đường, không giữ khoảng cách an toàn giữa hai xe theo quy định gây tai nạn giao thông hoặc đi vào đường có biển báo hiệu có nội dung cấm đi vào đối với loại phương tiện đang điều khiển, đi ngược chiều của đường một chiều, đi ngược chiều trên đường có biển “Cấm đi ngược chiều” gây tai nạn giao thông', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 5.000.000 đồng.', '- Trừ điểm giấy phép lái xe 10 điểm.', NULL, NULL, 1, 5, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1113),
