(377, 'Điều khiển xe không có kính chắn gió hoặc có nhưng vỡ không có tác dụng (đối với xe có thiết kế lắp kính chắn gió).', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 200.000 đồng đến 400.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1155),
(378, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô và các loại xe tương tự xe ô tô chở hàng siêu trường, siêu trọng không có giấy phép lưu hành hoặc có giấy phép lưu hành nhưng đã hết giá trị sử dụng hoặc sử dụng giấy phép lưu hành không do cơ quan có thẩm quyền cấp', 'Chủ phương tiện', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\n- Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1156),
(379, 'Đi ngược chiều của đường một chiều, đi ngược chiều trên đường có biển Cấm đi ngược chiều', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm đ khoản 9 Điều 8 Nghị định 168/2024/NĐ-CP và các trường hợp xe ưu tiên đang đi làm nhiệm vụ khẩn cấp theo quy định.', 3, 8, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1159),
(380, 'Điều khiển xe không có đủ đèn chiếu sáng, đèn soi biển số, đèn báo hãm, đèn tín hiệu, cần gạt nước, gương chiếu hậu, dây đai an toàn, dụng cụ thoát hiểm, thiết bị chữa cháy, đồng hồ báo áp lực hơi, đồng hồ báo tốc độ của xe hoặc có những thiết bị đó nhưng không có tác dụng, không đúng tiêu chuẩn thiết kế (đối với loại xe được quy định phải có những thiết bị đó)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định', 'Trừ các hành vi vi phạm quy định tại điểm h khoản 3 Điều 20, điểm d khoản 4 Điều 26 của Nghị định 168/2024/NĐ-CP', 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1160),
(381, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô và các loại xe tương tự xe ô tô chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng, kích thước bao ngoài của xe (sau khi đã xếp hàng lên xe) vượt quá quy định trong Giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe ô tô, và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng', '- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có);\r\n- Chủ phương tiện là người trực tiếp điều khiển phương tiện bị trừ điểm giấy phép lái xe 04 điểm.', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1161),
(382, 'Điều khiển xe chạy bằng một bánh đối với xe hai bánh, chạy bằng hai bánh đối với xe ba bánh', 'xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Tịch thu phương tiện đối với người điều khiển xe', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1162),
(383, 'Điều khiển xe không có còi hoặc có nhưng còi không có tác dụng', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, 'Buộc phải lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1163),
(384, 'Không tuân thủ các quy định khi vào hoặc ra đường cao tốc', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1164),
(385, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển phương tiện thực hiện hành vi chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng', '- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có);\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện thì bị trừ điểm giấy phép lái xe 04 điểm.', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1165),
(386, 'Điều khiển xe không có bộ phận giảm thanh, giảm khói hoặc có nhưng không có tác dụng, không bảo đảm quy chuẩn môi trường về khí thải, tiếng ồn', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:03', '2025-05-10 18:40:03', 1166),
(387, 'Điều khiển xe lạng lách, đánh võng trên đường bộ; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', '- Gây tai nạn giao thông phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng', NULL, '- Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 5, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1167),
(388, 'Điều khiển xe chạy ở làn dừng xe khẩn cấp hoặc phần lề đường của đường cao tốc', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 8.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1168),
(389, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng chở không đúng loại hàng quy định trong Giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', '- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có);\r\n- Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1169),
(390, 'Điều khiển xe lắp thêm đèn phía trước, phía sau, trên nóc, dưới gầm, một hoặc cả hai bên thành xe', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm.', NULL, 'Trừ đèn sương mù dạng rời được lấp theo quy định.', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1170),
(391, 'Chuyển làn đường không đúng nơi cho phép hoặc không có tín hiệu báo trước khi chạy trên đường cao tốc', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 8.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1172),
(392, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô và các loại xe tương tự xe ô tô mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của cầu, đường trên 50% đến 100%', 'Chủ phương tiện', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng đối với chủ xe là cá nhân. Phạt tiền từ 28.000.000 đồng đến 32.000.000 đồng đối với chủ xe là tổ chức.', '- Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng. \r\n- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1173),
(393, 'Điều khiển xe có hệ thống chuyển hướng của xe không đúng tiêu chuẩn an toàn kỹ thuật', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô.', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Trừ điểm giấy phép lái xe 02 điểm', 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1174),
(394, 'Không tuân thủ quy định về khoảng cách an toàn đối với xe chạy liền trước khi chạy trên đường cao tốc', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1175),
