(405, 'Quay đầu xe tại nơi đường bộ giao nhau cùng mức với đường sắt', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 1000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1188),
(406, 'Sử dụng chất liệu khác sơn, dán lên chữ, số của biển số xe, làm thay đổi chữ, số, màu sắc (của chữ, số, nền biển số xe), hình dạng, kích thước của biển số xe (kể cả rơ moóc và sơ mi rơ moóc).', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 06 điểm.', 'Buộc thực hiện đúng quy định về biển số.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1189),
(407, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô và các loại xe tương tự xe ô tô điều khiển xe chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%', 'Tổ chức, cá nhân là chủ xe ô tô tải và các loại xe tương tự xe ô tô', 'Phạt tiền từ 30.000.000 đồng đến 40.000.000 đồng đối với cá nhân, từ 60.000.000 đồng đến 80.000.000 đồng đối với tổ chức', '- Phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng\r\n- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\n- Trừ điểm giấy phép lái xe 08 điểm', '- Phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1190),
(408, 'Quay đầu xe tại nơi đường hẹp, đường dốc, đoạn đường cong tầm nhìn bị che khuất, nơi có biển báo hiệu có nội dung cấm quay đầu đối với loại phương tiện đang điều khiển', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1192),
(409, 'Không đội “mũ bảo hiểm cho người đi mô tô, xe máy” hoặc đội “mũ bảo hiểm cho người đi mô tô, xe máy” không cài quai đúng quy cách khi điều khiển xe tham gia giao thông trên đường bộ', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 1, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1193),
(410, 'Điều khiển xe không lắp đủ bánh lốp hoặc lắp bánh lốp không đúng kích cỡ hoặc không bảo đảm tiêu chuẩn kỹ thuật (kể cả rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', NULL, 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1194),
(411, 'Điều khiển xe ô tô tải (kể cả rơ moóc và sơ mi rơ moóc) có kích thước thùng xe không đúng với thông số kỹ thuật được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Người điều khiển phương tiện', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1195),
(412, 'Lùi xe, quay đầu xe trong hầm đường bộ', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1196),
(413, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%.', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 30.000.000 đồng đến 40.000.000 đồng đối với cá nhân, từ 60.000.000 đồng đến 80.000.000 đồng đối với tổ chức.', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).\r\n- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 08 điểm.', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1197),
(414, 'Đưa xe ô tô kinh doanh vận tải hành khách lắp thêm hoặc tháo bớt ghế, giường nằm hoặc có kích thước khoang chở hành lý (hầm xe) không đúng với thông số kỹ thuật được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe tham gia giao thông.', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.', 'Buộc khôi phục lại hình dáng, kích thước, tình trạng an toàn kỹ thuật ban đầu của xe và đăng kiểm lại trước khi đưa phương tiện ra tham gia giao thông.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1198),
(415, 'Người đang điều khiển xe hoặc chở người ngồi trên xe bám, kéo, đẩy xe khác, vật khác, dẫn dắt vật nuôi, mang vác vật cồng kềnh; chở người đứng trên yên, giá đèo hàng hoặc ngồi trên tay lái của xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng đối với người điều khiển xe gây tai nạn giao thông', 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1199),
(416, 'Không thực hiện biện pháp bảo đảm an toàn theo quy định khi phương tiện bị hư hỏng trên đoạn đường bộ giao nhau cùng mức với đường sắt', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1201),
(417, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).\r\n- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 10 điểm.', '- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.\r\n- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1202),
(418, 'Dừng xe, đỗ xe trong hầm đường bộ không đúng nơi quy định', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1204),
(419, 'Không chấp hành hiệu lệnh, hướng dẫn của người điều khiển giao thông hoặc người kiểm soát giao thông', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng đối với người điều khiển phương tiện gây tai nạn giao thông', NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1205);
