(420, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%.', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 10 điểm.', '- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.\r\n- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1207),
(421, 'Ném đinh, rải đinh hoặc vật sắc nhọn khác, đổ dầu nhờn hoặc các chất gây trơn khác trên đường bộ; chăng dây hoặc các vật cản khác qua đường gây nguy hiểm đến người và phương tiện tham gia giao thông', 'Cá nhân thực hiện hành vi vi phạm', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Bị tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng', 'Buộc phải thu dọn đinh, vật sắc nhọn, dây hoặc các vật cản khác và khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1208),
(422, 'Không chấp hành hiệu lệnh của đèn tín hiệu giao thông', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng đối với người điều khiển xe gây tai nạn giao thông', NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1209),
(423, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển hoặc trực tiếp điều khiển xe ô tô và các loại xe tương tự xe ô tô mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của cầu, đường trên 100% đến 150%  mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của cầu, đường trên 100% đến 150%,', 'Chủ phương tiện', 'Phạt tiền từ 18.000.000 đồng đến 20.000.000 đồng đối với chủ xe là cá nhân. Phạt tiền từ 36.000.000 đồng đến 40.000.000 đồng đối với chủ xe là tổ chức.', 'chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe (khi điều khiển xe cơ giới), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng;', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với xe có Giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1210),
(424, 'chăng dây hoặc các vật cản khác qua đường gây nguy hiểm đến người và phương tiện tham gia giao thông', 'Cá nhân thực hiện hành vi vi phạm', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Bị tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng.', 'Buộc phải thu dọn dây hoặc các vật cản khác và khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1211),
(425, 'Xâm phạm sức khỏe, tài sản của người bị nạn hoặc người gây tai nạn', 'Cá nhân thực hiện hành vi vi phạm', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng.', 'Tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng', NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1212),
(426, 'Lợi dụng việc xảy ra tai nạn giao thông đường bộ để hành hung, đe dọa, xúi giục, gây sức ép, làm mất trật tự, cản trở việc xử lý tai nạn giao thông đường bộ', 'Cá nhân thực hiện hành vi vi phạm', '500.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.000.000 đồng đến 2.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1213),
(427, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện hoặc trực tiếp điều khiển phương tiện thực hiện hành vi điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Cá nhân, tổ chức là chủ xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng', '- Nếu phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 10 điểm.', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1214),
(428, 'Không hỗ trợ, giúp đỡ hành khách đi xe là người cao tuổi, trẻ em không tự lên xuống xe được, người khuyết tật vận động hoặc khuyết tật thị giác', 'Nhân viên phục vụ trên xe buýt, xe vận chuyển hành khách theo tuyến cố định, xe vận chuyển hành khách theo hợp đồng, xe vận chuyển khách du lịch', 'Phạt tiền từ 80.000 đồng đến 100.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1215),
(429, 'Không mặc đồng phục, không đeo thẻ tên của nhân viên phục vụ trên xe theo quy định', 'Nhân viên phục vụ trên xe buýt, xe vận chuyển hành khách theo tuyến cố định, xe vận chuyển hành khách theo hợp đồng, xe vận chuyển khách du lịch', 'Phạt tiền từ 80.000 đồng đến 100.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1217),
(430, 'Điều khiển xe không có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường (đối với loại xe có quy định phải kiểm định, trừ xe đăng ký tạm thời) hoặc có nhưng đã hết hiệu lực (hạn sử dụng) từ 01 tháng trở lên (kê cả rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Người điều khiển xe bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1218),
(431, 'Thu tiền vé nhưng không trao vé cho hành khách', 'Nhân viên phục vụ trên xe buýt', 'Phạt tiền từ 100.000 đồng đến 200.000', NULL, 'Buộc phải nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính.', 'Trong trường hợp cá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện hoặc là nhân viên phục vụ trên xe thì bị xử phạt theo quy định tại điểm d khoản 6 Điều 28 Nghị định 100/2019/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1219),
(432, 'Dừng xe, đỗ xe trên đường cao tốc không đúng nơi quy định', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1220),
(433, 'Điều khiển xe không có còi hoặc có nhưng không có tác dụng', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 1, 4, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1221),
(434, 'Không có báo hiệu để người lái xe khác biết khi buộc phải dừng xe, đỗ xe trên đường cao tốc không đúng nơi quy định', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1223),
(435, 'Điều khiển xe không có đèn soi biển số hoặc có nhưng không có tác dụng', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1224),
(436, 'Điều khiển xe không có đèn báo hãm hoặc có nhưng không có tác dụng', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1225),
(437, 'Quay đầu xe trên đường cao tốc', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 18.000.000 đồng đến 20.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1227),
(438, 'Thu tiền vé cao hơn quy định', 'Nhân viên phục vụ trên xe buýt', 'Phạt tiền từ 100.000 đồng đến 200.000.', NULL, 'Buộc phải nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1228),
(439, 'Điều khiển xe không có gương chiếu hậu bên trái người điều khiển hoặc có nhưng không có tác dụng', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1229),
