(441, 'Thu tiền vé cao hơn quy định', 'Nhân viên phục vụ trên xe vận chuyển hành khách theo tuyến cố định', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng.', NULL, 'Buộc phải nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1231),
(442, 'Sang nhượng hành khách dọc đường cho xe khác mà không được hành khách đồng ý', 'Nhân viên phục vụ trên xe buýt, xe vận chuyển hành khách theo tuyến cố định, xe vận chuyển hành khách theo hợp đồng, xe vận chuyển khách du lịch', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1232),
(443, 'Chạy quá tốc độ quy định trên 20 km/h', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1234),
(444, 'Đe dọa, xúc phạm, tranh giành, lôi kéo hành khách', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1235),
(445, 'Bắt ép hành khách sử dụng dịch vụ ngoài ý muốn', 'Nhân viên phục vụ trên xe buýt, xe vận chuyển hành khách theo tuyến cố định, xe vận chuyển hành khách theo hợp đồng, xe vận chuyển khách du lịch', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1236),
(446, 'Xuống khách nhằm trốn tránh phát hiện xe chở quá tải, quá số người theo quy định của pháp luật', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1237),
(447, 'Điều khiển xe trên đường mà trong máu hoặc hơi thở có nồng độ cồn nhưng chưa vượt quá 50 miligam/100 mililít máu hoặc chưa vượt quá 0,25 miligam/1 lít khí thở', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 9, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1238),
(448, 'Hành hung hành khách', 'Nhân viên phục vụ trên xe buýt, xe vận chuyển hành khách theo tuyến cố định, xe vận chuyển hành khách theo hợp đồng, xe vận chuyển khách du lịch', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1239),
(449, 'Điều khiển xe gắn biển số không đúng quy cách theo quy định', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 06 điểm.', NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1240),
(450, 'Không chấp hành hướng dẫn của lái xe, nhân viên phục vụ trên xe về các quy định bảo đảm trật tự, an toàn giao thông', 'Hành khách đi xe', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1241),
(451, 'Gây mất trật tự trên xe', 'Hành khách đi xe', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1242),
(452, 'Điều khiển xe không quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn theo quy định mà gây tai nạn giao thông', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1243),
(453, 'Mang hóa chất độc hại, chất dễ cháy, nổ, hàng nguy hiểm hoặc hàng cấm lưu thông trên xe chở khách', 'Hành khách đi xe', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Tịch thu hóa chất độc hại, chất dễ cháy, nổ, hàng nguy hiểm, hàng cấm lưu thông mang theo trên xe chở khách', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1244),
(454, 'Điều khiển xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) không gắn biển số (đối với loại xe có quy định phải gắn biển số).', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', 'Trừ điểm giấy phép lái xe 06 điểm.', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1245),
(455, 'Đu, bám vào thành xe', 'Hành khách đi xe', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1246),
(456, 'Đứng, ngồi, nằm trên mui xe, nóc xe, trong khoang chở hành lý', 'Hành khách đi xe', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1247),
(457, 'Tự ý mở cửa xe hoặc có hành vi khác không bảo đảm an toàn khi xe đang chạy', 'Hành khách đi xe', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1248),
(458, 'Đe dọa, xâm phạm sức khỏe của người khác đi trên xe, lái xe, nhân viên phục vụ trên xe', 'Hành khách đi xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1249),
(459, 'Điều khiển xe có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường nhưng đã hết hiệu lực (hạn sử dụng) dưới 01 tháng (kể cả rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng', 'Người điều khiển xe bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1250),
(460, 'Dừng xe, đỗ xe, quay đầu xe, lùi xe, tránh xe, vượt xe, chuyển hướng, chuyển làn đường không đúng quy định gây tai nạn giao thông', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 8, điểm đ khoản 9 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1251),
(461, 'Điều khiển xe lắp đặt, sử dụng còi vượt quá âm lượng theo quy định', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định', NULL, 2, 4, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1252),
(462, 'Không thực hiện đúng quy định trong Giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', 'Trường hợp này không áp dụng đối với hành vi vi phạm quy định tại khoản 2; điểm b, điểm c, điểm d khoản 3 Điều 22 Nghị định 168/2024/NĐ-CP.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1253),
(463, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe vượt quá tải trọng cho phép của đường bộ trên 10% đến 20%', 'Người điều khiển xe ô tô quá tải trọng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Trường hợp này không áp dụng đối với xe có giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1254),
(464, 'Điều khiển xe gắn biển số không rõ chữ, số', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 06 điểm.', NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1255),
(465, 'Chở hàng vượt khổ giới hạn của đường bộ ghi trong giấy phép lưu hành', 'Người điều khiển xe ô tô quá khổ giới hạn', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1256),
(466, 'Điều khiển xe không đủ hệ thống hàm hoặc có đủ hệ thống hãm nhưng không có tác dụng, không đúng tiêu chuẩn an toàn kỹ thuật (kể cả rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1257),
(467, 'Điều khiển xe có kích thước bao ngoài vượt quá khổ giới hạn của đường bộ hoặc chở hàng vượt khổ giới hạn của đường bộ hoặc chở hàng vượt quá kích thước giới hạn xếp hàng hóa của xe tham gia giao thông', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng.', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với xe có Giấy phép lưu hành còn giá trị sử dụng', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1258),
(468, 'Điều khiển xe gắn biển số bị bẻ cong, bị che lấp, làm thay đổi chữ, số, màu sắc (của chữ, số, nền biển số xe), hình dạng, kích thước của biển số xe.', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 06 điểm.', NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1259),
(469, 'không đi đúng phần đường, làn đường, không giữ khoảng cách an toàn giữa hai xe theo quy định gây tai nạn giao thông hoặc đi vào đường có biển báo hiệu có nội dung cấm đi vào đối với loại phương tiện đang điều khiển, đi ngược chiều của đường một chiều, đi ngược chiều trên đường có biển “Cấm đi ngược chiều” gây tai nạn giao thông', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm b khoản 8, điểm đ khoản 9 Điều 8 Nghị định 168/2024/NĐ-CP.', 3, 8, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1260),
(470, 'Điều khiển xe gắn biển số bị bẻ cong, che lấp, làm thay đổi chữ, số, màu sắc (của chữ, số, nền biển số xe), hình dạng, kích thước của biển số xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 06 điểm.', NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1261),
(471, 'Điều khiển xe đăng ký tạm thời, xe có phạm vi hoạt động hạn chế hoạt động quá phạm vi, tuyến đường, thời hạn cho phép', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1262),
(472, 'Điều khiển xe quá niên hạn sử dụng tham gia giao thông', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Tịch thu phương tiện', NULL, NULL, '- Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.\r\n- Trừ hành vi quy định tại điểm c khoản 5 Điều 13 Nghị định 168/2024/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1263),
(473, 'Điều khiển xe ô tô mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 20% đến 50%', 'Người điều khiển xe ô tô quá tải trọng', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với xe có giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1264),
(474, 'Điều khiển loại xe sản xuất, lắp ráp trái quy định tham gia giao thông (bao gồm cả xe công nông thuộc diện bị đình chỉ tham gia giao thông)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Tịch thu phương tiện', NULL, NULL, 'Tạm giữ phương tiện, giấy tờ có liên quan', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1265),
(475, 'Điều khiển xe gắn biển số không đúng với chứng nhận đăng ký xe hoặc gắn biển số không do cơ quan có thẩm quyền cấp (kể cả rơ moóc và sơ mi rơ moóc);', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng', '- Tịch thu biển số xe;\r\n- Trừ điểm giấy phép lái xe 10 điểm.', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1267),
(476, 'Điều khiển xe có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe nếu có) vượt quá quy định trong giấy phép lưu hành.', 'Người điều khiển xe ô tô quá tải trọng', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng.', 'Trừ điểm giấy phép lái xe 03 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1268),
(477, 'Có giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1269),
(478, 'Sử dụng chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', '- Tịch thu phương tiện trong trường hợp sử dụng chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa (kê cả rơ moóc và sơ mi rơ moóc) mà không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng nhận nguồn gốc xe, chứng nhận quyền sở hữu hợp pháp)\r\n- Thu hồi chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường không do cơ quan có thẩm quyền cấp.\r\n- Người điều khiển xe bị trừ điểm giấy phép lái xe 02 điểm', 'Buộc nộp lại chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường, chứng nhận đăng ký xe bị tẩy xóa.', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1270),
(479, 'Điều khiển xe trên đường mà trong máu hoặc hơi thở có nồng độ cồn vượt quá 50 miligam đến 80 miligam/100 mililít máu hoặc vượt quá 0,25 miligam đến 0,4 miligam/1 lít khí thở', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 9, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1272),
(480, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 50%', 'Người điều khiển xe ô tô quá tải trọng', 'Phạt tiền từ 40.000.000 đồng đến 50.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1273),
(481, 'Sử dụng chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không đúng số khung, số động cơ (số máy) của xe (kể cả rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', '- Tịch thu phương tiện trong trường hợp sử dụng chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không đúng số khung, số động cơ (số máy) của xe\r\n- Người điều khiển xe bị trừ điểm giấy phép lái xe 02 điểm', '- Bị thu hồi chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không đúng số khung, số động cơ (số máy) của xe', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1274),
(482, 'Điều khiển xe không có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường (đối với loại xe có quy định phải kiểm định, trừ xe đăng ký tạm thời) hoặc có nhưng đã hết hiệu lực (hạn sử dụng) từ 01 tháng trở lên (kê cả rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1275),
