(497, 'Đua xe ô tô trái phép', 'Cá nhân', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Tịch thu phương tiện và tước quyền sử dụng giấy phép lái xe từ 22 tháng đến 24 tháng', NULL, NULL, 2, 5, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1293),
(498, 'Chở đất đá, phế thải, hàng rời mà không có mui, bạt che đậy hoặc có mui, bạt che đậy nhưng vẫn để rơi vãi', 'Người điều khiển máy kéo', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1294),
(499, 'gắn biển số bị bẻ cong, che lấp, làm thay đổi chữ, số, màu sắc (của chữ, số, nền biển số xe), hình dạng, kích thước của biển số xe', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1295),
(500, 'Điều khiển phương tiện không gắn ký hiệu phân biệt quốc gia theo quy định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1296),
(501, 'Sử dụng chất liệu khác sơn, dán lên chữ, số của biển số xe', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1297),
(502, 'Lôi kéo bùn, đất, cát, nguyên liệu, vật liệu hoặc chất phế thải khác ra đường bộ gây mất an toàn giao thông', 'Người điều khiển máy kéo', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1298),
(503, 'Giấy tờ xe không có bản dịch sang tiếng Anh hoặc tiếng Việt theo quy định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', NULL, NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1299),
(504, 'Đổ trái phép rác, đất, cát, đá, vật liệu, chất phế thải trong phạm vi đất dành cho đường bộ ở đoạn đường ngoài đô thị', 'Người điều khiển máy kéo', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1300),
(505, 'Điều khiển xe chở hành khách không có danh sách hành khách theo quy định', 'Người điều khiển xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1301),
(506, 'Lưu hành phương tiện trên lãnh thổ Việt Nam quá thời hạn quy định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước', 'Phạt tiền từ 30.000.000 đồng đến 35.000.000 đồng', NULL, 'Buộc tái xuất phương tiện khỏi Việt Nam.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1302),
(507, 'Điều khiển xe không có hệ thống hãm hoặc có hệ thống hãm nhưng không bảo đảm tiêu chuẩn kỹ thuật; điều khiển xe có hệ thống chuyển hướng không bảo đảm tiêu chuẩn kỹ thuật', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1303),
(508, 'Hoạt động quá phạm vi, tuyến đường, đoạn đường được phép hoạt động', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1305),
(509, 'Không có giấy phép liên vận, giấy phép vận tải đường bộ quốc tế theo quy định hoặc có nhưng đã hết giá trị sử dụng', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, 'Buộc tái xuất phương tiện khỏi Việt Nam.', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1306),
(510, 'Điều khiển phương tiện không gắn biển số tạm thời hoặc gắn biển số tạm thời không do cơ quan có thẩm quyền cấp (nếu có quy định phải gắn biển số tạm thời)', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, 'Buộc tái xuất phương tiện khỏi Việt Nam.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1307),
(511, 'Vận chuyển hành khách hoặc hàng hóa không đúng với quy định tại các điều ước quốc tế mà Việt Nam đã ký kết', 'Người điều khiển xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, 'Bị áp dụng biện pháp khắc phục hậu quả buộc tái xuất phương tiện khỏi Việt Nam', 'Trừ các hành vi vi phạm quy định tại khoản 1, khoản 4, khoản 5, khoản 6 Điều 36 Nghị định 168/2024/NĐ-CP', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1308),
(512, 'Điều khiển xe ô tô có tay lái bên phải tham gia giao thông mà không đi theo đoàn, không có người, phương tiện hỗ trợ, hướng dẫn giao thông theo quy định', 'Người điều khiển phương tiện giao thông cơ giới đường bộ gắn biển số nước ngoài', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1309),
(513, 'Điều khiển xe ô tô có tay lái bên phải tham gia giao thông mà không đi theo đoàn, không có người, phương tiện hỗ trợ, hướng dẫn giao thông theo quy định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1310),
(514, 'Không có tờ khai xe tạm nhập, tái xuất theo quy định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô đăng ký hoạt động trong Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng.', 'Tịch thu phương tiện (trường hợp tái phạm, vi phạm nhiều lần)', 'Buộc phải đưa phương tiện quay trở lại Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế.', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1311),
(515, 'Điều khiển xe không có phù hiệu kiểm soát theo quy định hoặc có nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp.', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô đăng ký hoạt động trong Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Thu hồi phù hiệu đã hết giá trị sử dụng hoặc phù hiệu không do cơ quan có thẩm quyền cấp.', 'Buộc đưa phương tiện quay trở lại Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1312),
(516, 'Điều khiển xe không có phù hiệu kiểm soát theo quy định hoặc có nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô đăng ký hoạt động trong Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng.', NULL, '- Buộc phải đưa phương tiện quay trở lại Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế.\r\n-  Thu hồi phù hiệu đã hết giá trị sử dụng hoặc phù hiệu không do cơ quan có thẩm quyền cấp.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1313),
(517, 'Đổ trái phép rác, đất, cát, đá, vật liệu, chất phế thải ra đường phố', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 15.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1314),
(518, 'Điều khiển xe không có đèn tín hiệu hoặc có nhưng không có tác dụng', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1315),
(519, 'Điều khiển xe ô tô, điều khiển xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Người điều khiển xe từ đủ 14 tuổi đến dưới 16 tuổi', 'Cảnh cáo', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1316),
(520, 'Sử dụng còi không đúng quy chuẩn kỹ thuật cho từng loại xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Buộc thay thế thiết bị đủ tiêu chuẩn an toàn kỹ thuật hoặc khôi phục tính năng kỹ thuật của thiết bị.', NULL, NULL, 1, 4, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1317),
(521, 'Điều khiển xe không có bộ phận giảm thanh, giảm khói hoặc có nhưng không bảo đảm quy chuẩn môi trường về khí thải, tiếng ồn', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1318),
(522, 'Không mang theo Giấy phép lái xe', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng với các hành vi vi phạm quy định tại điểm c khoản 8 Điều 21 Nghị định 168/2024/NĐ-CP.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1319),
(523, 'Điều khiển xe không có đèn chiếu sáng gần, xa hoặc có nhưng không có tác dụng, không đúng tiêu chuẩn thiết kế', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1320),
(524, 'Không mang theo chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe)', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô kinh doanh vận tải', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng', NULL, NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1321),
(525, 'Điều khiển xe không có hệ thống hãm hoặc có nhưng không có tác dụng, không bảo đảm tiêu chuẩn kỹ thuật', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1322),
(526, 'Không mang theo giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường đối với loại xe có quy định phải kiểm định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô kinh doanh vận tải', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng', NULL, NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1323);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(527, 'Điều khiển xe lắp đèn chiếu sáng về phía sau xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1324),
(528, 'Không có chứng nhận bảo hiểm bắt buộc trách nhiệm dân sự của chủ xe cơ giới còn hiệu lực', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1325),
(529, 'Có giấy phép lái xe nhưng đã hết hạn sử dụng dưới 01 năm', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1326),
(530, 'Điều khiển xe không có Giấy đăng ký xe theo quy định hoặc sử dụng Giấy đăng ký xe đã hết hạn sử dụng', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng.', 'Nếu không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng từ chuyển quyền sở hữu xe hoặc giấy tờ, chứng từ nguồn gốc xe hợp pháp) thì bị tịch thu phương tiện', NULL, 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1327),
(531, 'Điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Người từ đủ 16 tuổi đến dưới 18 tuổi', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1328),
(532, 'Sử dụng Giấy đăng ký xe đã bị tẩy xóa', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng.', '- Tịch thu Giấy đăng ký xe, biển số không đúng quy định hoặc bị tẩy xóa.\r\n- Nếu không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng từ chuyển quyền sở hữu xe hoặc giấy tờ, chứng từ nguồn gốc xe hợp pháp) thì bị tịch thu phương tiện.', NULL, 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1329),
(533, 'Có giấy phép lái xe nhưng không phù hợp với loại xe đang điều khiển hoặc có giấy phép lái xe nhưng đã hết hạn sử dụng từ 01 năm trở lên', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 18.000.000 đồng đến 20.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1330),
(534, 'Không có giấy phép lái xe hoặc sử dụng giấy phép lái xe đã bị trừ hết điểm hoặc sử dụng giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe bị tẩy xóa, giấy phép lái xe không còn hiệu lực', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 18.000.000 đồng đến 20.000.000 đồng', 'Thu hồi giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe không hợp lệ', 'Buộc nộp lại giấy phép lái xe bị tẩy xóa', 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1331),
(535, 'Sử dụng Giấy đăng ký xe không đúng số khung, số máy của xe hoặc không do cơ quan có thẩm quyền cấp', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng.', '- Tịch thu Giấy đăng ký xe, biển số không đúng quy định hoặc bị tẩy xóa.\r\n- Nếu không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng từ chuyển quyền sở hữu xe hoặc giấy tờ, chứng từ nguồn gốc xe hợp pháp) thì bị tịch thu phương tiện.', 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1332),
(536, 'Xếp hàng hóa lên mỗi xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) vượt quá trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 50% (trừ xe xi téc chở chất lỏng), trên 20% đến 50% đối với xe xi téc chở chất lỏng', 'Cá nhân, tổ chức xếp hàng hóa', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.000.000 đồng đến 2.000.000 đồng đối với tổ chức', NULL, NULL, 'Trừ xe xi téc chở chất lỏng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1333),
(537, 'Có giấy phép lái xe quốc tế do các nước tham gia Công ước của Liên hợp quốc về Giao thông đường bộ năm 1968 cấp nhưng không mang theo giấy phép lái xe quốc gia phù hợp với loại xe được phép điều khiển', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, '- Trừ giấy phép lái xe quốc tế do Việt Nam cấp\r\n- Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1334),
(538, 'Điều khiển xe có hệ thống chuyển hướng không bảo đảm tiêu chuẩn kỹ thuật', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1335),
(539, 'Xếp hàng hóa lên xe ô tô và các loại xe tương tự xe ô tô mà không ký xác nhận việc xếp hàng hóa vào Giấy vận tải theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.000.000 đồng đến 2.000.000 đồng đối với tổ chức.', NULL, NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1336),
(540, 'Sử dụng giấy phép lái xe không hợp lệ (giấy phép lái xe có số phôi ghi ở mặt sau không trùng với số phôi được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe)', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', '- Bị thu hồi giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe không hợp lệ\r\n- Người điều khiển phương tiện bị trừ điểm giấy phép lái xe được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe 02 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1337),
(541, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ tên, số điện thoại của đơn vị kinh doanh vận tải ở phần đầu mặt ngoài hai bên thân hoặc mặt ngoài hai bên cánh cửa xe ô tô chở hành khách theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', 'Trường hợp này không áp dụng đối với hành vi vi phạm quy định tại điểm d khoản 4 Điều 28 Nghị định 100/2019/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1338),
(542, 'Điều khiển xe không gắn biển số (đối với loại xe có quy định phải gắn biển số)', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 06 điểm.', NULL, 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1339),
(543, 'Không hướng dẫn hành khách đứng, nằm, ngồi đúng vị trí quy định trong xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1340),
(544, 'Không mặc đồng phục, không đeo thẻ tên của lái xe theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1341),
(545, 'Điều khiển xe gắn biển số không đúng với Giấy đăng ký xe hoặc gắn biển số không do cơ quan có thẩm quyền cấp', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng.', '- Bị tịch thu biển số xe\r\n- Trừ điểm giấy phép lái xe 06 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1342),
(546, 'Điều khiển xe đăng ký tạm thời hoạt động quá phạm vi, tuyến đường, thời hạn cho phép', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1343),
(547, 'Điều khiển xe lắp đèn chiếu sáng về phía sau xe.', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', 'Tịch thu phương tiện', NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1344),
(548, 'Chở quá số người quy định được phép chở của xe ô tô chở hành khách, ô tô chở người (trừ xe buýt)', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng trên mỗi người vượt quá quy định được phép chở của phương tiện nhưng tổng mức phạt tiền tối đa không vượt quá 75.000.000 đồng', '- Trừ điểm giấy phép lái xe 04 điểm (trường hợp vượt trên 50% đến 100% số người quy định được phép chở của phương tiện)\r\n- Trừ điểm giấy phép lái xe 10 điểm (trường hợp vượt trên 100% số người quy định được phép chở của phương tiện)', NULL, '- Trừ xe buýt\r\n- Trừ các hành vi vi phạm quy định tại khoản 4 Điều 20 Nghị định 168/2024/NĐ-CP', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1345),
(549, 'Không bảo đảm an toàn khi di chuyển', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định.', NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1346),
(550, 'Không đóng cửa lên xuống khi xe đang chạy', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1347),
(551, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ tên, số điện thoại của đơn vị kinh doanh vận tải hàng hóa, khối lượng bản thân xe, khối lượng hàng hóa cho phép chuyên chở, khối lượng toàn bộ cho phép tham gia giao thông trên cánh cửa xe ô tô tải theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1348),
(552, 'Điều khiển xe không có đủ đèn chiếu sáng', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị', NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1349),
(553, 'Điều khiển xe là người từ đủ 14 tuổi đến dưới 16 tuổi', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt cảnh cáo', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1350),
(554, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ tên, số điện thoại của đơn vị kinh doanh vận tải hàng hóa, khối lượng bản thân ô tô đầu kéo, khối lượng hàng hóa cho phép chuyên chở, khối lượng toàn bộ cho phép kéo theo trên cánh cửa xe ô tô đầu kéo theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1351),
(555, 'Để người ngồi trên xe khi xe xuống phà, đang trên phà và khi lên bến', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, 'Trường hợp này không áp dụng với người lái xe, trẻ em, phụ nữ mang thai, người già yếu, người bệnh, người khuyết tật', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1352),
(556, 'Không có hoặc không mang theo Giấy chứng nhận bảo hiểm trách nhiệm dân sự của chủ xe cơ giới còn hiệu lực', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1353),
(557, 'Không mang theo Giấy đăng ký xe', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1354),
(558, 'Điều khiển xe không có bộ phận giảm thanh, giảm khói hoặc có nhưng không có tác dụng, không bảo đảm quy chuẩn môi trường về khí thải, tiếng ồn', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định', NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1355),
(559, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ tên, số điện thoại của đơn vị kinh doanh vận tải hàng hóa, khối lượng hàng hóa cho phép chuyên chở, khối lượng toàn bộ cho phép tham gia giao thông trên rơ moóc, sơ mi rơ moóc theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1356),
(560, 'Không chạy đúng tuyến đường, lịch trình, hành trình vận tải được phép hoạt động theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1357),
(561, 'Không mang theo Giấy phép lái xe', 'Người điều khiển xe mô tô và các loại xe tương tự xe mô tô', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng.', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại Điểm b Khoản 5, Điểm c Khoản 7 Điều 21 Nghị định 100/2019/NĐ-CP.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1358),
(562, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ tên, số điện thoại của đơn vị kinh doanh taxi tải, chữ taxi tải, tự trọng của xe, trọng tải được phép chở của xe ở mặt ngoài hai bên thành xe hoặc mặt ngoài hai bên cánh cửa buồng lái xe taxi tải theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1359),
(563, 'Để người mắc võng nằm trên xe khi xe đang chạy', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1360),
(564, 'Điều khiển xe mô tô có dung tích xi- lanh từ 50 cm3 trở lên hoặc có công suất động cơ điện từ 04 kW trở lênxe mô tô có dung tích xi lanh từ 50 cm3 trở lên', 'Người từ đủ 16 tuổi đến dưới 18 tuổi', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng.', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1361),
(565, 'Sắp xếp, chằng buộc hành lý, hàng hóa không bảo đảm an toàn', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1362),
(566, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ theo quy định trên xe ô tô chở hành khách về Biển số xe', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1363),
(567, 'Để rơi hành lý, hàng hóa trên xe xuống đường', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1364),
(568, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ theo quy định trên xe ô tô chở hành khách về khối lượng hành lý miễn cước', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1365),
(569, 'Không có giấy phép lái xe hoặc sử dụng giấy phép lái xe đã bị trừ hết điểm, giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe bị tẩy xóa, giấy phép lái xe không còn hiệu lực', 'Người điều khiển xe mô tô hai bánh có dung tích xi-lanh trên 125 cm3 trở lên hoặc có công suất động cơ điện trên 11 kW, xe mô tô ba bánh', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Bị thu hồi giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe không hợp lệ.', 'Nộp lại giấy phép lái xe bị tẩy xóa', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1366),
(570, 'Để hàng hóa trong khoang chở hành khách', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1367),
(571, 'Không niêm yết hoặc niêm yết không chính xác, đầy đủ theo quy định trên xe ô tô chở hành khách về số điện thoại đường dây nóng', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải niêm yết đầy đủ, chính xác các thông tin theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1368),
(572, 'Không đánh số thứ tự ghế ngồi, giường nằm trên xe ô tô chở hành khách theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1369),
(573, 'Không đánh số thứ tự ghế ngồi, giường nằm trên xe ô tô chở hành khách theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1370),
(574, 'Chở hành lý, hàng hóa vượt quá kích thước bao ngoài của xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1371),
(575, 'Có giấy phép lái xe quốc tế do các nước tham gia Công ước của Liên hợp quốc về Giao thông đường bộ năm 1968 cấp (trừ giấy phép lái xe quốc tế do Việt Nam cấp) nhưng không mang theo giấy phép lái xe quốc gia phù hợp với loại xe được phép điều khiển', 'Người điều khiển xe mô tô hai bánh có dung tích xi-lanh đến 125 cm3 hoặc có công suất động cơ điện đến 11 kW và các loại xe tương tự xe mô tô', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1372),
(576, 'Sử dụng xe ô tô kinh doanh vận tải hành khách theo tuyến cố định, xe ô tô kinh doanh vận tải hành khách bằng xe buýt không có chỗ ưu tiên cho người khuyết tật, người cao tuổi và phụ nữ mang thai theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1373),
(577, 'Sử dụng xe ô tô kinh doanh vận tải hành khách không có hướng dẫn cho hành khách về an toàn giao thông, thoát hiểm khi xảy ra sự cố trên xe theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1374),
(578, 'Vận chuyển hàng có mùi hôi thối', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1375),
(579, 'Sử dụng giấy phép lái xe không hợp lệ (giấy phép lái xe có số phôi ghi ở mặt sau không trùng với số phôi được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe)', 'Người điều khiển xe mô tô hai bánh có dung tích xi-lanh đến 125 cm3 hoặc có công suất động cơ điện đến 11 kW và các loại xe tương tự xe mô tô', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng', '-  Bị trừ điểm giấy phép lái xe được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe 02 điểm.\r\n- Bọ yhu hồi giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe không hợp lệ', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1376),
(580, 'Xếp hàng hóa lên mỗi xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) vượt quá trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Cá nhân, tổ chức thực hiện hành vi vi phạm xếp hàng hóa', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 6.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1377),
(581, 'Điều khiển xe có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường nhưng đã hết hiệu lực (hạn sử dụng) dưới 01 tháng (kể cả rơ moóc)', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, 'Buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1378),
(582, 'Điều khiển xe vận tải hành khách không có nhân viên phục vụ trên xe đối với những xe quy định phải có nhân viên phục vụ', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1379),
(583, 'Không cấp lệnh vận chuyển, giấy vận tải cho lái xe hoặc cấp lệnh vận chuyển, giấy vận tải nhưng không đúng theo quy định (đối với loại xe quy định phải cấp lệnh vận chuyển, giấy vận tải)', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức', 'Cá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1380),
(584, 'Có giấy phép lái xe nhưng đã hết hạn sử dụng dưới 01 năm', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1381),
(585, 'Điều khiển xe taxi không có đồng hồ tính tiền cước (đối với loại xe đăng ký sử dụng đồng hồ tính tiền) hoặc có nhưng không đúng quy định hoặc không sử dụng đồng hồ tính tiền cước theo quy định khi chở khách', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1382),
(586, 'Không thực hiện việc niêm yết thông tin trên xe theo quy định hoặc có niêm yết nhưng không chính xác, không đầy đủ thông tin theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1383),
(587, 'Điều khiển xe hoạt động không đúng phạm vi quy định', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1384),
(588, 'Điều khiển xe niêm yết hành trình chạy xe không đúng với hành trình đà được cơ quan có thẩm quyền cấp phép', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1385),
(589, 'Không có giấy phép lái xe hoặc sử dụng giấy phép lái xe đã bị trừ hết điểm hoặc sử dụng giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe bị tẩy xóa, giấy phép lái xe không còn hiệu lực, giấy phép lái xe không phù hợp với loại xe đang điều khiển', 'Người điều khiển xe mô tô hai bánh có dung tích xi-lanh đến 125 cm3 hoặc có công suất động cơ điện đến 11 kW và các loại xe tương tự xe mô tô', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng', 'Bị thu hồi giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe không hợp lệ.', 'Nộp lại giấy phép lái xe bị tẩy xóa.', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1386),
(590, 'Không thực hiện việc đăng ký, niêm yết hoặc niêm yết không chính xác, đầy đủ theo quy định về  điểm đầu, điểm cuối của tuyến', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Đăng ký, niêm yết đầy đủ, chính xác các thông tin theo quy định', 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm đ khoản 2 Điều 28 Nghị định 100/2019/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1387),
(591, 'Điều khiển xe kinh doanh vận tải hành khách theo tuyến cố định thu tiền vé nhưng không trao vé cho hành khách, thu tiền vé cao hơn quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, 'Trường hợp thu tiền vé cao hơn quy định buộc phải nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính', 'Trong trường hợp cá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện hoặc là nhân viên phục vụ trên xe thì bị xử phạt theo quy định tại điểm d khoản 6 Điều 28 Nghị định 100/2019/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1388),
(592, 'Không thực hiện việc niêm yết thông tin trên xe theo quy định hoặc có niêm yết nhưng không chính xác, không đầy đủ thông tin theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1389),
(593, 'Có giấy phép lái xe quốc tế do các nước tham gia Công ước của Liên hợp quốc về Giao thông đường bộ năm 1968 cấp (trừ giấy phép lái xe quốc tế do Việt Nam cấp) nhưng không mang theo giấy phép lái xe quốc gia phù hợp với loại xe được phép điều khiển', 'Người điều khiển xe mô tô hai bánh có dung tích xi-lanh trên 125 cm3 trở lên hoặc có công suất động cơ điện trên 11 kW, xe mô tô ba bánh', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1390),
(594, 'Điều khiển xe ô tô kinh doanh vận tải không có dây an toàn tại các vị trí ghế ngồi, giường nằm theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, 'Trường hợp này không áp dụng với xe buýt nội tỉnh.', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1391),
(595, 'Điều khiển máy kéo, xe máy chuyên dùng sản xuất, lắp ráp hoặc cải tạo trái quy định tham gia giao thông', 'Người điều khiển máy kéo (kể cả rơ moóc được kéo theo), xe máy chuyên dùng.', 'Tịch thu phương tiện', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1392),
(596, 'Không thực hiện việc đăng ký, niêm yết hoặc niêm yết không chính xác, đầy đủ theo quy định về giá dịch vụ', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Đăng ký, niêm yết đầy đủ, chính xác các thông tin theo quy định', 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm đ khoản 2 Điều 28 Nghị định 100/2019/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1393),
(597, 'Điều khiển xe ô tô kinh doanh vận tải không có hướng dẫn cho hành khách về an toàn giao thông và thoát hiểm khi xảy ra sự cố trên xe theo quy địn', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1394),
(598, 'Không thực hiện việc niêm yết thông tin trên xe theo quy định hoặc có niêm yết nhưng không chính xác, không đầy đủ thông tin theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm đ khoản 2 Điều 28 Nghị định 100/2019/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1395),
(599, 'Sử dụng giấy phép lái xe không hợp lệ (giấy phép lái xe có số phôi ghi ở mặt sau không trùng với số phôi được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe)', 'Người điều khiển xe mô tô hai bánh có dung tích xi-lanh trên 125 cm3 trở lên hoặc có công suất động cơ điện trên 11 kW, xe mô tô ba bánh', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', '- Thu hồi giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe không hợp lệ.\r\n- Bị trừ điểm giấy phép lái xe được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe 02 điểm.', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1396),
(600, 'Sử dụng loại xe ô tô chở người có thiết kế từ 9 chỗ (kể cả người lái) trở lên làm xe taxi chở hành khách', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1397),
(601, 'Điều khiển xe taxi không sử dụng phần mềm tính tiền (đối với loại xe đăng ký sử dụng phần mềm tính tiền) hoặc sử dụng phần mềm tính tiền không bảo đảm các yêu cầu theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1398),
(602, 'Điều khiển xe không có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường (đối với loại xe có quy định phải kiểm định, trừ xe đăng ký tạm thời) hoặc có nhưng đã hết hiệu lực (hạn sử dụng) từ 01 tháng trở lên (kể cả rơ moóc)', 'Xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1399),
(603, 'Điều khiển xe taxi sử dụng phần mềm tính tiền mà trên xe không có thiết bị để kết nối trực tiếp với hành khách theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1400),
(604, 'Sử dụng xe taxi chở hành khách không gắn hộp đèn với chữ \"TAXI\" trên nóc xe hoặc không niêm yết cụm từ “XE TAXI” trên kính phía trước, kính phía sau xe theo quy định hoặc có gắn hộp đèn, có niêm yết cụm từ “XE TAXI” nhưng không cố định, không đúng kích thước, không làm bằng vật liệu phản quang theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Buộc phải gắn hộp đèn với chữ “TAXI” hoặc buộc phải niêm yết cụm từ “XE TAXI” theo đúng quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1401),
(605, 'Bán biển số xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy không phải là biển số do cơ quan nhà nước có thẩm quyền sản xuất hoặc không được cơ quan nhà nước có thẩm quyền cho phép', 'Cá nhân, tổ chức thực hiện hành vi', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức.', 'Tịch thu biển số, phương tiện sản xuất, lắp ráp trái phép.', 'Buộc nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính.', NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1402),
(606, 'Sử dụng xe taxi chở hành khách không có hoặc có số điện thoại giao dịch ghi trên xe không đúng với đăng ký của doanh nghiệp (hợp tác xã)', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1403),
(607, 'Sản xuất biển số trái phép hoặc sản xuất, lắp ráp trái phép xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Cá nhân, tổ chức thực hiện hành vi', 'Phạt tiền từ 40.000.000 đồng đến 50.000.000 đồng đối với cá nhân, từ 80.000.000 đồng đến 100.000.000 đồng đối với tổ chức.', 'Tịch thu biển số, phương tiện sản xuất, lắp ráp trái phép.', 'Buộc nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính.', NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1404),
(608, 'Chở quá số người quy định được phép chở của xe ô tô chở hành khách (kinh doanh vận tải hành khách theo tuyến cố định, hợp đồng) chạy tuyến có cự ly lớn hơn 300 km', 'Người điều khiển xe ô tô chở hành khách (kinh doanh vận tải hành khách theo tuyến cố định, hợp đồng) chạy tuyến có cự ly lớn hơn 300 km', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng trên mỗi người vượt quá quy định được phép chở của phương tiện nhưng tổng mức phạt tiền tối đa không vượt quá 75.000.000 đồng', '- Trừ điểm giấy phép lái xe 04 điểm (trường hợp vượt trên 50% đến 100% số người quy định được phép chở của phương tiện)\r\n- Trừ điểm giấy phép lái xe 10 điểm (trường hợp vượt trên 100% số người quy định được phép chở của phương tiện)', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1405),
(609, 'Không thực hiện việc niêm yết thông tin trên xe theo quy định hoặc có niêm yết nhưng không chính xác, không đầy đủ thông tin theo quy định.', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1406),
(610, 'Để người lên, xuống xe khi xe đang chạy', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người để người lên, xuống xe khi xe đang chạy', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1407),
(611, 'Không cấp thẻ nhận dạng lái xe cho lái xe theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', 'Buộc cấp thẻ nhận dạng lái xe cho lái xe theo quy định', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1408),
(612, 'Tự ý thay đổi nhãn hiệu, màu sơn của xe không đúng với chứng nhận đăng ký xe', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 200.000 đồng đến 300.000 đồng', NULL, NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1409),
(613, 'Sử dụng lái xe, nhân viên phục vụ trên xe để tham gia kinh doanh vận tải bằng xe ô tô mà không được tập huấn, hướng dẫn về nghiệp vụ vận tải hành khách và an toàn giao thông theo quy định (đối với hình thức kinh doanh vận tải có quy định lái xe, nhân viên phục vụ trên xe phải được tập huấn, hướng dẫn nghiệp vụ)', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', 'Buộc tổ chức tập huấn, hướng dẫn nghiệp vụ, quy trình hoặc tổ chức khám sức khỏe định kỳ cho lái xe và nhân viên phục vụ trên xe theo quy định', 'Trừ các hành vi vi phạm quy định tại điểm c, điểm d khoản 4 Điều 26 Nghị định 168/2024/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1410),
(614, 'Không làm thủ tục đăng ký sang tên xe (để chuyển tên chủ xe trong Giấy đăng ký xe sang tên của mình) theo quy định khi mua, được cho, được tặng, được phân bổ, được điều chuyển, được thừa kế tài sản là xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng đối với cá nhân, từ 800.000 đồng đến 1.200.000 đồng đối với tổ chức.', NULL, NULL, NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1412),
(615, 'Đe dọa, xúc phạm, tranh giành, lôi kéo hành khách; đe dọa, cưỡng ép hành khách sử dụng dịch vụ ngoài ý muốn', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1413),
(616, 'Sử dụng lái xe, nhân viên phục vụ trên xe để tham gia kinh doanh vận tải bằng xe ô tô mà không có hợp đồng lao động theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', 'Buộc phải ký hợp đồng với lái xe và nhân viên phục vụ trên xe theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1414),
(617, 'Điều khiển xe không có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) hoặc sử dụng chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) đã hết hạn sử dụng, hết hiệu lực (kể cả rơ moóc)', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, 'Tịch thu phương tiện', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1415),
(618, 'Không làm thủ tục đổi lại Giấy đăng ký xe theo quy định khi thay đổi địa chỉ của chủ xe hoặc các trường hợp khác theo quy định', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng đối với cá nhân, từ 800.000 đồng đến 1.200.000 đồng đối với tổ chức.', NULL, 'Buộc phải làm thủ tục đổi lại đăng ký xe.', NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1416),
(619, 'Đe dọa, cưỡng ép hành khách sử dụng dịch vụ ngoài ý muốn', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1417),
(620, 'Không thực hiện đúng quy định về biển số', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.600.000 đồng đến 2.000.000 đồng đối với tổ chức.', NULL, 'Buộc phải thực hiện đúng quy định về biển số', 'Trường hợp này không áp dụng đới với các hành vi vi phạm quy định điểm g, điểm h khoản 8 Điều 32 Nghị định 168/2024/NĐ-CP.', 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1418),
(621, 'Không xây dựng quy trình bảo đảm an toàn giao thông hoặc xây dựng nhưng không đầy đủ các nội dung theo quy định hoặc không thực hiện đúng quy trình bảo đảm an toàn giao thông theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Bị tước quyền sử dụng giấy phép kinh doanh vận tải từ 01 tháng đến 03 tháng', 'Buộc phải xây dựng và thực hiện quy trình bảo đảm an toàn giao thông theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1419),
(622, 'Xuống khách hoặc các hành vi khác nhằm trốn tránh phát hiện xe chở quá tải, quá số người theo quy định của pháp luật', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1420);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(623, 'Không bố trí người trực tiếp điều hành hoạt động vận tải hoặc có bố trí nhưng không đáp ứng đủ điều kiện theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng giấy phép kinh doanh vận tải từ 01 tháng đến 03 tháng', 'Buộc phải bố trí người trực tiếp điều hành hoạt động vận tải đủ điều kiện theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1421),
(624, 'Không bố trí người trực tiếp điều hành hoạt động vận tải hoặc có bố trí nhưng không đáp ứng đủ điều kiện theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Bị tước quyền sử dụng giấy phép kinh doanh vận tải từ 01 tháng đến 03 tháng', 'Buộc phải bố trí người trực tiếp điều hành hoạt động vận tải đủ điều kiện theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1422),
(625, 'Cắt, hàn, tẩy xoá, đục sửa, đóng lại trái phép số khung, số động cơ (số máy); đưa phương tiện đã bị cắt, hàn, tẩy xoá, đục sửa, đóng lại trái phép số khung, số động cơ (số máy) tham gia giao thông', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Tịch thu phương tiện', NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1423),
(626, 'Điều khiển xe không gắn biển số (đối với loại xe có quy định phải gắn biển số)', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1424),
(627, 'Sử dụng phương tiện thuộc sở hữu của thành viên hợp tác xã để kinh doanh vận tải bằng xe ô tô mà không có hợp đồng dịch vụ giữa thành viên với hợp tác xã theo quy định hoặc sử dụng phương tiện không thuộc quyền sử dụng hợp pháp để kinh doanh vận tải bằng xe ô tô', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1425),
(628, 'Xếp hành lý, hàng hóa trên xe làm lệch xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1426),
(629, 'Điều khiển xe gắn biển số không đúng với chứng nhận đăng ký xe hoặc gắn biển số không do cơ quan có thẩm quyền cấp (kể cả rơ moóc)', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị tịch thu biển số xe', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1427),
(630, 'Không có nơi đỗ xe theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1429),
(631, 'Đưa phương tiện đã bị cắt, hàn, tẩy xoá, đục sửa, đóng lại trái phép số khung, số động cơ (số máy) tham gia giao thông', 'Chủ xe máy chuyên dùng, xe mô tô, xe gắn máy và các loại xe tương tự xe ô tô, xe mô tô, xe gắn máy', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng', 'Bị tịch thu phương tiện', NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1430),
(632, 'Bến xe không xác nhận hoặc xác nhận không chính xác, đầy đủ các thông tin trong Lệnh vận chuyển theo quy định hoặc xác nhận vào Lệnh vận chuyển khi xe không có ở bến', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1431),
(633, 'Đón, trả hành khách không đúng nơi quy định trên những tuyến đường đã xác định nơi đón, trả khách hoặc dừng đón, trả hành khách quá thời gian quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm;', NULL, 'Trừ hành vi đón, trả hành khách trên đường cao tốc.', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1432),
(634, 'Không thông báo nội dung hợp đồng vận chuyển khách tới Sở Giao thông vận tải trước khi thực hiện hợp đồng vận chuyển hành khách theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1433),
(635, 'Đón, trả hành khách tại nơi cấm dừng, cấm đỗ, nơi đường cong tầm nhìn bị che khuất', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Người điều khiển phương tiện thực hiện hành vi vi phạm còn bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp này không áp dụng với hành vi người điều khiển xe thực hiện hành vi đón, trả hành khách trên đường cao tốc', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1434),
(636, 'Tẩy xóa, sửa chữa hoặc giả mạo hồ sơ đăng ký xe nhưng chưa đến mức truy cứu trách nhiệm hình sự', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng đối với tổ chức', 'Bị thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo; giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường; chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc không đúng với số khung, số động cơ (số máy); giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe không do cơ quan có thẩm quyền cấp.', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1435),
(637, 'Gom khách, bán vé, thu tiền, xác nhận đặt chỗ cho từng hành khách đi xe đối với xe kinh doanh vận tải hành khách theo hợp đồng, xe kinh doanh vận tải khách du lịch', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1436),
(638, 'Gom khách, bán vé, thu tiền, xác nhận đặt chỗ cho từng hành khách đi xe đối với xe kinh doanh vận tải hành khách theo hợp đồng, xe kinh doanh vận tải khách du lịch', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1437),
(639, 'Ấn định hành trình, lịch trình cố định để phục vụ cho nhiều hành khách hoặc nhiều người thuê vận tải khác nhau đối với xe kinh doanh vận tải hành khách theo hợp đồng', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1439),
(640, 'Tự ý thay đổi khung, máy, hình dáng, kích thước, đặc tính của xe', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1440),
(641, 'Sử dụng chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngán hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị tịch thu phương tiện\r\nBị buộc nộp lại chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường bị tẩy xóa\r\nBị thu hồi chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc không đúng số khung, số động cơ (số máy) của xe, giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường không do cơ quan có thẩm quyền cấp', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1441),
(642, 'Sử dụng xe ô tô kinh doanh vận tải hành khách không có dây đai an toàn tại các vị trí ghế ngồi, giường nằm theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Buộc phải lắp đặt dây đai an toàn trên xe theo đúng quy định.', 'Trường hợp này không áp dụng với xe buýt nội tỉnh', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1442),
(643, 'Điều khiển xe vận tải hành khách theo hợp đồng sử dụng hợp đồng bằng văn bản giấy không có hoặc không mang theo danh sách hành khách theo quy định, chở người không có tên trong danh sách hành khách hoặc vận chuyển không đúng đối tượng theo quy định (đối với xe kinh doanh vận tải hành khách theo hợp đồng vận chuyển trẻ em mầm non, học sinh, sinh viên, cán bộ, công chức, viên chức, công nhân), không có hoặc không mang theo hợp đồng vận tải hoặc có hợp đồng vận tải nhưng không đúng theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1443),
(644, 'Khai báo không đúng sự thật hoặc sử dụng các giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe nhưng chưa đến mức bị truy cứu trách nhiệm hình sự', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng đối với tổ chức', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1444),
(645, 'Sử dụng xe kinh doanh vận tải hành khách theo hợp đồng, xe kinh doanh vận tải khách du lịch mà xe đó có số chuyến trùng lặp điểm đầu và trùng lặp điểm cuối vượt quá quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tớc quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1445),
(646, 'Vận chuyển hành khách theo tuyến cố định không có hoặc không mang theo lệnh vận chuyển hoặc có mang theo lệnh vận chuyển nhưng không ghi đầy đủ thông tin, không có xác nhận của bến xe khách nơi đi, bến xe khách nơi đến theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1446),
(647, 'Sử dụng chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không đúng số khung, số động cơ (số máy) của xe (kể cả rơ moóc)', 'Người điều khiển xe máy chuyên dùng (kể cả rơ moóc được kéo theo)', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị tịch thu phương tiện\r\nBuộc nộp lại chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường bị tẩy xóa\r\nBị thu hồi chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc không đúng số khung, số động cơ (số máy) của xe, giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường không do cơ quan có thẩm quyền cấp', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1448),
(648, 'Kinh doanh vận tải hành khách theo hợp đồng, kinh doanh vận tải khách du lịch không thực hiện đúng quy định về đón, trả khách tại trụ sở chính, trụ sở chi nhánh, văn phòng đại diện hoặc tại một địa điểm cố định khác do đơn vị kinh doanh vận tải thuê, hợp tác kinh doanh', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1449),
(649, 'Giao xe hoặc để cho người không đủ điều kiện theo quy định tại khoản 1 Điều 56 của Luật Trật tự, an toàn giao thông đường bộ điều khiển xe tham gia giao thông (bao gồm cả trường hợp người điều khiển phương tiện có giấy phép lái xe nhưng đang trong thời gian bị tước quyền sử dụng)', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1450),
(650, 'Đón, trả hành khách không đúng địa điểm đón, trả hành khách được ghi trong hợp đồng', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1451),
(651, 'Sử dụng xe taxi, xe kinh doanh vận tải hành khách theo hợp đồng, xe kinh doanh vận tải khách du lịch có trên 70% tổng thời gian hoạt động trong 1 tháng (của xe) tại địa bàn của một địa phương (tỉnh, thành phố trực thuộc trung ương) mà không có phù hiệu do Sở Giao thông vận tải địa phương đó cấp theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1452),
(652, 'Điều khiển xe không đáp ứng yêu cầu về vệ sinh lưu thông trong đô thị', 'Người điều khiển máy kéo', 'Phạt tiền 500.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1454),
(653, 'Không làm thủ tục thu hồi chứng nhận đăng ký xe, biển số xe theo quy định', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng', 'Buộc làm thủ tục đổi chứng nhận đăng ký xe, biển số xe (trừ trường hợp bị tịch thu phương tiện)', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1455),
(654, 'Xếp hàng hóa lên mỗi xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) vượt quá trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100%.', 'Cá nhân, tổ chức xếp hàng hóa lên xe ô tô (kể cả rơ moóc và sơ mi rơ moóc)', 'Phạt tiền từ 4.000.000 đồng đến 5.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 10.000.000 đồng đối với tổ chức.', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1456),
(655, 'Vận chuyển khách liên vận quốc tế theo tuyến cố định không có hoặc không mang theo lệnh vận chuyển, không có danh sách hành khách theo quy định hoặc chở người không có tên trong danh sách hành khách', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp này không áp dụng với các hành vi vi phạm quy định tại điểm b khoản 1 Điều 37 của Nghị định 168/2024/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1457),
(656, 'Xả thải, làm rơi vãi hóa chất, chất thải gây mất an toàn giao thông đường bộ', 'Các hành vi vi phạm khác về quy tắc giao thông đường bộ; sử dụng lòng đường, vỉa hè vào mục đích khác', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1459),
(657, 'Tổ chức hoạt động khai thác bến xe, bãi đỗ xe, trạm dừng nghỉ khi chưa được cơ quan có thẩm quyền cho phép theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1460),
(658, 'Chở hành lý, hàng hóa vượt quá trọng tải theo thiết kế của xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1461),
(659, 'Đưa phương tiện không có Giấy đăng ký xe tham gia giao thông hoặc có nhưng đã hết hạn sử dụng', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô', 'Phạt tiền từ 800.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 1.600.000 đồng đến 4.000.000 đồng đối với tổ chức.', '-Trường hợp không có Giấy đăng ký xe hoặc có Giấy đăng ký xe nhưng không do cơ quan có thẩm quyền cấp, không đúng số khung, số máy của xe hoặc bị tẩy xóa (kể cả rơ moóc và sơ mi rơ moóc) mà không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng từ chuyển quyền sở hữu xe hoặc giấy tờ, chứng từ nguồn gốc xe hợp pháp) thì bị tịch thu phương tiện; \r\n- Nếu chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng.', 'Thu hồi Giấy đăng ký xe', 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1462),
(660, 'Điều khiển xe vận chuyển khách du lịch, xe vận chuyển hành khách theo hợp đồng gom khách, bán vé, thu tiền hoặc thực hiện việc xác nhận đặt chỗ cho từng hành khách đi xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1463),
(661, 'Để xe ô tô không đủ điều kiện kinh doanh vận tải khách vào bến xe ô tô khách đón khách', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1464),
(662, 'Chở đất đá, phế thải, hàng rời mà không có mui, bạt che đậy hoặc có mui, bạt che đậy nhưng vẫn để rơi vãi', 'Người điều khiển máy kéo', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1466),
(663, 'Điều khiển xe vận chuyển hành khách theo hợp đồng ấn định hành trình, lịch trình cố định để phục vụ cho nhiều hành khách hoặc nhiều người thuê vận tải khác nhau', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1467),
(664, 'Chở hàng hoặc chất thải để nước chảy xuống mặt đường gây mất an toàn giao thông', 'Người điều khiển máy kéo', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1469),
(665, 'Không thực hiện việc cung cấp, cập nhật, truyền, lưu trữ, quản lý thông tin, dữ liệu từ thiết bị giám sát hành trình theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', NULL, 'Buộc cung cấp, cập nhật, truyền dẫn, lưu trữ, quản lý thông tin, dữ liệu thu thập từ thiết bị giám sát hành trình, thiết bị ghi nhận hình ảnh người lái xe lắp trên xe ô tô theo quy định', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1470),
(666, 'Đưa phương tiện có Giấy chứng nhận đăng ký xe tạm thời, phương tiện có phạm vi hoạt động hạn chế tham gia giao thông quá thời hạn, tuyến đường, phạm vi cho phép', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô', 'Phạt tiền từ 800.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 1.600.000 đồng đến 4.000.000 đồng đối với tổ chức.', '- Nếu không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng từ chuyển quyền sở hữu xe hoặc giấy tờ, chứng từ nguồn gốc xe hợp pháp) thì bị tịch thu phương tiện.\r\n- Nếu chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng.', 'Buộc phải làm thủ tục đăng ký xe, đăng ký sang tên, đổi lại, thu hồi Giấy đăng ký xe, biển số xe, Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện).', 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1471),
(667, 'Không sử dụng thẻ nhận dạng lái xe để đăng nhập thông tin theo quy định hoặc sử dụng thẻ nhận dạng lái xe của lái xe khác để đăng nhập thông tin khi điều khiển xe ô tô chở khách', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1473),
(668, 'Lôi kéo bùn, đất, cát, nguyên liệu, vật liệu hoặc chất phế thải khác ra đường bộ gây mất an toàn giao thông và vệ sinh môi trường', 'Người điều khiển máy kéo', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1474),
(669, 'Điều khiển xe kinh doanh vận tải hành khách không lắp thiết bị giám sát hành trình của xe theo quy định hoặc có lắp thiết bị giám sát hành trình của xe nhưng thiết bị không hoạt động theo quy định', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1475),
(670, 'Không thực hiện đúng các nội dung đã đăng ký, niêm yết về: giá cước; giá dịch vụ; tiêu chuẩn chất lượng dịch vụ vận tải, dịch vụ hỗ trợ vận tải;', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', '- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Trường hợp thu tiền cước, tiền dịch vụ cao hơn quy định buộc phải nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1477),
(671, 'Điều khiển xe vận tải hành khách theo hợp đồng sử dụng hợp đồng điện tử không có thiết bị để truy cập được nội dung của hợp đồng điện tử và danh sách hành khách hoặc có nhưng không cung cấp cho lực lượng chức năng khi có yêu cầu, chở người không có tên trong danh sách hành khách hoặc vận chuyển không đúng đối tượng theo quy định (đối với xe kinh doanh vận tải hành khách theo hợp đồng vận chuyển trẻ em mầm non, học sinh, sinh viên, cán bộ, công chức, viên chức, công nhân)', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1478),
(672, 'Vận chuyển hàng hóa nguy hiểm, hàng độc hại, dễ cháy, dễ nổ, động vật có mùi hôi thối hoặc hàng hóa khác ảnh hưởng đến sức khỏe của hành khách trên xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách, chở người', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1479),
(673, 'Đỗ trái phép rác, đất, cát, đá, vật liệu, chất phế thải trong phạm vi đất dành cho đường bộ ở đoạn đường ngoài đô th', 'Người điều khiển xe ô tô, máy kéo và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1480),
(674, 'Không thực hiện đúng các nội dung đã đăng ký, niêm yết về giá cước', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', '- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Buộc phải nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1481),
(675, 'Chở người trên mui xe, trong khoang chở hành lý của xe', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1482),
(676, 'Đổ trái phép rác, đất, cát, đá, vật liệu, chất phế thải ra đường phố', 'Người điều khiển xe ô tô, máy kéo và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 15.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1484),
(677, 'Đưa phương tiện có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) nhưng không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa tham gia giao thông', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng', '- Trường hợp không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng nhận nguồn gốc xe, chứng nhận quyền sở hữu hợp pháp) thì bị tịch thu phương tiện;\r\n- Bị thu hồi chứng nhận đăng ký xe\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm.', NULL, 'Tạm giữ phương tiện không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1486),
(678, 'Không thực hiện đúng các nội dung đã đăng ký, niêm yết về: giá cước; giá dịch vụ; tiêu chuẩn chất lượng dịch vụ vận tải, dịch vụ hỗ trợ vận tải', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', '- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1488),
(679, 'Chưa đủ tuổi điều khiển máy kéo', 'Người từ đủ 14 tuổi đến dưới 16 tuổi điều khiển máy kéo', 'Phạt cảnh cáo', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1489),
(680, 'Sử dụng phương tiện kinh doanh vận tải không lắp thiết bị giám sát hành trình của xe (đối với hình thức kinh doanh vận tải có quy định phương tiện phải lắp thiết bị) hoặc lắp thiết bị nhưng thiết bị không hoạt động, không đúng quy chuẩn theo quy định hoặc làm sai lệch dữ liệu của thiết bị giám sát hành trình của xe ô tô', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.\r\n- Trừ điểm giấy phép lái xe 02 điểm.', '- Buộc lắp đặt thiết bị giám sát hành trình trên xe theo đúng quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1490),
(681, 'Điều khiển xe ô tô quá thời gian quy định tại khoản 1 Điều 64 Luật trật tự, an toàn giao thông đường bộ 2024', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1491),
(682, 'Sử dụng xe trung chuyển chở hành khách không đúng quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1492),
(683, 'Không mang theo giấy phép lái xe', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô kinh doanh vận tải', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng', NULL, NULL, 'Trừ trường hợp hành vi vi phạm quy định tại điểm c khoản 8 Điều 18 Nghị định 168/2024', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1493),
(684, 'Sử dụng lái xe điều khiển xe khách giường nằm hai tầng chưa đủ số năm kinh nghiệm theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1494),
(685, 'Điều khiển xe kinh doanh vận tải hành khách không lắp thiết bị giám sát hành trình của xe theo quy định hoặc có lắp thiết bị giám sát hành trình của xe nhưng thiết bị không hoạt động theo quy định hoặc làm sai lệch dữ liệu của thiết bị giám sát hành trình của xe ô tô', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1495),
(686, 'Không có bộ phận quản lý, theo dõi các điều kiện về an toàn giao thông theo quy định hoặc có nhưng bộ phận này không thực hiện đầy đủ các nhiệm vụ theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng giấy phép kinh doanh vận tải từ 01 tháng đến 03 tháng', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1496),
(687, 'Đưa phương tiện có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) nhưng không đúng với số khung, số động cơ (số máy) của xe tham gia giao thông', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng', '- Đưa phương tiện có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) nhưng không đúng với số khung, số động cơ (số máy) của xe tham gia giao thông mà không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng nhận nguồn gốc xe, chứng nhận quyền sở hữu hợp pháp) thì bị tịch thu phương tiện.\r\n- Buộc nộp lại chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe).\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1499),
(688, 'Sử dụng phương tiện kinh doanh vận tải có chất lượng không bảo đảm điều kiện của hình thức kinh doanh đã đăng ký', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm\r\n- Tước quyền sử dụng giấy phép kinh doanh vận tải từ 01 tháng đến 03 tháng', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1500),
(689, 'Không mang theo giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường đối với loại xe có quy định phải kiểm định.', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, rơ moóc, sơ mi rơ moóc và các loại xe tương tự xe ô tô kinh doanh vận tải', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1501),
(690, 'Điều khiển xe chở hành khách liên vận quốc tế không có hoặc không gắn ký hiệu phân biệt quốc gia.', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1502),
(691, 'Lắp đặt, sử dụng thiết bị thay đổi biển số trên xe trái quy định', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng đối với tổ chức', 'Tịch thu biển số.', NULL, NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1503),
(692, 'Đón, trả hành khách trên đường cao tốc', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1504),
(693, 'Không lưu trữ theo quy định các hồ sơ, tài liệu có liên quan trong quá trình quản lý, điều hành hoạt động vận tải của đơn vị', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', 'Buộc phải lập, cập nhật, lưu trữ đầy đủ, chính xác các hồ sơ, tài liệu có liên quan trong quá trình quản lý, điều hành hoạt động vận tải của đơn vị theo quy định.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1505),
(694, 'Không lập hoặc có lập nhưng không cập nhật đầy đủ, chính xác lý lịch phương tiện, lý lịch hành nghề của lái xe theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', 'Buộc phải lập, cập nhật, lưu trữ đầy đủ, chính xác lý lịch phương tiện, lý lịch hành nghề của lái xe, các hồ sơ, tài liệu có liên quan trong quá trình quản lý, điều hành hoạt động vận tải của đơn vị theo quy định', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1506),
(695, 'Không mang theo chứng nhận bảo hiểm bắt buộc trách nhiệm dân sự của chủ xe cơ giới còn hiệu lực', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô kinh doanh vận tải', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1507),
(696, 'Điều khiển xe chở hành khách không có hoặc không gắn phù hiệu theo quy định hoặc có nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp.', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Thu hồi phù hiệu đã hết giá trị sử dụng hoặc phù hiệu không do cơ quan có thẩm quyền cấp.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1508),
(697, 'Đưa phương tiện không gắn biển số (đối với loại xe có quy định phải gắn biển số) tham gia giao thông', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng đối với tổ chức.', '- Tịch thu biển số\r\n- Trừ điểm giấy phép lái xe 06 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1509),
(698, 'Vận chuyển hàng trên xe phải chằng buộc mà không chằng buộc hoặc có chằng buộc nhưng không bảo đảm an toàn', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 8.000.000 đồng đến 12.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', NULL, 'Trừ hành vi vi phạm quy định tại khoản 10 Điều 21 Nghị định 168/2024/NĐ-CP', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1510),
(699, 'Sử dụng xe kinh doanh vận tải hành khách theo hợp đồng mà trên xe không có hợp đồng vận tải, danh sách hành khách kèm theo, thiết bị để truy cập nội dung hợp đồng điện tử và danh sách hành khách theo quy định hoặc có hợp đồng vận tải, danh sách hành khách, thiết bị để truy cập nhưng không bảo đảm yêu cầu theo quy định, chở người không có tên trong danh sách hành khách hoặc vận chuyển không đúng đối tượng theo quy định (đối với xe kinh doanh vận tải hành khách theo hợp đồng vận chuyển trẻ em mầm non, học sinh, sinh viên, cán bộ, công chức, viên chức, công nhân)', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm\r\n- Cá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1511),
(700, 'Có giấy phép lái xe nhưng đã hết hạn sử dụng dưới 01 năm', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1513),
(701, 'Điều khiển xe xếp hàng trên nóc buồng lái, xếp hàng làm lệch xe', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1514),
(702, 'Sử dụng xe taxi chở hành khách không lắp đồng hồ tính tiền (đối với loại xe đăng ký sử dụng đồng hồ tính tiền) hoặc lắp đồng hồ tính tiền không đúng quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Buộc lắp đặt đồng hồ tính tiền cước trên xe theo đúng quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1515),
(703, 'Không chốt, đóng cố định cửa sau, cửa bên thùng xe khi xe đang chạy', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1516),
(704, 'Đưa phương tiện gắn biển số không đúng với Giấy đăng ký xe hoặc gắn biển số không do cơ quan có thẩm quyền cấp tham gia giao thông', 'Chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng đối với tổ chức.', '- Tịch thu biển số\r\n- Trừ điểm giấy phép lái xe 06 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1517),
(705, 'Chưa đủ tuổi điều khiển máy kéo', 'Người từ đủ 16 tuổi đến dưới 18 tuổi điều khiển máy kéo', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, 'Tạm giữ phương tiện tối đa đến 07 ngày.', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1518),
(706, 'Sử dụng xe taxi chở hành khách không có thiết bị in hóa đơn (phiếu thu tiền) được kết nối với đồng hồ tính tiền theo quy định hoặc có nhưng không sử dụng được hoặc in ra phiếu thu tiền nhưng không có đầy đủ các thông tin theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Buộc lắp đặt thiết bị in hóa đơn trên xe theo đúng quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1519),
(707, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30% (trừ xe xi téc chở chất lỏng), trên 20% đến 30% đối với xe xi téc chở chất lỏng', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1520),
(708, 'Tụ tập để cổ vũ, giúp sức, xúi giục hành vi điều khiển xe chạy quá tốc độ quy định, lạng lách, đánh võng, đuổi nhau trên đường hoặc đua xe trái phép', 'Người', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1521),
(709, 'Giấy phép lái xe nhưng đã hết hạn sử dụng dưới 01 năm', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1522);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(710, 'Sử dụng xe ô tô kinh doanh vận tải không lắp thiết bị ghi nhận hình ảnh người lái xe theo quy định (đối với loại xe có quy định phải lắp thiết bị ghi nhận hình ảnh người lái xe) hoặc có lắp thiết bị ghi nhận hình ảnh người lái xe nhưng không ghi, không lưu trữ được dữ liệu trên xe trong quá trình xe tham gia giao thông theo quy định hoặc làm sai lệch dữ liệu của thiết bị ghi nhận hình ảnh người lái xe lắp trên xe ô tô', 'Tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Buộc lắp đặt thiết bị giám sát hành trình, thiết bị ghi nhận hình ảnh người lái xe, dây đai an toàn, ghế ngồi cho trẻ em mầm non, học sinh tiểu học trên xe theo đúng quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1523),
(711, 'Đua xe trái phép', 'Người đua xe mô tô, xe gắn máy, xe máy điện trái phép', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Tịch thu phương tiện', NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1524),
(712, 'Chở hàng trên nóc thùng xe', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1525),
(713, 'Không thực hiện việc cung cấp, cập nhật, truyền dẫn, lưu trữ, quản lý thông tin, dữ liệu thu thập từ thiết bị ghi nhận hình ảnh người lái xe lắp trên xe ô tô theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng', NULL, 'Buộc cung cấp, cập nhật, truyền dẫn, lưu trữ, quản lý thông tin, dữ liệu thu thập từ thiết bị giám sát hành trình, thiết bị ghi nhận hình ảnh người lái xe lắp trên xe ô tô theo quy định', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1526),
(714, 'Điều khiển phương tiện không gắn ký hiệu phân biệt quốc gia theo quy định', 'Người điều khiển phương tiện giao thông cơ giới đường bộ gắn biển số nước ngoài', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', NULL, NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1527),
(715, 'Chở hàng vượt quá bề rộng thùng xe (kể cả bề rộng rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1528),
(716, 'Sử dụng xe taxi chở hành khách mà trên xe không có thiết bị để kết nối trực tiếp với hành khách theo quy định (đối với loại xe đăng ký sử dụng phần mềm tính tiền) hoặc sử dụng phần mềm tính tiền không bảo đảm các yêu cầu theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1529),
(717, 'Giấy tờ của phương tiện không có bản dịch sang tiếng Anh hoặc tiếng Việt theo quy định', 'Người điều khiển phương tiện giao thông cơ giới đường bộ gắn biển số nước ngoài', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1530),
(718, 'Chở hàng vượt phía trước, phía sau thùng xe (kể cả rơ moóc và sơ mi rơ moóc) trên 1,1 lần chiều dài toàn bộ của xe theo thiết kế được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1531),
(719, 'Kinh doanh vận tải bằng xe ô tô mà không có Giấy phép kinh doanh vận tải theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1532),
(720, 'Lưu hành phương tiện trên lãnh thổ Việt Nam quá thời hạn quy định', 'Người điều khiển phương tiện giao thông cơ giới đường bộ gắn biển số nước ngoài', 'Phạt tiền từ 30.000.000 đồng đến 35.000.000 đồng', NULL, 'Buộc tái xuất phương tiện khỏi Việt Nam.', NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1533),
(721, 'Thực hiện không đúng hình thức kinh doanh đã đăng ký trong Giấy phép kinh doanh vận tải', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1534),
(722, 'Hoạt động quá phạm vi, tuyến đường, đoạn đường được phép hoạt động.', 'Người điều khiển phương tiện giao thông cơ giới đường bộ gắn biển số nước ngoài', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', NULL, NULL, NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1535),
(723, 'Chở người trên thùng xe trái quy định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Trừ điểm giấy phép lái xe 06 điểm.', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1536),
(724, 'Thành lập điểm giao dịch đón, trả khách trái phép (bến dù, bến cóc)', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1537),
(725, 'Bến xe không thực hiện quy trình đảm bảo an toàn giao thông cho xe ra, vào bến hoặc thực hiện không đúng, không đầy đủ quy trình đảm bảo an toàn giao thông cho xe ra, vào bến', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1538),
(726, 'Điều khiển phương tiện không gắn biển số tạm thời hoặc gắn biển số tạm thời không do cơ quan có thẩm quyền cấp (nếu có quy định phải gắn biển số tạm thời)', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy gắn biển số nước ngoài', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng.', NULL, 'Buộc tái xuất phương tiện khỏi Việt Nam.', NULL, 1, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1539),
(727, 'Chở người trên mui xe', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1540),
(728, 'Không sử dụng thẻ nhận dạng lái xe để đăng nhập thông tin theo quy định hoặc sử dụng thẻ nhận dạng lái xe của lái xe khác để đăng nhập thông tin khi điều khiển xe tham gia kinh doanh vận tải hàng hóa', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1541),
(729, 'Không tổ chức khám sức khỏe định kỳ cho lái xe theo quy định hoặc có tổ chức khám nhưng không đầy đủ các nội dung theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng', NULL, 'Buộc tổ chức khám sức khỏe định kỳ cho lái xe và nhân viên phục vụ trên xe theo quy định', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1542),
(730, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng.', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1543),
(731, 'Không có tờ khai phương tiện vận tải đường bộ tạm nhập, tái xuất theo quy định', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng', 'Tịch thu phương tiện đối với người điều khiển phương tiện tái phạm', 'Buộc đưa phương tiện quay trở lại Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế', NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1544),
(732, 'Không thực hiện việc cung cấp các thông tin trên Lệnh vận chuyển của từng chuyến xe buýt, xe chạy tuyến cố định theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1545),
(733, 'Bến xe khách không áp dụng phần mềm quản lý bến xe, hệ thống camera giám sát theo quy định', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1546),
(734, 'Điều khiển xe ô tô tham gia kinh doanh vận tải hàng hoá không lắp thiết bị giám sát hành trình hoặc có lắp thiết bị giám sát hành trình nhưng không có tác dụng trong quá trình xe tham gia giao thông theo quy định hoặc làm sai lệch dữ liệu của thiết bị giám sát hành trình lắp trên xe ô tô', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Trừ điểm giấy phép lái xe 02 điểm;', NULL, 'Trường hợp này không áp dụng với hành vi vi phạm quy định tại điểm c khoản 5 Điều 24 Nghị định 100/2019/NĐ-CP.', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1547),
(735, 'Vi phạm quy định về kinh doanh, điều kiện kinh doanh vận tải bằng xe ô tô để xảy ra tai nạn giao thông gây hậu quả từ mức nghiêm trọng trở lên', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1549),
(736, 'Điều khiển xe không có phù hiệu kiểm soát theo quy định hoặc có nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy đăng ký hoạt động trong Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng.', '- Tịch thu phù hiệu trong trường hợp sử dụng phù hiệu đã hết giá trị sử dụng, phù hiệu không do cơ quan có thẩm quyền cấp.\r\n- Nếu tái phạm hoặc vi phạm nhiều lần thì bị tịch thu phương tiện.', 'Buộc đưa phương tiện quay trở lại Khu kinh tế thương mại đặc biệt, Khu kinh tế cửa khẩu quốc tế.', NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1550),
(737, 'Không sử dụng thẻ nhận dạng lái xe để đăng nhập thông tin theo quy định hoặc sử dụng thẻ nhận dạng lái xe của lái xe khác để đăng nhập thông tin khi điều khiển xe tham gia kinh doanh vận tải hàng hóa', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1551),
(738, 'Sử dụng xe ô tô kinh doanh vận tải để đón, trả khách', 'Tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải\r\nCá nhân kinh doanh vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.\r\nCá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 06 điểm.', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1552),
