(752, 'Làm sai lệch dữ liệu của thiết bị giám sát hành trình của xe ô tô', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm\r\n- Trường hợp cá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm', '- Buộc lắp đặt thiết bị giám sát hành trình trên xe theo đúng quy định', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1566),
(753, 'Chở công-ten-nơ trên xe (kể cả sơ mi rơ moóc) mà không sử dụng cơ cấu khoá hãm công-ten-nơ với xe hoặc có sử dụng cơ cấu khoá hãm nhưng công-ten- nơ vẫn bị xê dịch trong quá trình vận chuyển.', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 18.000.000 đồng đến 22.000.000 đồng.', 'Tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng.', '- Bị trừ điểm giấy phép lái xe 04 điểm;\r\n- Trường hợp gây ra tai nạn giao thông thì bị trừ điểm giấy phép lái xe 10 điểm.', 'Trường hợp gây ra tai nạn giao thông thì bị phạt từ 30.000.000 đồng đến 35.000.000 đồng.', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1567),
(754, 'Không chấp hành hiệu lệnh, chỉ dẫn của nhân viên gác đường ngang, cầu chung khi đi qua đường ngang, cầu chung', 'xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng.', 'Tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng.', NULL, NULL, 1, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1568),
(755, 'Không có giấy phép lái xe hoặc sử dụng giấy phép lái xe đã bị trừ hết điểm hoặc sử dụng giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe bị tẩy xóa, giấy phép lái xe không còn hiệu lực', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ', 'Phạt tiền từ 18.000.000 đồng đến 20.000.000 đồng', NULL, 'Buộc nộp lại giấy phép lái xe bị tẩy xóa', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1569),
(756, 'Điều khiển xe làm hỏng cần chắn, giàn chắn, các thiết bị khác tại đường ngang', 'Người điều khiển xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng.', 'Tước quyền sử dụng Giấy phép lái xe từ 01 tháng đến 03 tháng.', 'Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1570),
(757, 'Điều khiển xe ô tô tải, và các loại xe tương tự xe ô tô vận chuyển hàng hóa chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1571),
(758, 'Có giấy phép lái xe quốc tế do các nước tham gia Công ước của Liên hợp quốc về Giao thông đường bộ năm 1968 cấp (trừ giấy phép lái xe quốc tế do Việt Nam cấp) nhưng không mang theo giấy phép lái xe quốc gia phù hợp với loại xe được phép điều khiển', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1572),
(759, 'Điều khiển xe ô tô kinh doanh vận tải quá thời gian quy định tại khoản 1 Điều 64 của Luật Trật tự, an toàn giao thông đường bộ', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1573),
(760, 'Điều khiển xe kinh doanh vận tải hành khách không lắp thiết bị giám sát hành trình của xe theo quy định hoặc có lắp thiết bị giám sát hành trình của xe nhưng thiết bị không hoạt động theo quy định hoặc làm sai lệch dữ liệu của thiết bị giám sát hành trình của xe ô tô', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng.', 'Trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1574),
(761, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm.', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1575),
(762, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 50% đến 100%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1576),
(763, 'Sử dụng giấy phép lái xe không hợp lệ (giấy phép lái xe có số phôi ghi ở mặt sau không trùng với số phôi được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe)', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Bị thu hồi giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe không hợp lệ\r\nBị trừ điểm giấy phép lái xe được cấp mới nhất trong hệ thống thông tin quản lý giấy phép lái xe 02 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1577),
(764, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 50% đến 100%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1578),
(765, 'Nhận, trả hàng trên đường cao tốc', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', 'Trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1580),
(766, 'Điều khiển xe máy chuyên dùng không đúng độ tuổi hoặc tuổi không phù hợp với ngành nghề theo quy định', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1581),
(767, 'Điều khiển xe không có hoặc không gắn phù hiệu theo quy định (đối với loại xe có quy định phải gắn phù hiệu) hoặc có phù hiệu nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng.', '- Thu hồi phù hiệu đã hết giá trị sử dụng hoặc phù hiệu không do cơ quan có thẩm quyền cấp.\r\n- Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1582),
(768, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 7.000.000 đồng đến 8.000.000 đồng', 'Trừ điểm giấy phép lái xe 08 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1583),
(769, 'Không có chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1584),
(770, 'Không có giấy phép lái xe (hoặc sử dụng giấy phép lái xe đã bị trừ hết điểm)', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1586),
(771, 'Không có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường (đối với loại xe có quy định phải kiểm định) hoặc có nhưng đã hết hiệu lực (hạn sử dụng) từ 01 tháng trở lên (kể cả rơ moóc và sơ mi rơ moóc) tham gia giao thông;', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1587),
(772, 'Không có bằng (hoặc chứng chỉ) điều khiển xe máy chuyên dùng, không có giấy phép lái xe (hoặc sử dụng giấy phép lái xe đã bị trừ hết điểm, giấy phép lái xe không do cơ quan có thẩm quyền cấp, giấy phép lái xe bị tẩy xóa, giấy phép lái xe không còn hiệu lực) hoặc không có chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ.', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1589),
(773, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 8.000.000 đồng đến 12.000.000 đồng', 'Trừ điểm giấy phép lái xe 10 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1590),
(774, 'Vận chuyển hàng trên xe phải chằng buộc mà không chằng buộc hoặc có chằng buộc nhưng không bảo đảm an toàn theo quy định', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 8.000.000 đồng đến 12.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với hành vi vi phạm quy định tại khoản 10 Điều 21 Nghị định 168/2024/NĐ-CP', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1591),
(775, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 8.000.000 đồng đến 12.000.000 đồng', 'Trừ điểm giấy phép lái xe 10 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1592),
(776, 'Điều khiển xe xếp hàng trên nóc buồng lái, xếp hàng làm lệch xe', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trường hợp gây tai nạn giao thông đường bộ sẽ bị phạt tiền từ 30.000.000 đồng đến 35.000.000 đồng.', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1593),
(777, 'Không chốt, đóng cố định cửa sau thùng xe khi xe đang chạy', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1594),
(778, 'Điều khiển xe chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30% (trừ xe xi téc chở chất lỏng), trên 20% đến 30% đối với xe xi téc chở chất lỏng', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1595),
(779, 'Vận chuyển hàng trên xe phải chằng buộc mà không chằng buộc hoặc có chằng buộc nhưng không bảo đảm an toàn mà gây tai nạn giao thông', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 30.000.000 đồng đến 35.000.000 đồng', 'Trừ điểm giấy phép lái xe 10 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1596),
