(783, 'Không chốt, đóng cố định cửa sau, cửa bên thùng xe khi xe đang chạy', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1601),
(784, 'Chở hàng vượt phía trước, phía sau thùng xe (kể cả rơ moóc và sơ mi rơ moóc) trên 1,1 lần chiều dài toàn bộ của xe theo thiết kế được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1602),
(785, 'Chở công-ten-nơ trên xe (kể cả sơ mi rơ moóc) mà không sử dụng cơ cấu khoá hãm công-ten-nơ với xe hoặc có sử dụng cơ cấu khoá hãm nhưng công-ten- nơ vẫn bị xê dịch trong quá trình vận chuyển', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 18.000.000 đồng đến 22.000.000 đồng.', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, 'Chở công-ten-nơ trên xe (kể cả sơ mi rơ moóc) mà không sử dụng cơ cấu khoá hãm công-ten-nơ với xe hoặc có sử dụng cơ cấu khoá hãm nhưng công-ten- nơ vẫn bị xê dịch trong quá trình vận chuyển mà gây tai nạn thì bị phạt từ 30.000.000 đồng đến 35.000.000 đồng và bị trừ điểm giấy phép lái xe 10 điểm.', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1605),
(786, 'Chở hàng siêu trường, siêu trọng không có báo hiệu kích thước của hàng theo quy định', 'Người điều khiển xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1606),
(787, 'Không thực hiện đúng quy định trong Giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng với các hành vi vi phạm quy định tại khoản 2; điểm b, điểm c, điểm d khoản 3 Điều 22 Nghị định 168/2024/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1607),
(788, 'Chở người trên mui xe', 'Người điều khiển xe máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1608),
(789, 'Không sử dụng thẻ nhận dạng lái xe để đăng nhập thông tin theo quy định hoặc sử dụng thẻ nhận dạng lái xe của lái xe khác để đăng nhập thông tin khi điều khiển xe tham gia kinh doanh vận tải hàng hóa', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', '- Trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1609),
(790, 'Chở hàng siêu trường, siêu trọng không có Giấy phép lưu hành hoặc có Giấy phép lưu hành nhưng đã hết giá trị sử dụng hoặc sử dụng Giấy phép lưu hành không do cơ quan có thẩm quyền cấp', 'Người điều khiển xe ô tô', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', '- Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra\r\n- Thu hồi giấy phép lưu hành hết giá trị sử dụng hoặc giấy phép lưu hành không do cơ quan có thẩm quyền cấp', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1610),
(791, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30%', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1611),
(792, 'Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng kích thước bao ngoài của xe (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành', 'Người điều khiển xe ô tô thực hiện hành vi vi phạm quy định về vận chuyển hàng siêu trường, siêu trọng', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng kích thước bao ngoài của xe (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1612),
(793, 'Chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong Giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1613),
(794, 'Chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng chở không đúng loại hàng quy định trong Giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1616),
(795, 'Không sử dụng thẻ nhận dạng lái xe để đăng nhập thông tin theo quy định hoặc sử dụng thẻ nhận dạng lái xe của lái xe khác để đăng nhập thông tin khi điều khiển xe tham gia kinh doanh vận tải hàng hóa', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1617),
(796, 'Điều khiển xe ô tô đầu kéo không lắp thiết bị ghi nhận hình ảnh người lái xe hoặc có lắp thiết bị ghi nhận hình ảnh người lái xe nhưng không có tác dụng trong quá trình xe tham gia giao thông theo quy định hoặc làm sai lệch dữ liệu của thiết bị ghi nhận hình ảnh người lái xe lắp trên xe ô tô.', 'Người điều khiển xe ô tô đầu kéo', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1619),
(797, 'Vận chuyển hàng nguy hiểm không dán nhãn, biểu trưng nhận diện hàng hóa nguy hiểm', 'Người điều khiển xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1620),
