(799, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1622),
(800, 'Vận chuyển hàng hoá nguy hiểm không có giấy phép vận chuyển hàng hóa nguy hiểm hoặc có nhưng hết hiệu lực hoặc không thực hiện đúng quy định trong giấy phép vận chuyển hàng hóa nguy hiểm', 'Người điều khiển xe ô tô', 'Phạt tiền từ 12.000.000 đồng đến 14.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây ô nhiễm môi trường còn bị áp dụng các biện pháp khắc phục hậu quả buộc thực hiện các biện pháp khắc phục tình trạng ô nhiễm môi trường do vi phạm hành chính gây ra', 'Trừ các hành vi vi phạm quy định tại điểm a khoản 6 Điều 20 Nghị định 168/2024/NĐ-CP', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1623),
(801, 'Điều khiển xe không chạy đúng tuyến, phạm vi, thời gian quy định', 'Người điều khiển xe vệ sinh môi trường, xe ô tô chở phế thải', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1624),
(802, 'Dừng xe, đỗ xe quay đầu xe trong phạm vi an toàn đường ngang, cầu chung', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng.', NULL, NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1625),
(803, 'Không chấp hành hiệu lệnh, chỉ dẫn của biển báo hiệu, vạch kẻ đường khi đi qua đường ngang, cầu chung', 'Người điều khiển xe ô tô, các loại xe tương tự xe ô tô', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng.', NULL, NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1626),
(804, 'Vượt rào chắn đường ngang, cầu chung khi chắn đang dịch chuyển', 'Người điều khiển xe ô tô, các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Tước quyền sử dụng Giấy phép lái xe (khi điều khiển phương tiện giao thông cơ giới đường bộ), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng.', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1627),
(805, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', '- Trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1628),
(806, 'Vượt đường ngang, cầu chung khi đèn đỏ đã bật sáng', 'Người điều khiển xe ô tô, các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng”', 'Tước quyền sử dụng Giấy phép lái xe (khi điều khiển phương tiện giao thông cơ giới đường bộ), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng.', NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1629),
(807, 'Không chấp hành hiệu lệnh, chỉ dẫn của nhân viên gác đường ngang, cầu chung khi đi qua đường ngang, cầu chung', 'Người điều khiển xe ô tô, các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Tước quyền sử dụng Giấy phép lái xe (khi điều khiển phương tiện giao thông cơ giới đường bộ), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng.', NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1630),
(808, 'Điều khiển phương tiện giao thông cơ giới đường bộ làm hỏng cần chắn, giàn chắn, các thiết bị khác tại đường ngang, cầu chung', 'Người điều khiển xe ô tô, các loại xe tương tự xe ô tô', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng.', 'Tước quyền sử dụng Giấy phép lái xe (khi điều khiển phương tiện giao thông cơ giới đường bộ), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng.', 'Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1631),
(809, 'Điều khiển xe ô tô vận chuyển hàng siêu trường, siêu trọng, quá khổ giới hạn đi qua đường ngang mà không thông báo cho tổ chức quản lý đường ngang, không thực hiện đúng các biện pháp bảo đảm an toàn', 'Người điều khiển xe ô tô vận chuyển hàng siêu trường, siêu trọng, quá khổ giới hạn đi qua đường ngang', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'Tước quyền sử dụng Giấy phép lái xe (khi điều khiển phương tiện giao thông cơ giới đường bộ), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng', 'Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1632),
(810, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 50% đến 100%', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', '- Trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1633),
(811, 'Không thắt dây đai an toàn (tại vị trí có trang bị dây đai an toàn) khi xe đang chạy.', 'Người được chở trên xe ô tô', 'Phạt tiền từ 350.000 đồng đến 400.000 đồng.', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1634),
(812, 'Khi có điều kiện mà cố ý không cứu giúp người bị tai nạn giao thông đường bộ', 'Cá nhân, tổ chức', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.000.000 đồng đến 2.000.000 đồng đối với tổ chức.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1635),
(813, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 50% đến 100%', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', '- trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1636),
(814, 'Ném gạch, đất, đá, cát hoặc vật thể khác vào người, phương tiện đang tham gia giao thông trên đường bộ', 'Cá nhân, tổ chức', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.000.000 đồng đến 2.000.000 đồng đối với tổ chức.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1637);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(815, 'Cố ý thay đổi, xóa dấu vết hiện trường vụ tai nạn giao thông', 'Cá nhân, tổ chức', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', NULL, NULL, 'Trường hợp này không áp dụng với các hành vi vi phạm quy định tại  điểm g khoản 4, khoản 8 Điều 6; điểm b khoản 5, điểm c khoản 9 Điều 7; điểm d khoản 5, điểm c khoản 8 Điều 8; điểm a khoản 4 Điều 9 Nghị định 168/2024/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1639),
(816, 'Không chấp hành yêu cầu kiểm tra, kiểm soát của người thi hành công vụ về bảo đảm trật tự, an toàn giao thông đường bộ', 'Cá nhân, tổ chức', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, NULL, '- Trường hợp người vi phạm là người điều khiển phương tiện vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.\r\n- Trường hợp này không áp dụng với các hành vi vi phạm quy định tại điểm b, điểm d khoản 11 Điều 6; điểm đ, điểm g khoản 9 Điều 7; điểm b, điểm d khoản 9 Điều 8; điểm c khoản 4 Điều 9; điểm b khoản 5 Điều 34 Nghị định 168/2024/NĐ-CP', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1640),
(817, 'Điều khiển xe không có hoặc không gắn phù hiệu theo quy định (đối với loại xe có quy định phải gắn phù hiệu) hoặc có phù hiệu nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', '- Bị thu hồi phù hiệu đã hết giá trị sử dụng hoặc phù hiệu không do cơ quan có thẩm quyền cấp\r\n- Trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1641),
(818, 'Rải vật sắc nhọn trên đường bộ', 'Cá nhân', 'Phạt tiền từ 35.000.000 đồng đến 37.000.000 đồng.', 'Nếu là người điều khiển phương tiện còn bị tước quyền sử dụng giấy phép lát xe từ 22 tháng đến 24 tháng', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1642),
(819, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 7.000.000 đồng đến 8.000.000 đồng', '- Trừ điểm giấy phép lái xe 08 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1643),
(820, 'Đặt, để chướng ngại vật, vật cản khác trái phép trên đường bộ', 'Cá nhân', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng.', 'Nếu là người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1644),
(821, 'Xâm phạm tính mạng, sức khỏe, tài sản của người bị nạn, người gây tai nạn giao thông đường bộ hoặc người giúp đỡ, cứu chữa, đưa người bị nạn đi cấp cứu', 'Cá nhân', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng.', 'Nếu là người điều khiển phương tiện bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1645),
