(828, 'Không chốt, đóng cố định cửa sau, cửa bên thùng xe khi xe đang chạy', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1653),
(829, 'Không chốt, đóng cố định cửa sau thùng xe khi xe đang chạy gây tai nạn giao thông', 'Người điều khiển máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 30.000.000 đồng đến 35.000.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1654),
(830, 'Lắp kính chắn gió, kính cửa của xe không phải là loại kính an toàn', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng đối với cá nhân, từ 600.000 đồng đến 800.000 đồng đối với tổ chức', NULL, 'Buộc thay thế thiết bị đủ tiêu chuẩn an toàn kỹ thuật theo quy định (lắp đúng loại kính an toàn);', NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1655),
(831, 'Không làm thủ tục khai báo với cơ quan đăng ký xe theo quy định trước khi cải tạo xe (đối với loại xe có quy định phải làm thủ tục khai báo)', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng đối với cá nhân, từ 600.000 đồng đến 800.000 đồng đối với tổ chức', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1657),
(832, 'Không làm thủ tục khai báo với cơ quan đăng ký xe theo quy định trước khi cải tạo xe (đối với loại xe có quy định phải làm thủ tục khai báo)', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 300.000 đồng đến 400.000 đồng đối với cá nhân, từ 600.000 đồng đến 800.000 đồng đối với tổ chức', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1658),
(833, 'Cắt, hàn, tẩy xoá, đục sửa, đóng lại trái phép số khung, số động cơ (số máy)', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng, xe mô tô, xe gắn máy và các loại xe tương tự xe ô tô, xe mô tô, xe gắn máy', 'Bị tịch thu phương tiện', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1659),
(834, 'Đưa phương tiện đã bị cắt, hàn, tẩy xoá, đục sửa, đóng lại trái phép số khung, số động cơ (số máy) tham gia giao thông', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng, xe mô tô, xe gắn máy và các loại xe tương tự xe ô tô, xe mô tô, xe gắn máy', 'Bị tịch thu phương tiện', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1660),
(835, 'Tẩy xóa, sửa chữa hoặc giả mạo hồ sơ đăng ký xe nhưng chưa đến mức truy cứu trách nhiệm hình sự', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Bị thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo; giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường; chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc không đúng với số khung, số động cơ (số máy); giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe không do cơ quan có thẩm quyền cấp.', '- Buộc khôi phục lại nhãn hiệu, màu sơn ghi trong chứng nhận đăng ký xe theo quy định', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1661),
(836, 'Không làm thủ tục thu hồi chứng nhận đăng ký xe, biển số xe theo quy định', 'Cá nhân, tổ chức là chủ xe mô tô, xe gắn máy và các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện)', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1662),
(837, 'Không làm thủ tục thu hồi biển số xe', 'Cá nhân, tổ chức là chủ xe ô tô máy kéo, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc phải làm thủ tục thu hồi biển số xe.', NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1663),
(838, 'Không làm thủ tục thu hồi chứng nhận đăng ký xe; biển số xe; giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định', 'Chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng', 'Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm.', 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện.', NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1664),
(839, 'Không làm thủ tục đổi chứng nhận đăng ký xe, biển số xe theo quy định', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện);', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1665),
(840, 'Khai báo không đúng sự thật hoặc sử dụng các giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường nhưng chưa đến mức bị truy cứu trách nhiệm hình sự', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo; giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường; chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc không đúng với số khung, số động cơ (số máy); giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe không do cơ quan có thẩm quyền cấp.', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1667),
(841, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hành lý, hàng hóa vượt quá kích thước bao ngoài của xe', 'Cá nhân, tổ chức là chủ xe xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', '4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1668),
(842, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách chở hành lý, hàng hóa vượt quá kích thước bao ngoài của xe', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1669),
(843, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hành lý, hàng hóa vượt quá trọng tải theo thiết kế của xe', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1670),
(844, 'Trực tiếp điều khiển phương tiện chở hành lý, hàng hóa vượt quá kích thước bao ngoài của xe', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1671),
(845, 'Trực tiếp điều khiển phương tiện chở hành lý, hàng hóa vượt quá trọng tải theo thiết kế của xe', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1672),
(846, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30%', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trừ xe xi téc chở chất lỏng.', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1673),
(847, 'Dừng xe, đỗ xe, quay đầu xe trong phạm vi an toàn đường ngang, cầu chung', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1674),
(848, 'Không chấp hành hiệu lệnh, chỉ dẫn của biển báo hiệu, vạch kẻ đường khi đi qua đường ngang, cầu chung', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1675),
(849, 'Vượt rào chắn đường ngang, cầu chung khi chắn đang dịch chuyển', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Tước quyền sử dụng Giấy phép lái xe (khi điều khiển phương tiện giao thông cơ giới đường bộ)\r\nTước chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng.', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1676),
(850, 'Vượt đường ngang, cầu chung khi đèn đỏ đã bật sáng', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Tước chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng.', NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1677),
(851, 'Không chấp hành hiệu lệnh, chỉ dẫn của nhân viên gác đường ngang, cầu chung khi đi qua đường ngang, cầu chung', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Tước chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng.', NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1678),
(852, 'Thuê, mượn linh kiện, phụ kiện của xe ô tô khi kiểm định', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1679),
(853, 'Đưa xe cơ giới, xe máy chuyên dùng có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường (đối với loại xe có quy định phải kiểm định) nhưng đã hết hiệu lực (hạn sử dụng) dưới 01 tháng (kể cả rơ moóc và sơ mi rơ moóc) tham gia giao thông', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1680),
(854, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt quá chiều cao xếp hàng cho phép', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1681),
(855, 'Trực tiếp điều khiển phương tiện chở hàng vượt quá chiều cao xếp hàng cho phép', 'Chủ xe máy chuyên dùng kể cả rơ moóc và sơ mi rơ moóc', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1682),
(856, 'Đưa phương tiện quá niên hạn sử dụng tham gia giao thông', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng, xe mô tô, xe gắn máy và các loại xe tương tự xe ô tô, xe mô tô, xe gắn máy', 'Tịch thu phương tiện', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm i khoản 7 Điều 26 của Nghị định 168/2024/NĐ-CP.', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1683),
(857, 'Đưa phương tiện có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe nhưng không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa tham gia giao thông', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Bị thu hồi hồ sơ đăng ký xe bị tẩy xóa, sửa chữa hoặc giả mạo; giấy tờ, tài liệu giả để được cấp lại biển số xe, chứng nhận đăng ký xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường; chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) không do cơ quan có thẩm quyền cấp hoặc không đúng với số khung, số động cơ (số máy); giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe không do cơ quan có thẩm quyền cấp\r\nBị trừ điểm giấy phép lái xe 02 điểm', 'Buộc nộp lại chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe bị tẩy xóa', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1684),
(858, 'Đưa phương tiện có chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe) nhưng không đúng với số khung, số động cơ (số máy) của xe (kể cả rơ moóc và sơ mi rơ moóc) tham gia giao thông', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Bị tịch thu phương tiện\r\nBị trừ điểm giấy phép lái xe 02 điểm', 'Buộc nộp lại chứng nhận đăng ký xe (hoặc bản sao chứng nhận đăng ký xe có chứng thực kèm theo bản gốc giấy biên nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài trong trường hợp tổ chức tín dụng, chi nhánh ngân hàng nước ngoài giữ bản gốc chứng nhận đăng ký xe), giấy chứng nhận, tem kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe bị tẩy xóa', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1685),
(859, 'Giao xe hoặc để cho người không đủ điều kiện điều khiển máy kéo, xe máy chuyên dùng tham gia giao thông', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, NULL, '- Trường hợp này bao gồm cả trường hợp người điều khiển phương tiện có Giấy phép lái xe, chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ nhưng đã hết hạn sử dụng hoặc đang trong thời gian bị tước quyền sử dụng.\r\n- Tạm giữ phương tiện tối đa đến 07 ngày.', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1688),
(860, 'Lắp đặt, sử dụng thiết bị thay đổi biển số trên xe trái quy định (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô, phương tiện giao thông thông minh', 'Phạt tiền từ 16.000.000 đồng đến 18.000.000 đồng đối với cá nhân, từ 32.000.000 đồng đến 36.000.000 đồng đối với tổ chức', 'Tịch thu biển số, thiết bị thay đổi biển số', NULL, NULL, 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1689),
(861, 'Tự ý thay đổi tổng thành khung, tổng thành máy (động cơ), hệ thống phanh, hệ thống truyền động (truyền lực), hệ thống chuyển động hoặc tự ý cải tạo kết cấu, hình dáng, kích thước của xe không đúng thiết kế của nhà sản xuất hoặc thiết kế trong hồ sơ đã nộp cho cơ quan đăng ký xe hoặc thiết kế cải tạo đã được cơ quan có thẩm quyền phê duyệt', 'Chủ xe ô tô, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)', 'Buộc khôi phục lại hình dáng, kích thước, tình trạng an toàn kỹ thuật ban đầu của xe và đăng kiểm lại trước khi đưa phương tiện ra tham gia giao thông;', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1690),
(862, 'Tự ý thay đổi tính năng sử dụng của xe hoặc tự ý lắp đặt thêm cơ cấu nâng hạ thùng xe, nâng hạ công-ten-nơ trên xe (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng\r\nBị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1691),
(863, 'Điều khiển xe không có giấy chứng nhận hoặc tem kiểm định an toàn kỹ thuật và bảo vệ môi trường (đối với loại xe có quy định phải kiểm định, trừ xe đăng ký tạm thời) hoặc có nhưng đã hết hiệu lực (hạn sử dụng) từ 01 tháng trở lên (kể cả rơ moóc và sơ mi rơ moóc)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tư xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1692),
(864, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Tổ chức, cá nhân là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1693),
(865, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%.', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, 'Bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1694),
(866, 'Trực tiếp điều khiển phương tiện chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Chủ xe máy chuyên dùng, kể cả rơ moóc và sơ mi rơ moóc', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', '- Bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n- Bị trừ điểm giấy phép lái xe 02 điểm', '- Buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông;\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1695),
(867, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1696),
(868, 'Giao hoặc để cho người làm công, người đại diện điều khiển xe bánh xích tham gia giao thông không có giấy phép lưu hành hoặc có giấy phép lưu hành nhưng không còn giá trị sử dụng theo quy định hoặc lưu thông trực tiếp trên đường mà không thực hiện biện pháp bảo vệ đường theo quy định', 'Chủ xe ô tô, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\nBị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1698),
(869, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện mà tổng trọng lượng (khối lượng toàn bộ) của xe vượt quá tải trọng cho phép của cầu, đường trên 10% đến 20%', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1700),
(870, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 20% đến 50%, trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng;', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', NULL, 'Gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trừ điểm giấy phép lái xe 02 điểm.', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1704),
(871, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe không có hoặc không gắn phù hiệu theo quy định (đối với loại xe có quy định phải gắn phù hiệu) hoặc có phù hiệu nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp;', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1705),
(872, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện không có hoặc không gắn phù hiệu theo quy định (đối với loại xe có quy định phải gắn phù hiệu) hoặc có phù hiệu nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng đối với cá nhân, từ 12.000.000 đồng đến 16.000.000 đồng đối với tổ chức', 'Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe (khi điều khiển xe cơ giới), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1706),
(873, 'Điều khiển xe chở hành khách không có hoặc không gắn phù hiệu theo quy định hoặc có nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp.', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Thu hồi phù hiệu đã hết giá trị sử dụng hoặc phù hiệu không do cơ quan có thẩm quyền cấp.', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1707),
(874, 'Điều khiển xe không có hoặc không gắn phù hiệu theo quy định (đối với loại xe có quy định phải gắn phù hiệu) hoặc có phù hiệu nhưng đã hết giá trị sử dụng hoặc sử dụng phù hiệu không do cơ quan có thẩm quyền cấp', 'Cá nhân là chủ máy kéo', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', 'thu hồi phù hiệu đã hết giá trị sử dụng hoặc phù hiệu không do cơ quan có thẩm quyền cấp.', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1708),
