(877, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 50% đến 100%', 'Người điều khiển xe máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1711),
(878, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 50% đến 100%', 'Người điều khiển xe máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1712),
(879, 'giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 30.000.000 đồng đến 40.000.000 đồng đối với cá nhân, từ 60.000.000 đồng đến 80.000.000 đồng đối với tổ chức', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1727),
(880, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%', 'Người điều khiển xe máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 7.000.000 đồng đến 8.000.000 đồng', 'Trừ điểm giấy phép lái xe 08 điểm.', NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1728),
(881, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%.', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 7.000.000 đồng đến 8.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 08 điểm', NULL, 'Bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1729),
(882, 'Trực tiếp điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%', 'người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 7.000.000 đồng đến 8.000.000 đồng', 'bị trừ điểm giấy phép lái xe 08 điểm;', NULL, 'Bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1730),
(883, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1731),
(884, 'Trực tiếp điều khiển xe chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1732);
INSERT INTO `law_violations` (`id`, `description`, `entities`, `fines`, `additional_penalties`, `remedial`, `other_penalties`, `type_id`, `topic_id`, `image`, `keyword`, `created_at`, `updated_at`, `violation_no`) VALUES
(885, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe (khi điều khiển xe cơ giới), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 03 tháng đến 05 tháng.\r\n- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và Tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có).', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc phải thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1733),
(886, 'Điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 150%', 'Người điều khiển xe máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo)', 'Phạt tiền từ 8.000.000 đồng đến 12.000.000 đồng', NULL, 'Trừ điểm giấy phép lái xe 10 điểm.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1734),
(887, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30%', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1739),
(888, 'Trực tiếp điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30%', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Trừ điểm giấy phép lái xe 02 điểm\r\n- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc phải thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông\r\n\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1740),
(889, 'Trực tiếp điều khiển xe kéo theo rơ moóc, sơ mi rơ moóc mà khối lượng toàn bộ (bao gồm khối lượng bản thân rơ moóc, sơ mi rơ moóc và khối lượng hàng chuyên chở) của rơ moóc, sơ mi rơ moóc vượt khối lượng cho phép kéo theo được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 30%', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 8.000.000 đồng đối với tổ chức', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và Tem kiểm định của phương tiện từ 01 tháng đến 03 tháng\r\n\r\n- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có).', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc phải thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông\r\n\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Trường hợp này không áp dụng đối với 20% đến 30% đối với xe xi téc chở chất lỏng.', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1741),
(890, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng trên nóc thùng xe', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1742),
(891, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt quá bề rộng thùng xe', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\n- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', '- Trường hợp phương tiện có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1743),
(892, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt phía trước, phía sau thùng xe (kể cả rơ moóc và sơ mi rơ moóc) trên 1,1 lần chiều dài toàn bộ của xe theo thiết kế được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1744),
(893, 'Trực tiếp điều khiển phương tiện chở hàng trên nóc thùng xe', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1745),
(894, 'Trực tiếp điều khiển phương tiện chở hàng vượt quá bề rộng thùng xe (kể cả bề rộng rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1746),
(895, 'Trực tiếp điều khiển phương tiện chở hàng vượt phía trước, phía sau thùng xe (kể cả rơ moóc và sơ mi rơ moóc) trên 1,1 lần chiều dài toàn bộ của xe theo thiết kế được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1747),
(896, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện mà tổng trọng lượng (khối lượng toàn bộ) của xe vượt quá tải trọng cho phép của cầu, đường trên 10% đến 20%', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Không áp dụng đối với trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1748),
(897, 'Trực tiếp điều khiển phương tiện mà tổng trọng lượng (khối lượng toàn bộ) của xe vượt quá tải trọng cho phép của cầu, đường trên 10% đến 20%', 'Chủ xe máy chuyên dùng', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', NULL, 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Không áp dụng đối với trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1749),
(898, 'Không làm thủ tục cấp chứng nhận đăng ký xe, biển số xe trong trường hợp thay đổi chủ xe theo quy định', 'Cá nhân, tổ chức chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện)', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1750),
(899, 'Tự ý thay đổi màu sơn của xe không đúng với màu sơn ghi trong Giấy đăng ký xe', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc khôi phục lại nhãn hiệu, màu sơn ghi trong chứng nhận đăng ký xe theo quy định;', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1751),
(900, 'Không thực hiện đúng quy định trong giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', 'Trường hợp này không áp dụng với các hành vi vi phạm quy định tại khoản 2; điểm b, điểm c, điểm d khoản 3 Điều 22 Nghị định 168/2024', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1753),
(901, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe vượt quá tải trọng cho phép của đường bộ trên 10% đến 20%', 'Người điều khiển xe quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1754),
(902, 'Chở hàng vượt khổ giới hạn của xe hoặc của đường bộ ghi trong giấy phép lưu hành', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1755),
(903, 'Điều khiển xe có kích thước bao ngoài vượt quá khép giới hạn của đường bộ hoặc chở hàng vượt khổ giới hạn của đường bộ', 'Người điều khiển xe quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1756),
(904, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 20% đến 50%', 'Người điều khiển xe quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1757),
(905, 'Điều khiển xe có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe nếu có) vượt quá quy định trong giấy phép lưu hành', 'Người điều khiển xe quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 03 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1759),
(906, 'Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', 'Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1760),
(907, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 50%,', 'Người điều khiển xe quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ', 'Phạt tiền từ 40.000.000 đồng đến 50.000.000 đồng', 'Từ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trường hợp này không áp dụng đối với trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1762),
(908, 'Không chấp hành việc kiểm tra tải trọng, khổ giới hạn xe khi có tín hiệu, hiệu lệnh yêu cầu kiểm tra tải trọng, khổ giới hạn xe', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 40.000.000 đồng đến 50.000.000 đồng', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Nếu gây hư hại cầu, đường, buộc phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.\r\nBị trừ điểm giấy phép lái xe 10 điểm.', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1763),
(909, 'Chuyển tải hoặc dùng các thủ đoạn khác để trốn tránh việc phát hiện xe chở quá tải, quá khổ', 'Người điều khiển xe quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ', 'Phạt tiền từ 40.000.000 đồng đến 50.000.000 đồng', 'Trừ điểm giấy phép lái xe 10 điểm.', 'Nếu gây hư hại cầu, đường, buộc phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1764),
(910, 'Cố ý thay đổi, xóa dấu vết hiện trường vụ tai nạn giao thông', 'Cá nhân, tổ chức', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 8.000.000 đồng đối với tổ chức', NULL, NULL, 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại điểm g khoản 4, khoản 8 Điều 6; điểm b khoản 5, điểm c khoản 9 Điều 7; điểm d khoản 5, điểm c khoản 8 Điều 8; điểm a khoản 4 Điều 9 của Nghị định 168/2024/NĐ-CP.', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1765),
(911, 'Cản trở hoặc không chấp hành yêu cầu kiểm tra, kiểm soát của người thi hành công vụ', 'Cá nhân, tổ chức', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng', NULL, NULL, 'trừ các hành vi vi phạm quy định tại điểm b, điểm d khoản 11 Điều 6; điểm đ, điểm g khoản 9 Điều 7; điểm b, điểm d khoản 9 Điều 8; điểm c khoản 4 Điều 9; điểm b khoản 5 Điều 34 của Nghị định 168/2024/NĐ-CP\r\nTrường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1766),
(912, 'Rải vật sắc nhọn trên đường bộ', 'Vi phạm khác về quy tắc giao thông đường bộ; sử dụng lòng đường, vỉa hè vào mục đích khác', 'Phạt tiền từ 35.000.000 đồng đến 37.000.000 đồng đối với cá nhân', 'Nếu là người điều khiển phương tiện bị tước quyền sử dụng giấy phép lái xe từ 22 tháng đến 24 tháng.', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1767),
(913, 'Đặt, để chướng ngại vật, vật cản khác trái phép trên đường bộ', 'Cá nhân', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1768),
(914, 'Xâm phạm tính mạng, sức khỏe, tài sản của người bị nạn, người gây tai nạn giao thông đường bộ', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', 'trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1769),
(915, 'Lợi dụng việc xảy ra tai nạn giao thông để hành hung, đe dọa, xúi giục, gây sức ép, làm mất trật tự, cản trở việc xử lý tai nạn giao thông', 'Người điều khiển máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng', NULL, NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1770),
(916, 'Bán biển số xe không phải là biển số do cơ quan nhà nước có thẩm quyền sản xuất hoặc không được cơ quan nhà nước có thẩm quyền cho phép.', 'Cá nhân, tổ chức', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', 'Tịch thu biển số, phương tiện sản xuất, lắp ráp trái phép', 'Buộc nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1771),
(917, 'Sản xuất biển số trái phép hoặc sản xuất, lắp ráp trái phép máy kéo, xe máy chuyên dùng', 'Cá nhân, tổ chức', 'Phạt tiền từ 40.000.000 đồng đến 50.000.000 đồng đối với cá nhân, từ 80.000.000 đồng đến 100.000.000 đồng đối với tổ chức', 'tịch thu biển số, phương tiện sản xuất, lắp ráp trái phép.', 'buộc nộp lại số lợi bất hợp pháp có được do thực hiện vi phạm hành chính.', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1772),
(918, 'Nhận, trả hàng trên đường cao tốc', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm\r\n- Trong trường hợp cá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1773),
(919, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 30% đến 50%', 'Người điều khiển xe ô tô tải (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1774),
(920, 'Điều khiển xe có các bộ phận chuyên dùng lắp đặt không đúng vị trí', 'Người điều khiển máy kéo (kể cả rơ moóc được kéo theo), xe máy chuyên dùng.', 'Phạt tiền từ 800.000 đồng đến 1.000.000 đồng', NULL, 'buộc lắp đầy đủ thiết bị hoặc thay thế thiết bị đủ tiêu chuẩn, quy chuẩn an toàn kỹ thuật hoặc khôi phục lại tính năng kỹ thuật của thiết bị theo quy định', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1775),
(921, 'Chở hàng hoặc chất thải để nước chảy xuống mặt đường gây mất an toàn giao thông', 'Người điều khiển máy kéo', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1776),
(922, 'Không xuất trình chứng minh nhân dân (hoặc giấy tờ tương đương như: căn cước công dân, hộ chiếu) khi có yêu cầu kiểm tra của người có thẩm quyền.', 'Người tham gia giao thông', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 1, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1777),
(923, 'Không xuất trình chứng minh nhân dân (hoặc giấy tờ tương đương như: căn cước công dân, hộ chiếu) khi có yêu cầu kiểm tra của người có thẩm quyền.', 'Người tham gia giao thông', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1778),
(924, 'Cố ý can thiệp làm sai lệch chỉ số trên đồng hồ báo quãng đường đã chạy của xe ô tô', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng', NULL, 'Buộc điều chỉnh lại chỉ số trên đồng hồ báo quãng đường của xe ô tô bị làm sai lệch', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1779),
(925, 'Điều khiển xe rẽ trái tại nơi có biển báo hiệu có nội dung cấm rẽ trái đối với loại phương tiện đang điều khiển', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1781),
(926, 'Điều khiển xe rẽ phải tại nơi có biển báo hiệu có nội dung cấm rẽ phải đối với loại phương tiện đang điều khiển', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 3, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1782),
(927, 'Điều khiển xe rẽ trái tại nơi có biển báo hiệu có nội dung cấm rẽ trái đối với loại phương tiện đang điều khiển', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1783),
(928, 'Điều khiển xe rẽ phải tại nơi có biển báo hiệu có nội dung cấm rẽ phải đối với loại phương tiện đang điều khiển', 'Điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng.', NULL, NULL, NULL, 1, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1784),
(929, 'Có giấy phép lái xe nhưng không phù hợp với loại xe đang điều khiển hoặc có giấy phép lái xe nhưng đã hết hạn sử dụng từ 01 năm trở lên', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ', 'Phạt tiền từ 18.000.000 đồng đến 20.000.000 đồng', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1785),
(930, 'Nhận, trả hàng trên đường cao tốc', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 06 điểm.', NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1786),
(931, 'Lưu hành phương tiện trên lãnh thổ Việt Nam quá thời hạn quy định', 'Người điều khiển phương tiện giao thông cơ giới đường bộ gắn biển số nước ngoài', 'Phạt tiền từ 30.000.000 đồng đến 35.000.000 đồng', NULL, 'Buộc tái xuất phương tiện khỏi Việt Nam', NULL, 1, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1787),
(932, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng trên nóc thùng xe', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1788),
(933, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt quá bề rộng thùng xe (kể cả bề rộng rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1789),
(934, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt phía trước, phía sau thùng xe (kể cả rơ moóc và sơ mi rơ moóc) trên 1,1 lần chiều dài toàn bộ của xe theo thiết kế được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Cá nhân, tổ chức là chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1790),
(935, 'Trực tiếp điều khiển phương tiện chở hàng trên nóc thùng xe', 'Chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).\r\n- Bị trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1791),
(936, 'Trực tiếp điều khiển phương tiện chở hàng vượt quá bề rộng thùng xe', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 8.000.000 đồng đối với tổ chức', '- Trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe (khi điều khiển xe cơ giới), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng\r\n\r\n- Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1792),
(937, 'Trực tiếp điều khiển phương tiện chở hàng vượt phía trước, phía sau thùng xe (kể cả rơ moóc và sơ mi rơ moóc) trên 1,1 lần chiều dài toàn bộ của xe theo thiết kế được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe', 'Chủ xe ô tô (kể cả rơ moóc và sơ mi rơ moóc), xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).\r\n- Bị trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1793),
(938, 'Không thực hiện đúng quy định về biển số, quy định về kẻ hoặc dán chữ, số biển số, thông tin trên thành xe, cửa xe (kể cả rơ moóc và sơ mi rơ moóc)', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 8.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc thực hiện đúng quy định về biển số xe, quy định về kẻ hoặc dán chữ, số biển số, thông tin trên thành xe, cửa xe.', 'Trường hợp này không áp dụng đối với các hành vi vi phạm quy định tại: điểm b, điểm c khoản 12; điểm d khoản 13 Điều 32 và các hành vi vi phạm quy định tại điểm b khoản 3 Điều 39 Nghị định 168/2024/NĐ-CP.', 3, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1794),
(939, 'Đưa phương tiện không gắn biển số (đối với loại xe có quy định phải gắn biển số) tham gia giao thông', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô, phương tiện giao thông thông minh', 'Phạt tiền từ 16.000.000 đồng đến 18.000.000 đồng đối với cá nhân, từ 32.000.000 đồng đến 36.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1795),
(940, 'Đưa phương tiện gắn biển số không đúng với chứng nhận đăng ký xe hoặc gắn biển số không do cơ quan có thẩm quyền cấp (kể cả rơ moóc và sơ mi rơ moóc) tham gia giao thông', 'Chủ xe ô tô, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng đối với tổ chức', 'Bị trừ điểm giấy phép lái xe 10 điểm', 'Tịch thu biển số, thiết bị thay đổi biển số', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1796),
(941, 'Đưa phương tiện không có Giấy đăng ký xe tham gia giao thông hoặc có nhưng đã hết hạn sử dụng', 'Cá nhân, tổ chức là chủ xe ô tô, máy kéo, xe máy chuyên dùng và các loại xe tương tự xe ô tô.', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng đối với cá nhân, từ 28.000.000 đồng đến 32.000.000 đồng đối với tổ chức', '- Thực hiện hành vi trong trường hợp không có Giấy đăng ký xe hoặc có Giấy đăng ký xe nhưng không do cơ quan có thẩm quyền cấp, không đúng số khung, số máy của xe hoặc bị tẩy xóa (kể cả rơ moóc và sơ mi rơ moóc) mà không chứng minh được nguồn gốc xuất xứ của phương tiện (không có giấy tờ, chứng từ chuyển quyền sở hữu xe hoặc giấy tờ, chứng từ nguồn gốc xe hợp pháp) thì bị tịch thu phương tiện;\r\n\r\n- Thực hiện hành vi trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị tước quyền sử dụng Giấy phép lái xe (khi điều khiển xe cơ giới), chứng chỉ bồi dưỡng kiến thức pháp luật về giao thông đường bộ (khi điều khiển xe máy chuyên dùng) từ 01 tháng đến 03 tháng;\r\n\r\n- Tạm giữ phương tiên không quá 7 ngày làm việc, trường hợp chuyển đến người có thẩm quyền không quá 10 ngày làm việc', 'Buộc phải làm thủ tục đăng ký xe, đăng ký sang tên, đổi lại, thu hồi Giấy đăng ký xe, biển số xe, Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện)', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1797),
(942, 'Đưa phương tiện có chứng nhận đăng ký xe tạm thời, phương tiện có phạm vi hoạt động hạn chế tham gia giao thông quá thời hạn, tuyến đường, phạm vi cho phép', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô, phương tiện giao thông thông minh', 'Phạt tiền từ 16.000.000 đồng đến 18.000.000 đồng đối với cá nhân, từ 32.000.000 đồng đến 36.000.000 đồng đối với tổ chức', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Buộc làm thủ tục đổi, thu hồi, cấp mới, cấp chứng nhận đăng ký xe, biển số xe, giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định', 'Trừ trường hợp bị tịch thu phương tiện\r\nTrường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1798),
(943, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng kích thước bao ngoài của xe (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1799),
(944, 'Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng kích thước bao ngoài của xe (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành.', 'Người điều khiển xe ô tô thực hiện hành vi vi phạm quy định về vận chuyển hàng siêu trường, siêu trọng', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1800),
(945, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng vượt khổ giới hạn của xe hoặc của đường bộ ghi trong giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe máy chuyên dùng', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1801),
(946, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe có kích thước bao ngoài vượt quá khổ giới hạn của đường bộ hoặc chở hàng vượt khổ giới hạn của đường bộ hoặc chở hàng vượt quá kích thước giới hạn xếp hàng hóa của xe tham gia giao thông, trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng hoặc trực tiếp điều khiển phương tiện thực hiện hành vi vi phạm', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).\r\nNếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.\r\nChủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1802),
(947, 'Chở hàng vượt khổ giới hạn của xe hoặc của đường bộ ghi trong giấy phép lưu hành', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1803),
(948, 'Điều khiển xe bánh xích tham gia giao thông không có giấy phép lưu hành hoặc có giấy phép lưu hành nhưng không còn giá trị sử dụng theo quy định hoặc lưu thông trực tiếp trên đường mà không thực hiện biện pháp bảo vệ đường theo quy định', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ  8.000.000 đồng đến 10.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1804),
(949, 'Trực tiếp điều khiển xe vượt trọng tải giới hạn của cầu, đường hoặc chở hàng vượt trọng tải giới hạn của cầu, đường tham gia giao thông, trừ trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 'Cá nhân, tổ chức là chủ xe ô tô, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng;\r\n-  Tịch thu phương tiện đối với chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng, xe mô tô, xe gắn máy và các loại xe tương tự xe ô tô, xe mô tô, xe gắn máy nếu tái phạm. \r\n- Trừ điểm giấy phép lái xe 10 điểm;', '- Phương tiện đó có thùng xe, khối lượng hàng hóa cho phép chuyên chở không đúng theo quy định hiện hành thì còn bị buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông;\r\n- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra;', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1805),
(950, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng siêu trường, siêu trọng không có Giấy phép lưu hành hoặc có Giấy phép lưu hành nhưng đã hết giá trị sử dụng hoặc sử dụng Giấy phép lưu hành không do cơ quan có thẩm quyền cấp;', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', '- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\n- Bị trừ điểm giấy phép lái xe 04 điểm;', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1806),
(951, 'Chở hàng siêu trường, siêu trọng không có giấy phép lưu hành hoặc có giấy phép lưu hành nhưng đã hết giá trị sử dụng hoặc sử dụng giấy phép lưu hành không do cơ quan có thẩm quyền cấp', 'Người điều khiển xe ô tô thực hiện hành vi vi phạm quy định về vận chuyển hàng siêu trường, siêu trọng', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1807),
(952, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1808),
(953, 'Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 28.000.000 đồng đến 32.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 64.000.000 đồng đối với tổ chức', '- Trừ điểm giấy phép lái xe 04 điểm.\r\n- Thu hồi giấy phép lưu hành hết giá trị sử dụng hoặc giấy phép lưu hành không do cơ quan có thẩm quyền cấp.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1809),
(954, 'Không gắn biển báo hiệu ở phía trước xe kéo, phía sau xe được kéo', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1810),
(955, 'Điều khiển xe có giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong giấy phép lưu hành', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 03 điểm', 'Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1811),
(956, 'Trực tiếp điều khiển phương tiện chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong Giấy phép lưu hành', 'Chủ phương tiện, người điều khiển phương tiện', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\nBị trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1812),
(957, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng chở không đúng loại hàng quy định trong Giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1813),
(958, 'Trực tiếp điều khiển phương tiện chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng chở không đúng loại hàng quy định trong Giấy phép lưu hành', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 04 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1814),
(959, 'Dùng tay cầm và sử dụng điện thoại hoặc các thiết bị điện tử khác khi điều khiển phương tiện tham gia giao thông đang di chuyển trên đường bộ', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 04 điểm', NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1815);
