(960, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 20% đến 50%', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 40.000.000 đồng đến 50.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng', 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1816),
(961, 'Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 20% đến 50%', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1817),
(962, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe nếu có) vượt quá quy định trong giấy phép lưu hành', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\nBị trừ điểm giấy phép lái xe 03 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1818),
(963, 'Không thực hiện biện pháp bảo đảm an toàn theo quy định khi xe ô tô bị hư hỏng ngay tại nơi đường bộ giao nhau cùng mức với đường sắt', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', 'Người điều khiển xe bị trừ điểm giấy phép lái xe 02 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1819),
(964, 'Trực tiếp điều khiển xe có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe nếu có) vượt quá quy định trong giấy phép lưu hành', 'Chủ xe máy chuyên dùng', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\nBị trừ điểm giấy phép lái xe 03 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1820),
(965, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe có Giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong Giấy phép lưu hành', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', '- Thực hiện hành vi quy định trong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 03 điểm.', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1821),
(966, 'Điều khiển xe ô tô, điều khiển xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô.', 'Người điều khiển xe cơ giới từ đủ 14 tuổi đến dưới 16 tuổi', 'Phạt cảnh cáo', NULL, NULL, 'Trường hợp vi phạm có thể bị tạm giữ phương tiện không quá 7 ngày làm việc kể từ ngày tạm giữ, trường hợp vụ việc phải chuyển hồ sơ đến người có thẩm quyền xử phạt thì thời hạn tạm giữ không quá 10 ngày làm việc.', 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1822),
(967, 'Trực tiếp điều khiển xe có giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong giấy phép lưu hành', 'Chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\nBị trừ điểm giấy phép lái xe 03 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1823),
(968, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của đường bộ trên 50%, trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng', 'Chủ xe ô tô, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 65.000.000 đồng đến 75.000.000 đồng đối với cá nhân, từ 130.000.000 đồng đến 150.000.000 đồng đối với tổ chức', '- Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có),', '- Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra;', NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1824),
(969, 'Điều khiển xe kinh doanh vận tải hành khách không lắp thiết bị giám sát hành trình của xe theo quy định hoặc có lắp thiết bị giám sát hành trình của xe nhưng thiết bị không hoạt động theo quy định hoặc làm sai lệch dữ liệu của thiết bị giám sát hành trình của xe ô tô', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1825),
