(971, 'Điều khiển xe kinh doanh vận tải hành khách không lắp thiết bị giám sát hành trình của xe theo quy định hoặc có lắp thiết bị giám sát hành trình của xe nhưng thiết bị không hoạt động theo quy định hoặc làm sai lệch dữ liệu của thiết bị giám sát hành trình của xe ô tô', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'Trừ điểm giấy phép lái xe 02 điểm.', NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1827),
(972, 'Điều khiển xe ô tô tham gia kinh doanh vận tải hàng hóa không lắp thiết bị giám sát hành trình hoặc có lắp thiết bị giám sát hành trình nhưng không có tác dụng trong quá trình xe tham gia giao thông theo quy định hoặc làm sai lệch dữ liệu của thiết bị giám sát hành trình lắp trên xe ô tô', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng', 'bị trừ điểm giấy phép lái xe (khi điều khiển xe ô tô) 02 điểm', NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1828),
(973, 'Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành', 'Người điều khiển xe ô tô', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Bị tước quyền sử dụng Giấy phép lái xe từ 02 tháng đến 04 tháng', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do hành vi vi phạm hành chính gây ra', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1829),
(974, 'Không thanh toán tiền vé cho hành khách theo quy định đối với tuyến cố định có cự ly từ 300 km trở xuống', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng đối với cá nhân, từ 2.000.000 đồng đến 4.000.000 đồng đối với tổ chức.', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1830),
(975, 'Đưa phương tiện không gắn biển số (đối với loại xe có quy định phải gắn biển số) tham gia giao thông', 'Chủ phương tiện', 'Phạt tiền từ 16.000.000 đồng đến 18.000.000 đồng đối với cá nhân, từ 32.000.000 đồng đến 36.000.000 đồng đối với tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô, phương tiện giao thông thông minh', 'Bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1831),
(976, 'Không thanh toán tiền vé cho hành khách theo quy định đối với tuyến cố định có cự ly trên 300 km', 'Cá nhân, tổ chức', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 6.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1832),
(977, 'Không nộp lại phù hiệu về Sở Giao thông vận tải theo quy định', 'Cá nhân, tổ chức', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 6.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1833),
(978, 'Đưa phương tiện gắn biển số không đúng với chứng nhận đăng ký xe hoặc gắn biển số không do cơ quan có thẩm quyền cấp (kể cả rơ moóc và sơ mi rơ moóc) tham gia giao thông', 'Chủ phương tiện', 'Phạt tiền từ 20.000.000 đồng đến 26.000.000 đồng đối với cá nhân, từ 40.000.000 đồng đến 52.000.000 đồng', '- Tịch thu biển số\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 10 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1834),
(979, 'Không niêm yết hành trình chạy xe hoặc niêm yết hành trình chạy xe không đúng với hành trình đà được cơ quan có thẩm quyền cấp phép', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1835),
(980, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hành vi vi phạm quy định tại điểm a, điểm b khoản 8 Điều 21 của Nghị định này hoặc trực tiếp điều khiển phương tiện thực hiện hành vi vi phạm quy định tại điểm a, điểm b khoản 8 Điều 21 của Nghị định này', 'Chủ phương tiện', 'Phạt tiền từ  18.000.000 đồng đến 20.000.000 đồng đối với chủ xe là cá nhân. Phạt tiền từ 36.000.000 đồng đến 40.000.000 đồng đối với chủ xe là tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 10 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1836),
(981, 'Không cung cấp cho cơ quan quản lý danh sách các đơn vị kinh doanh vận tải, xe ô tô và lái xe của các đơn vị vận tải hợp tác với đơn vị cung cấp phần mềm ứng dụng hỗ trợ kết nối vận tải hoặc không cung cấp tài khoản truy cập vào phần mềm ứng dụng hỗ trợ kết nối vận tải cho cơ quan quản lý khi có yêu cầu hoặc không thực hiện lưu trữ theo quy định', 'Đơn vị cung cấp phần mềm ứng dụng hỗ trợ kết nối vận tải', 'Phạt tiền từ 20.000.000 đồng đến 40.000.000 đồng', NULL, NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1837),
(982, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hành vi Chở hàng siêu trường, siêu trọng không có giấy phép lưu hành hoặc có giấy phép lưu hành nhưng đã hết giá trị sử dụng hoặc sử dụng giấy phép lưu hành không do cơ quan có thẩm quyền cấp; Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (sau khi đã xếp hàng lên xe) vượt quá quy định trong giấy phép lưu hành; Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong giấy phép lưu hành; Chở hàng siêu trường, siêu trọng có giấy phép lưu hành còn giá trị sử dụng nhưng chở không đúng loại hàng quy định trong giấy phép lưu hành.', 'Chủ phương tiện', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1838),
(983, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hành vi vi phạm chở hàng siêu trường, siêu trọng không có Giấy phép lưu hành hoặc có Giấy phép lưu hành nhưng đã hết giá trị sử dụng hoặc sử dụng Giấy phép lưu hành không do cơ quan có thẩm quyền cấp;', 'Chủ phương tiện', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1839),
(984, 'Lưu hành phương tiện trên lãnh thổ Việt Nam quá thời hạn quy định', 'Người điều khiển phương tiện giao thông cơ giới đường bộ gắn biển số nước ngoài', 'Phạt tiền từ 30.000.000 đồng đến 35.000.000 đồng', NULL, 'Buộc tái xuất phương tiện khỏi Việt Nam.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1840),
(985, 'Điều khiển xe có giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe nếu có) vượt quá quy định trong giấy phép lưu hành', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô', 'Phạt tiền từ 13.000.000 đồng đến 15.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 03 điểm', 'Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1841),
(986, 'Chở hàng vượt khổ giới hạn của đường bộ hoặc chở hàng vượt quá kích thước giới hạn xếp hàng hóa của xe tham gia giao thông', 'Người điều khiển quá khổ giới hạn', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', 'Trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1842),
(987, 'Chở hàng vượt khổ giới hạn của đường bộ', 'Người điều khiển xe ô tô quá khổ giới hạn', 'Phạt tiền từ 8.000.000 đồng đến 10.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 02 điểm', 'Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trừ trường hợp có giấy phép lưu hành còn giá trị sử dụng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1843),
(988, 'Tổng trọng lượng (khối lượng toàn bộ) của xe vượt quá tải trọng cho phép của đường bộ trên 10% đến 20%', 'Người điều khiển quá khổ giới hạn, xe quá tải trọng, xe bánh xích lưu hành đường bộ (kể cả xe ô tô chở hành khách)', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, '- Nếu gây hư hại cầu, đường còn bị áp dụng biện pháp khắc phục hậu quả buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', 'Trừ trường hợp có Giấy phép lưu hành còn giá trị sử dụng', 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1844),
(989, 'Giấy tờ của phương tiện không có bản dịch sang tiếng Anh hoặc tiếng Việt theo quy định', 'Người điều khiển xe ô tô và các loại xe tương tự xe ô tô gắn biển số nước ngoài', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', NULL, NULL, NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1845),
