(992, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện hoặc trực tiếp điều khiển phương tiện thực hiện hành vi chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong Giấy phép lưu hành', 'Chủ phương tiện', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 04 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1848),
(993, 'Không chấp hành việc thu hồi Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường phương tiện giao thông cơ giới đường bộ theo quy định', 'Cá nhân, tổ chức là chủ máy kéo, xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 4.000.000 đồng đến 8.000.000 đồng đối với tổ chức', 'Buộc phải làm thủ tục đăng ký xe, đăng ký sang tên, đổi lại, thu hồi Giấy đăng ký xe, biển số xe, Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định (trừ trường hợp bị tịch thu phương tiện).', NULL, NULL, 3, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1849),
(994, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hành vi vi phạm Chở hàng siêu trường, siêu trọng có Giấy phép lưu hành còn giá trị sử dụng nhưng chở không đúng loại hàng quy định trong Giấy phép lưu hành hoặc trực tiếp điều khiển phương tiện thực hiện hành vi vi phạm trên.', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức', 'Bị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\nTrong trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 04 điểm;', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra;', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1850),
(995, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển xe chở hàng vượt trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 100% đến 150%', 'Người điều khiển xe ô tô tải, máy kéo (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 30.000.000 đồng đến 40.000.000 đồng đối với cá nhân, từ 60.000.000 đồng đến 80.000.000 đồng đối với tổ chức.', 'Bị tước quyền sử dụng giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường và tem kiểm định của phương tiện từ 01 tháng đến 03 tháng.\r\nBị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có).', 'Buộc thực hiện điều chỉnh thùng xe theo đúng quy định hiện hành, đăng kiểm lại và điều chỉnh lại khối lượng hàng hóa cho phép chuyên chở ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường theo quy định hiện hành trước khi đưa phương tiện ra tham gia giao thông.\r\nNếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1851),
(996, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hành vi vi phạm Điều khiển xe mà tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe, người được chở trên xe) vượt quá tải trọng cho phép của cầu, đường trên 20% đến 50%, trừ trường hợp có Giấy phép lưu hành còn giá trị sử dụng; hoặc trực tiếp điều khiển phương tiện thực hiện hành vi vi phạm trên.', 'Cá nhân, tổ chức là chủ xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng đối với tổ chức là chủ xe ô tô, máy kéo, xe máy chuyên dùng và các loại xe tương tự xe ô tô', 'bị trừ điểm giấy phép lái xe 02 điểm', 'nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1852),
(997, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện hoặc trực tiếp điều khiển phương tiện thực hiện hành vi vi phạm trên điều khiển xe có Giấy phép lưu hành còn giá trị sử dụng nhưng tổng trọng lượng (khối lượng toàn bộ) của xe hoặc tải trọng trục xe (bao gồm cả hàng hóa xếp trên xe nếu có) vượt quá quy định trong Giấy phép lưu hành', 'Chủ phương tiện', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng', '- Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)\r\n- Trường hợp chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 03 điểm', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1853),
(998, 'Xếp hàng hóa lên mỗi xe ô tô (kể cả rơ moóc và sơ mi rơ moóc) vượt quá trọng tải (khối lượng hàng chuyên chở) cho phép tham gia giao thông được ghi trong giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường của xe trên 10% đến 50%, trên 20% đến 50% đối với xe xi téc chở chất lỏng', 'Cá nhân, tổ chức xếp hàng hóa lên mỗi xe ô tô', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.000.000 đồng đến 2.000.000 đồng đối với tổ chức', NULL, NULL, 'Trừ xe xi téc chở chất lỏng', 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1854),
(999, 'Giao phương tiện hoặc để cho người làm công, người đại diện điều khiển phương tiện thực hiện hành vi vi phạm Điều khiển xe có Giấy phép lưu hành còn giá trị sử dụng nhưng đi không đúng tuyến đường quy định trong Giấy phép lưu hành. hoặc trực tiếp điều khiển phương tiện thực hiện hành vi vi phạm trên.', 'Cá nhân, tổ chức là chủ xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe máy chuyên dùng', 'Phạt tiền từ 28.000.000 đồng đến 30.000.000 đồng đối với cá nhân, từ 56.000.000 đồng đến 60.000.000 đồng', 'Chủ phương tiện là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 03 điểm.\r\nBị tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có)', 'Nếu gây hư hại cầu, đường phải khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra.', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1855),
(1000, 'Xếp hàng hóa lên xe ô tô mà không ký xác nhận việc xếp hàng hóa vào giấy vận tải theo quy định', 'Cá nhân, tổ chức xếp hàng hóa lên xe ô tô', 'Phạt tiền từ 500.000 đồng đến 1.000.000 đồng đối với cá nhân, từ 1.000.000 đồng đến 2.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1856),
(1001, 'Sử dụng loại xe ô tô chở người có thiết kế từ 09 chỗ (kể cả người lái) trở lên làm xe taxi chở hành khách', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1857),
(1002, 'Sử dụng xe taxi chở hành khách không có hoặc có số điện thoại giao dịch ghi trên xe không đúng với đăng ký của doanh nghiệp (hợp tác xã)', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 3.000.000 đồng đến 4.000.000 đồng đối với cá nhân, từ 6.000.000 đồng đến 8.000.000 đồng đối với tổ chức.', 'Tước quyền sử dụng phù hiệu (biển hiệu) từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.', 'Buộc phải gắn hộp đèn với chữ “TAXI” hoặc buộc phải niêm yết cụm từ “XE TAXI”, “XE HỢP ĐỒNG”, “XE DU LỊCH” theo đúng quy định.', NULL, 2, 7, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1858),
(1003, 'Không thực hiện việc truyền, lưu trữ thông tin, dữ liệu từ thiết bị giám sát hành trình theo quy địnhh', 'Cá nhân, tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Phạt tiền từ 5.000.000 đồng đến 6.000.000 đồng đối với cá nhân, từ 10.000.000 đồng đến 12.000.000 đồng đối với tổ chức', NULL, 'Buộc truyền dẫn, lưu trữ thông tin, dữ liệu thu thập từ thiết bị giám sát hành trình, thiết bị ghi nhận hình ảnh người lái xe lắp trên xe ô tô theo quy định', NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1859),
(1004, 'Sử dụng xe ô tô kinh doanh vận tải để đón, trả khách; nhận, trả hàng trên đường cao tốc', 'Tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải\r\nCá nhân kinh doanh vận tải', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng đối với cá nhân, từ 20.000.000 đồng đến 24.000.000 đồng đối với tổ chức kinh doanh vận tải, dịch vụ hỗ trợ vận tải', 'Tước quyền sử dụng phù hiệu từ 01 tháng đến 03 tháng (nếu có hoặc đã được cấp) đối với xe vi phạm.\r\nCá nhân kinh doanh vận tải là người trực tiếp điều khiển phương tiện còn bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1860),
(1005, 'Nhận, trả hàng trên đường cao tốc', 'Người điều khiển xe ô tô tải và các loại xe tương tự xe ô tô vận chuyển hàng hóa', 'Phạt tiền từ 10.000.000 đồng đến 12.000.0000 đồng', 'Bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 11, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1861),
(1006, 'Không công bố quy trình giải quyết khiếu nại của khách hàng, không có hệ thống lưu trữ các khiếu nại của khách hàng theo quy định', 'Đơn vị cung cấp phần mềm ứng dụng hỗ trợ kết nối vận tải', 'Phạt tiền từ 20.000.000 đồng đến 40.000.000 đồng', NULL, NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1862),
(1007, 'Đón, trả hành khách trên đường cao tốc', 'Người điều khiển xe ô tô chở hành khách, ô tô chở người và các loại xe tương tự xe ô tô chở hành khách', 'Phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1863),
(1008, 'Điều khiển xe (kể cả rơ moóc và sơ mi rơ moóc) không gắn biển số (đối với loại xe có quy định phải gắn biển số)', 'Người điều khiển xe ô tô (bao gồm cả rơ moóc hoặc sơ mi rơ moóc được kéo theo) và các loại xe tương tự xe ô tô', 'Phạt tiền từ 10.000.000 đồng đến 12.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1864),
(1009, 'Dừng xe, đỗ xe trên đường cao tốc không đúng nơi quy định', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền 12.000.000 đồng đến 14.000.000 đồng', 'bị trừ điểm giấy phép lái xe 06 điểm', NULL, NULL, 2, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1865),
(1010, 'Người điều khiển xe đạp máy không đội “mũ bảo hiểm cho người đi mô tô, xe máy” hoặc đội “mũ bảo hiểm cho người đi mô tô, xe máy” không cài quai đúng quy cách khi tham gia giao thông trên đường bộ', 'Người điều khiển xe đạp máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1866),
(1011, 'Chở người ngôi trên xe đạp máy không đội “mũ bảo hiểm cho người đi mô tô, xe máy” hoặc đội “mũ bảo hiểm cho người đi mô tô, xe máy” không cài quai đúng quy cách, trừ trường hợp chở người bệnh đi cấp cứu, trẻ em dưới 06 tuổi, áp giải người có hành vi vi phạm pháp luật.', 'Người điều khiển xe đạp máy', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1867),
(1012, 'Không đội “mũ bảo hiểm cho người đi mô tô, xe máy” hoặc đội “mũ bảo hiểm cho người đi mô tô, xe máy” không cài quai đúng quy cách khi tham gia giao thông trên đường bộ.', 'Người được chở trên xe mô tô, xe gắn máy (kể cả xe máy điện), các loại xe tương tự xe mô tô, các loại xe tương tự xe gắn máy, xe đạp máy (kể cả xe đạp điện)', 'Phạt tiền từ 400.000 đồng đến 600.000 đồng', NULL, NULL, NULL, 3, 6, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1869),
(1013, 'Trốn tránh, không trả tiền dịch vụ sử dụng đường bộ khi phương tiện tham gia giao thông qua các trạm thu phí.', 'Người điều khiển phương tiện, chủ phương tiện', 'Phạt tiền từ 4.000.000 đồng đến 6.000.000 đồng', NULL, NULL, NULL, 3, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1870),
(1014, 'Điều khiển xe rẽ trái tại nơi có biển báo hiệu có nội dung cấm rẽ trái đối với loại phương tiện đang điều khiển; điều khiển xe rẽ phải tại nơi có biển báo hiệu có nội dung cấm rẽ phải đối với loại phương tiện đang điều khiển', 'Người điều khiển xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, NULL, 2, 2, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1871),
(1015, 'Có giấy phép lái xe nhưng không phù hợp với loại xe đang điều khiển', 'Người điều khiển xe mô tô hai bánh có dung tích xi-lanh trên 125 cm3 trở lên hoặc có công suất động cơ điện trên 11 kW, xe mô tô ba bánh', 'Phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng', NULL, NULL, NULL, 3, 10, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1872),
(1016, 'Không chấp hành hiệu lệnh của đèn tín hiệu giao thông mà gây ra tai nạn giao thông', 'Người điều khiển xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy', 'Phạt tiền từ 10.000.000 đồng đến 14.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 10 điểm.', NULL, NULL, 1, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1873),
(1017, 'Không chấp hành hiệu lệnh của đèn tín hiệu giao thông mà gây ra tai nạn giao thông', 'Người điều khiển xe ô tô, xe ô tô, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ và các loại xe tương tự xe ô tô', 'Phạt tiền từ 20.000.000 đồng đến 22.000.000 đồng', 'Bị trừ điểm giấy phép lái xe 10 điểm.', NULL, NULL, 2, 1, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1874),
(1018, 'Đi ngược chiều của đường một chiều, đi ngược chiều trên đường có biển “Cấm đi ngược chiều” gây tai nạn giao thông', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng', NULL, NULL, 'Trường hợp này không áp dụng đối với hành vi quy định tại điểm b khoản 8, điểm đ khoản 9 Điều 8 Nghị định 168/2024/NĐ-CP', 3, 8, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1875),
(1019, 'Dừng xe, đỗ xe trong hầm đường bộ không đúng nơi quy định', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 2.000.000 đồng đến 3.000.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1876),
(1020, 'Để xe ở lòng đường, vỉa hè trái phép', 'người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1877),
(1021, 'Dừng xe, đỗ xe trên phần đường xe chạy ở đoạn đường ngoài đô thị nơi có lề đường', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ khác', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1878),
(1022, 'Dừng xe, đỗ xe trên phần đường xe chạy ở đoạn đường ngoài đô thị nơi có lề đường rộng', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 600.000 đồng đến 800.000 đồng', NULL, NULL, 'Trừ hành vi vi phạm quy định tại điểm b khoản 6 Điều 8 Nghị định 16/2024/NĐ-CP', 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1879),
(1023, 'Không tuân thủ các quy định về dừng xe, đỗ xe tại nơi đường bộ giao nhau cùng mức với đường sắt', 'Người điều khiển xe đạp, xe đạp máy, người điều khiển xe thô sơ', 'Phạt tiền từ 100.000 đồng đến 200.000 đồng', NULL, NULL, NULL, 3, 3, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1880),
(1024, 'Điều khiển xe chạy quá tốc độ quy định gây tai nạn giao thông', 'Người điều khiển xe máy chuyên dùng', 'Phạt tiền từ 14.000.000 đồng đến 16.000.000 đồng', NULL, NULL, NULL, 3, 5, NULL, NULL, '2025-05-10 18:40:04', '2025-05-10 18:40:04', 1881);
