(237, '108', '[Tai nạn] Trời mưa, đường trơn trượt xe tải khi vào cua không làm chủ tốc độ đã đâm vào xe ben đi ngược chiều', 'video', 'https://cdn.dtlx.app/simulation/videos/108.mp4', 'https://cdn.dtlx.app/simulation/images/108.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '31.1', '22.995', '25.241'),
(238, '109', '[Tai nạn] Xe 16 chỗ từ đường nhánh, khuất tầm nhìn rẽ vào đường chính không giảm tốc độ, bị xe sơ mi rơ moóc đâm vào (tại Ngã 3 Nà Phặc - Bắc Kạn)', 'video', 'https://cdn.dtlx.app/simulation/videos/109.mp4', 'https://cdn.dtlx.app/simulation/images/109.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '25.2', '12.362', '15.490'),
(239, '110', '[Tai nạn] Xe container bất ngờ tông vào hàng loạt phương tiện đang dừng đèn đỏ tại quốc lộ 1, đoạn nút giao Mỹ Phước - Tân Vạn, Bình Dương', 'video', 'https://cdn.dtlx.app/simulation/videos/110.mp4', 'https://cdn.dtlx.app/simulation/images/110.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '23.6', '12.205', '15.249'),
(240, '111', '[Tai nạn] Xe khách lấn làn vượt xe tải chỗ đường cong, đâm vào xe khách đi ngược chiều Tai nạn tại km 1791+ 400 trên đường Hồ Chi Minh, đoạn qua thôn 7, xã Hoà Phú, TP.Buôn Ma Thuật(nhất Lik)', 'video', 'https://cdn.dtlx.app/simulation/videos/111.mp4', 'https://cdn.dtlx.app/simulation/images/111.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '19.1', '11.565', '14.685'),
(241, '112', '[Tai nạn] Xe khách 16 chỗ vượt ẩu qua xe đầu kéo va chạm với xe khách đang xuống dốc tốc độ cao, gây tai nạn liên hoàn giữa 3 xe tại km12+400 đoạn qua phường Hương Hồ, TP. Huế', 'video', 'https://cdn.dtlx.app/simulation/videos/112.mp4', 'https://cdn.dtlx.app/simulation/images/112.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '21.4', '7.257', '11.187'),
(242, '113', '[Tai nạn] Khi đen tín hiệu chuyển sang xanh, đột ngột co xe con co vượt từ đường giao bên trai sang làm va chạm với xe con', 'video', 'https://cdn.dtlx.app/simulation/videos/113.mp4', 'https://cdn.dtlx.app/simulation/images/113.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '24.0', '16.891', '19.934'),
(243, '114', '[Tai nạn] Ô tô 7 chỗ đi trên cầu treo hẹp ban đêm, tài xế lái xe va chạm với xe máy, xe đâm xuống sông tại cầu treo qua sông Giăng, Thanh Chương, Nghệ An', 'video', 'https://cdn.dtlx.app/simulation/videos/114.mp4', 'https://cdn.dtlx.app/simulation/images/114.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '31.3', '12.154', '16.330'),
(244, '115', '[Tai nạn] Xe con phanh gấp tránh xe máy từ ngõ lao ra, xe khách không làm chủ tốc độ đã đâm trực diện vào xe con', 'video', 'https://cdn.dtlx.app/simulation/videos/115.mp4', 'https://cdn.dtlx.app/simulation/images/115.jpg', '2025-04-19 19:17:28', '2025-04-19 19:17:28', 18, '27.6', '11.997', '15.892'),
