INSERT INTO `quizzes` (`id`, `quiz_set_id`, `question`, `name`, `image`, `explanation`, `mandatory`, `wrong`, `created_at`, `updated_at`, `tip`, `tip_image`) VALUES
(1605, 47, 'Phần của đường bộ được sử dụng cho phương tiện giao thông đường bộ đi lại là gì?', '1', '', 'Phần của đường bộ được sử dụng cho phương tiện giao thông đường bộ đi lại là gì là Phần đường xe chạy.', 0, 1, NULL, '2025-08-09 14:07:00', NULL, NULL),
(1606, 47, 'Làn đường là gì?', '2', '', 'Làn đường là gì là Là một phần của phần đường xe chạy được chia theo chiều dọc của đường, có đủ chiều rộng cho xe chạy an toàn.', 0, 1, NULL, '2025-08-09 19:47:36', NULL, NULL),
(1607, 47, 'Khổ giới hạn của đường bộ được hiểu như thế nào là đúng?', '3', '', 'Khổ giới hạn của đường bộ được hiểu như thế nào là đúng là Khổ giới hạn của đường bộ là khoảng trống có kích thước giới hạn về chiều rộng, chiều cao của đường bộ để các xe, bao gồm cả hàng hoá xếp trên xe đi qua được an toàn và được xác định theo quy chuẩ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1608, 47, 'Dải phân cách được lắp đặt để làm gì?', '4', '', 'Dải phân cách được lắp đặt để làm gì là Để phân chia các làn đường dành cho xe cơ giới và xe thô sơ trên đường cao tốc.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1609, 47, 'Vạch kẻ đường là gì?', '5', '', 'Vạch kẻ đường là gì là Là vạch chỉ sự phân chia làn đường, vị trí hoặc hướng đi, vị trí dừng lại.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1610, 47, 'Người điều khiển phương tiện tham gia giao thông đường bộ được hiểu như thế nào là đúng?', '6', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ được hiểu như thế nào là đúng là Là người điều khiển xe cơ giới, người điều khiển xe thô sơ, người điều khiển xe máy chuyên dùng.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1611, 47, 'Người lái xe được hiểu như thế nào là đúng?', '7', '', 'Người lái xe được hiểu như thế nào là đúng là Là người điều khiển xe cơ giới.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1612, 47, 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe cơ giới?', '8', '', 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe cơ giới là Xe ô tô; rơ moóc được kéo bởi xe ô tô; sơ mi rơ moóc được kéo bởi ô tô đầu kéo; xe chở người bốn bánh có gắn động cơ; xe chở hàng bốn bánh có gắn động cơ; xe mô', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1613, 47, 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe thô sơ?', '9', '', 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe thô sơ là Xe đạp, xe đạp máy, xe đạp điện; xe xích lô; xe lăn dùng cho người khuyết tật; xe vật nuôi kéo và các loại xe tương tự.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1614, 47, 'Phương tiện giao thông đường bộ gồm những loại nào?', '10', '', 'Phương tiện giao thông đường bộ gồm những loại nào là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1615, 47, 'Người tham gia giao thông đường bộ gồm những đối tượng nào?', '11', '', 'Người tham gia giao thông đường bộ gồm những đối tượng nào là Người điều khiển, dẫn dắt vật nuôi trên đường bộ; người đi bộ trên đường bộ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1616, 47, 'Người điều khiển phương tiện tham gia giao thông đường bộ gồm những đối tượng nào dưới đây?', '12', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ gồm những đối tượng nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1617, 47, 'Người điều khiển giao thông đường bộ được hiểu như thế nào là đúng?', '13', '', 'Người điều khiển giao thông đường bộ được hiểu như thế nào là đúng là Là Cảnh sát giao thông và người được giao nhiệm vụ hướng dẫn giao thông trên đường bộ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1618, 47, 'Dừng xe được hiểu như thế nào là đúng?', '14', '', 'Dừng xe được hiểu như thế nào là đúng là Là trạng thái đứng yên tạm thời của xe trong một khoảng thời gian cần thiết đủ để cho người lên xe, xuống xe, xếp dỡ hàng hóa, kiểm tra kỹ thuật xe hoặc hoạt động khác. Khi dừng xe không được tắt máy và không được ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1619, 47, 'Đỗ xe được hiểu như thế nào là đúng?', '15', '', 'Đỗ xe được hiểu như thế nào là đúng là Là trạng thái đứng yên của xe không giới hạn thời gian. Khi đỗ xe, người điều khiển phương tiện tham gia giao thông đường bộ chỉ được rời khỏi xe khi đã sử dụng phanh đỗ xe hoặc thực hiện biện pháp an toàn khác. Xe đ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1620, 47, 'Đường cao tốc được hiểu như thế nào là đúng?', '16', '', 'Đường cao tốc được hiểu như thế nào là đúng là Là một cấp kỹ thuật của đường bộ, chỉ dành cho một số loại xe cơ giới, xe máy chuyên dùng tham gia giao thông theo quy định của pháp luật. Có dải phân cách phân chia hai chiều xe chạy riêng biệt, không giao n', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1621, 47, 'Thiết bị an toàn cho trẻ em được hiểu như thế nào là đúng?', '17', '', 'Thiết bị an toàn cho trẻ em được hiểu như thế nào là đúng là Là thiết bị có đủ khả năng bảo đảm an toàn cho trẻ em ở tư thế ngồi hoặc nằm trên xe ô tô, được thiết kế để giảm nguy cơ chấn thương cho người dùng trong trường hợp xảy ra va chạm hoặc xe ô tô g', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1622, 47, 'Theo chức năng phục vụ thì đường bộ được phân loại như thế nào?', '18', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1623, 47, 'Hành vi nào dưới đây bị nghiêm cấm?', '19', '', 'Hành vi nào dưới đây bị nghiêm cấm là Rải vật sắc nhọn, đổ chất gây trơn trượt trên đường bộ.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1624, 47, 'Hành vi đưa xe cơ giới, xe máy chuyên dùng tham gia giao thông đường bộ nào dưới đây bị cấm?', '20', '', 'Hành vi đưa xe cơ giới, xe máy chuyên dùng tham gia giao thông đường bộ nào dưới đây bị cấm là Cả hai ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1625, 47, 'Tổ chức đua xe được phép thực hiện khi nào?', '21', '', 'Tổ chức đua xe được phép thực hiện khi nào là Được cơ quan có thẩm quyền cấp phép.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1626, 47, 'Hành vi đua xe trái phép bị xử lý như thế nào?', '22', '', '', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1627, 47, 'Hành vi của người điều khiển xe ô tô và các loại xe tương tự khi tham gia giao thông đường bộ mà trong cơ thể có chất ma túy thì bị áp dụng hình thức xử phạt vi phạm hành chính nào dưới đây?', '23', '', 'Hành vi của người điều khiển xe ô tô và các loại xe tương tự khi tham gia giao thông đường bộ mà trong cơ thể có chất ma túy thì bị áp dụng hình thức xử phạt vi phạm hành chính nào dưới đây là Cả hai ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1628, 47, 'Người điều khiển phương tiện tham gia giao thông đường bộ mà trong máu hoặc hơi thở có nồng độ cồn có bị nghiêm cấm không?', '24', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ mà trong máu hoặc hơi thở có nồng độ cồn có bị nghiêm cấm không là Bị nghiêm cấm.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1629, 47, 'Hành vi của người điều khiển xe ô tô và các loại xe tương tự khi tham gia giao thông đường bộ mà trong máu hoặc hơi thở có nồng độ cồn thì bị áp dụng hình thức xử phạt vi phạm hành chính nào dưới đây?', '25', '', 'Hành vi của người điều khiển xe ô tô và các loại xe tương tự khi tham gia giao thông đường bộ mà trong máu hoặc hơi thở có nồng độ cồn thì bị áp dụng hình thức xử phạt vi phạm hành chính nào dưới đây là Cả hai ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1630, 47, 'Theo Luật Phòng chống tác hại của rượu, bia, đối tượng nào dưới đây bị cấm sử dụng rượu, bia khi tham gia giao thông?', '26', '', 'Theo Luật Phòng chống tác hại của rượu, bia, đối tượng nào dưới đây bị cấm sử dụng rượu, bia khi tham gia giao thông là Người điều khiển xe ô tô, xe mô tô, xe đạp, xe gắn máy.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1631, 47, 'Hành vi giao xe ô tô, mô tô cho người nào sau đây tham gia giao thông đường bộ bị nghiêm cấm?', '27', '', 'Hành vi giao xe ô tô, mô tô cho người nào sau đây tham gia giao thông đường bộ bị nghiêm cấm là Cả ba ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1632, 47, 'Hành vi nào sau đây bị nghiêm cấm?', '28', '', 'Hành vi nào sau đây bị nghiêm cấm là Cả hai ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1633, 47, 'Các hành vi nào sau đây bị cấm đối với phương tiện tham gia giao thông đường bộ?', '29', '', 'Các hành vi nào sau đây bị cấm đối với phương tiện tham gia giao thông đường bộ là Cải tạo trái phép; cố ý can thiệp làm sai lệch chỉ số trên đồng hồ báo quãng đường đã chạy của xe ô tô; cắt, hàn, tẩy xóa, đục sửa, đóng lại trái phép số khung, số động cơ ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1634, 47, 'Hành vi nào sau đây bị cấm?', '30', '', 'Hành vi nào sau đây bị cấm là Cả hai ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1635, 47, 'Việc sản xuất, sử dụng, mua, bán trái phép biển số xe có bị nghiêm cấm hay không?', '31', '', 'Việc sản xuất, sử dụng, mua, bán trái phép biển số xe có bị nghiêm cấm hay không là Bị nghiêm cấm.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1636, 47, 'Khi điều khiển phương tiện tham gia giao thông, những hành vi nào dưới đây bị nghiêm cấm?', '32', '', 'Khi điều khiển phương tiện tham gia giao thông, những hành vi nào dưới đây bị nghiêm cấm là Lạng lách, đánh võng, rú ga liên tục.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1637, 47, 'Có bao nhiêu nhóm biển báo hiệu đường bộ?', '33', '', 'Có bao nhiêu nhóm biển báo hiệu đường bộ là Bốn nhóm: Biển báo cấm, biển báo nguy hiểm, biển hiệu lệnh và biển phụ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1638, 47, 'Tại nơi có vạch kẻ đường hoặc tại nơi mà người đi bộ, xe lăn của người khuyết tật đang qua đường, người điều khiển phương tiện tham gia giao thông phải thực hiện như thế nào?', '34', '', 'Tại nơi có vạch kẻ đường hoặc tại nơi mà người đi bộ, xe lăn của người khuyết tật đang qua đường, người điều khiển phương tiện tham gia giao thông phải thực hiện như thế nào là Quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn cho người đi bộ, xe lăn', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1639, 47, 'Người điều khiển xe mô tô phải phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây?', '35', '', 'Người điều khiển xe mô tô phải phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây là Cả ba ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1640, 47, 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông?', '36', 'oto/36.webp', 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông là Người tham gia giao thông đường bộ ở phía trước và phía sau người điều khiển phải dừng lại; ngư', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1641, 47, 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông?', '37', 'oto/37.webp', 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông là Người tham gia giao thông đường bộ ở tất cả các hướng phải dừng lại, trừ các xe đã ở trong khu ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1642, 47, 'Khi hiệu lệnh của người điều khiển giao thông trái với tín hiệu đèn giao thông hoặc biển báo hiệu đường bộ thì người tham gia giao thông đường bộ phải chấp hành báo hiệu đường bộ nào dưới đây?', '38', '', 'Khi hiệu lệnh của người điều khiển giao thông trái với tín hiệu đèn giao thông hoặc biển báo hiệu đường bộ thì người tham gia giao thông đường bộ phải chấp hành báo hiệu đường bộ nào dưới đây là Theo hiệu lệnh của người điều khiển giao thông.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1643, 47, 'Khi ở một vị trí vừa có biển báo hiệu đặt cố định vừa có biển báo hiệu tạm thời mà hai biển có ý nghĩa khác nhau, người tham gia giao thông đường bộ phải chấp hành hiệu lệnh của biển báo hiệu nào?', '39', '', 'Khi ở một vị trí vừa có biển báo hiệu đặt cố định vừa có biển báo hiệu tạm thời mà hai biển có ý nghĩa khác nhau, người tham gia giao thông đường bộ phải chấp hành hiệu lệnh của biển báo hiệu nào là Biển báo hiệu tạm thời.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1644, 47, 'Tại nơi đường giao nhau, khi đèn điều khiển giao thông có tín hiệu màu vàng, người điều khiển phương tiện tham gia giao thông phải chấp hành như thế nào là đúng quy tắc giao thông?', '40', '', 'Tại nơi đường giao nhau, khi đèn điều khiển giao thông có tín hiệu màu vàng, người điều khiển phương tiện tham gia giao thông phải chấp hành như thế nào là đúng quy tắc giao thông là Dừng lại trước vạch dừng; trường hợp đang đi trên vạch dừng hoặc đã đi q', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1645, 47, 'Người lái xe trên đường cần chấp hành quy định về tốc độ tối đa như thế nào?', '41', '', 'Người lái xe trên đường cần chấp hành quy định về tốc độ tối đa như thế nào là Không vượt quá tốc độ tối đa cho phép.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1646, 47, 'Khi chở trẻ em dưới 10 tuổi và chiều cao dưới 1,35 mét trên xe ô tô, người lái xe phải thực hiện quy tắc nào dưới đây để bảo đảm an toàn?', '42', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1647, 47, 'Phương tiện tham gia giao thông đường bộ di chuyển với tốc độ thấp hơn phải đi như thế nào?', '43', '', 'Phương tiện tham gia giao thông đường bộ di chuyển với tốc độ thấp hơn phải đi như thế nào là Đi về bên phải theo chiều đi của mình.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1648, 47, 'Trên một chiều đường có vạch kẻ phân làn đường, người lái xe cơ giới, xe máy chuyên dùng phải điều khiển xe đi trên làn đường nào?', '44', '', 'Trên một chiều đường có vạch kẻ phân làn đường, người lái xe cơ giới, xe máy chuyên dùng phải điều khiển xe đi trên làn đường nào là Đi trên làn đường bên trái.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1649, 47, 'Người lái xe phải giảm tốc độ, có tín hiệu rẽ phải và đi sát về bên phải của phần đường xe chạy trong các trường hợp nào dưới đây?', '45', '', 'Người lái xe phải giảm tốc độ, có tín hiệu rẽ phải và đi sát về bên phải của phần đường xe chạy trong các trường hợp nào dưới đây là Khi xe sau xin vượt nếu đủ điều kiện an toàn.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1650, 47, 'Vượt xe là gì?', '46', '', 'Vượt xe là gì là Là tình huống giao thông trên đường mà mỗi chiều đường xe chạy chỉ có một làn đường dành cho xe cơ giới, xe đi phía sau di chuyển sang bên trái để di chuyển lên trước xe phía trước.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1651, 47, 'Người lái xe được phép vượt xe trên cầu hẹp có một làn đường, đường cong có tầm nhìn bị hạn chế hay không?', '47', '', 'Người lái xe được phép vượt xe trên cầu hẹp có một làn đường, đường cong có tầm nhìn bị hạn chế hay không là Không được phép vượt.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1652, 47, 'Muốn vượt xe phía trước, người lái xe mô tô phải có tín hiệu như thế nào dưới đây để bảo đảm an toàn?', '48', '', 'Muốn vượt xe phía trước, người lái xe mô tô phải có tín hiệu như thế nào dưới đây để bảo đảm an toàn là Báo hiệu nhấp nháy bằng đèn chiếu sáng phía trước hoặc còi.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1653, 47, 'Khi lái xe trong khu đông dân cư, khu vực cơ sở khám bệnh, chữa bệnh trừ các khu vực có biển cấm sử dụng còi, người lái xe được sử dụng còi trong thời gian nào?', '49', '', 'Khi lái xe trong khu đông dân cư, khu vực cơ sở khám bệnh, chữa bệnh trừ các khu vực có biển cấm sử dụng còi, người lái xe được sử dụng còi trong thời gian nào là Từ 05 giờ đến 22 giờ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1654, 47, 'Phương tiện tham gia giao thông đường bộ chỉ được sử dụng tín hiệu còi trong các trường hợp nào sau đây?', '50', '', 'Phương tiện tham gia giao thông đường bộ chỉ được sử dụng tín hiệu còi trong các trường hợp nào sau đây là Để báo hiệu cho người tham gia giao thông đường bộ khi xuất hiện tình huống có thể mất an toàn giao thông hoặc báo hiệu chuẩn bị vượt xe.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1655, 47, 'Người lái xe sử dụng đèn như thế nào khi đi trên các đoạn đường qua khu đông dân cư có hệ thống chiếu sáng đang hoạt động?', '51', '', 'Người lái xe sử dụng đèn như thế nào khi đi trên các đoạn đường qua khu đông dân cư có hệ thống chiếu sáng đang hoạt động là Chỉ bật đèn chiếu gần (đèn cốt).', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1656, 47, 'Khi điều khiển phương tiện tham gia giao thông, hành vi nào sau đây bị cấm?', '52', '', 'Khi điều khiển phương tiện tham gia giao thông, hành vi nào sau đây bị cấm là Dùng tay cầm và sử dụng điện thoại hoặc thiết bị điện tử khác.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1657, 47, 'Người lái xe không được vượt xe khác khi gặp trường hợp nào dưới đây?', '53', '', '', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1658, 47, 'Nơi nào cấm quay đầu xe?', '54', '', 'Nơi nào cấm quay đầu xe là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1659, 47, 'Người lái xe không được quay đầu xe trong các trường hợp nào dưới đây?', '55', '', '', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1660, 47, 'Trước khi cho xe chuyển hướng, người lái xe phải làm gì để bảo đảm an toàn giao thông?', '56', '', 'Trước khi cho xe chuyển hướng, người lái xe phải làm gì để bảo đảm an toàn giao thông là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1661, 47, 'Khi chuyển làn đường, người lái xe phải bật đèn tín hiệu báo rẽ như thế nào là đúng quy tắc giao thông?', '57', '', 'Khi chuyển làn đường, người lái xe phải bật đèn tín hiệu báo rẽ như thế nào là đúng quy tắc giao thông là Trước khi thay đổi làn đường.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1662, 47, 'Người lái xe không được lùi xe ở những khu vực nào dưới đây?', '58', '', 'Người lái xe không được lùi xe ở những khu vực nào dưới đây là Cả ba ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1663, 47, 'Người điều khiển phương tiện tham gia giao thông không được dừng xe, đỗ xe ở những vị trí nào sau đây?', '59', '', 'Người điều khiển phương tiện tham gia giao thông không được dừng xe, đỗ xe ở những vị trí nào sau đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1664, 47, 'Trên đường phố, người điều khiển phương tiện tham gia giao thông đường bộ được dừng xe, đỗ xe sát theo lề đường, vỉa hè phía bên phải theo chiều đi của mình; bánh xe gần nhất không được cách xa lề đường, vỉa hè không quá bao nhiêu mét trong các trường hợp dưới đây và không gây cản trở, nguy hiểm cho người và phương tiện tham gia giao thông đường bộ?', '60', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1665, 47, 'Khi dừng, đỗ xe trên đường phố hẹp, người lái xe ô tô phải dừng, đỗ xe ở vị trí cách xe ô tô đang đỗ ngược chiều khoảng cách tối thiểu là bao nhiêu mét trong các trường hợp dưới đây để bảo đảm an toàn?', '61', '', 'Khi dừng, đỗ xe trên đường phố hẹp, người lái xe ô tô phải dừng, đỗ xe ở vị trí cách xe ô tô đang đỗ ngược chiều khoảng cách tối thiểu là bao nhiêu mét trong các trường hợp dưới đây để bảo đảm an toàn là 20 mét.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1666, 47, 'Người điều khiển phương tiện tham gia giao thông đường bộ không được dừng xe, đỗ xe tại các vị trí nào sau đây?', '62', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ không được dừng xe, đỗ xe tại các vị trí nào sau đây là Song song cùng chiều với một xe khác đang dừng, đỗ trên đường; trên đoạn đường cong hoặc gần đầu dốc mà tầm nhìn bị che khuất; bên trái đường', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1667, 47, 'Người điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy có được phép sử dụng xe để kéo hoặc đẩy các phương tiện khác khi tham gia giao thông không?', '63', '', 'Người điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy có được phép sử dụng xe để kéo hoặc đẩy các phương tiện khác khi tham gia giao thông không là Không được phép.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1668, 47, 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép?', '64', '', 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép là Buông cả hai tay; đứng, nằm trên xe điều khiển xe; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1669, 47, 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép?', '65', '', 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép là Buông cả hai tay; sử dụng xe để kéo, đẩy xe khác, vật khác; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1670, 47, 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ không được thực hiện hành vi nào sau đây?', '66', '', 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ không được thực hiện hành vi nào sau đây là Ý 1 và ý 2.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1671, 47, 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được bám, kéo hoặc đẩy các phương tiện khác không?', '67', '', 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được bám, kéo hoặc đẩy các phương tiện khác không là Không được phép.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1672, 47, 'Người lái xe, người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy phải thực hiện quy định nào dưới đây?', '68', '', 'Người lái xe, người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy phải thực hiện quy định nào dưới đây là Đội mũ bảo hiểm theo đúng quy chuẩn kỹ thuật quốc gia và cài quai đúng quy cách.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1673, 47, 'Người lái xe mô tô hai bánh, xe gắn máy được phép chở tối đa hai người trong những trường hợp nào?', '69', '', 'Người lái xe mô tô hai bánh, xe gắn máy được phép chở tối đa hai người trong những trường hợp nào là Chở người bệnh đi cấp cứu; áp giải người có hành vi vi phạm pháp luật; trẻ em dưới 12 tuổi; người già yếu hoặc người khuyết tật.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1674, 47, 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào dưới đây?', '70', '', 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào dưới đây là Ngồi về một bên điều khiển xe; đứng, nằm trên xe điều khiển xe; thay người lái xe khi xe đang chạy; quay người về phía sau để điều khiển xe hoặc bịt', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1675, 47, 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào sau đây?', '71', '', 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào sau đây là Cả hai ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1676, 47, 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện hành vi nào sau đây?', '72', '', 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện hành vi nào sau đây là Đi xe dàn hàng ngang, đi xe vào phần đường dành cho người đi bộ.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1677, 47, 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được sử dụng ô khi trời mưa hay không?', '73', '', 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được sử dụng ô khi trời mưa hay không là Không được sử dụng.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1678, 47, 'Người được chở trên xe mô tô có được kéo theo người đang điều khiển xe đạp hay không?', '74', '', 'Người được chở trên xe mô tô có được kéo theo người đang điều khiển xe đạp hay không là Không được phép.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1679, 47, 'Trường hợp người được chở trên xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy không đội mũ bảo hiểm cho người đi mô tô, xe máy hoặc không cài quai đúng quy cách (trừ trường hợp chở người bệnh đi cấp cứu, trẻ em dưới 06 tuổi, áp giải người có hành vi vi phạm pháp luật) thì việc xử phạt vi phạm hành chính được quy định như thế nào?', '75', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1680, 47, 'Trong các trường hợp dưới đây, để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô cần thực hiện như thế nào?', '76', '', 'Trong các trường hợp dưới đây, để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô cần thực hiện như thế nào là Phải đội mũ bảo hiểm theo đúng quy chuẩn kỹ thuật quốc gia và cài quai đúng quy cách, không sử dụng ô, điện thoại di động, thiết bị ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1681, 47, 'Thứ tự xuống phà như thế nào là đúng quy tắc giao thông?', '77', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1682, 47, 'Trên đường có nhiều làn đường cho xe đi cùng chiều được phân biệt bằng vạch kẻ phân làn đường, người điều khiển phương tiện tham gia giao thông đường bộ phải cho xe đi như thế nào?', '78', '', 'Trên đường có nhiều làn đường cho xe đi cùng chiều được phân biệt bằng vạch kẻ phân làn đường, người điều khiển phương tiện tham gia giao thông đường bộ phải cho xe đi như thế nào là Phải cho xe đi trong một làn đường và chỉ được chuyển làn đường ở những ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1683, 47, 'Trên đường một chiều có vạch kẻ phân làn đường, xe thô sơ và xe cơ giới phải đi như thế nào là đúng quy tắc giao thông?', '79', '', 'Trên đường một chiều có vạch kẻ phân làn đường, xe thô sơ và xe cơ giới phải đi như thế nào là đúng quy tắc giao thông là Xe thô sơ phải đi trên làn đường bên phải trong cùng, xe cơ giới, xe máy chuyên dùng đi trên làn đường bên trái.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1684, 47, 'Khi lái xe trong đô thị và khu đông dân cư trong thời gian từ 22 giờ ngày hôm trước đến 05 giờ ngày hôm sau, nếu cần vượt một xe khác, người lái xe phải báo hiệu như thế nào là đúng quy tắc giao thông?', '80', '', 'Khi lái xe trong đô thị và khu đông dân cư trong thời gian từ 22 giờ ngày hôm trước đến 05 giờ ngày hôm sau, nếu cần vượt một xe khác, người lái xe phải báo hiệu như thế nào là đúng quy tắc giao thông là Chỉ được báo hiệu bằng đèn.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1685, 47, 'Khi điều khiển xe chạy trên đường, biết có xe sau xin vượt, nếu đủ điều kiện an toàn người điều khiển phương tiện phải làm gì?', '81', '', 'Khi điều khiển xe chạy trên đường, biết có xe sau xin vượt, nếu đủ điều kiện an toàn người điều khiển phương tiện phải làm gì là Giảm tốc độ, có tín hiệu rẽ phải để báo hiệu cho người điều khiển phương tiện tham gia giao thông đường bộ phía sau biết được ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1686, 47, 'Khi điều khiển xe chạy trên đường, biết có xe sau xin vượt, nếu không đủ điều kiện an toàn người điều khiển phương tiện phải làm gì?', '82', '', 'Khi điều khiển xe chạy trên đường, biết có xe sau xin vượt, nếu không đủ điều kiện an toàn người điều khiển phương tiện phải làm gì là Có tín hiệu rẽ trái để báo hiệu cho người điều khiển phương tiện tham gia giao thông đường bộ phía sau biết là chưa được', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1687, 47, 'Khi chuyển hướng, người lái xe, người điều khiển xe máy chuyên dùng phải làm gì để bảo đảm an toàn?', '83', '', 'Khi chuyển hướng, người lái xe, người điều khiển xe máy chuyên dùng phải làm gì để bảo đảm an toàn là Phải nhường đường cho người đi bộ, xe thô sơ, xe đi ngược chiều và chỉ chuyển hướng khi không gây trở ngại hoặc nguy hiểm cho người, phương tiện khác.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1688, 47, 'Trước khi chuyển hướng, người điều khiển phương tiện tham gia giao thông đường bộ phải thực hiện như thế nào để bảo đảm an toàn?', '84', '', 'Trước khi chuyển hướng, người điều khiển phương tiện tham gia giao thông đường bộ phải thực hiện như thế nào để bảo đảm an toàn là Quan sát, bảo đảm khoảng cách an toàn với xe phía sau, giảm tốc độ và có tín hiệu báo hướng rẽ hoặc có tín hiệu bằng tay the', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1689, 47, 'Khi lùi xe, người điều khiển phương tiện tham gia giao thông đường bộ phải làm gì để bảo đảm an toàn?', '85', '', 'Khi lùi xe, người điều khiển phương tiện tham gia giao thông đường bộ phải làm gì để bảo đảm an toàn là Phải quan sát hai bên và phía sau xe, có tín hiệu lùi và chỉ lùi xe khi bảo đảm an toàn.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1690, 47, 'Khi muốn lùi xe ở nơi có tầm nhìn bị che khuất, người lái xe phải xử lý như thế nào để đảm bảo an toàn?', '86', '', 'Khi muốn lùi xe ở nơi có tầm nhìn bị che khuất, người lái xe phải xử lý như thế nào để đảm bảo an toàn là Không được lùi xe.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1691, 47, 'Trên đường không phân chia thành hai chiều xe chạy riêng biệt, người điều khiển phương tiện tham gia giao thông đường bộ phải tránh xe đi ngược chiều như thế nào để bảo đảm an toàn?', '87', '', 'Trên đường không phân chia thành hai chiều xe chạy riêng biệt, người điều khiển phương tiện tham gia giao thông đường bộ phải tránh xe đi ngược chiều như thế nào để bảo đảm an toàn là Giảm tốc độ và cho xe đi về bên phải theo chiều xe chạy của mình.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1692, 47, 'Khi tránh xe đi ngược chiều, các xe phải nhường đường như thế nào là đúng quy tắc giao thông?', '88', '', 'Khi tránh xe đi ngược chiều, các xe phải nhường đường như thế nào là đúng quy tắc giao thông là Cả ba ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1693, 47, 'Khi đang lái xe xuống dốc gặp một xe đang đi lên dốc, người lái xe phải làm gì?', '89', '', 'Khi đang lái xe xuống dốc gặp một xe đang đi lên dốc, người lái xe phải làm gì là Nhường đường cho xe lên dốc.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1694, 47, 'Người lái xe phải làm gì để bảo đảm an toàn khi lái xe trên đường cong có tầm nhìn bị hạn chế?', '90', '', 'Người lái xe phải làm gì để bảo đảm an toàn khi lái xe trên đường cong có tầm nhìn bị hạn chế là Quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1695, 47, 'Tại nơi đường giao nhau, người lái xe đang đi trên đường không ưu tiên, đường nhánh phải nhường đường như thế nào là đúng quy tắc giao thông?', '91', '', 'Tại nơi đường giao nhau, người lái xe đang đi trên đường không ưu tiên, đường nhánh phải nhường đường như thế nào là đúng quy tắc giao thông là Nhường đường cho xe đi trên đường ưu tiên hoặc đường chính từ bất kỳ hướng nào tới.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1696, 47, 'Tại nơi đường giao nhau có báo hiệu đi theo vòng xuyến, người lái xe phải nhường đường như thế nào là đúng quy tắc giao thông?', '92', '', 'Tại nơi đường giao nhau có báo hiệu đi theo vòng xuyến, người lái xe phải nhường đường như thế nào là đúng quy tắc giao thông là Nhường đường cho xe đi đến từ bên trái.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1697, 47, 'Tại nơi đường giao nhau không có báo hiệu đi theo vòng xuyến, người điều khiển phương tiện phải nhường đường như thế nào là đúng quy tắc giao thông?', '93', '', 'Tại nơi đường giao nhau không có báo hiệu đi theo vòng xuyến, người điều khiển phương tiện phải nhường đường như thế nào là đúng quy tắc giao thông là Phải nhường đường cho xe đi đến từ bên phải.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1698, 47, 'Người lái xe phải nhanh chóng giảm tốc độ, đi sát lề đường bên phải hoặc dừng lại để nhường đường cho các loại xe nào dưới đây?', '94', '', 'Người lái xe phải nhanh chóng giảm tốc độ, đi sát lề đường bên phải hoặc dừng lại để nhường đường cho các loại xe nào dưới đây là Xe ưu tiên gồm xe chữa cháy của Cảnh sát phòng cháy, chữa cháy và cứu nạn, cứu hộ và xe chữa cháy của các lực lượng khác được', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1699, 47, 'Xe ưu tiên (trừ đoàn xe tang) tham gia giao thông đường bộ khi đi làm nhiệm vụ được quyền ưu tiên nào dưới đây?', '95', '', 'Xe ưu tiên (trừ đoàn xe tang) tham gia giao thông đường bộ khi đi làm nhiệm vụ được quyền ưu tiên nào dưới đây là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1700, 47, 'Khi có tín hiệu của xe ưu tiên, người và phương tiện tham gia giao thông đường bộ phải tuân thủ quy định nào dưới đây?', '96', '', 'Khi có tín hiệu của xe ưu tiên, người và phương tiện tham gia giao thông đường bộ phải tuân thủ quy định nào dưới đây là Giảm tốc độ, đi sát lề đường bên phải hoặc dừng lại để nhường đường.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1701, 47, 'Khi đang lái xe, phía trước có một xe Cảnh sát giao thông không phát tín hiệu ưu tiên, người lái xe có được phép vượt hay không?', '97', '', 'Khi đang lái xe, phía trước có một xe Cảnh sát giao thông không phát tín hiệu ưu tiên, người lái xe có được phép vượt hay không là Được vượt khi bảo đảm an toàn.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1702, 47, 'Khi đang lái xe, phía trước có một xe cứu thương đang phát tín hiệu ưu tiên, người lái xe có được phép vượt hay không?', '98', '', 'Khi đang lái xe, phía trước có một xe cứu thương đang phát tín hiệu ưu tiên, người lái xe có được phép vượt hay không là Không được vượt.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1703, 47, 'Khi tới đường ngang không có người gác, chắn đường bộ, chuông, đèn tín hiệu, người tham gia giao thông đường bộ phải làm gì để bảo đảm an toàn?', '99', '', 'Khi tới đường ngang không có người gác, chắn đường bộ, chuông, đèn tín hiệu, người tham gia giao thông đường bộ phải làm gì để bảo đảm an toàn là Dừng lại về bên phải đường của mình, trước vạch dừng xe và quan sát hai phía, khi không có phương tiện giao t', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1704, 47, 'Tại đường ngang, cầu chung đường sắt, khi có hiệu lệnh của nhân viên gác chắn, đèn đỏ sáng nhấp nháy, chuông kêu, chắn đường bộ đang dịch chuyển hoặc đã đóng, người tham gia giao thông đường bộ phải làm gì để bảo đảm an toàn?', '100', '', 'Tại đường ngang, cầu chung đường sắt, khi có hiệu lệnh của nhân viên gác chắn, đèn đỏ sáng nhấp nháy, chuông kêu, chắn đường bộ đang dịch chuyển hoặc đã đóng, người tham gia giao thông đường bộ phải làm gì để bảo đảm an toàn là Dừng lại về bên phải đường ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1705, 47, 'Khi xe ô tô bị hư hỏng, bị tai nạn trên đường ngang, cầu chung đường sắt mà không thể di chuyển ngay khỏi phạm vi an toàn đường sắt, người lái xe và người có mặt xử lý như thế nào là đúng quy định?', '101', '', 'Khi xe ô tô bị hư hỏng, bị tai nạn trên đường ngang, cầu chung đường sắt mà không thể di chuyển ngay khỏi phạm vi an toàn đường sắt, người lái xe và người có mặt xử lý như thế nào là đúng quy định là Người lái xe và người có mặt phải ngay lập tức báo hiệu', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1706, 47, 'Người tham gia giao thông đường bộ phải dừng lại về bên phải đường của mình trước vạch dừng xe tại đường ngang, cầu chung đường sắt khi có báo hiệu nào dưới đây?', '102', '', 'Người tham gia giao thông đường bộ phải dừng lại về bên phải đường của mình trước vạch dừng xe tại đường ngang, cầu chung đường sắt khi có báo hiệu nào dưới đây là Cả ba ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1707, 47, 'Người điều khiển phương tiện tham gia giao thông trong hầm đường bộ ngoài việc phải tuân thủ các quy tắc giao thông còn phải thực hiện những quy định nào dưới đây?', '103', '', 'Người điều khiển phương tiện tham gia giao thông trong hầm đường bộ ngoài việc phải tuân thủ các quy tắc giao thông còn phải thực hiện những quy định nào dưới đây là Xe cơ giới, xe máy chuyên dùng phải bật đèn chiếu gần; xe thô sơ phải bật đèn hoặc có vật', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1708, 47, 'Việc nối giữa xe kéo với xe được kéo trong trường hợp hệ thống hãm của xe được kéo không còn hiệu lực thì xe kéo nhau phải nối bằng cách nào?', '104', '', 'Việc nối giữa xe kéo với xe được kéo trong trường hợp hệ thống hãm của xe được kéo không còn hiệu lực thì xe kéo nhau phải nối bằng cách nào là Nối bằng thanh nối cứng.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1709, 47, 'Xe kéo rơ moóc, xe ô tô đầu kéo khi tham gia giao thông đường bộ phải tuân thủ quy tắc giao thông nào ghi ở dưới đây?', '105', '', 'Xe kéo rơ moóc, xe ô tô đầu kéo khi tham gia giao thông đường bộ phải tuân thủ quy tắc giao thông nào ghi ở dưới đây là Chỉ được kéo rơ moóc, sơ mi rơ moóc phù hợp với thiết kế của xe; việc kết nối xe kéo với rơ moóc, xe ô tô đầu kéo với sơ mi rơ moóc phả', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1710, 47, 'Luật Trật tự, an toàn giao thông đường bộ quy định về xe kéo xe, xe kéo rơ moóc và xe ô tô đầu kéo kéo sơ mi rơ moóc như thế nào dưới đây?', '106', '', 'Luật Trật tự, an toàn giao thông đường bộ quy định về xe kéo xe, xe kéo rơ moóc và xe ô tô đầu kéo kéo sơ mi rơ moóc như thế nào dưới đây là Xe được kéo phải có người điều khiển và hệ thống lái của xe đó phải còn hiệu lực; việc nối xe kéo với xe được kéo ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1711, 47, 'Người điều khiển phương tiện tham gia giao thông đường bộ phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây?', '107', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1712, 47, 'Trên đường mà mỗi chiều đường xe chạy chỉ có một làn đường dành cho xe cơ giới, người lái xe không được vượt xe khác trong trường hợp nào dưới đây?', '108', '', 'Trên đường mà mỗi chiều đường xe chạy chỉ có một làn đường dành cho xe cơ giới, người lái xe không được vượt xe khác trong trường hợp nào dưới đây là Có chướng ngại vật phía trước, xe chạy phía trước có tín hiệu vượt xe khác.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1713, 47, 'Người lái xe được phép vượt xe khác về bên phải trong trường hợp nào dưới đây?', '109', '', 'Người lái xe được phép vượt xe khác về bên phải trong trường hợp nào dưới đây là Xe phía trước có tín hiệu rẽ trái hoặc đang rẽ trái hoặc khi xe chuyên dùng đang làm việc trên đường mà không thể vượt bên trái.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1714, 47, 'Khi có xe xin vượt, người lái xe mô tô xử lý như thế nào nếu đủ điều kiện an toàn cho xe phía sau vượt?', '110', '', 'Khi có xe xin vượt, người lái xe mô tô xử lý như thế nào nếu đủ điều kiện an toàn cho xe phía sau vượt là Giảm tốc độ, có tín hiệu rẽ phải để báo hiệu cho người điều khiển phương tiện tham gia giao thông đường bộ phía sau biết được vượt và đi sát về bên p', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1715, 47, 'Những trường hợp nào dưới đây không được đi trên đường cao tốc, trừ người, phương tiện giao thông đường bộ và thiết bị phục vụ việc quản lý, bảo trì đường cao tốc?', '111', '', 'Những trường hợp nào dưới đây không được đi trên đường cao tốc, trừ người, phương tiện giao thông đường bộ và thiết bị phục vụ việc quản lý, bảo trì đường cao tốc là Xe máy chuyên dùng có tốc độ thiết kế nhỏ hơn tốc độ tối thiểu quy định đối với đường cao', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1716, 47, 'Khi tham gia giao thông trên đường cao tốc, xe ưu tiên đi làm nhiệm vụ khẩn cấp được đi ngược chiều trong trường hợp nào dưới đây?', '112', '', 'Khi tham gia giao thông trên đường cao tốc, xe ưu tiên đi làm nhiệm vụ khẩn cấp được đi ngược chiều trong trường hợp nào dưới đây là Được đi ngược chiều bất cứ làn đường nào của đường cao tốc có thể đi được.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1717, 47, 'Khi tham gia giao thông trên đường cao tốc, người lái xe không được thực hiện hành vi nào sau đây?', '113', '', 'Khi tham gia giao thông trên đường cao tốc, người lái xe không được thực hiện hành vi nào sau đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1718, 47, 'Khi xe gặp sự cố kỹ thuật trên đường cao tốc, bạn phải xử lý như thế nào để bảo đảm an toàn giao thông?', '114', '', 'Khi xe gặp sự cố kỹ thuật trên đường cao tốc, bạn phải xử lý như thế nào để bảo đảm an toàn giao thông là Dừng xe, đỗ xe ở làn dừng khẩn cấp cùng chiều xe chạy và phải có báo hiệu bằng đèn khẩn cấp; trường hợp xe không thể di chuyển được vào làn dừng khẩn', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1719, 47, 'Trên đường cao tốc, người lái xe xử lý như thế nào khi đã vượt quá lối ra của đường định rẽ?', '115', '', 'Trên đường cao tốc, người lái xe xử lý như thế nào khi đã vượt quá lối ra của đường định rẽ là Tiếp tục lái xe và rẽ ở lối ra tiếp theo.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1720, 47, 'Khi xảy ra ùn tắc trên đường cao tốc có làn dừng xe khẩn cấp, người lái xe có được cho xe chạy ở làn dừng xe khẩn cấp để nhanh chóng thoát khỏi khu vực ùn tắc không (trừ xe ưu tiên)?', '116', '', 'Khi xảy ra ùn tắc trên đường cao tốc có làn dừng xe khẩn cấp, người lái xe có được cho xe chạy ở làn dừng xe khẩn cấp để nhanh chóng thoát khỏi khu vực ùn tắc không (trừ xe ưu tiên) là Không.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1721, 47, 'Khi chuẩn bị nhập vào làn đường của đường cao tốc, người lái xe, người điều khiển xe máy chuyên dùng phải thực hiện như thế nào là đúng quy tắc giao thông?', '117', '', 'Khi chuẩn bị nhập vào làn đường của đường cao tốc, người lái xe, người điều khiển xe máy chuyên dùng phải thực hiện như thế nào là đúng quy tắc giao thông là Cả ba ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1722, 47, 'Theo quy định về độ tuổi, người đủ bao nhiêu tuổi trở lên thì được cấp giấy phép lái xe ô tô tải và ô tô chuyên dùng có khối lượng toàn bộ theo thiết kế trên 3.500 kg đến 7.500 kg; các loại xe ô tô tải quy định cho giấy phép lái xe hạng C1 kéo rơ moóc có khối lượng toàn bộ theo thiết kế đến 750 kg?', '118', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1723, 47, 'Theo quy định về độ tuổi, người đủ bao nhiêu tuổi trở lên thì được cấp giấy phép lái xe mô tô hai bánh có dung tích xi lanh đến 125 cm3 và xe ô tô chở người đến 8 chỗ (không kể chỗ của người lái xe); xe ô tô tải và ô tô chuyên dùng có khối lượng toàn bộ theo thiết kế đến 3.500 kg?', '119', '', 'Theo quy định về độ tuổi, người đủ bao nhiêu tuổi trở lên thì được cấp giấy phép lái xe mô tô hai bánh có dung tích xi lanh đến 125 cm3 và xe ô tô chở người đến 8 chỗ (không kể chỗ của người lái xe); xe ô tô tải và ô tô chuyên dùng có khối lượng toàn bộ t', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1724, 47, 'Theo quy định về độ tuổi, người lái xe ô tô chở người (kể cả xe buýt) trên 29 chỗ (không kể chỗ của người lái xe); xe ô tô chở người giường nằm; các loại xe ô tô chở người quy định cho giấy phép lái xe hạng D kéo rơ moóc có khối lượng toàn bộ theo thiết kế đến 750 kg phải đủ bao nhiêu tuổi trở lên?', '120', '', 'Theo quy định về độ tuổi, người lái xe ô tô chở người (kể cả xe buýt) trên 29 chỗ (không kể chỗ của người lái xe); xe ô tô chở người giường nằm; các loại xe ô tô chở người quy định cho giấy phép lái xe hạng D kéo rơ moóc có khối lượng toàn bộ theo thiết k', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1725, 47, 'Tuổi tối đa của người lái xe ô tô chở người (kể cả xe buýt) trên 29 chỗ (không kể chỗ của người lái xe), xe ô tô chở người giường nằm là bao nhiêu tuổi?', '121', '', 'Tuổi tối đa của người lái xe ô tô chở người (kể cả xe buýt) trên 29 chỗ (không kể chỗ của người lái xe), xe ô tô chở người giường nằm là bao nhiêu tuổi là Đủ 57 tuổi đối với nam và đủ 55 tuổi đối với nữ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1726, 47, 'Theo quy định về độ tuổi, người lái xe ô tô chở người (kể cả xe buýt) trên 16 chỗ (không kể chỗ của người lái xe) đến 29 chỗ (không kể chỗ của người lái xe); các loại xe ô tô chở người quy định cho giấy phép lái xe hạng D2 kéo rơ moóc có khối lượng toàn bộ theo thiết kế đến 750 kg phải đủ bao nhiêu tuổi trở lên?', '122', '', 'Theo quy định về độ tuổi, người lái xe ô tô chở người (kể cả xe buýt) trên 16 chỗ (không kể chỗ của người lái xe) đến 29 chỗ (không kể chỗ của người lái xe); các loại xe ô tô chở người quy định cho giấy phép lái xe hạng D2 kéo rơ moóc có khối lượng toàn b', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1727, 47, 'Người đủ 16 tuổi đến dưới 18 tuổi chỉ được điều khiển các loại xe nào dưới đây?', '123', '', 'Người đủ 16 tuổi đến dưới 18 tuổi chỉ được điều khiển các loại xe nào dưới đây là Xe gắn máy.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1728, 47, 'Người có Giấy phép lái xe mô tô hạng A1 không được phép điều khiển loại xe nào dưới đây?', '124', '', 'Người có Giấy phép lái xe mô tô hạng A1 không được phép điều khiển loại xe nào dưới đây là Xe mô tô ba bánh.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1729, 47, 'Người có Giấy phép lái xe mô tô hạng A1 được cấp sau ngày 01/01/2025 được phép điều khiển loại xe nào dưới đây?', '125', '', 'Người có Giấy phép lái xe mô tô hạng A1 được cấp sau ngày 01/01/2025 được phép điều khiển loại xe nào dưới đây là Xe mô tô hai bánh có dung tích xi-lanh đến 125 cm3 hoặc có công suất động cơ điện đến 11 kW.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1730, 47, 'Người có Giấy phép lái xe mô tô hạng A được phép điều khiển loại xe nào dưới đây?', '126', '', 'Người có Giấy phép lái xe mô tô hạng A được phép điều khiển loại xe nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1731, 47, 'Người có Giấy phép lái xe ô tô hạng B được phép điều khiển loại xe nào dưới đây?', '127', '', 'Người có Giấy phép lái xe ô tô hạng B được phép điều khiển loại xe nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1732, 47, 'Người có Giấy phép lái xe hạng C1 được điều khiển loại xe nào dưới đây?', '128', '', 'Người có Giấy phép lái xe hạng C1 được điều khiển loại xe nào dưới đây là Xe ô tô tải và ô tô chuyên dùng có khối lượng toàn bộ theo thiết kế trên 3.500 kg đến 7.500 kg; các loại xe ô tô tải quy định cho giấy phép lái xe hạng C1 kéo rơ moóc có khối lượng ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1733, 47, 'Người có Giấy phép lái xe hạng C được điều khiển loại xe nào dưới đây?', '129', '', 'Người có Giấy phép lái xe hạng C được điều khiển loại xe nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1734, 47, 'Người có Giấy phép lái xe hạng D1 được điều khiển loại xe nào dưới đây?', '130', '', 'Người có Giấy phép lái xe hạng D1 được điều khiển loại xe nào dưới đây là Xe ô tô chở người trên 08 chỗ (không kể chỗ của người lái xe) đến 16 chỗ (không kể chỗ của người lái xe); các loại xe ô tô chở người quy định cho giấy phép lái xe hạng D1 kéo rơ moó', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1735, 47, 'Người có Giấy phép lái xe hạng D2 được điều khiển loại xe nào dưới đây?', '131', '', 'Người có Giấy phép lái xe hạng D2 được điều khiển loại xe nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1736, 47, 'Người có Giấy phép lái xe hạng D được điều khiển loại xe nào dưới đây?', '132', '', 'Người có Giấy phép lái xe hạng D được điều khiển loại xe nào dưới đây là Ý 1 và ý 2.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1737, 47, 'Người có Giấy phép lái xe hạng BE được điều khiển loại xe nào dưới đây?', '133', '', 'Người có Giấy phép lái xe hạng BE được điều khiển loại xe nào dưới đây là Các loại xe ô tô quy định cho giấy phép lái xe hạng B kéo rơ moóc có khối lượng toàn bộ theo thiết kế trên 750 kg.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1738, 47, 'Người có Giấy phép lái xe hạng CE được điều khiển loại xe nào dưới đây?', '134', '', 'Người có Giấy phép lái xe hạng CE được điều khiển loại xe nào dưới đây là Các loại xe ô tô quy định cho giấy phép lái xe hạng C kéo rơ moóc có khối lượng toàn bộ theo thiết kế trên 750 kg; xe ô tô đầu kéo kéo sơ mi rơ moóc.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1739, 47, 'Người có Giấy phép lái xe hạng DE được điều khiển loại xe nào dưới đây?', '135', '', 'Người có Giấy phép lái xe hạng DE được điều khiển loại xe nào dưới đây là Các loại xe ô tô quy định cho giấy phép lái xe hạng D kéo rơ moóc có khối lượng toàn bộ theo thiết kế trên 750 kg; xe ô tô chở khách nối toa.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1740, 47, 'Người tập lái xe ô tô khi tham gia giao thông đường bộ phải bảo đảm các điều kiện nào dưới đây?', '136', '', 'Người tập lái xe ô tô khi tham gia giao thông đường bộ phải bảo đảm các điều kiện nào dưới đây là Phải thực hành trên xe tập lái, trên tuyến đường tập lái và có giáo viên dạy lái bảo trợ tay lái.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1741, 47, 'Người lái xe khi tham gia giao thông đường bộ phải đảm bảo các điều kiện nào dưới đây?', '137', '', 'Người lái xe khi tham gia giao thông đường bộ phải đảm bảo các điều kiện nào dưới đây là Phải đủ tuổi, sức khỏe theo quy định của pháp luật; có giấy phép lái xe đang còn điểm, còn hiệu lực phù hợp với loại xe đang điều khiển do cơ quan có thẩm quyền cấp (', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1742, 47, 'Khi tham gia giao thông đường bộ, người lái xe phải mang theo các giấy tờ gì?', '138', '', 'Khi tham gia giao thông đường bộ, người lái xe phải mang theo các giấy tờ gì là Giấy phép lái xe phù hợp với loại xe đang điều khiển; chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường đối với xe cơ giới theo quy định của pháp luật; chứng nhận bảo', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL);
INSERT INTO `quizzes` (`id`, `quiz_set_id`, `question`, `name`, `image`, `explanation`, `mandatory`, `wrong`, `created_at`, `updated_at`, `tip`, `tip_image`) VALUES
(1743, 47, 'Giấy phép lái xe bị thu hồi trong các trường hợp nào sau đây?', '139', '', 'Giấy phép lái xe bị thu hồi trong các trường hợp nào sau đây là Giấy phép lái xe đã quá thời hạn tạm giữ hoặc hết thời hiệu thi hành quyết định xử phạt vi phạm hành chính theo quy định của pháp luật về xử lý vi phạm hành chính nếu người vi phạm không đến ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1744, 47, 'Người có giấy phép lái xe chưa bị trừ hết 12 điểm, được phục hồi điểm giấy phép lái xe trong trường hợp nào sau đây?', '140', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1745, 47, 'Người có giấy phép lái xe đã bị trừ hết điểm phải làm gì để phục hồi điểm giấy phép lái xe?', '141', '', 'Người có giấy phép lái xe đã bị trừ hết điểm phải làm gì để phục hồi điểm giấy phép lái xe là Sau thời hạn ít nhất là 06 tháng kể từ ngày bị trừ hết điểm, người có phép lái xe được tham gia kiểm tra nội dung kiến thức pháp luật về trật tự, an toàn giao th', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1746, 47, 'Trách nhiệm của tổ chức, cá nhân đứng tên trong giấy chứng nhận đăng ký xe khi chưa thực hiện thu hồi chứng nhận đăng ký xe, biển số xe được quy định như thế nào?', '142', '', 'Trách nhiệm của tổ chức, cá nhân đứng tên trong giấy chứng nhận đăng ký xe khi chưa thực hiện thu hồi chứng nhận đăng ký xe, biển số xe được quy định như thế nào là Tiếp tục chịu trách nhiệm của chủ xe.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1747, 47, 'Để bảo đảm điều kiện tham gia giao thông đường bộ, loại phương tiện nào phải lắp thiết bị giám sát hành trình?', '143', '', 'Để bảo đảm điều kiện tham gia giao thông đường bộ, loại phương tiện nào phải lắp thiết bị giám sát hành trình là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1748, 47, 'Tốc độ khai thác tối đa cho phép đối với xe máy chuyên dùng, xe gắn máy và các loại xe tương tự tham gia giao thông trên đường bộ (trừ đường cao tốc) là bao nhiêu km/h?', '144', '', 'Tốc độ khai thác tối đa cho phép đối với xe máy chuyên dùng, xe gắn máy và các loại xe tương tự tham gia giao thông trên đường bộ (trừ đường cao tốc) là bao nhiêu km/h là 40 km/h.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
