(1762, 47, 'Khi tham gia giao thông trên đoạn đường không có biển báo Cự ly tối thiểu giữa hai xe, trong điều kiện mặt đường khô ráo, không có sương mù, mặt đường không trơn trượt, địa hình bằng phẳng, đường thẳng, tầm nhìn bảo đảm, xe cơ giới đang chạy với tốc độ từ trên 80 km/h đến 100 km/h, người lái xe phải giữ khoảng cách an toàn với xe đang chạy liền trước tối thiểu là bao nhiêu?', '158', '', 'Khi tham gia giao thông trên đoạn đường không có biển báo  là 70 m.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1763, 47, 'Khi tham gia giao thông trên đoạn đường không có biển báo cự ly tối thiểu giữa hai xe, trong điều kiện mặt đường khô ráo, không có sương mù, mặt đường không trơn trượt, địa hình bằng phẳng, đường thẳng, tầm nhìn bảo đảm, xe cơ giới đang chạy với tốc độ từ trên 100 km/h đến 120 km/h, người lái xe phải giữ khoảng cách an toàn với xe đang chạy liền trước tối thiểu là bao nhiêu?', '159', '', 'Khi tham gia giao thông trên đoạn đường không có biển báo  là 100 m.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1764, 47, 'Khi tham gia giao thông trên đoạn đường không có biển báo cự ly tối thiểu giữa hai xe, trong điều kiện mặt đường khô ráo, không có sương mù, mặt đường không trơn trượt, địa hình bằng phẳng, đường thẳng, tầm nhìn bảo đảm, xe cơ giới đang chạy với tốc độ từ trên 60 km/h đến 80 km/h, người lái xe phải giữ khoảng cách an toàn với xe đang chạy liền trước tối thiểu là bao nhiêu?', '160', '', 'Khi tham gia giao thông trên đoạn đường không có biển báo  là 55 m.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1765, 47, 'Khi tham gia giao thông trên đoạn đường không có biển báo cự ly tối thiểu giữa hai xe, trong điều kiện mặt đường khô ráo, không có sương mù, mặt đường không trơn trượt, địa hình bằng phẳng, đường thẳng, tầm nhìn bảo đảm, xe cơ giới đang chạy với tốc độ 60 km/h, người lái xe phải giữ khoảng cách an toàn với xe đang chạy liền trước tối thiểu là bao nhiêu?', '161', '', 'Khi tham gia giao thông trên đoạn đường không có biển báo  là 35 m.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1766, 47, 'Khi điều khiển xe chạy với tốc độ dưới 60 km/h, để bảo đảm khoảng cách an toàn giữa hai xe, người lái xe phải điều khiển xe như thế nào?', '162', '', 'Khi điều khiển xe chạy với tốc độ dưới 60 km/h, để bảo đảm khoảng cách an toàn giữa hai xe, người lái xe phải điều khiển xe như thế nào là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1767, 47, 'Người lái xe phải giảm tốc độ thấp hơn tốc độ tối đa cho phép đến mức cần thiết, chú ý quan sát và chuẩn bị sẵn sàng những tình huống có thể xảy ra để phòng ngừa tai nạn trong các trường hợp nào dưới đây?', '163', '', 'Người lái xe phải giảm tốc độ thấp hơn tốc độ tối đa cho phép đến mức cần thiết, chú ý quan sát và chuẩn bị sẵn sàng những tình huống có thể xảy ra để phòng ngừa tai nạn trong các trường hợp nào dưới đây là Gặp biển báo nguy hiểm và cảnh báo trên đường.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1768, 47, 'Xe đưa đón trẻ em mầm non, học sinh được ưu tiên gì khi tham gia giao thông đường bộ?', '164', '', 'Xe đưa đón trẻ em mầm non, học sinh được ưu tiên gì khi tham gia giao thông đường bộ là Tổ chức phân luồng, điều tiết giao thông, bố trí nơi dừng xe, đỗ xe tại khu vực trường học và tại các điểm trên lộ trình đưa đón trẻ em mầm non, học sinh.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1769, 47, 'Người điều khiển phương tiện tham gia giao thông đường bộ phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây?', '165', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây là Cả ba ý trên.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1770, 47, 'Tại những đoạn đường không bố trí biển báo hạn chế tốc độ, không bố trí biển báo khoảng cách an toàn tối thiểu giữa hai xe, người lái xe phải thực hiện quy định nào dưới đây để bảo đảm an toàn?', '166', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1771, 47, 'Khi gặp xe buýt đang dừng đón, trả khách, người điều khiển xe mô tô phải xử lý như thế nào dưới đây?', '167', '', '', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1772, 47, 'Việc vận chuyển hành khách bằng xe ô tô phải tuân thủ các quy định nào dưới đây?', '168', '', 'Việc vận chuyển hành khách bằng xe ô tô phải tuân thủ các quy định nào dưới đây là Đón, trả hành khách đúng nơi quy định; hướng dẫn sử dụng trang thiết bị an toàn trên xe; có biện pháp giữ gìn vệ sinh trong xe; vận chuyển hành khách đúng lịch trình, lộ tr', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1773, 47, 'Trong hoạt động vận tải đường bộ, các hành vi nào dưới đây bị nghiêm cấm?', '169', '', 'Trong hoạt động vận tải đường bộ, các hành vi nào dưới đây bị nghiêm cấm là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1774, 47, 'Trong hoạt động vận tải hành khách, những hành vi nào dưới đây bị nghiêm cấm?', '170', '', 'Trong hoạt động vận tải hành khách, những hành vi nào dưới đây bị nghiêm cấm là Đe dọa, xúc phạm, tranh giành, lôi kéo hành khách; đe doạ, cưỡng ép hành khách sử dụng dịch vụ ngoài ý muốn; chuyển tải, xuống khách hoặc các hành vi khác nhằm trốn tránh phát', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1775, 47, 'Thời gian lái xe liên tục của người lái xe ô tô kinh doanh vận tải được quy định như thế nào để bảo đảm an toàn giao thông?', '171', '', 'Thời gian lái xe liên tục của người lái xe ô tô kinh doanh vận tải được quy định như thế nào để bảo đảm an toàn giao thông là Không quá 4 giờ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1776, 47, 'Thời gian làm việc của người lái xe ô tô kinh doanh vận tải trong một ngày được quy định như thế nào để bảo đảm an toàn giao thông?', '172', '', 'Thời gian làm việc của người lái xe ô tô kinh doanh vận tải trong một ngày được quy định như thế nào để bảo đảm an toàn giao thông là Không quá 10 giờ trong một ngày.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1777, 47, 'Trước khi xe khởi hành, người lái xe, nhân viên phục vụ trên xe ô tô vận chuyển hành khách có trách nhiệm nào sau đây?', '173', '', 'Trước khi xe khởi hành, người lái xe, nhân viên phục vụ trên xe ô tô vận chuyển hành khách có trách nhiệm nào sau đây là Ý 1 và ý 2.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1778, 47, 'Xe ô tô kinh doanh vận tải chở trẻ em mầm non, học sinh phải đáp ứng các yêu cầu nào dưới đây?', '174', '', 'Xe ô tô kinh doanh vận tải chở trẻ em mầm non, học sinh phải đáp ứng các yêu cầu nào dưới đây là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1779, 47, 'Việc vận chuyển động vật sống khi tham gia giao thông đường bộ phải thực hiện các yêu cầu nào dưới đây?', '175', '', 'Việc vận chuyển động vật sống khi tham gia giao thông đường bộ phải thực hiện các yêu cầu nào dưới đây là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1780, 47, 'Việc vận chuyển hàng hóa nguy hiểm khi tham gia giao thông đường bộ phải chấp hành các quy định nào dưới đây?', '176', '', 'Việc vận chuyển hàng hóa nguy hiểm khi tham gia giao thông đường bộ phải chấp hành các quy định nào dưới đây là Phải có giấy phép vận chuyển; trong trường hợp cần thiết, đơn vị vận chuyển hàng hoá nguy hiểm phải bố trí người áp tải để bảo đảm trật tự, an ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1781, 47, 'Việc lưu hành xe ô tô của người nước ngoài đăng ký tại nước ngoài có tay lái ở bên phải tham gia giao thông tại Việt Nam, xe cơ giới nước ngoài do người nước ngoài đưa vào Việt Nam du lịch được quy định như như thế nào?', '177', '', 'Việc lưu hành xe ô tô của người nước ngoài đăng ký tại nước ngoài có tay lái ở bên phải tham gia giao thông tại Việt Nam, xe cơ giới nước ngoài do người nước ngoài đưa vào Việt Nam du lịch được quy định như như thế nào là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1782, 47, 'Việc sử dụng xe mô tô, xe gắn máy, xe thô sơ để vận chuyển hành khách, hàng hóa phải thực hiện các quy định nào dưới đây để đảm bảo an toàn giao thông?', '178', '', 'Việc sử dụng xe mô tô, xe gắn máy, xe thô sơ để vận chuyển hành khách, hàng hóa phải thực hiện các quy định nào dưới đây để đảm bảo an toàn giao thông là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1783, 47, 'Xe vận chuyển hàng siêu trường, siêu trọng phải thực hiện các quy định nào dưới đây để bảo đảm an toàn giao thông?', '179', '', 'Xe vận chuyển hàng siêu trường, siêu trọng phải thực hiện các quy định nào dưới đây để bảo đảm an toàn giao thông là Phải chạy với tốc độ quy định trong giấy phép và phải có báo hiệu kích thước của hàng; trường hợp cần thiết, phải có người, phương tiện hỗ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1784, 47, 'Xe cứu hộ giao thông đường bộ cần thực hiện yêu cầu nào sau đây để bảo đảm trật tự an toàn giao thông?', '180', '', 'Xe cứu hộ giao thông đường bộ cần thực hiện yêu cầu nào sau đây để bảo đảm trật tự an toàn giao thông là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1785, 48, 'Người lái xe kinh doanh vận tải khi thực hiện tốt việc rèn luyện, nâng cao trách nhiệm, đạo đức nghề nghiệp sẽ thu được kết quả như thế nào dưới đây?', '181', '', 'Người lái xe kinh doanh vận tải khi thực hiện tốt việc rèn luyện, nâng cao trách nhiệm, đạo đức nghề nghiệp sẽ thu được kết quả như thế nào dưới đây là Được khách hàng, xã hội tôn trọng; được đồng nghiệp quý mến, giúp đỡ; được doanh nghiệp tin dùng và đón', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1786, 48, 'Những hành vi nào sau đây thể hiện là người có văn hóa giao thông?', '182', '', 'Những hành vi nào sau đây thể hiện là người có văn hóa giao thông là Luôn tuân thủ pháp luật về trật tự, an toàn giao thông đường bộ, nhường nhịn và giúp đỡ người khác.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1787, 48, 'Người lái xe kinh doanh vận tải cần thực hiện những công việc gì ghi ở dưới đây để thường xuyên rèn luyện nâng cao đạo đức nghề nghiệp?', '183', '', 'Người lái xe kinh doanh vận tải cần thực hiện những công việc gì ghi ở dưới đây để thường xuyên rèn luyện nâng cao đạo đức nghề nghiệp là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1788, 48, 'Người lái xe ô tô vận chuyển hành khách phải có những phẩm chất, đạo đức nghề nghiệp gì dưới đây?', '184', '', 'Người lái xe ô tô vận chuyển hành khách phải có những phẩm chất, đạo đức nghề nghiệp gì dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1789, 48, 'Khái niệm về văn hóa giao thông được hiểu như thế nào là đúng?', '185', '', 'Khái niệm về văn hóa giao thông được hiểu như thế nào là đúng là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1790, 48, 'Trên làn đường dành cho ô tô có vũng nước lớn, người lái xe ô tô bắt buộc phải đi qua vũng nước, trên làn đường bên cạnh có nhiều người đang lái xe mô tô tham gia giao thông, người lái xe ô tô xử lý như thế nào khi lái xe qua vũng nước là có văn hóa giao thông?', '186', '', 'Trên làn đường dành cho ô tô có vũng nước lớn, người lái xe ô tô bắt buộc phải đi qua vũng nước, trên làn đường bên cạnh có nhiều người đang lái xe mô tô tham gia giao thông, người lái xe ô tô xử lý như thế nào khi lái xe qua vũng nước là có văn hóa giao ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1791, 48, 'Người lái xe không điều khiển xe đi đúng làn đường quy định, phóng nhanh, vượt ẩu, vượt đèn đỏ, đi vào đường cấm được coi là hành vi nào trong các hành vi dưới đây?', '187', '', 'Người lái xe không điều khiển xe đi đúng làn đường quy định, phóng nhanh, vượt ẩu, vượt đèn đỏ, đi vào đường cấm được coi là hành vi nào trong các hành vi dưới đây là Là thiếu văn hóa giao thông, vi phạm pháp luật về trật tự, an toàn giao thông đường bộ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1792, 48, 'Khi sơ cứu người bị tai nạn giao thông đường bộ, có vết thương chảy máu ngoài, phun thành tia và phun mạnh khi mạch đập, bạn phải làm gì dưới đây?', '188', '', 'Khi sơ cứu người bị tai nạn giao thông đường bộ, có vết thương chảy máu ngoài, phun thành tia và phun mạnh khi mạch đập, bạn phải làm gì dưới đây là Thực hiện cầm máu không trực tiếp (chặn động mạch).', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1793, 48, 'Người lái xe có văn hóa giao thông khi tham gia giao thông đường bộ phải đáp ứng các điều kiện nào dưới đây?', '189', '', 'Người lái xe có văn hóa giao thông khi tham gia giao thông đường bộ phải đáp ứng các điều kiện nào dưới đây là Hiểu biết và chấp hành nghiêm chỉnh pháp luật về giao thông đường bộ; có ý thức trách nhiệm với cộng đồng khi tham gia giao thông; tôn trọng, nh', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1794, 48, 'Người lái xe có văn hóa giao thông khi tham gia giao thông phải tuân thủ những quy định nào dưới đây?', '190', '', 'Người lái xe có văn hóa giao thông khi tham gia giao thông phải tuân thủ những quy định nào dưới đây là Chấp hành hiệu lệnh, chỉ dẫn của người điều khiển giao thông, quy định về tốc độ, tín hiệu đèn, biển báo hiệu, vạch kẻ đường khi lái xe; nhường đường c', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1795, 48, 'Người lái xe mô tô có văn hóa giao thông khi tham gia giao thông phải tuân thủ những quy định nào dưới đây?', '191', '', 'Người lái xe mô tô có văn hóa giao thông khi tham gia giao thông phải tuân thủ những quy định nào dưới đây là Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; đội mũ bảo hiểm đúng quy chuẩn kỹ thuật quốc gia, cài q', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1796, 48, 'Trong các hành vi dưới đây, người lái xe có văn hóa giao thông phải ứng xử như thế nào?', '192', '', 'Trong các hành vi dưới đây, người lái xe có văn hóa giao thông phải ứng xử như thế nào là Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; dừng, đỗ xe đúng nơi quy định; đã uống rượu, bia thì không lái xe.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1797, 48, 'Khi tham gia giao thông việc sử dụng còi xe nên dùng như thế nào để thể hiện là người có văn hóa giao thông?', '193', '', 'Khi tham gia giao thông việc sử dụng còi xe nên dùng như thế nào để thể hiện là người có văn hóa giao thông là Chỉ bấm còi khi thật sự cần thiết, không bấm còi liên tục hoặc kéo dài, sử dụng còi với mức âm lượng theo quy định.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1798, 48, 'Người điều khiển phương tiện tham giao thông đường bộ gây ra tai nạn giao thông đường bộ, người liên quan đến vụ tai nạn giao thông đường bộ có trách nhiệm gì dưới đây?', '194', '', 'Người điều khiển phương tiện tham giao thông đường bộ gây ra tai nạn giao thông đường bộ, người liên quan đến vụ tai nạn giao thông đường bộ có trách nhiệm gì dưới đây là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1799, 48, 'Người có mặt tại nơi xảy ra vụ tai giao thông đường bộ có trách nhiệm gì dưới đây?', '195', '', 'Người có mặt tại nơi xảy ra vụ tai giao thông đường bộ có trách nhiệm gì dưới đây là Giúp đỡ, cứu chữa kịp thời người bị nạn; báo tin ngay cho cơ quan Công an, cơ sở khám bệnh, chữa bệnh hoặc Ủy ban nhân dân nơi gần nhất; tham gia bảo vệ hiện trường; tham', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1800, 48, 'Khi sơ cứu ban đầu cho người bị tai nạn giao thông đường bộ không còn hô hấp, người lái xe và người có mặt tại hiện trường vụ tai nạn phải thực hiện các công việc gì dưới đây?', '196', '', 'Khi sơ cứu ban đầu cho người bị tai nạn giao thông đường bộ không còn hô hấp, người lái xe và người có mặt tại hiện trường vụ tai nạn phải thực hiện các công việc gì dưới đây là Đặt nạn nhân nằm ngửa, khai thông đường thở của nạn nhân; thực hiện các biện ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1801, 48, 'Hành vi bỏ trốn sau khi gây tai nạn để trốn tránh trách nhiệm hoặc khi có điều kiện mà cố ý không cứu giúp người bị tai nạn giao thông có bị nghiêm cấm hay không?', '197', '', 'Hành vi bỏ trốn sau khi gây tai nạn để trốn tránh trách nhiệm hoặc khi có điều kiện mà cố ý không cứu giúp người bị tai nạn giao thông có bị nghiêm cấm hay không là Bị nghiêm cấm.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1802, 48, 'Khi đang lái xe, thấy một người đi bộ đang sang đường trên vạch kẻ đường dành cho người đi bộ, người lái xe nên làm gì?', '198', '', 'Khi đang lái xe, thấy một người đi bộ đang sang đường trên vạch kẻ đường dành cho người đi bộ, người lái xe nên làm gì là Giảm tốc độ và nhường đường cho người đi bộ.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1803, 48, 'Khi gặp vụ tai nạn giao thông, người lái xe nên hành động như thế nào?', '199', '', 'Khi gặp vụ tai nạn giao thông, người lái xe nên hành động như thế nào là Dừng xe, hỗ trợ nạn nhân và báo cho cơ quan chức năng.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1804, 48, 'Trong đoạn đường hai chiều tại khu đông dân cư đang ùn tắc, người điều khiển xe mô tô có văn hóa giao thông sẽ lựa chọn cách xử lý tình huống nào dưới đây?', '200', '', 'Trong đoạn đường hai chiều tại khu đông dân cư đang ùn tắc, người điều khiển xe mô tô có văn hóa giao thông sẽ lựa chọn cách xử lý tình huống nào dưới đây là Kiên nhẫn tuân thủ hướng dẫn của người điều khiển giao thông hoặc tín hiệu đèn giao thông, di chu', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1805, 48, 'Khi điều khiển phương tiện tham gia giao thông trên đoạn đường bộ đang xảy ra ùn tắc, những hành vi nào dưới đây là thiếu văn hóa?', '201', '', 'Khi điều khiển phương tiện tham gia giao thông trên đoạn đường bộ đang xảy ra ùn tắc, những hành vi nào dưới đây là thiếu văn hóa là Bấm còi liên tục thúc giục các phương tiện phía trước nhường đường; đi trên vỉa hè, tận dụng mọi khoảng trống để nhanh chó', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1806, 48, 'Người lái xe, chủ phương tiện giao thông cơ giới đường bộ nên thực hiện các biện pháp phòng cháy, chữa cháy như thế nào dưới đây?', '202', '', 'Người lái xe, chủ phương tiện giao thông cơ giới đường bộ nên thực hiện các biện pháp phòng cháy, chữa cháy như thế nào dưới đây là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1807, 48, 'Người điều khiển phương tiện cơ giới đường bộ phải thực hiện những biện pháp gì dưới đây để chữa cháy trong trường hợp phương tiện bị cháy, xét thấy có khả năng dập tắt đám cháy?', '203', '', 'Người điều khiển phương tiện cơ giới đường bộ phải thực hiện những biện pháp gì dưới đây để chữa cháy trong trường hợp phương tiện bị cháy, xét thấy có khả năng dập tắt đám cháy là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1808, 48, 'Khi phát hiện thấy có ngọn lửa, khói hoặc nhiệt độ cao bất thường từ phương tiện giao thông do mình điều khiển người lái xe phải làm gì trước tiên?', '204', '', 'Khi phát hiện thấy có ngọn lửa, khói hoặc nhiệt độ cao bất thường từ phương tiện giao thông do mình điều khiển người lái xe phải làm gì trước tiên là Bình tĩnh, đưa xe sát vào lề đường, tránh xa nơi có nhiều người, nhiều chất dễ cháy và tắt khóa điện, thự', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1809, 48, 'Khi gặp nạn nhân bị bỏng trong vụ tai nạn giao thông, người lái xe cần làm gì?', '205', '', 'Khi gặp nạn nhân bị bỏng trong vụ tai nạn giao thông, người lái xe cần làm gì là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1810, 49, 'Khi điều khiển xe mô tô tay ga xuống đường dốc dài, độ dốc cao, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn?', '206', '', 'Khi điều khiển xe mô tô tay ga xuống đường dốc dài, độ dốc cao, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn là Giữ tay ga ở mức độ phù hợp, sử dụng phanh trước và phanh sau để giảm tốc độ.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1811, 49, 'Khi vào số để khởi hành xe ô tô có số tự động, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn?', '207', '', 'Khi vào số để khởi hành xe ô tô có số tự động, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn là Đạp bàn đạp phanh chân hết hành trình, vào số và nhả phanh đỗ, kiểm tra lại xem có bị nhầm số không rồi mới cho xe lăn bánh.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1812, 49, 'Khi nhả phanh đỗ cơ khí điều khiển bằng tay (phanh tay), người lái xe cần phải thực hiện các thao tác nào?', '208', '', 'Khi nhả phanh đỗ cơ khí điều khiển bằng tay (phanh tay), người lái xe cần phải thực hiện các thao tác nào là Dùng lực tay phải bóp khóa hãm đẩy cần phanh tay về phía trước hết hành trình; nếu khóa hãm bị kẹt cứng phải kéo cần phanh tay về phía sau đồng th', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1813, 49, 'Khi khởi hành ô tô sử dụng hộp số cơ khí trên đường bằng, người lái xe cần thực hiện các thao tác nào theo trình tự dưới đây?', '209', '', 'Khi khởi hành ô tô sử dụng hộp số cơ khí trên đường bằng, người lái xe cần thực hiện các thao tác nào theo trình tự dưới đây là Kiểm tra an toàn xung quanh xe ô tô; đạp ly hợp (côn) hết hành trình; vào số 1; nhả hết phanh tay, báo hiệu bằng còi, đèn trước', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1814, 49, 'Khi quay đầu xe, người lái xe cần phải quan sát và thực hiện các thao tác nào để bảo đảm an toàn giao thông?', '210', '', 'Khi quay đầu xe, người lái xe cần phải quan sát và thực hiện các thao tác nào để bảo đảm an toàn giao thông là Quan sát biển báo hiệu để biết nơi được phép quay đầu; quan sát kỹ địa hình nơi chọn để quay đầu; lựa chọn quỹ đạo quay đầu xe cho thích hợp; qu', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1815, 49, 'Khi ngồi lái ô tô tư thế chân, lưng, tay của người lái xe như thế nào là đúng để bảo đảm an toàn và thoải mái?', '211', '', 'Khi ngồi lái ô tô tư thế chân, lưng, tay của người lái xe như thế nào là đúng để bảo đảm an toàn và thoải mái là Điều chỉnh ghế sao cho chân có thể đạp phanh và ga dễ dàng, ngồi thẳng lưng, hai tay nắm vô lăng, tay trái nắm ở vị trí 9 đến 10 giờ và tay ph', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1816, 49, 'Khi điều khiển ô tô lên dốc cao, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn?', '212', '', 'Khi điều khiển ô tô lên dốc cao, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn là Tăng lên số cao từ chân dốc, điều chỉnh ga cho xe nhanh lên dốc; đến gần đỉnh dốc phải tăng ga để xe nhanh chóng qua dốc; về số thấp, đi sát về phí', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1817, 49, 'Khi điều khiển ô tô xuống dốc dài, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn?', '213', '', 'Khi điều khiển ô tô xuống dốc dài, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn là Về số thấp, nhả bàn đạp ga ở mức độ phù hợp, kết hợp với phanh chân để khống chế tốc độ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1818, 49, 'Khi xuống dốc, muốn dừng xe, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn?', '214', '', 'Khi xuống dốc, muốn dừng xe, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn là Có tín hiệu rẽ phải, điều khiển xe sát vào lề đường bên phải; đạp phanh sớm và mạnh hơn lúc dừng xe trên đường bằng để xe đi với tốc độ chậm đến mức dễ dàng dừn', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1819, 49, 'Khi điều khiển xe trên đường vòng người lái xe cần phải làm gì để bảo đảm an toàn?', '215', '', 'Khi điều khiển xe trên đường vòng người lái xe cần phải làm gì để bảo đảm an toàn là Quan sát cẩn thận các chướng ngại vật và báo hiệu bằng coi, đèn; giảm tốc độ tới mức cần thiết, về số thấp và thực hiện quay vòng với tốc độ phù hợp với bán kính cong của', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1820, 49, 'Khi điều khiển xe ô tô rẽ phải, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn?', '216', '', 'Khi điều khiển xe ô tô rẽ phải, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn là Cách chỗ rẽ một khoảng cách an toàn có tín hiệu rẽ phải; giảm tốc độ, quan sát an toàn phía trước, sau, bên phải và điều khiển xe từ từ rẽ phải.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1821, 49, 'Khi điều khiển xe ô tô rẽ trái, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn?', '217', '', 'Khi điều khiển xe ô tô rẽ trái, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn là Cách chỗ rẽ một khoảng cách an toàn có tín hiệu rẽ trái; giảm tốc độ, quan sát an toàn xung quanh đặc biệt là bên trái; đổi sang làn đường bên trái và điều k', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1822, 49, 'Khi điều khiển xe sử dụng hộp số cơ khí vượt qua rãnh lớn cắt ngang mặt đường, người lái xe cần thực hiện các thao tác nào để đảm bảo an toàn?', '218', '', 'Khi điều khiển xe sử dụng hộp số cơ khí vượt qua rãnh lớn cắt ngang mặt đường, người lái xe cần thực hiện các thao tác nào để đảm bảo an toàn là Vào số một (1) và từ từ cho hai bánh xe trước xuống rãnh, tăng ga cho hai bánh xe trước vượt lên khỏi rãnh, ti', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1823, 49, 'Khi điều khiển xe qua đường sắt, người lái xe cần phải thực hiện các thao tác nào dưới đây để bảo đảm an toàn?', '219', '', 'Khi điều khiển xe qua đường sắt, người lái xe cần phải thực hiện các thao tác nào dưới đây để bảo đảm an toàn là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1824, 49, 'Khi điều khiển xe ô tô tự đổ, người lái xe cần chú ý những điểm gì để  bảo đảm an toàn?', '220', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1825, 49, 'Khi điều khiển xe tăng số, người lái xe cần chú ý những điểm gì để bảo đảm an toàn?', '221', '', 'Khi điều khiển xe tăng số, người lái xe cần chú ý những điểm gì để bảo đảm an toàn là Không được nhìn xuống buồng lái, cần phải tăng thứ tự từ thấp đến cao, phối hợp các động tác phải nhịp nhàng, chính xác.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1826, 49, 'Khi điều khiển xe giảm số, người lái xe cần phải chú ý những điểm gì để bảo đảm an toàn?', '222', '', 'Khi điều khiển xe giảm số, người lái xe cần phải chú ý những điểm gì để bảo đảm an toàn là Không được nhìn xuống buồng lái, cần phải giảm thứ tự từ cao xuống thấp, phối hợp các động tác phải nhịp nhàng, chính xác, vù ga phải phù hợp với tốc độ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1827, 49, 'Để giảm tốc độ khi ô tô đi xuống đường dốc dài, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn?', '223', '', 'Để giảm tốc độ khi ô tô đi xuống đường dốc dài, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn là Về số thấp phù hợp, nhả bàn đạp ga, kết hợp đạp phanh chân với mức độ phù hợp để giảm tốc độ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1828, 49, 'Khi điều khiển ô tô qua đường ngập nước, người lái xe cần thực hiện các thao tác nào để đảm bảo an toàn?', '224', '', 'Khi điều khiển ô tô qua đường ngập nước, người lái xe cần thực hiện các thao tác nào để đảm bảo an toàn là Quan sát, ước lượng độ ngập nước mà xe ô tô có thể vượt qua an toàn, về số thấp, giữ đều ga và giữ vững tay lái để ô tô vượt qua đoạn đường ngập nướ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1829, 49, 'Khi điều khiển xe ô tô tới gần xe chạy ngược chiều vào ban đêm, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn?', '225', '', 'Khi điều khiển xe ô tô tới gần xe chạy ngược chiều vào ban đêm, người lái xe cần thực hiện các thao tác nào để bảo đảm an toàn là Chuyển từ đèn chiếu xa sang đèn chiếu gần; không nhìn thẳng vào đèn của xe chạy ngược chiều mà nhìn chếch sang phía phải theo', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1830, 49, 'Khi điều khiển xe ô tô trên đường trơn cần chú ý những điểm gì để bảo đảm an toàn?', '226', '', 'Khi điều khiển xe ô tô trên đường trơn cần chú ý những điểm gì để bảo đảm an toàn là Giữ vững tay lái cho xe đi đúng vệt bánh xe đi trước, sử dụng số thấp đi chậm, gài cầu (nếu có), giữ đều ga, không lấy nhiều lái, không đánh lái ngoặt và phanh gấp.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1831, 49, 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô?', '227', 'oto/227.webp', 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô là Đang sử dụng phanh đỗ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1832, 49, 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô?', '228', 'oto/228.webp', 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô là Nhiệt độ nước làm mát tăng quá mức cho phép.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1833, 49, 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô?', '229', 'oto/229.webp', 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô là Cửa xe đóng chưa chặt hoặc có cửa xe chưa đóng.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1834, 49, 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô?', '230', 'oto/230.webp', 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô là Lái xe và người ngồi ghế trước chưa cài dây đai an toàn.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1835, 49, 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô?', '231', 'oto/231.webp', 'Khi động cơ xe ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây là báo hiệu tình trạng gì của xe ô tô là Báo hiệu thiếu dầu phanh.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1836, 49, 'Trong các loại nhiên liệu dưới đây, loại nhiên liệu nào giảm thiểu ô nhiễm môi trường?', '232', '', 'Trong các loại nhiên liệu dưới đây, loại nhiên liệu nào giảm thiểu ô nhiễm môi trường là Xăng sinh học và khí sinh học.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1837, 49, 'Các biện pháp tiết kiệm nhiên liệu khi chạy xe?', '233', '', 'Các biện pháp tiết kiệm nhiên liệu khi chạy xe là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1838, 49, 'Khi đã đỗ xe ô tô sát lề đường bên phải, người lái xe phải thực hiện các thao tác nào dưới đây khi mở cửa xuống xe để đảm bảo an toàn?', '234', '', '', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1839, 49, 'Khi điều khiển xe ô tô qua đường sắt không có rào chắn, không có người điều khiển giao thông, người lái xe phải xử lý như thế nào?', '235', '', 'Khi điều khiển xe ô tô qua đường sắt không có rào chắn, không có người điều khiển giao thông, người lái xe phải xử lý như thế nào là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1840, 49, 'Khi lái xe ô tô qua đường sắt không có rào chắn, không có người điều khiển giao thông, người lái xe thực hiện thao tác: “giảm tốc độ, dừng lại trước vạch dừng, quan sát cả hai phía, nếu không có tàu đi tới, tăng ga nhẹ vượt qua đường sắt. Nếu thấy có tàu đi tới thì dừng lại trước vạch dừng, chỉ khi tàu đi qua mới được đi” để đảm bảo an toàn là đúng hay không?', '236', '', 'Khi lái xe ô tô qua đường sắt không có rào chắn, không có người điều khiển giao thông, người lái xe thực hiện thao tác: “giảm tốc độ, dừng lại trước vạch dừng, quan sát cả hai phía, nếu không có tàu đi tới, tăng ga nhẹ vượt qua đường sắt. Nếu thấy có tàu ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1841, 49, 'Khi điều khiển xe ô tô có hộp số tự động đi vào đường trơn trượt, lầy lội, người lái xe phải xử lý như thế nào để đảm bảo an toàn?', '237', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1842, 49, 'Khi động cơ ô tô đã khởi động, muốn điều chỉnh ghế của người lái, người lái xe phải để cần số ở vị trí nào?', '238', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1843, 49, 'Khi điều khiển xe ô tô có hộp số tự động, người lái xe sử dụng chân như thế nào là đúng để bảo đảm an toàn?', '239', '', 'Khi điều khiển xe ô tô có hộp số tự động, người lái xe sử dụng chân như thế nào là đúng để bảo đảm an toàn là Không sử dụng chân trái; chân phải điều khiển bàn đạp phanh và bàn đạp ga.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1844, 49, 'Khi tầm nhìn bị hạn chế bởi sương mù hoặc mưa to, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn?', '240', '', 'Khi tầm nhìn bị hạn chế bởi sương mù hoặc mưa to, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn là Giảm tốc độ, chạy cách xa xe trước với khoảng cách an toàn, bật đèn sương mù và đèn chiếu gần.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1845, 49, 'Khi đèn pha của xe đi ngược chiều gây chói mắt, làm giảm khả năng quan sát trên đường, người lái xe xử lý như thế nào dưới đây để bảo đảm an toàn?', '241', '', 'Khi đèn pha của xe đi ngược chiều gây chói mắt, làm giảm khả năng quan sát trên đường, người lái xe xử lý như thế nào dưới đây để bảo đảm an toàn là Giảm tốc độ, giữ vững tay lái, nhìn chếch sang lề đường bên phải.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1846, 49, 'Để đạt được hiệu quả phanh cao nhất, người lái xe mô tô phải sử dụng các kỹ năng như thế nào dưới đây?', '242', '', 'Để đạt được hiệu quả phanh cao nhất, người lái xe mô tô phải sử dụng các kỹ năng như thế nào dưới đây là Giảm hết ga, sử dụng đồng thời cả phanh sau và phanh trước.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1847, 49, 'Khi lái xe ô tô trên mặt đường có nhiều ổ gà, người lái xe phải thực hiện thao tác như thế nào để bảo đảm an toàn?', '243', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1848, 49, 'Khi điều khiển xe ô tô gặp mưa to hoặc sương mù, người lái xe phải làm gì để bảo đảm an toàn?', '244', '', 'Khi điều khiển xe ô tô gặp mưa to hoặc sương mù, người lái xe phải làm gì để bảo đảm an toàn là Bật đèn chiếu gần và đèn vàng (nếu có), điều khiển gạt nước, điều khiển ô tô đi với tốc độ chậm để có thể quan sát được; tìm chỗ an toàn dừng xe, bật đèn dừng ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1849, 49, 'Điều khiển xe ô tô trong trời mưa, người lái xe phải xử lý như thế nào để bảo đảm an toàn?', '245', '', 'Điều khiển xe ô tô trong trời mưa, người lái xe phải xử lý như thế nào để bảo đảm an toàn là Giảm tốc độ, tăng cường quan sát, không nên phanh gấp, không nên tăng ga hay đánh vô lăng đột ngột, bật đèn chiếu gần, mở chế độ gạt nước ở chế độ phù hợp để đảm ', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1850, 49, 'Khi lùi xe, người lái xe phải xử lý như thế nào để bảo đảm an toàn giao thông?', '246', '', 'Khi lùi xe, người lái xe phải xử lý như thế nào để bảo đảm an toàn giao thông là Quan sát bên trái, bên phải, phía sau xe, có tín hiệu cần thiết và lùi xe với tốc độ phù hợp.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1851, 49, 'Điều khiển xe ô tô trong khu vực đông dân cư cần lưu ý điều gì dưới đây?', '247', '', 'Điều khiển xe ô tô trong khu vực đông dân cư cần lưu ý điều gì dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1852, 49, 'Khi điều khiển xe ô tô nhập vào đường cao tốc người lái xe cần thực hiện như thế nào dưới đây để bảo đảm an toàn giao thông?', '248', '', 'Khi điều khiển xe ô tô nhập vào đường cao tốc người lái xe cần thực hiện như thế nào dưới đây để bảo đảm an toàn giao thông là Quan sát, phát tín hiệu, nhường đường cho các xe đang chạy trên đường cao tốc, khi đủ điều kiện an toàn thì tăng tốc độ cho xe n', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1853, 49, 'Khi điều khiển xe ô tô ra khỏi đường cao tốc người lái xe cần thực hiện như thế nào dưới đây để bảo đảm an toàn giao thông?', '249', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1854, 49, 'Người lái xe được dừng xe, đỗ xe trên làn dừng khẩn cấp của đường cao tốc trong trường hợp nào dưới đây?', '250', '', 'Người lái xe được dừng xe, đỗ xe trên làn dừng khẩn cấp của đường cao tốc trong trường hợp nào dưới đây là Xe gặp sự cố, tai nạn hoặc trường hợp khẩn cấp không thể di chuyển bình thường.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1855, 49, 'Trên đường đôi muốn vượt xe kéo rơ moóc phía trước, người lái xe phải xử lý như thế nào?', '251', '', 'Trên đường đôi muốn vượt xe kéo rơ moóc phía trước, người lái xe phải xử lý như thế nào là Khi vượt qua, phải quan sát gương chiếu hậu bên phải nếu có khoảng trống an toàn mới được cho xe chạy vào làn của mình, tắt xi nhan và tiếp tục hành trình.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1856, 49, 'Khi điều khiển xe ô tô xuống đường dốc dài, độ dốc cao, người lái xe số tự động cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn?', '252', '', 'Khi điều khiển xe ô tô xuống đường dốc dài, độ dốc cao, người lái xe số tự động cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn là Nhả bàn đạp ga, về số thấp, đạp phanh chân với mức độ phù hợp để giảm tốc độ.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1857, 49, 'Khi đi từ đường nhánh ra đường chính, người lái xe phải xử lý như thế nào là đúng?', '253', '', 'Khi đi từ đường nhánh ra đường chính, người lái xe phải xử lý như thế nào là đúng là Quan sát, giảm tốc độ, phát tín hiệu, nhường đường cho xe trên đường chính từ bất kỳ hướng nào tới.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1858, 49, 'Khi đang lái xe mô tô hoặc ô tô, nếu có nhu cầu sử dụng điện thoại để nhắn tin hoặc gọi điện, người lái xe phải thực hiện như thế nào trong các tình huống nêu dưới đây?', '254', '', 'Khi đang lái xe mô tô hoặc ô tô, nếu có nhu cầu sử dụng điện thoại để nhắn tin hoặc gọi điện, người lái xe phải thực hiện như thế nào trong các tình huống nêu dưới đây là Giảm tốc độ để dừng xe ở nơi cho phép sau đó sử dụng điện thoại để liên lạc.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1859, 49, 'Những thói quen nào dưới đây khi điều khiển xe mô tô tay ga tham gia giao thông dễ gây tai nạn nguy hiểm?', '255', '', 'Những thói quen nào dưới đây khi điều khiển xe mô tô tay ga tham gia giao thông dễ gây tai nạn nguy hiểm là Phanh đồng thời cả phanh trước và phanh sau.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1860, 49, 'Người ngồi trên xe ô tô cần thực hiện những thao tác mở cửa như thế nào dưới đây để xuống xe để bảo đảm an toàn?', '256', '', 'Người ngồi trên xe ô tô cần thực hiện những thao tác mở cửa như thế nào dưới đây để xuống xe để bảo đảm an toàn là Quan sát phía trước, phía sau và bên phía mở cửa để phát hiện các phương tiện đang di chuyển tới gần, khi đủ điều kiện an toàn, mở hé cửa, s', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1861, 49, 'Khi điều khiển xe mô tô quay đầu, người lái xe cần thực hiện như thế nào để bảo đảm an toàn?', '257', '', 'Khi điều khiển xe mô tô quay đầu, người lái xe cần thực hiện như thế nào để bảo đảm an toàn là Quan sát an toàn các phương tiện tới từ phía trước, phía sau, hai bên đồng thời nhường đường cho xe từ bên phải và phía trước đi tới.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1862, 49, 'Tay ga trên xe mô tô hai bánh có tác dụng gì dưới đây?', '258', '', 'Tay ga trên xe mô tô hai bánh có tác dụng gì dưới đây là Ý 1 và ý 2.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1863, 49, 'Gương chiếu hậu của xe mô tô hai bánh có tác dụng gì dưới đây?', '259', '', 'Gương chiếu hậu của xe mô tô hai bánh có tác dụng gì dưới đây là Để quan sát an toàn phía sau của bên trái và bên phải trước khi chuyển hướng.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1864, 49, 'Để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô hai bánh cần điều khiển tay ga như thế nào?', '260', '', 'Để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô hai bánh cần điều khiển tay ga như thế nào là Tăng ga thật mạnh, giảm ga thật nhanh.', 1, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1865, 49, 'Để tránh đổ, ngã khi điều khiển xe mô tô hai bánh ở nơi đường xấu, nhỏ và hẹp, người lái xe cần xử lý như thế nào?', '261', '', 'Để tránh đổ, ngã khi điều khiển xe mô tô hai bánh ở nơi đường xấu, nhỏ và hẹp, người lái xe cần xử lý như thế nào là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1866, 49, 'Khi lái xe ô tô điện xuống dốc dài, đổ đèo, người lái xe cần chú ý những vấn đề gì để bảo đảm an toàn?', '262', '', 'Khi lái xe ô tô điện xuống dốc dài, đổ đèo, người lái xe cần chú ý những vấn đề gì để bảo đảm an toàn là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1867, 49, 'Khi lái xe ô tô điện qua khu vực ngập nước, người lái xe cần phải chú ý những vấn đề gì?', '263', '', 'Khi lái xe ô tô điện qua khu vực ngập nước, người lái xe cần phải chú ý những vấn đề gì là Cả ba ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1868, 50, 'Phương pháp kiểm tra mức dầu bôi trơn động cơ nào dưới đây là đúng?', '264', '', 'Phương pháp kiểm tra mức dầu bôi trơn động cơ nào dưới đây là đúng là Rút que thăm dầu trên các-te, lau sạch que thăm sau đó cắm vào các-te và rút ra quan sát vệt dầu trên que thăm, mức dầu phải nằm trong khoảng vạch mức tối thiểu và tối đa được thể hiện ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL);
INSERT INTO `quizzes` (`id`, `quiz_set_id`, `question`, `name`, `image`, `explanation`, `mandatory`, `wrong`, `created_at`, `updated_at`, `tip`, `tip_image`) VALUES
(1869, 50, 'Xe ô tô tham gia giao thông đường bộ phải bảo đảm các quy định về chất lượng, an toàn kỹ thuật và bảo vệ môi trường nào dưới đây?', '265', '', 'Xe ô tô tham gia giao thông đường bộ phải bảo đảm các quy định về chất lượng, an toàn kỹ thuật và bảo vệ môi trường nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1870, 50, 'Xe mô tô và xe ô tô tham gia giao thông trên đường bộ có bắt buộc phải đủ bộ phận giảm thanh không?', '266', '', 'Xe mô tô và xe ô tô tham gia giao thông trên đường bộ có bắt buộc phải đủ bộ phận giảm thanh không là Bắt buộc.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1871, 50, 'Xe ô tô tham gia giao thông trên đường bộ phải có đủ các loại đèn nào dưới đây?', '267', '', 'Xe ô tô tham gia giao thông trên đường bộ phải có đủ các loại đèn nào dưới đây là Ý 1 và ý 2.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1872, 50, 'Kính chắn gió của xe ô tô phải bảo đảm yêu cầu nào dưới đây?', '268', '', 'Kính chắn gió của xe ô tô phải bảo đảm yêu cầu nào dưới đây là Là loại kính an toàn, kính nhiều lớp, đúng quy cách, không rạn nứt, bảo đảm hình ảnh quan sát rõ ràng, không bị méo mó.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1873, 50, 'Bánh xe, lốp lắp cho xe ô tô phải bảo đảm an toàn kỹ thuật như thế nào dưới đây?', '269', '', 'Bánh xe, lốp lắp cho xe ô tô phải bảo đảm an toàn kỹ thuật như thế nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1874, 50, 'Hệ thống lái trên xe ô tô phải bảo đảm yêu cầu nào dưới đây?', '270', '', 'Hệ thống lái trên xe ô tô phải bảo đảm yêu cầu nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1875, 50, 'Mục đích của bảo dưỡng thường xuyên đối với xe ô tô có tác dụng gì dưới đây?', '271', '', 'Mục đích của bảo dưỡng thường xuyên đối với xe ô tô có tác dụng gì dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1876, 50, 'Trong các nguyên nhân nêu dưới đây, nguyên nhân nào làm động cơ diesel không nổ?', '272', '', 'Trong các nguyên nhân nêu dưới đây, nguyên nhân nào làm động cơ diesel không nổ là Hết nhiên liệu, lõi lọc nhiên liệu bị tắc, lọc khí bị tắc, nhiên liệu lẫn không khí, tạp chất.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1877, 50, 'Ống xả lắp trên xe ô tô phải bảo đảm yêu cầu an toàn kỹ thuật nào dưới đây?', '273', '', 'Ống xả lắp trên xe ô tô phải bảo đảm yêu cầu an toàn kỹ thuật nào dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1878, 50, 'Dây đai an toàn lắp trên xe ô tô phải bảo đảm yêu cầu an toàn kỹ thuật nào dưới đây?', '274', '', 'Dây đai an toàn lắp trên xe ô tô phải bảo đảm yêu cầu an toàn kỹ thuật nào dưới đây là Đủ số lượng, lắp đặt chắc chắn không bị rách, đứt, khóa cài đóng, mở nhẹ nhàng, không tự mở, không bị kẹt; kéo ra thu vào dễ dàng, cơ cấu hãm giữ chặt dây khi giật dây ', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1879, 50, 'Thế nào là động cơ 4 kỳ?', '275', '', 'Thế nào là động cơ 4 kỳ là Là loại động cơ: để hoàn thành một chu trình công tác của động cơ, pít tông thực hiện 4 (bốn) hành trình, trong đó có một lần sinh công.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1880, 50, 'Công dụng của hệ thống bôi trơn đối với động cơ ô tô?', '276', '', 'Công dụng của hệ thống bôi trơn đối với động cơ ô tô là Cung cấp một lượng dầu bôi trơn đủ và sạch dưới áp suất nhất định đi bôi trơn cho các chi tiết của động cơ để giảm ma sát, giảm mài mòn, làm kín, làm sạch, làm mát và chống gỉ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1881, 50, 'Niên hạn sử dụng của xe ô tô tải (tính bắt đầu từ năm sản xuất) không quá bao nhiêu năm?', '277', '', 'Niên hạn sử dụng của xe ô tô tải (tính bắt đầu từ năm sản xuất) không quá bao nhiêu năm là 25 năm.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1882, 50, 'Niên hạn sử dụng của xe ô tô chở người trên 8 chỗ ngồi (không kể chỗ của người lái xe) tính bắt đầu từ năm sản xuất không quá bao nhiêu năm?', '278', '', 'Niên hạn sử dụng của xe ô tô chở người trên 8 chỗ ngồi (không kể chỗ của người lái xe) tính bắt đầu từ năm sản xuất không quá bao nhiêu năm là 20 năm.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1883, 50, 'Hãy nêu công dụng của động cơ xe ô tô?', '279', '', 'Hãy nêu công dụng của động cơ xe ô tô là Khi làm việc, nhiệt năng được biến đổi thành cơ năng làm trục khủy động cơ quay, truyền lực đến các bánh xe chủ động tạo ra chuyển động tịnh tiến cho xe ô tô.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1884, 50, 'Hãy nêu công dụng hệ thống truyền lực của xe ô tô?', '280', '', 'Hãy nêu công dụng hệ thống truyền lực của xe ô tô là Dùng để truyền mô men quay từ động cơ tới các bánh xe chủ động của xe ô tô.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1885, 50, 'Hãy nêu công dụng ly hợp (côn) của xe ô tô?', '281', '', 'Hãy nêu công dụng ly hợp (côn) của xe ô tô là Dùng để truyền hoặc ngắt truyền động từ động cơ đến hộp số của xe ô tô.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1886, 50, 'Hãy nêu công dụng hộp số của xe ô tô?', '282', '', 'Hãy nêu công dụng hộp số của xe ô tô là Truyền và thay đổi mô men từ động cơ đến bánh xe chủ động, cắt truyền động từ động cơ đến bánh xe chủ động, bảo đảm cho xe ô tô chuyển động lùi.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1887, 50, 'Hãy nêu công dụng hệ thống lái của xe ô tô?', '283', '', 'Hãy nêu công dụng hệ thống lái của xe ô tô là Dùng để thay đổi hướng chuyển động hoặc giữ cho xe ô tô chuyển động ổn định theo hướng xác định.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1888, 50, 'Hãy nêu công dụng hệ thống phanh của xe ô tô?', '284', '', 'Hãy nêu công dụng hệ thống phanh của xe ô tô là Dùng để giảm tốc độ, dừng chuyển động của xe ô tô và giữ cho xe ô tô đứng yên trên dốc.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1889, 50, 'Đèn phanh trên xe mô tô có tác dụng gì dưới đây?', '285', '', 'Đèn phanh trên xe mô tô có tác dụng gì dưới đây là Cả hai ý trên.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1890, 50, 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây, báo hiệu tình trạng như thế nào của xe ô tô?', '286', 'oto/286.webp', 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây, báo hiệu tình trạng như thế nào của xe ô tô là Nhiệt độ nước làm mát động cơ quá ngưỡng cho phép.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1891, 50, 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây, báo hiệu tình trạng như thế nào của xe ô tô?', '287', 'oto/287.webp', 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây, báo hiệu tình trạng như thế nào của xe ô tô là Cần kiểm tra động cơ.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1892, 50, 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây, báo hiệu tình trạng như thế nào của xe ô tô?', '288', 'oto/288.webp', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1893, 50, 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây, báo hiệu tình trạng như thế nào của xe ô tô?', '289', 'oto/289.webp', 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây, báo hiệu tình trạng như thế nào của xe ô tô là Báo hiệu hệ thống chống bó cứng phanh bị lỗi.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1894, 50, 'Khi khởi động xe ô tô số tự động có trang bị chìa khóa thông minh có cần đạp hết hành trình bàn đạp chân phanh hay không?', '290', 'oto/290.webp', 'Khi khởi động xe ô tô số tự động có trang bị chìa khóa thông minh có cần đạp hết hành trình bàn đạp chân phanh hay không là Phải đạp hết hành trình bàn đạp chân phanh.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1895, 50, 'Ắc quy được trang bị trên xe ô tô có tác dụng gì dưới đây?', '291', '', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1896, 50, 'Máy phát điện được trang bị trên xe ô tô có tác dụng gì dưới đây?', '292', '', 'Máy phát điện được trang bị trên xe ô tô có tác dụng gì dưới đây là Để phát điện năng cung cấp cho các phụ tải làm việc và nạp điện cho ắc quy.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1897, 50, 'Dây đai an toàn được trang bị trên xe ô tô có tác dụng gì dưới đây?', '293', '', 'Dây đai an toàn được trang bị trên xe ô tô có tác dụng gì dưới đây là Giữ chặt người lái và hành khách trên ghế ngồi khi xe ô tô đột ngột dừng lại.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1898, 50, 'Túi khí được trang bị trên xe ô tô có tác dụng gì dưới đây?', '294', '', 'Túi khí được trang bị trên xe ô tô có tác dụng gì dưới đây là Ý 2 và ý 3.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1899, 50, 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây không tắt trong thời gian dài, báo hiệu tình trạng như thế nào của xe ô tô?', '295', 'oto/295.webp', 'Khi động cơ ô tô đã khởi động, bảng đồng hồ xuất hiện ký hiệu như hình vẽ dưới đây không tắt trong thời gian dài, báo hiệu tình trạng như thế nào của xe ô tô là Hệ thống lái gặp sự cố.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1900, 50, 'Trên xe ô tô có trang bị thiết bị như hình vẽ dưới đây có tác dụng gì?', '296', 'oto/296.webp', '', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1901, 50, 'Trên xe ô tô có trang bị thiết bị như hình vẽ dưới đây, dùng để làm gì?', '297', 'oto/297.webp', 'Trên xe ô tô có trang bị thiết bị như hình vẽ dưới đây, dùng để làm gì là Phá cửa kính xe ô tô trong các trường hợp khẩn cấp.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(1902, 50, 'Trên xe ô tô có trang bị thiết bị như hình vẽ dưới đây, dùng để làm gì?', '298', 'oto/298.webp', 'Trên xe ô tô có trang bị thiết bị như hình vẽ dưới đây, dùng để làm gì là Chữa cháy trong các trường hợp hỏa hoạn.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
