(2027, 51, 'Biển báo này có ý nghĩa như thế nào?', '423', 'oto/423.webp', 'Biển báo này có ý nghĩa như thế nào là Để báo trước nơi có kết cấu mặt đường rời rạc, khi phương tiện đi qua, làm cho các viên đá, sỏi văng lên gây nguy hiểm và mất an toàn cho người và phương tiện tham gia giao thông.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2028, 51, 'Gặp biển báo này người lái xe phải xử lý thế nào?', '424', 'oto/424.webp', 'Gặp biển báo này người lái xe phải xử lý thế nào là Đi chậm, quan sát và dừng lại nếu gặp gia súc trên đường.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2029, 51, 'Biển báo này có ý nghĩa như thế nào?', '425', 'oto/425.webp', 'Biển báo này có ý nghĩa như thế nào là Báo hiệu khu vực có đường dây điện cắt ngang phía trên tuyến đường.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
