(2196, 52, 'Xe nào dừng đúng theo quy tắc giao thông?', '592', 'oto/592.webp', 'Xe nào dừng đúng theo quy tắc giao thông là Xe con.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2197, 52, 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ?', '593', 'oto/593.webp', 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ là Xe tải, xe đạp, xe của bạn.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2198, 52, 'Để điều khiển xe rẽ trái, bạn chọn hướng đi nào dưới đây?', '594', 'oto/594.webp', 'Để điều khiển xe rẽ trái, bạn chọn hướng đi nào dưới đây là Hướng 1.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2199, 52, 'Khi gặp xe ngược chiều bật đèn pha trong tình huống dưới dây, bạn xử lý như thế nào?', '595', 'oto/595.webp', 'Khi gặp xe ngược chiều bật đèn pha trong tình huống dưới dây, bạn xử lý như thế nào là Giữ nguyên đèn chiếu gần, giảm tốc độ, đi sau xe phía trước.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2200, 52, 'Xe của bạn đang di chuyển gần đến khu vực giao cắt với đường sắt, khi rào chắn đang dịch chuyển, bạn điều khiển xe như thế nào là đúng quy tắc giao thông?', '596', 'oto/596.webp', 'Xe của bạn đang di chuyển gần đến khu vực giao cắt với đường sắt, khi rào chắn đang dịch chuyển, bạn điều khiển xe như thế nào là đúng quy tắc giao thông là Quan sát nếu thấy không có tàu thì tăng tốc cho xe vượt qua đường sắt.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2201, 52, 'Trong tình huống dưới đây, xe con màu đỏ nhập làn đường cao tốc theo hướng mũi tên là đúng hay sai?', '597', 'oto/597.webp', 'Trong tình huống dưới đây, xe con màu đỏ nhập làn đường cao tốc theo hướng mũi tên là đúng hay sai là Đúng.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2202, 52, 'Trong tình huống dưới đây, xe con màu đỏ có được phép vượt khi xe con màu xanh đang vượt xe tải hay không?', '598', 'oto/598.webp', 'Trong tình huống dưới đây, xe con màu đỏ có được phép vượt khi xe con màu xanh đang vượt xe tải hay không là Không được vượt.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2203, 52, 'Trong tình huống dưới đây, xe con màu vàng vượt xe con màu đỏ là đúng quy tắc giao thông hay không?', '599', 'oto/599.webp', 'Trong tình huống dưới đây, xe con màu vàng vượt xe con màu đỏ là đúng quy tắc giao thông hay không là Đúng.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2204, 52, 'Trong tình huống dưới đây, xe đầu kéo kéo rơ moóc (xe container) đang rẽ phải, xe con màu xanh và xe máy phía sau xe container đi như thế nào để bảo đảm an toàn?', '600', 'oto/600.webp', 'Trong tình huống dưới đây, xe đầu kéo kéo rơ moóc (xe container) đang rẽ phải, xe con màu xanh và xe máy phía sau xe container đi như thế nào để bảo đảm an toàn là Giảm tốc độ chờ xe container rẽ xong rồi tiếp tục đi.', 0, 0, NULL, '2025-05-23 13:12:11', NULL, NULL),
(2205, 58, 'Phần của đường bộ được sử dụng cho phương tiện giao thông đường bộ đi lại là gì?', '1', '', 'Phần của đường bộ được sử dụng cho phương tiện giao thông đường bộ đi lại là gì là Phần đường xe chạy.', 0, 1, '2025-06-04 01:38:20', '2025-08-09 19:47:53', NULL, NULL),
(2206, 58, 'Làn đường là gì?', '2', '', 'Làn đường là gì là Là một phần của phần đường xe chạy được chia theo chiều dọc của đường, có đủ chiều rộng cho xe chạy an toàn.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2207, 58, 'Khổ giới hạn của đường bộ được hiểu như thế nào là đúng?', '3', '', 'Khổ giới hạn của đường bộ được hiểu như thế nào là đúng là Khổ giới hạn của đường bộ là khoảng trống có kích thước giới hạn về chiều rộng, chiều cao của đường bộ để các xe, bao gồm cả hàng hoá xếp trên xe đi qua được an toàn và được xác định theo quy chuẩ', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2208, 58, 'Dải phân cách được lắp đặt để làm gì?', '4', '', 'Dải phân cách được lắp đặt để làm gì là Để phân chia các làn đường dành cho xe cơ giới và xe thô sơ trên đường cao tốc.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2209, 58, 'Vạch kẻ đường là gì?', '5', '', 'Vạch kẻ đường là gì là Là vạch chỉ sự phân chia làn đường, vị trí hoặc hướng đi, vị trí dừng lại.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2210, 58, 'Người điều khiển phương tiện tham gia giao thông đường bộ được hiểu như thế nào là đúng?', '6', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ được hiểu như thế nào là đúng là Là người điều khiển xe cơ giới, người điều khiển xe thô sơ, người điều khiển xe máy chuyên dùng.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2211, 58, 'Người lái xe được hiểu như thế nào là đúng?', '7', '', 'Người lái xe được hiểu như thế nào là đúng là Là người điều khiển xe cơ giới.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2212, 58, 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe cơ giới?', '8', '', 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe cơ giới là Xe ô tô; rơ moóc được kéo bởi xe ô tô; sơ mi rơ moóc được kéo bởi ô tô đầu kéo; xe chở người bốn bánh có gắn động cơ; xe chở hàng bốn bánh có gắn động cơ; xe mô', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2213, 58, 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe thô sơ?', '9', '', 'Trong nhóm các phương tiện giao thông đường bộ dưới đây, nhóm phương tiện nào là xe thô sơ là Xe đạp, xe đạp máy, xe đạp điện; xe xích lô; xe lăn dùng cho người khuyết tật; xe vật nuôi kéo và các loại xe tương tự.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2214, 58, 'Phương tiện giao thông đường bộ gồm những loại nào?', '10', '', 'Phương tiện giao thông đường bộ gồm những loại nào là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2215, 58, 'Người tham gia giao thông đường bộ gồm những đối tượng nào?', '11', '', 'Người tham gia giao thông đường bộ gồm những đối tượng nào là Người điều khiển, dẫn dắt vật nuôi trên đường bộ; người đi bộ trên đường bộ.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2216, 58, 'Người điều khiển phương tiện tham gia giao thông đường bộ gồm những đối tượng nào dưới đây?', '12', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ gồm những đối tượng nào dưới đây là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2217, 58, 'Người điều khiển giao thông đường bộ được hiểu như thế nào là đúng?', '13', '', 'Người điều khiển giao thông đường bộ được hiểu như thế nào là đúng là Là Cảnh sát giao thông và người được giao nhiệm vụ hướng dẫn giao thông trên đường bộ.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2218, 58, 'Hành vi nào dưới đây bị nghiêm cấm?', '14', '', 'Hành vi nào dưới đây bị nghiêm cấm là Rải vật sắc nhọn, đổ chất gây trơn trượt trên đường bộ.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2219, 58, 'Hành vi đưa xe cơ giới, xe máy chuyên dùng tham gia giao thông đường bộ nào dưới đây bị cấm?', '15', '', 'Hành vi đưa xe cơ giới, xe máy chuyên dùng tham gia giao thông đường bộ nào dưới đây bị cấm là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2220, 58, 'Tổ chức đua xe được phép thực hiện khi nào?', '16', '', 'Tổ chức đua xe được phép thực hiện khi nào là Được cơ quan có thẩm quyền cấp phép.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2221, 58, 'Hành vi đua xe trái phép bị xử lý như thế nào?', '17', '', '', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2222, 58, 'Người điều khiển phương tiện tham gia giao thông đường bộ mà trong máu hoặc hơi thở có nồng độ cồn có bị nghiêm cấm không?', '18', '', 'Người điều khiển phương tiện tham gia giao thông đường bộ mà trong máu hoặc hơi thở có nồng độ cồn có bị nghiêm cấm không là Bị nghiêm cấm.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2223, 58, 'Theo Luật Phòng chống tác hại của rượu, bia, đối tượng nào dưới đây bị cấm sử dụng rượu, bia khi tham gia giao thông?', '19', '', 'Theo Luật Phòng chống tác hại của rượu, bia, đối tượng nào dưới đây bị cấm sử dụng rượu, bia khi tham gia giao thông là Người điều khiển xe ô tô, xe mô tô, xe đạp, xe gắn máy.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2224, 58, 'Hành vi giao xe ô tô, mô tô cho người nào sau đây tham gia giao thông đường bộ bị nghiêm cấm?', '20', '', 'Hành vi giao xe ô tô, mô tô cho người nào sau đây tham gia giao thông đường bộ bị nghiêm cấm là Cả ba ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2225, 58, 'Hành vi nào sau đây bị nghiêm cấm?', '21', '', 'Hành vi nào sau đây bị nghiêm cấm là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2226, 58, 'Các hành vi nào sau đây bị cấm đối với phương tiện tham gia giao thông đường bộ?', '22', '', 'Các hành vi nào sau đây bị cấm đối với phương tiện tham gia giao thông đường bộ là Cải tạo trái phép; cố ý can thiệp làm sai lệch chỉ số trên đồng hồ báo quãng đường đã chạy của xe ô tô; cắt, hàn, tẩy xóa, đục sửa, đóng lại trái phép số khung, số động cơ ', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2227, 58, 'Hành vi nào sau đây bị cấm?', '23', '', 'Hành vi nào sau đây bị cấm là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2228, 58, 'Việc sản xuất, sử dụng, mua, bán trái phép biển số xe có bị nghiêm cấm hay không?', '24', '', 'Việc sản xuất, sử dụng, mua, bán trái phép biển số xe có bị nghiêm cấm hay không là Bị nghiêm cấm.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2229, 58, 'Khi điều khiển phương tiện tham gia giao thông, những hành vi nào dưới đây bị nghiêm cấm?', '25', '', 'Khi điều khiển phương tiện tham gia giao thông, những hành vi nào dưới đây bị nghiêm cấm là Lạng lách, đánh võng, rú ga liên tục.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2230, 58, 'Có bao nhiêu nhóm biển báo hiệu đường bộ?', '26', '', 'Có bao nhiêu nhóm biển báo hiệu đường bộ là Bốn nhóm: Biển báo cấm, biển báo nguy hiểm, biển hiệu lệnh và biển phụ.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2231, 58, 'Tại nơi có vạch kẻ đường hoặc tại nơi mà người đi bộ, xe lăn của người khuyết tật đang qua đường, người điều khiển phương tiện tham gia giao thông phải thực hiện như thế nào?', '27', '', 'Tại nơi có vạch kẻ đường hoặc tại nơi mà người đi bộ, xe lăn của người khuyết tật đang qua đường, người điều khiển phương tiện tham gia giao thông phải thực hiện như thế nào là Quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn cho người đi bộ, xe lăn', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2232, 58, 'Người điều khiển xe mô tô phải phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây?', '28', '', 'Người điều khiển xe mô tô phải phải quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn trong các trường hợp nào dưới đây là Cả ba ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2233, 58, 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông?', '29', 'oto/36.webp', 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông là Người tham gia giao thông đường bộ ở phía trước và phía sau người điều khiển phải dừng lại; ngư', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2234, 58, 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông?', '30', 'oto/37.webp', 'Khi gặp hiệu lệnh điều khiển của Cảnh sát giao thông như hình dưới đây thì người tham gia giao thông đường bộ phải đi như thế nào là đúng quy tắc giao thông là Người tham gia giao thông đường bộ ở tất cả các hướng phải dừng lại, trừ các xe đã ở trong khu ', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2235, 58, 'Khi hiệu lệnh của người điều khiển giao thông trái với tín hiệu đèn giao thông hoặc biển báo hiệu đường bộ thì người tham gia giao thông đường bộ phải chấp hành báo hiệu đường bộ nào dưới đây?', '31', '', 'Khi hiệu lệnh của người điều khiển giao thông trái với tín hiệu đèn giao thông hoặc biển báo hiệu đường bộ thì người tham gia giao thông đường bộ phải chấp hành báo hiệu đường bộ nào dưới đây là Theo hiệu lệnh của người điều khiển giao thông.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2236, 58, 'Khi ở một vị trí vừa có biển báo hiệu đặt cố định vừa có biển báo hiệu tạm thời mà hai biển có ý nghĩa khác nhau, người tham gia giao thông đường bộ phải chấp hành hiệu lệnh của biển báo hiệu nào?', '32', '', 'Khi ở một vị trí vừa có biển báo hiệu đặt cố định vừa có biển báo hiệu tạm thời mà hai biển có ý nghĩa khác nhau, người tham gia giao thông đường bộ phải chấp hành hiệu lệnh của biển báo hiệu nào là Biển báo hiệu tạm thời.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2237, 58, 'Tại nơi đường giao nhau, khi đèn điều khiển giao thông có tín hiệu màu vàng, người điều khiển phương tiện tham gia giao thông phải chấp hành như thế nào là đúng quy tắc giao thông?', '33', '', 'Tại nơi đường giao nhau, khi đèn điều khiển giao thông có tín hiệu màu vàng, người điều khiển phương tiện tham gia giao thông phải chấp hành như thế nào là đúng quy tắc giao thông là Dừng lại trước vạch dừng; trường hợp đang đi trên vạch dừng hoặc đã đi q', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2238, 58, 'Người lái xe trên đường cần chấp hành quy định về tốc độ tối đa như thế nào?', '34', '', 'Người lái xe trên đường cần chấp hành quy định về tốc độ tối đa như thế nào là Không vượt quá tốc độ tối đa cho phép.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2239, 58, 'Phương tiện tham gia giao thông đường bộ di chuyển với tốc độ thấp hơn phải đi như thế nào?', '35', '', 'Phương tiện tham gia giao thông đường bộ di chuyển với tốc độ thấp hơn phải đi như thế nào là Đi về bên phải theo chiều đi của mình.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2240, 58, 'Trên một chiều đường có vạch kẻ phân làn đường, người lái xe cơ giới, xe máy chuyên dùng phải điều khiển xe đi trên làn đường nào?', '36', '', 'Trên một chiều đường có vạch kẻ phân làn đường, người lái xe cơ giới, xe máy chuyên dùng phải điều khiển xe đi trên làn đường nào là Đi trên làn đường bên trái.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2241, 58, 'Người lái xe phải giảm tốc độ, có tín hiệu rẽ phải và đi sát về bên phải của phần đường xe chạy trong các trường hợp nào dưới đây?', '37', '', 'Người lái xe phải giảm tốc độ, có tín hiệu rẽ phải và đi sát về bên phải của phần đường xe chạy trong các trường hợp nào dưới đây là Khi xe sau xin vượt nếu đủ điều kiện an toàn.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2242, 58, 'Vượt xe là gì?', '38', '', 'Vượt xe là gì là Là tình huống giao thông trên đường mà mỗi chiều đường xe chạy chỉ có một làn đường dành cho xe cơ giới, xe đi phía sau di chuyển sang bên trái để di chuyển lên trước xe phía trước.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2243, 58, 'Người lái xe được phép vượt xe trên cầu hẹp có một làn đường, đường cong có tầm nhìn bị hạn chế hay không?', '39', '', 'Người lái xe được phép vượt xe trên cầu hẹp có một làn đường, đường cong có tầm nhìn bị hạn chế hay không là Không được phép vượt.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2244, 58, 'Muốn vượt xe phía trước, người lái xe mô tô phải có tín hiệu như thế nào dưới đây để bảo đảm an toàn?', '40', '', 'Muốn vượt xe phía trước, người lái xe mô tô phải có tín hiệu như thế nào dưới đây để bảo đảm an toàn là Báo hiệu nhấp nháy bằng đèn chiếu sáng phía trước hoặc còi.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2245, 58, 'Khi lái xe trong khu đông dân cư, khu vực cơ sở khám bệnh, chữa bệnh trừ các khu vực có biển cấm sử dụng còi, người lái xe được sử dụng còi trong thời gian nào?', '41', '', 'Khi lái xe trong khu đông dân cư, khu vực cơ sở khám bệnh, chữa bệnh trừ các khu vực có biển cấm sử dụng còi, người lái xe được sử dụng còi trong thời gian nào là Từ 05 giờ đến 22 giờ.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2246, 58, 'Người lái xe sử dụng đèn như thế nào khi đi trên các đoạn đường qua khu đông dân cư có hệ thống chiếu sáng đang hoạt động?', '42', '', 'Người lái xe sử dụng đèn như thế nào khi đi trên các đoạn đường qua khu đông dân cư có hệ thống chiếu sáng đang hoạt động là Chỉ bật đèn chiếu gần (đèn cốt).', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2247, 58, 'Khi điều khiển phương tiện tham gia giao thông, hành vi nào sau đây bị cấm?', '43', '', 'Khi điều khiển phương tiện tham gia giao thông, hành vi nào sau đây bị cấm là Dùng tay cầm và sử dụng điện thoại hoặc thiết bị điện tử khác.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2248, 58, 'Người lái xe không được vượt xe khác khi gặp trường hợp nào dưới đây?', '44', '', '', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2249, 58, 'Nơi nào cấm quay đầu xe?', '45', '', 'Nơi nào cấm quay đầu xe là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2250, 58, 'Trước khi cho xe chuyển hướng, người lái xe phải làm gì để bảo đảm an toàn giao thông?', '46', '', 'Trước khi cho xe chuyển hướng, người lái xe phải làm gì để bảo đảm an toàn giao thông là Cả ba ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2251, 58, 'Khi chuyển làn đường, người lái xe phải bật đèn tín hiệu báo rẽ như thế nào là đúng quy tắc giao thông?', '47', '', 'Khi chuyển làn đường, người lái xe phải bật đèn tín hiệu báo rẽ như thế nào là đúng quy tắc giao thông là Trước khi thay đổi làn đường.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2252, 58, 'Người điều khiển phương tiện tham gia giao thông không được dừng xe, đỗ xe ở những vị trí nào sau đây?', '48', '', 'Người điều khiển phương tiện tham gia giao thông không được dừng xe, đỗ xe ở những vị trí nào sau đây là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2253, 58, 'Người điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy có được phép sử dụng xe để kéo hoặc đẩy các phương tiện khác khi tham gia giao thông không?', '49', '', 'Người điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy có được phép sử dụng xe để kéo hoặc đẩy các phương tiện khác khi tham gia giao thông không là Không được phép.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2254, 58, 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép?', '50', '', 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép là Buông cả hai tay; đứng, nằm trên xe điều khiển xe; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2255, 58, 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép?', '51', '', 'Khi điều khiển xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy, những hành vi nào sau đây không được phép là Buông cả hai tay; sử dụng xe để kéo, đẩy xe khác, vật khác; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2256, 58, 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ không được thực hiện hành vi nào sau đây?', '52', '', 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ không được thực hiện hành vi nào sau đây là Ý 1 và ý 2.', 0, 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20', NULL, NULL),
(2257, 58, 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được bám, kéo hoặc đẩy các phương tiện khác không?', '53', '', 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được bám, kéo hoặc đẩy các phương tiện khác không là Không được phép.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2258, 58, 'Người lái xe, người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy phải thực hiện quy định nào dưới đây?', '54', '', 'Người lái xe, người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy phải thực hiện quy định nào dưới đây là Đội mũ bảo hiểm theo đúng quy chuẩn kỹ thuật quốc gia và cài quai đúng quy cách.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2259, 58, 'Người lái xe mô tô hai bánh, xe gắn máy được phép chở tối đa hai người trong những trường hợp nào?', '55', '', 'Người lái xe mô tô hai bánh, xe gắn máy được phép chở tối đa hai người trong những trường hợp nào là Chở người bệnh đi cấp cứu; áp giải người có hành vi vi phạm pháp luật; trẻ em dưới 12 tuổi; người già yếu hoặc người khuyết tật.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2260, 58, 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào dưới đây?', '56', '', 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào dưới đây là Ngồi về một bên điều khiển xe; đứng, nằm trên xe điều khiển xe; thay người lái xe khi xe đang chạy; quay người về phía sau để điều khiển xe hoặc bịt', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2261, 58, 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào sau đây?', '57', '', 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện các hành vi nào sau đây là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2262, 58, 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện hành vi nào sau đây?', '58', '', 'Người lái xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy không được thực hiện hành vi nào sau đây là Đi xe dàn hàng ngang, đi xe vào phần đường dành cho người đi bộ.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2263, 58, 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được sử dụng ô khi trời mưa hay không?', '59', '', 'Người được chở trên xe mô tô hai bánh, xe mô tô ba bánh, xe gắn máy khi tham gia giao thông đường bộ có được sử dụng ô khi trời mưa hay không là Không được sử dụng.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2264, 58, 'Người được chở trên xe mô tô có được kéo theo người đang điều khiển xe đạp hay không?', '60', '', 'Người được chở trên xe mô tô có được kéo theo người đang điều khiển xe đạp hay không là Không được phép.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL);
INSERT INTO `quizzes` (`id`, `quiz_set_id`, `question`, `name`, `image`, `explanation`, `mandatory`, `wrong`, `created_at`, `updated_at`, `tip`, `tip_image`) VALUES
(2265, 58, 'Trường hợp người được chở trên xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô và các loại xe tương tự xe gắn máy không đội mũ bảo hiểm cho người đi mô tô, xe máy hoặc không cài quai đúng quy cách (trừ trường hợp chở người bệnh đi cấp cứu, trẻ em dưới 06 tuổi, áp giải người có hành vi vi phạm pháp luật) thì việc xử phạt vi phạm hành chính được quy định như thế nào?', '61', '', '', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2266, 58, 'Trong các trường hợp dưới đây, để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô cần thực hiện như thế nào?', '62', '', 'Trong các trường hợp dưới đây, để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô cần thực hiện như thế nào là Phải đội mũ bảo hiểm theo đúng quy chuẩn kỹ thuật quốc gia và cài quai đúng quy cách, không sử dụng ô, điện thoại di động, thiết bị ', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2267, 58, 'Thứ tự xuống phà như thế nào là đúng quy tắc giao thông?', '63', '', '', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2268, 58, 'Khi lái xe trong đô thị và khu đông dân cư trong thời gian từ 22 giờ ngày hôm trước đến 05 giờ ngày hôm sau, nếu cần vượt một xe khác, người lái xe phải báo hiệu như thế nào là đúng quy tắc giao thông?', '64', '', 'Khi lái xe trong đô thị và khu đông dân cư trong thời gian từ 22 giờ ngày hôm trước đến 05 giờ ngày hôm sau, nếu cần vượt một xe khác, người lái xe phải báo hiệu như thế nào là đúng quy tắc giao thông là Chỉ được báo hiệu bằng đèn.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2269, 58, 'Khi điều khiển xe chạy trên đường, biết có xe sau xin vượt, nếu đủ điều kiện an toàn người điều khiển phương tiện phải làm gì?', '65', '', 'Khi điều khiển xe chạy trên đường, biết có xe sau xin vượt, nếu đủ điều kiện an toàn người điều khiển phương tiện phải làm gì là Giảm tốc độ, có tín hiệu rẽ phải để báo hiệu cho người điều khiển phương tiện tham gia giao thông đường bộ phía sau biết được ', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2270, 58, 'Trên đường không phân chia thành hai chiều xe chạy riêng biệt, người điều khiển phương tiện tham gia giao thông đường bộ phải tránh xe đi ngược chiều như thế nào để bảo đảm an toàn?', '66', '', 'Trên đường không phân chia thành hai chiều xe chạy riêng biệt, người điều khiển phương tiện tham gia giao thông đường bộ phải tránh xe đi ngược chiều như thế nào để bảo đảm an toàn là Giảm tốc độ và cho xe đi về bên phải theo chiều xe chạy của mình.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2271, 58, 'Khi tránh xe đi ngược chiều, các xe phải nhường đường như thế nào là đúng quy tắc giao thông?', '67', '', 'Khi tránh xe đi ngược chiều, các xe phải nhường đường như thế nào là đúng quy tắc giao thông là Cả ba ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2272, 58, 'Người lái xe phải làm gì để bảo đảm an toàn khi lái xe trên đường cong có tầm nhìn bị hạn chế?', '68', '', 'Người lái xe phải làm gì để bảo đảm an toàn khi lái xe trên đường cong có tầm nhìn bị hạn chế là Quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2273, 58, 'Tại nơi đường giao nhau, người lái xe đang đi trên đường không ưu tiên, đường nhánh phải nhường đường như thế nào là đúng quy tắc giao thông?', '69', '', 'Tại nơi đường giao nhau, người lái xe đang đi trên đường không ưu tiên, đường nhánh phải nhường đường như thế nào là đúng quy tắc giao thông là Nhường đường cho xe đi trên đường ưu tiên hoặc đường chính từ bất kỳ hướng nào tới.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2274, 58, 'Tại nơi đường giao nhau có báo hiệu đi theo vòng xuyến, người lái xe phải nhường đường như thế nào là đúng quy tắc giao thông?', '70', '', 'Tại nơi đường giao nhau có báo hiệu đi theo vòng xuyến, người lái xe phải nhường đường như thế nào là đúng quy tắc giao thông là Nhường đường cho xe đi đến từ bên trái.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
