(2276, 58, 'Người lái xe phải nhanh chóng giảm tốc độ, đi sát lề đường bên phải hoặc dừng lại để nhường đường cho các loại xe nào dưới đây?', '72', '', 'Người lái xe phải nhanh chóng giảm tốc độ, đi sát lề đường bên phải hoặc dừng lại để nhường đường cho các loại xe nào dưới đây là Xe ưu tiên gồm xe chữa cháy của Cảnh sát phòng cháy, chữa cháy và cứu nạn, cứu hộ và xe chữa cháy của các lực lượng khác được', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2277, 58, 'Khi có tín hiệu của xe ưu tiên, người và phương tiện tham gia giao thông đường bộ phải tuân thủ quy định nào dưới đây?', '73', '', 'Khi có tín hiệu của xe ưu tiên, người và phương tiện tham gia giao thông đường bộ phải tuân thủ quy định nào dưới đây là Giảm tốc độ, đi sát lề đường bên phải hoặc dừng lại để nhường đường.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
