(2300, 58, 'Trên đường bộ ngoài khu vực đông dân cư, đường đôi hoặc đường một chiều có từ hai làn xe cơ giới trở lên (trừ đường cao tốc) loại xe nào dưới đây được tham gia giao thông với tốc độ khai thác tối đa cho phép là 70 km/h?', '96', '', 'Trên đường bộ ngoài khu vực đông dân cư, đường đôi hoặc đường một chiều có từ hai làn xe cơ giới trở lên (trừ đường cao tốc) loại xe nào dưới đây được tham gia giao thông với tốc độ khai thác tối đa cho phép là 70 km/h là Xe buýt; ô tô đầu kéo kéo sơ mi r', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2301, 58, 'Trên đường bộ ngoài khu vực đông dân cư, đường hai chiều hoặc đường một chiều có một làn xe cơ giới (trừ đường cao tốc), loại xe nào dưới đây được tham gia giao thông với tốc độ khai thác tối đa cho phép là 60 km/h?', '97', '', 'Trên đường bộ ngoài khu vực đông dân cư, đường hai chiều hoặc đường một chiều có một làn xe cơ giới (trừ đường cao tốc), loại xe nào dưới đây được tham gia giao thông với tốc độ khai thác tối đa cho phép là 60 km/h là Xe buýt; ô tô đầu kéo kéo sơ mi rơ mo', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2302, 58, 'Người lái xe phải giảm tốc độ thấp hơn tốc độ tối đa cho phép đến mức cần thiết, chú ý quan sát và chuẩn bị sẵn sàng những tình huống có thể xảy ra để phòng ngừa tai nạn trong các trường hợp nào dưới đây?', '98', '', 'Người lái xe phải giảm tốc độ thấp hơn tốc độ tối đa cho phép đến mức cần thiết, chú ý quan sát và chuẩn bị sẵn sàng những tình huống có thể xảy ra để phòng ngừa tai nạn trong các trường hợp nào dưới đây là Gặp biển báo nguy hiểm và cảnh báo trên đường.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2303, 58, 'Khi gặp xe buýt đang dừng đón, trả khách, người điều khiển xe mô tô phải xử lý như thế nào dưới đây?', '99', '', '', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2304, 58, 'Việc sử dụng xe mô tô, xe gắn máy, xe thô sơ để vận chuyển hành khách, hàng hóa phải thực hiện các quy định nào dưới đây để đảm bảo an toàn giao thông?', '100', '', 'Việc sử dụng xe mô tô, xe gắn máy, xe thô sơ để vận chuyển hành khách, hàng hóa phải thực hiện các quy định nào dưới đây để đảm bảo an toàn giao thông là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2305, 59, 'Những hành vi nào sau đây thể hiện là người có văn hóa giao thông?', '101', '', 'Những hành vi nào sau đây thể hiện là người có văn hóa giao thông là Luôn tuân thủ pháp luật về trật tự, an toàn giao thông đường bộ, nhường nhịn và giúp đỡ người khác.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2306, 59, 'Khái niệm về văn hóa giao thông được hiểu như thế nào là đúng?', '102', '', 'Khái niệm về văn hóa giao thông được hiểu như thế nào là đúng là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2307, 59, 'Người lái xe không điều khiển xe đi đúng làn đường quy định, phóng nhanh, vượt ẩu, vượt đèn đỏ, đi vào đường cấm được coi là hành vi nào trong các hành vi dưới đây?', '103', '', 'Người lái xe không điều khiển xe đi đúng làn đường quy định, phóng nhanh, vượt ẩu, vượt đèn đỏ, đi vào đường cấm được coi là hành vi nào trong các hành vi dưới đây là Là thiếu văn hóa giao thông, vi phạm pháp luật về trật tự, an toàn giao thông đường bộ.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2308, 59, 'Người lái xe có văn hóa giao thông khi tham gia giao thông đường bộ phải đáp ứng các điều kiện nào dưới đây?', '104', '', 'Người lái xe có văn hóa giao thông khi tham gia giao thông đường bộ phải đáp ứng các điều kiện nào dưới đây là Hiểu biết và chấp hành nghiêm chỉnh pháp luật về giao thông đường bộ; có ý thức trách nhiệm với cộng đồng khi tham gia giao thông; tôn trọng, nh', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2309, 59, 'Người lái xe mô tô có văn hóa giao thông khi tham gia giao thông phải tuân thủ những quy định nào dưới đây?', '105', '', 'Người lái xe mô tô có văn hóa giao thông khi tham gia giao thông phải tuân thủ những quy định nào dưới đây là Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; đội mũ bảo hiểm đúng quy chuẩn kỹ thuật quốc gia, cài q', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2310, 59, 'Trong các hành vi dưới đây, người lái xe có văn hóa giao thông phải ứng xử như thế nào?', '106', '', 'Trong các hành vi dưới đây, người lái xe có văn hóa giao thông phải ứng xử như thế nào là Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; dừng, đỗ xe đúng nơi quy định; đã uống rượu, bia thì không lái xe.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2311, 59, 'Khi tham gia giao thông việc sử dụng còi xe nên dùng như thế nào để thể hiện là người có văn hóa giao thông?', '107', '', 'Khi tham gia giao thông việc sử dụng còi xe nên dùng như thế nào để thể hiện là người có văn hóa giao thông là Chỉ bấm còi khi thật sự cần thiết, không bấm còi liên tục hoặc kéo dài, sử dụng còi với mức âm lượng theo quy định.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2312, 59, 'Người điều khiển phương tiện tham giao thông đường bộ gây ra tai nạn giao thông đường bộ, người liên quan đến vụ tai nạn giao thông đường bộ có trách nhiệm gì dưới đây?', '108', '', 'Người điều khiển phương tiện tham giao thông đường bộ gây ra tai nạn giao thông đường bộ, người liên quan đến vụ tai nạn giao thông đường bộ có trách nhiệm gì dưới đây là Cả ba ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2313, 59, 'Người có mặt tại nơi xảy ra vụ tai giao thông đường bộ có trách nhiệm gì dưới đây?', '109', '', 'Người có mặt tại nơi xảy ra vụ tai giao thông đường bộ có trách nhiệm gì dưới đây là Giúp đỡ, cứu chữa kịp thời người bị nạn; báo tin ngay cho cơ quan Công an, cơ sở khám bệnh, chữa bệnh hoặc Ủy ban nhân dân nơi gần nhất; tham gia bảo vệ hiện trường; tham', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2314, 59, 'Trong đoạn đường hai chiều tại khu đông dân cư đang ùn tắc, người điều khiển xe mô tô có văn hóa giao thông sẽ lựa chọn cách xử lý tình huống nào dưới đây?', '110', '', 'Trong đoạn đường hai chiều tại khu đông dân cư đang ùn tắc, người điều khiển xe mô tô có văn hóa giao thông sẽ lựa chọn cách xử lý tình huống nào dưới đây là Kiên nhẫn tuân thủ hướng dẫn của người điều khiển giao thông hoặc tín hiệu đèn giao thông, di chu', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2315, 60, 'Khi điều khiển xe mô tô tay ga xuống đường dốc dài, độ dốc cao, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn?', '111', '', 'Khi điều khiển xe mô tô tay ga xuống đường dốc dài, độ dốc cao, người lái xe cần thực hiện các thao tác nào dưới đây để bảo đảm an toàn là Giữ tay ga ở mức độ phù hợp, sử dụng phanh trước và phanh sau để giảm tốc độ.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2316, 60, 'Khi điều khiển xe trên đường vòng người lái xe cần phải làm gì để bảo đảm an toàn?', '112', '', 'Khi điều khiển xe trên đường vòng người lái xe cần phải làm gì để bảo đảm an toàn là Quan sát cẩn thận các chướng ngại vật và báo hiệu bằng coi, đèn; giảm tốc độ tới mức cần thiết, về số thấp và thực hiện quay vòng với tốc độ phù hợp với bán kính cong của', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2317, 60, 'Khi điều khiển xe qua đường sắt, người lái xe cần phải thực hiện các thao tác nào dưới đây để bảo đảm an toàn?', '113', '', 'Khi điều khiển xe qua đường sắt, người lái xe cần phải thực hiện các thao tác nào dưới đây để bảo đảm an toàn là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2318, 60, 'Trong các loại nhiên liệu dưới đây, loại nhiên liệu nào giảm thiểu ô nhiễm môi trường?', '114', '', 'Trong các loại nhiên liệu dưới đây, loại nhiên liệu nào giảm thiểu ô nhiễm môi trường là Xăng sinh học và khí sinh học.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2319, 60, 'Các biện pháp tiết kiệm nhiên liệu khi chạy xe?', '115', '', 'Các biện pháp tiết kiệm nhiên liệu khi chạy xe là Cả hai ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2320, 60, 'Khi tầm nhìn bị hạn chế bởi sương mù hoặc mưa to, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn?', '116', '', 'Khi tầm nhìn bị hạn chế bởi sương mù hoặc mưa to, người lái xe phải thực hiện các thao tác nào để bảo đảm an toàn là Giảm tốc độ, chạy cách xa xe trước với khoảng cách an toàn, bật đèn sương mù và đèn chiếu gần.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2321, 60, 'Khi đèn pha của xe đi ngược chiều gây chói mắt, làm giảm khả năng quan sát trên đường, người lái xe xử lý như thế nào dưới đây để bảo đảm an toàn?', '117', '', 'Khi đèn pha của xe đi ngược chiều gây chói mắt, làm giảm khả năng quan sát trên đường, người lái xe xử lý như thế nào dưới đây để bảo đảm an toàn là Giảm tốc độ, giữ vững tay lái, nhìn chếch sang lề đường bên phải.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2322, 60, 'Để đạt được hiệu quả phanh cao nhất, người lái xe mô tô phải sử dụng các kỹ năng như thế nào dưới đây?', '118', '', 'Để đạt được hiệu quả phanh cao nhất, người lái xe mô tô phải sử dụng các kỹ năng như thế nào dưới đây là Giảm hết ga, sử dụng đồng thời cả phanh sau và phanh trước.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2323, 60, 'Khi đang lái xe mô tô hoặc ô tô, nếu có nhu cầu sử dụng điện thoại để nhắn tin hoặc gọi điện, người lái xe phải thực hiện như thế nào trong các tình huống nêu dưới đây?', '119', '', 'Khi đang lái xe mô tô hoặc ô tô, nếu có nhu cầu sử dụng điện thoại để nhắn tin hoặc gọi điện, người lái xe phải thực hiện như thế nào trong các tình huống nêu dưới đây là Giảm tốc độ để dừng xe ở nơi cho phép sau đó sử dụng điện thoại để liên lạc.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2324, 60, 'Những thói quen nào dưới đây khi điều khiển xe mô tô tay ga tham gia giao thông dễ gây tai nạn nguy hiểm?', '120', '', 'Những thói quen nào dưới đây khi điều khiển xe mô tô tay ga tham gia giao thông dễ gây tai nạn nguy hiểm là Phanh đồng thời cả phanh trước và phanh sau.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2325, 60, 'Khi điều khiển xe mô tô quay đầu, người lái xe cần thực hiện như thế nào để bảo đảm an toàn?', '121', '', 'Khi điều khiển xe mô tô quay đầu, người lái xe cần thực hiện như thế nào để bảo đảm an toàn là Quan sát an toàn các phương tiện tới từ phía trước, phía sau, hai bên đồng thời nhường đường cho xe từ bên phải và phía trước đi tới.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2326, 60, 'Tay ga trên xe mô tô hai bánh có tác dụng gì dưới đây?', '122', '', 'Tay ga trên xe mô tô hai bánh có tác dụng gì dưới đây là Ý 1 và ý 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2327, 60, 'Gương chiếu hậu của xe mô tô hai bánh có tác dụng gì dưới đây?', '123', '', 'Gương chiếu hậu của xe mô tô hai bánh có tác dụng gì dưới đây là Để quan sát an toàn phía sau của bên trái và bên phải trước khi chuyển hướng.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2328, 60, 'Để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô hai bánh cần điều khiển tay ga như thế nào?', '124', '', 'Để bảo đảm an toàn khi tham gia giao thông, người lái xe mô tô hai bánh cần điều khiển tay ga như thế nào là Tăng ga thật mạnh, giảm ga thật nhanh.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2329, 60, 'Để tránh đổ, ngã khi điều khiển xe mô tô hai bánh ở nơi đường xấu, nhỏ và hẹp, người lái xe cần xử lý như thế nào?', '125', '', 'Để tránh đổ, ngã khi điều khiển xe mô tô hai bánh ở nơi đường xấu, nhỏ và hẹp, người lái xe cần xử lý như thế nào là Cả ba ý trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2330, 61, 'Biển nào cấm máy kéo?', '126', 'oto/303.webp', 'Biển nào cấm máy kéo là Biển 2 và biển 3.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2331, 61, 'Biển nào báo hiệu cấm xe mô tô ba bánh chở hàng đi qua?', '127', 'oto/304.webp', 'Biển nào báo hiệu cấm xe mô tô ba bánh chở hàng đi qua là Biển 1 và biển 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2332, 61, 'Biển nào dưới đây xe gắn máy được phép đi vào?', '128', 'oto/305.webp', 'Biển nào dưới đây xe gắn máy được phép đi vào là Cả hai biển.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2333, 61, 'Biển nào báo hiệu cấm xe mô tô đi vào?', '129', 'oto/306.webp', 'Biển nào báo hiệu cấm xe mô tô đi vào là Biển 1.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2334, 61, 'Khi gặp biển nào thì xe mô tô hai bánh được đi vào?', '130', 'oto/307.webp', 'Khi gặp biển nào thì xe mô tô hai bánh được đi vào là Không biển nào.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2335, 61, 'Biển nào cấm quay đầu xe?', '131', 'oto/313.webp', 'Biển nào cấm quay đầu xe là Biển 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
