(2396, 61, 'Biển nào báo hiệu Hướng đi thẳng phải theo?', '192', 'oto/433.webp', 'Biển nào báo hiệu  là Biển 1.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2397, 61, 'Biển nào báo hiệu Đường một chiều?', '193', 'oto/434.webp', 'Biển nào báo hiệu  là Biển 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2398, 61, 'Trong các biển dưới đây biển nào là biển Hết tốc độ tối đa cho phép?', '194', 'oto/435.webp', 'Trong các biển dưới đây biển nào là biển  là Biển 1.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2399, 61, 'Trong các biển dưới đây biển nào là biển Hết tốc độ tối thiểu?', '195', 'oto/437.webp', 'Trong các biển dưới đây biển nào là biển  là Biển 3.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2400, 61, 'Biển nào dưới đây báo hiệu hết cấm vượt?', '196', 'oto/438.webp', 'Biển nào dưới đây báo hiệu hết cấm vượt là Biển 2 và biển 3.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2401, 61, 'Trong các biển dưới đây biển nào là biển Hết mọi lệnh cấm?', '197', 'oto/439.webp', 'Trong các biển dưới đây biển nào là biển  là Biển 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2402, 61, 'Biển nào cho phép được quay đầu xe đi theo hướng ngược lại khi đặt biển trước ngã ba, ngã tư?', '198', 'oto/440.webp', 'Biển nào cho phép được quay đầu xe đi theo hướng ngược lại khi đặt biển trước ngã ba, ngã tư là Biển 3.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2403, 61, 'Biển nào không cho phép rẽ phải?', '199', 'oto/441.webp', 'Biển nào không cho phép rẽ phải là Biển 1.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2404, 61, 'Khi đến chỗ giao nhau, gặp biển nào thì người lái xe không được cho xe đi thẳng, phải rẽ sang hướng khác?', '200', 'oto/442.webp', 'Khi đến chỗ giao nhau, gặp biển nào thì người lái xe không được cho xe đi thẳng, phải rẽ sang hướng khác là Biển 1 và biển 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2405, 61, 'Biển số 1 có ý nghĩa như thế nào?', '201', 'oto/445.webp', 'Biển số 1 có ý nghĩa như thế nào là Biển chỉ dẫn hết cấm đỗ xe theo giờ trong khu vực.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2406, 61, 'Biển nào chỉ dẫn cho người đi bộ sử dụng cầu vượt qua đường?', '202', 'oto/450.webp', 'Biển nào chỉ dẫn cho người đi bộ sử dụng cầu vượt qua đường là Biển 1.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2407, 61, 'Biển nào chỉ dẫn cho người đi bộ sử dụng hầm chui qua đường?', '203', 'oto/451.webp', 'Biển nào chỉ dẫn cho người đi bộ sử dụng hầm chui qua đường là Biển 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2408, 61, 'Biển nào báo hiệu Nơi đỗ xe dành cho người khuyết tật?', '204', 'oto/452.webp', 'Biển nào báo hiệu  là Biển 1.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2409, 61, 'Gặp biển báo này, người tham gia giao thông phải xử lý như thế nào?', '205', 'oto/454.webp', 'Gặp biển báo này, người tham gia giao thông phải xử lý như thế nào là Phải giảm tốc độ đến mức an toàn và không được vượt khi đi qua khu vực này.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2410, 61, 'Gặp biển báo dưới đây, người lái xe có bắt buộc phải chạy vòng theo đảo an toàn theo hướng mũi tên khi muốn chuyển hướng hay không?', '206', 'oto/455.webp', 'Gặp biển báo dưới đây, người lái xe có bắt buộc phải chạy vòng theo đảo an toàn theo hướng mũi tên khi muốn chuyển hướng hay không là Bắt buộc.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2411, 61, 'Biển nào báo hiệu Cầu vượt liên thông?', '207', 'oto/457.webp', 'Biển nào báo hiệu  là Biển 2 và biển 3.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2412, 61, 'Biển số 1 có ý nghĩa như thế nào?', '208', 'oto/458.webp', 'Biển số 1 có ý nghĩa như thế nào là Báo hiệu cầu vượt liên thông.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2413, 61, 'Biển nào báo hiệu Tuyến đường cầu vượt cắt qua?', '209', 'oto/459.webp', 'Biển nào báo hiệu  là Biển 1 và biển 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2414, 61, 'Biển báo dưới đây có ý nghĩa như thế nào?', '210', 'oto/460.webp', 'Biển báo dưới đây có ý nghĩa như thế nào là Chỉ dẫn khoảng cách đến làn đường cứu nạn (làn thoát xe khẩn cấp).', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2415, 61, 'Tại đoạn đường có biển Làn đường dành riêng cho từng loại xe dưới đây, các phương tiện có được phép chuyển sang làn khác để đi theo hành trình mong muốn khi đến gần nơi đường bộ giao nhau hay không?', '211', 'oto/461.webp', 'Tại đoạn đường có biển  là Được phép chuyển sang làn khác.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2416, 61, 'Biển nào chỉ dẫn người lái xe đi được cả hai hướng?', '212', 'oto/474.webp', 'Biển nào chỉ dẫn người lái xe đi được cả hai hướng là Biển 1.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2417, 61, 'Biển này có ý nghĩa như thế nào?', '213', 'oto/475.webp', 'Biển này có ý nghĩa như thế nào là Chỉ dẫn hướng rẽ để nhắc người điều khiển phương tiện chuẩn bị đổi hướng đi khi sắp vào đường cong nguy hiểm, có bán kính cong nhỏ.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2418, 61, 'Vạch mũi tên chỉ hướng trên mặt đường nào dưới đây cho phép xe chỉ được đi thẳng và rẽ phải?', '214', 'oto/476.webp', 'Vạch mũi tên chỉ hướng trên mặt đường nào dưới đây cho phép xe chỉ được đi thẳng và rẽ phải là Vạch 2 và vạch 3.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2419, 61, 'Vạch kẻ đường nào dưới đây là vạch phân chia hai chiều xe chạy (vạch tim đường), xe không được lấn làn, không được đè lên vạch?', '215', 'oto/478.webp', 'Vạch kẻ đường nào dưới đây là vạch phân chia hai chiều xe chạy (vạch tim đường), xe không được lấn làn, không được đè lên vạch là Vạch 2.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2420, 62, 'Theo hướng mũi tên, xe nào chấp hành đúng quy tắc giao thông?', '216', 'oto/486.webp', 'Theo hướng mũi tên, xe nào chấp hành đúng quy tắc giao thông là Xe khách, xe tải, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2421, 62, 'Theo hướng mũi tên, thứ tự các xe đi như thế nào là đúng quy tắc giao thông?', '217', 'oto/487.webp', 'Theo hướng mũi tên, thứ tự các xe đi như thế nào là đúng quy tắc giao thông là Xe tải, xe khách, xe con, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2422, 62, 'Theo hướng mũi tên, thứ tự các xe đi như thế nào là đúng quy tắc giao thông?', '218', 'oto/490.webp', 'Theo hướng mũi tên, thứ tự các xe đi như thế nào là đúng quy tắc giao thông là Xe tải, xe con, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2423, 62, 'Trường hợp này xe nào được quyền đi trước?', '219', 'oto/492.webp', 'Trường hợp này xe nào được quyền đi trước là Xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2424, 62, 'Xe nào được quyền đi trước trong trường hợp này?', '220', 'oto/495.webp', 'Xe nào được quyền đi trước trong trường hợp này là Xe cứu thương đi làm nhiệm vụ cấp cứu.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2425, 62, 'Theo tín hiệu đèn, xe nào được phép đi?', '221', 'oto/499.webp', 'Theo tín hiệu đèn, xe nào được phép đi là Xe con và xe khách.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2426, 62, 'Theo tín hiệu đèn, xe nào đi là đúng quy tắc giao thông?', '222', 'oto/500.webp', 'Theo tín hiệu đèn, xe nào đi là đúng quy tắc giao thông là Xe khách, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2427, 62, 'Các xe đi theo hướng mũi tên, những xe nào vi phạm quy tắc giao thông?', '223', 'oto/503.webp', 'Các xe đi theo hướng mũi tên, những xe nào vi phạm quy tắc giao thông là Xe khách, xe tải, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL);
INSERT INTO `quizzes` (`id`, `quiz_set_id`, `question`, `name`, `image`, `explanation`, `mandatory`, `wrong`, `created_at`, `updated_at`, `tip`, `tip_image`) VALUES
(2428, 62, 'Theo hướng mũi tên, thứ tự các xe đi như thế nào là đúng quy tắc giao thông?', '224', 'oto/504.webp', 'Theo hướng mũi tên, thứ tự các xe đi như thế nào là đúng quy tắc giao thông là Xe khách, xe tải, xe mô tô, xe con.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2429, 62, 'Trong trường hợp này xe nào đỗ vi phạm quy tắc giao thông?', '225', 'oto/505.webp', 'Trong trường hợp này xe nào đỗ vi phạm quy tắc giao thông là Xe tải.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2430, 62, 'Theo hướng mũi tên, những hướng nào xe gắn máy được phép đi?', '226', 'oto/507.webp', 'Theo hướng mũi tên, xe nào được quyền đi trước là Xe tải.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2431, 62, 'Xe nào đỗ vi phạm quy tắc giao thông?', '227', 'oto/508.webp', 'Xe nào đỗ vi phạm quy tắc giao thông là Cả hai xe.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2432, 62, 'Xe nào đỗ vi phạm quy tắc giao thông?', '228', 'oto/509.webp', 'Xe nào đỗ vi phạm quy tắc giao thông là Cả ba xe.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2433, 62, 'Xe nào được quyền đi trước trong trường hợp này?', '229', 'oto/517.webp', 'Xe nào được quyền đi trước trong trường hợp này là Xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2434, 62, 'Theo hướng mũi tên, thứ tự các xe đi như thế nào là đúng quy tắc giao thông?', '230', 'oto/520.webp', 'Theo hướng mũi tên, những hướng nào xe ô tô con được phép đi là Hướng 1, 3 và 4.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2435, 62, 'Xe nào được quyền đi trước trong trường hợp này?', '231', 'oto/525.webp', 'Xe nào được quyền đi trước trong trường hợp này là Xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2436, 62, 'Xe nào vi phạm quy tắc giao thông?', '232', 'oto/527.webp', 'Xe nào vi phạm quy tắc giao thông là Xe con.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2437, 62, 'Các xe đi như thế nào là đúng quy tắc giao thông?', '233', 'oto/528.webp', 'Tất cả các xe phải dừng lại trước ngã tư, trừ những xe đã ở trong ngã tư được phép tiếp tục đi.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2438, 62, 'Theo hướng mũi tên, xe nào được phép đi?', '234', 'oto/529.webp', 'Theo hướng mũi tên, xe nào được phép đi là Xe mô tô, xe con.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2439, 62, 'Trong hình dưới đây, xe nào chấp hành đúng quy tắc giao thông?', '235', 'oto/538.webp', 'Trong hình dưới đây, xe nào chấp hành đúng quy tắc giao thông là Tất cả các loại xe trên.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2440, 62, 'Theo hướng mũi tên, những hướng nào xe mô tô được phép đi?', '236', 'oto/539.webp', 'Theo hướng mũi tên, những hướng nào xe mô tô được phép đi là Cả ba hướng.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2441, 62, 'Trong trường hợp này, thứ tự xe đi như thế nào là đúng quy tắc giao thông?', '237', 'oto/540.webp', 'Trong trường hợp này, thứ tự xe đi như thế nào là đúng quy tắc giao thông là Xe quân sự đi làm nhiệm vụ khẩn cấp, xe công an đi làm nhiệm vụ khẩn cấp, xe con + xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2442, 62, 'Trong hình dưới, những xe nào vi phạm quy tắc giao thông?', '238', 'oto/543.webp', 'Trong hình dưới, những xe nào vi phạm quy tắc giao thông là Xe con (E), xe mô tô (C).', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2443, 62, 'Trong hình dưới, những xe nào vi phạm quy tắc giao thông?', '239', 'oto/548.webp', 'Trong hình dưới, những xe nào vi phạm quy tắc giao thông là Xe con (B), xe mô tô (C).', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2444, 62, 'Theo tín hiệu đèn, xe nào phải dừng lại là đúng quy tắc giao thông?', '240', 'oto/553.webp', 'Theo tín hiệu đèn, xe nào phải dừng lại là đúng quy tắc giao thông là Xe khách, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2445, 62, 'Bạn có được phép vượt xe mô tô phía trước không?', '241', 'oto/556.webp', 'Bạn có được phép vượt xe mô tô phía trước không là Không được vượt.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2446, 62, 'Theo tín hiệu đèn của xe cơ giới, xe nào vi phạm quy tắc giao thông?', '242', 'oto/559.webp', 'Theo tín hiệu đèn của xe cơ giới, xe nào vi phạm quy tắc giao thông là Không xe nào vi phạm.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2447, 62, 'Các xe đi theo hướng mũi tên, xe nào vi phạm quy tắc giao thông?', '243', 'oto/560.webp', 'Các xe đi theo hướng mũi tên, xe nào vi phạm quy tắc giao thông là Xe tải.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2448, 62, 'Các xe đi theo hướng mũi tên, xe nào vi phạm quy tắc giao thông?', '244', 'oto/562.webp', 'Các xe đi theo hướng mũi tên, xe nào vi phạm quy tắc giao thông là Xe tải, xe khách, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2449, 62, 'Các xe đi theo hướng mũi tên, xe nào chấp hành đúng quy tắc giao thông?', '245', 'oto/565.webp', 'Các xe đi theo hướng mũi tên, xe nào chấp hành đúng quy tắc giao thông là Xe khách, xe mô tô.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2450, 62, 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ?', '246', 'oto/567.webp', 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ là Xe của bạn, xe mô tô, xe con.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2451, 62, 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ?', '247', 'oto/568.webp', 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ là Xe của bạn, xe mô tô, xe con.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2452, 62, 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ?', '248', 'oto/583.webp', 'Các xe đi theo thứ tự nào là đúng quy tắc giao thông đường bộ là Xe của bạn, xe mô tô, xe đạp.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2453, 62, 'Xe nào dừng đúng theo quy tắc giao thông?', '249', 'oto/592.webp', 'Xe nào dừng đúng theo quy tắc giao thông là Xe con.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL),
(2454, 62, 'Trong tình huống dưới đây, xe đầu kéo kéo rơ moóc (xe container) đang rẽ phải, xe con màu xanh và xe máy phía sau xe container đi như thế nào để bảo đảm an toàn?', '250', 'oto/600.webp', 'Trong tình huống dưới đây, xe đầu kéo kéo rơ moóc (xe container) đang rẽ phải, xe con màu xanh và xe máy phía sau xe container đi như thế nào để bảo đảm an toàn là Giảm tốc độ chờ xe container rẽ xong rồi tiếp tục đi.', 0, 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21', NULL, NULL);
