(5631, 1777, 'Ý 1 và ý 2.', 1, NULL, NULL),
(5632, 1778, 'Có thiết bị ghi nhận hình ảnh trẻ em mầm non, học sinh và thiết bị có chức năng cảnh báo, chống bỏ quên trẻ em trên xe; có niên hạn sử dụng không quá 20 năm; có màu sơn theo quy định của Chính phủ.', 0, NULL, NULL),
(5633, 1778, 'Có dây đai an toàn phù hợp với lứa tuổi hoặc sử dụng xe có ghế ngồi phù hợp với lứa tuổi theo quy định của pháp luật.', 0, NULL, NULL),
(5634, 1778, 'Được cấp chứng nhận đăng kí xe và gắn biển số xe, bảo đảm an toàn kĩ thuật và bảo vệ môi trường theo quy định của pháp luật; xe ô tô chở người từ 08 chỗ trở lên (không kể chỗ của người lái xe) phải lắp thiết bị giám sát hành trình và thiết bị ghi nhận hình ảnh người lái xe.', 0, NULL, NULL),
(5635, 1778, 'Cả ba ý trên.', 1, NULL, NULL),
(5636, 1779, 'Người lái xe phải mang đủ giấy tờ theo quy định của pháp luật.', 0, NULL, NULL),
(5637, 1779, 'Phương tiện vận chuyển phải có kết cấu phù hợp với loại động vật chuyên chở.', 0, NULL, NULL),
(5638, 1779, 'Trong quá trình vận chuyển phải chấp hành các quy định của pháp luật về trật tự, an toàn giao thông đường bộ, vệ sinh dịch tễ, phòng dịch và bảo đảm vệ sinh môi trường.', 0, NULL, NULL),
(5639, 1779, 'Cả ba ý trên.', 1, NULL, NULL),
(5640, 1780, 'Phải có giấy phép vận chuyển; trong trường hợp cần thiết, đơn vị vận chuyển hàng hoá nguy hiểm phải bố trí người áp tải để bảo đảm trật tự, an toàn giao thông đường bộ.', 1, NULL, NULL),
(5641, 1780, 'Phải có giấy phép vận chuyển; không phải bố trí người áp tải khi tham gia giao thông đường bộ.', 0, NULL, NULL),
(5642, 1781, 'Phải chấp hành quy định của pháp luật về trật tự, an toàn giao thông đường bộ của Việt Nam. Trường hợp điều ước quốc tế mà nước Cộng hòa xã hội chủ nghĩa Việt Nam là thành viên có quy định khác thì áp dụng theo điều ước quốc tế đó.', 0, NULL, NULL),
(5643, 1781, 'Tham gia giao thông đúng trong phạm vi, tuyến đường, thời gian đã được cơ quan có thẩm quyền của Việt Nam cấp phép.', 0, NULL, NULL),
(5644, 1781, 'Xe ô tô của người nước ngoài đăng ký tại nước ngoài có tay lái ở bên phải phải đi theo đoàn và có người, phương tiện hỗ trợ, hướng dẫn giao thông.', 0, NULL, NULL),
(5645, 1781, 'Cả ba ý trên.', 1, NULL, NULL),
(5646, 1782, 'Kiểm tra điều kiện bảo đảm an toàn của xe trước khi tham gia giao thông đường bộ; mang đủ giấy tờ theo quy định của pháp luật.', 0, NULL, NULL),
(5647, 1782, 'Kiểm tra việc sắp xếp hàng hóa bảo đảm an toàn; không chở quá số người, chở hành lý, hàng hoá vượt quá khối lượng cho phép hoặc vượt quá khổ giới hạn của xe.', 0, NULL, NULL),
(5648, 1782, 'Cả hai ý trên.', 1, NULL, NULL),
(5649, 1783, 'Phải chạy với tốc độ quy định trong giấy phép và phải có báo hiệu kích thước của hàng; trường hợp cần thiết, phải có người, phương tiện hỗ trợ lái xe, cảnh báo cho người, phương tiện tham gia giao thông đường bộ khác và thực hiện các biện pháp bảo đảm an toàn giao thông khi vận chuyển hàng siêu trường, siêu trọng trên đường bộ.', 1, NULL, NULL),
(5650, 1783, 'Phải chạy với tốc độ quy định trong giấy phép; phải có người, phương tiện hỗ trợ lái xe, cảnh báo cho người, phương tiện tham gia giao thông đường bộ khác và thực hiện các biện pháp bảo đảm an toàn giao thông khi vận chuyển hàng siêu trường, siêu trọng trên đường dành cho giao thông công cộng.', 0, NULL, NULL),
(5651, 1784, 'Xe cứu hộ giao thông đường bộ phải có dấu hiệu nhận diện, niêm yết thông tin trên xe, gắn thiết bị giám sát hành trình và thiết bị ghi nhận hình ảnh người lái xe.', 0, NULL, NULL),
(5652, 1784, 'Phải tuân thủ quy định của pháp luật về khối lượng hàng hóa chuyên chở của xe cứu hộ và khối lượng của xe được cứu hộ ghi trên Chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường.', 0, NULL, NULL),
(5653, 1784, 'Cả hai ý trên.', 1, NULL, NULL),
(5654, 1785, 'Được khách hàng, xã hội tôn trọng; được đồng nghiệp quý mến, giúp đỡ; được doanh nghiệp tin dùng và đóng góp nhiều cho xã hội; thu hút được khách hàng, góp phần quan trọng trong xây dựng thương hiệu, kinh doanh có hiệu quả cao.', 1, NULL, NULL),
(5655, 1785, 'Được cộng điểm vào giấy phép lái xe.', 0, NULL, NULL),
(5656, 1785, 'Cả hai ý trên.', 0, NULL, NULL),
(5657, 1786, 'Luôn tuân thủ pháp luật về trật tự, an toàn giao thông đường bộ, nhường nhịn và giúp đỡ người khác.', 1, NULL, NULL),
(5658, 1786, 'Đi nhanh, vượt đèn đỏ nếu không có lực lượng Công an.', 0, NULL, NULL),
