(5660, 1786, 'Tránh nhường đường để đi nhanh hơn.', 0, NULL, NULL),
(5661, 1787, 'Quản lý và sử dụng xe tốt; bảo dưỡng xe đúng định kỳ; thực hành tiết kiệm vật tư, nhiên liệu; luôn tu dưỡng bản thân, có lối sống lành mạnh, tác phong làm việc công nghiệp.', 0, NULL, NULL),
(5662, 1787, 'Nắm vững và tự giác chấp hành các quy định của pháp luật về trật tự, an toàn giao thông đường bộ, lái xe an toàn; thực hiện đầy đủ trách nhiệm với khách hàng; có ý thức tổ chức kỷ luật và xây dựng doanh nghiệp vững mạnh; có tinh thần hợp tác, tương trợ, giúp đỡ đồng nghiệp.', 0, NULL, NULL),
(5663, 1787, 'Cả hai ý trên.', 1, NULL, NULL),
(5664, 1788, 'Phải có thái độ lịch sự, tôn trọng, thân mật với hành khách; giúp đỡ những người có hoàn cảnh khó khăn, người già, người khuyết tật, phụ nữ có thai, có con nhỏ và trẻ em.', 0, NULL, NULL),
(5665, 1788, 'Luôn tu dưỡng bản thân, có lối sống lành mạnh, khiêm tốn, có tác phong làm việc công nghiệp, không tham gia vào các tệ nạn xã hội; tôn trọng người cùng tham gia giao thông đường bộ và có ý thức bảo vệ môi trường.', 0, NULL, NULL),
(5666, 1788, 'Cả hai ý trên.', 1, NULL, NULL),
(5667, 1789, 'Là sự hiểu biết và chấp hành nghiêm chỉnh pháp luật về giao thông, là ý thức trách nhiệm với cộng đồng khi tham gia giao thông.', 0, NULL, NULL),
(5668, 1789, 'Là sự tôn trọng, nhường nhịn, giúp đỡ và ứng xử có văn hóa giữa những người tham gia giao thông với nhau.', 0, NULL, NULL),
(5669, 1789, 'Cả hai ý trên.', 1, NULL, NULL),
(5670, 1790, 'Cho xe chạy thật nhanh qua vũng nước.', 0, NULL, NULL),
(5671, 1790, 'Giảm tốc độ cho xe chạy chậm qua vũng nước.', 1, NULL, NULL),
(5672, 1790, 'Giảm tốc độ cho xe chạy qua làn đường dành cho mô tô để tránh vũng nước.', 0, NULL, NULL),
(5673, 1791, 'Là thiếu văn hóa giao thông, vi phạm pháp luật về trật tự, an toàn giao thông đường bộ.', 1, NULL, NULL),
(5674, 1791, 'Là thiếu văn hóa giao thông.', 0, NULL, NULL),
(5675, 1792, 'Thực hiện cầm máu trực tiếp.', 0, NULL, NULL),
(5676, 1792, 'Thực hiện cầm máu không trực tiếp (chặn động mạch).', 1, NULL, NULL),
(5677, 1793, 'Hiểu biết và chấp hành nghiêm chỉnh pháp luật về giao thông đường bộ; có ý thức trách nhiệm với cộng đồng khi tham gia giao thông; tôn trọng, nhường nhịn, giúp đỡ và ứng xử có văn hóa với những người cùng tham gia giao thông.', 1, NULL, NULL),
(5678, 1793, 'Điều khiển xe vượt quá tốc độ, đi không đúng làn đường.', 0, NULL, NULL),
(5679, 1794, 'Điều khiển xe đi trên phần đường, làn đường có ít phương tiện tham gia giao thông, chỉ đội mũ bảo hiểm ở nơi có biển báo bắt buộc đội mũ bảo hiểm.', 0, NULL, NULL),
(5680, 1794, 'Chấp hành hiệu lệnh, chỉ dẫn của người điều khiển giao thông, quy định về tốc độ, tín hiệu đèn, biển báo hiệu, vạch kẻ đường khi lái xe; nhường đường cho người đi bộ, người già, trẻ em, người khuyết tật.', 1, NULL, NULL),
(5681, 1795, 'Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; đội mũ bảo hiểm đúng quy chuẩn kỹ thuật quốc gia, cài quai đúng quy cách.', 1, NULL, NULL),
(5682, 1795, 'Điều khiển xe đi trên phần đường, làn đường có ít phương tiện tham gia giao thông.', 0, NULL, NULL),
(5683, 1795, 'Điều khiển xe và đội mũ bảo hiểm ở nơi có biển báo bắt buộc đội mũ bảo hiểm.', 0, NULL, NULL),
(5684, 1796, 'Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; dừng, đỗ xe đúng nơi quy định; đã uống rượu, bia thì không lái xe.', 1, NULL, NULL),
(5685, 1796, 'Điều khiển xe đi trên phần đường, làn đường có ít phương tiện giao thông; dừng xe, đỗ xe ở nơi thuận tiện hoặc theo yêu cầu của hành khách, của người thân.', 0, NULL, NULL),
(5686, 1796, 'Dừng và đỗ xe ở nơi thuận tiện cho việc chuyên chở hành khách và giao nhận hàng hóa; sử dụng ít rượu, bia thì có thể lái xe.', 0, NULL, NULL),
(5687, 1797, 'Chỉ bấm còi khi thật sự cần thiết, không bấm còi liên tục hoặc kéo dài, sử dụng còi với mức âm lượng theo quy định.', 1, NULL, NULL),
(5688, 1797, 'Bấm còi liên tục để các xe khác nhường đường.', 0, NULL, NULL),
(5689, 1797, 'Bấm còi to khi đi qua khu vực đông dân cư.', 0, NULL, NULL),
(5690, 1797, 'Không cần dùng còi, tránh gây tiếng ồn là văn minh.', 0, NULL, NULL),
(5691, 1798, 'Dừng ngay phương tiện, cảnh báo nguy hiểm, giữ nguyên hiện trường, trợ giúp người bị nạn và báo tin cho cơ quan Công an, cơ sở khám bệnh, chữa bệnh.', 0, NULL, NULL),
(5692, 1798, 'Ở lại hiện trường vụ tai nạn giao thông đường bộ cho đến khi người của cơ quan Công an đến, trừ trường hợp phải đi cấp cứu, đưa người bị nạn đi cấp cứu hoặc xét thấy bị đe dọa đến tính mạng, sức khỏe nhưng phải đến trình báo ngay cơ quan Công an, Ủy ban nhân dân nơi gần nhất.', 0, NULL, NULL),
(5693, 1798, 'Cung cấp thông tin xác định danh tính về bản thân, người liên quan đến vụ tai nạn giao thông đường bộ và thông tin liên quan của vụ tai nạn giao thông đường bộ cho cơ quan có thẩm quyền.', 0, NULL, NULL),
(5694, 1798, 'Cả ba ý trên.', 1, NULL, NULL),
(5695, 1799, 'Giúp đỡ, cứu chữa kịp thời người bị nạn; báo tin ngay cho cơ quan Công an, cơ sở khám bệnh, chữa bệnh hoặc Ủy ban nhân dân nơi gần nhất; tham gia bảo vệ hiện trường; tham gia bảo vệ tài sản của người bị nạn; cung cấp thông tin liên quan về vụ tai nạn theo yêu cầu của cơ quan có thẩm quyền.', 1, NULL, NULL),
(5696, 1799, 'Chụp lại hình ảnh vụ tai nạn (nếu có thiết bị ghi hình) và nhanh chóng rời khỏi hiện trường vụ tai nạn.', 0, NULL, NULL),
(5697, 1800, 'Đặt nạn nhân nằm ngửa, khai thông đường thở của nạn nhân; thực hiện các biện pháp hô hấp nhân tạo.', 1, NULL, NULL),
(5698, 1800, 'Thực hiện các biện pháp hô hấp nhân tạo.', 0, NULL, NULL),
(5699, 1801, 'Không bị nghiêm cấm.', 0, NULL, NULL),
(5700, 1801, 'Nghiêm cấm tuỳ từng trường hợp cụ thể.', 0, NULL, NULL),
(5701, 1801, 'Bị nghiêm cấm.', 1, NULL, NULL),
(5702, 1802, 'Giảm tốc độ và nhường đường cho người đi bộ.', 1, NULL, NULL),
(5703, 1802, 'Bấm còi để họ đi nhanh hơn.', 0, NULL, NULL),
(5704, 1802, 'Tiếp tục đi nếu đang vội.', 0, NULL, NULL),
(5705, 1802, 'Vượt qua nếu thấy khoảng trống đủ rộng.', 0, NULL, NULL),
(5706, 1803, 'Chạy đi để tránh rắc rối.', 0, NULL, NULL),
(5707, 1803, 'Dừng xe, hỗ trợ nạn nhân và báo cho cơ quan chức năng.', 1, NULL, NULL),
(5708, 1803, 'Chỉ quan sát rồi tiếp tục di chuyển.', 0, NULL, NULL),
(5709, 1803, 'Chỉ giúp đỡ nếu có người thân trong vụ tai nạn.', 0, NULL, NULL),
(5710, 1804, 'Cho xe lấn sang làn ngược chiều để nhanh chóng thoát khỏi nơi ùn tắc.', 0, NULL, NULL),
(5711, 1804, 'Điều khiển xe trên vỉa hè để nhanh chóng thoát khỏi nơi ùn tắc.', 0, NULL, NULL),
(5712, 1804, 'Kiên nhẫn tuân thủ hướng dẫn của người điều khiển giao thông hoặc tín hiệu đèn giao thông, di chuyển trên đúng phần đường bên phải theo chiều đi, nhường đường cho các phương tiện đi ngược chiều.', 1, NULL, NULL),
(5713, 1805, 'Bấm còi liên tục thúc giục các phương tiện phía trước nhường đường; đi trên vỉa hè, tận dụng mọi khoảng trống để nhanh chóng thoát khỏi nơi ùn tắc; lấn sang trái đường cố gắng vượt lên xe khác.', 1, NULL, NULL),
(5714, 1805, 'Tuân thủ hướng dẫn của người điều khiển giao thông hoặc tín hiệu giao thông, đi đúng phần đường, làn đường quy định.', 0, NULL, NULL),
(5715, 1806, 'Không lắp đặt thêm thiết bị điện, phụ kiện không đúng theo thiết kế của nhà sản xuất; tuân thủ quy trình vận hành bảo trì bảo dưỡng định kỳ; thường xuyên kiểm tra phương tiện, khi phát hiện thấy dấu hiệu khác lạ (khó nổ, có hơi xăng, có tiếng kêu bất thường, nhiệt độ của máy cao, có mùi khét) cần khắc phục ngay.', 0, NULL, NULL),
(5716, 1806, 'Khi để xe trong nhà, ở nơi trông giữ xe phải tắt khóa điện, để xa nguồn lửa, nguồn nhiệt; không mua xăng, dầu ở các điểm bán tự phát, không rõ nguồn gốc; không sử dụng các biện pháp “tiết kiệm xăng, dầu” khi chưa được kiểm chứng về mức độ an toàn có thể gây hỏng xe hoặc dẫn đến nguy cơ xảy ra cháy cao.', 0, NULL, NULL),
(5717, 1806, 'Không để các chất dễ cháy, dễ bắt lửa trong xe, dưới yên xe, trong cốp xe, trong khoang động cơ. Đối với xe điện cần chọn địa điểm sạc an toàn, sử dụng các thiết bị sạc đúng cách và giám sát quá trình sạc.', 0, NULL, NULL),
(5718, 1806, 'Cả ba ý trên.', 1, NULL, NULL),
(5719, 1807, 'Tắt khoá điện, hô hoán để mọi người đến trợ giúp chữa cháy, gọi Cảnh sát phòng cháy chữa cháy và cứu nạn cứu hộ (điện thoại 114).', 0, NULL, NULL),
(5720, 1807, 'Nếu nhiên liệu chưa trào ra ngoài (ngọn lửa chưa cháy dữ dội) thì có thể sử dụng nước, hoặc bất kỳ chất, phương tiện chữa cháy có được để dập lửa; nếu nhiên liệu đã trào ra ngoài (ngọn lửa cháy dữ dội) thì phải sử dụng các bình chữa cháy, cát, chăn chiên, bao tải, vải nhúng nước để dập lửa.', 0, NULL, NULL),
(5721, 1807, 'Cả hai ý trên.', 1, NULL, NULL),
(5722, 1808, 'Bình tĩnh, đưa xe sát vào lề đường, tránh xa nơi có nhiều người, nhiều chất dễ cháy và tắt khóa điện, thực hiện các bước chữa cháy.', 1, NULL, NULL),
(5723, 1808, 'Hô hoán để mọi người đến trợ giúp chữa cháy, gọi Cảnh sát giao thông, Cảnh sát phòng cháy, chữa cháy và cứu nạn, cứu hộ, lực lượng y tế để sẵn sàng hỗ trợ cứu người.', 0, NULL, NULL),
(5724, 1808, 'Nếu nhiên liệu trào ra ngoài, ngọn lửa chưa cháy dữ dội thì tiếp tục sử dụng nước, hoặc bất kỳ chất, phương tiện chữa cháy có được để dập lửa.', 0, NULL, NULL),
(5725, 1808, 'Cả ba ý trên.', 0, NULL, NULL),
(5726, 1809, 'Gọi số 115 để thông báo về tình trạng tai nạn và yêu cầu hỗ trợ y tế ngay lập tức. Quan sát hiện trường để giúp nạn nhân, đồng thời tránh gây tổn thương cho mình.', 0, NULL, NULL),
(5727, 1809, 'Nhanh chóng loại bỏ nguyên nhân gây bỏng bằng cách tách nạn nhân khỏi vật gây cháy, cởi bỏ quần áo nếu bén lửa, ngâm vùng da bị bỏng vào nước sạch hoặc đắp khăn mát, lưu ý không dùng khăn hoặc nước quá lạnh.', 0, NULL, NULL),
(5728, 1809, 'Nếu nạn nhân còn tỉnh, cần cho uống bù nước. Trong thời tiết lạnh, cần giữ ấm cho cơ thể nạn nhân, sau đó nhanh chóng đưa đến cơ sở y tế gần nhất.', 0, NULL, NULL),
(5729, 1809, 'Cả ba ý trên.', 1, NULL, NULL),
(5730, 1810, 'Giữ tay ga ở mức độ phù hợp, sử dụng phanh trước và phanh sau để giảm tốc độ.', 1, NULL, NULL),
(5731, 1810, 'Nhả hết tay ga, tắt động cơ, sử dụng phanh trước và phanh sau để giảm tốc độ.', 0, NULL, NULL),
(5732, 1810, 'Sử dụng phanh trước để giảm tốc độ kết hợp với tắt chìa khóa điện của xe.', 0, NULL, NULL),
(5733, 1811, 'Đạp bàn đạp phanh chân hết hành trình, vào số và nhả phanh đỗ, kiểm tra lại xem có bị nhầm số không rồi mới cho xe lăn bánh.', 1, NULL, NULL),
(5734, 1811, 'Đạp bàn đạp để tăng ga với mức độ phù hợp, vào số và kiểm tra lại xem có bị nhầm số không rồi mới cho xe lăn bánh.', 0, NULL, NULL),
(5735, 1812, 'Dùng lực tay phải kéo cần phanh tay về phía sau hết hành trình; nếu khóa hãm bị kẹt cứng phải đẩy mạnh phanh tay về phía trước, sau đó bóp khóa hãm.', 0, NULL, NULL),
(5736, 1812, 'Dùng lực tay phải bóp khóa hãm đẩy cần phanh tay về phía trước hết hành trình; nếu khóa hãm bị kẹt cứng phải kéo cần phanh tay về phía sau đồng thời bóp khóa hãm.', 1, NULL, NULL),
(5737, 1812, 'Dùng lực tay phải đẩy cần phanh tay về phía trước hết hành trình; nếu khóa hãm bị kẹt cứng phải đẩy mạnh phanh tay về phía trước, sau đó bóp khóa hãm.', 0, NULL, NULL),
(5738, 1813, 'Kiểm tra an toàn xung quanh xe ô tô; nhả từ từ đến 1/2 hành trình bàn đạp ly hợp (côn) và giữ trong khoảng 3 giây; vào số 1; nhả hết phanh tay, báo hiệu bằng còi, đèn trước khi xuất phát; tăng ga đủ để xuất phát, sau đó vừa tăng ga vừa nhả hết côn để cho xe ô tô chuyển động.', 0, NULL, NULL),
(5739, 1813, 'Kiểm tra an toàn xung quanh xe ô tô; đạp ly hợp (côn) hết hành trình; vào số 1; nhả hết phanh tay, báo hiệu bằng còi, đèn trước khi xuất phát; tăng ga đủ để xuất phát; nhả từ từ đến 1/2 hành trình bàn đạp côn và giữ trong khoảng 3 giây, sau đó vừa tăng ga vừa nhả hết côn để cho xe ô tô chuyển động.', 1, NULL, NULL),
(5740, 1814, 'Quan sát biển báo hiệu để biết nơi được phép quay đầu; quan sát kỹ địa hình nơi chọn để quay đầu; lựa chọn quỹ đạo quay đầu xe cho thích hợp; quay đầu xe với tốc độ thấp; thường xuyên báo tín hiệu để người, các phương tiện xung quanh được biết; nếu quay đầu xe ở nơi nguy hiểm thì đưa đầu xe về phía nguy hiểm, đưa đuôi xe về phía an toàn.', 1, NULL, NULL),
(5741, 1814, 'Quan sát biển báo hiệu để biết nơi được phép quay đầu; quan sát kỹ địa hình nơi chọn để quay đầu; lựa chọn quỹ đạo quay đầu xe; quay đầu xe với tốc độ tối đa; thường xuyên báo tín hiệu để người, các phương tiện xung quanh được biết; nếu quay đầu xe ở nơi nguy hiểm thì đưa đuôi xe về phía nguy hiểm và đầu xe về phía an toàn.', 0, NULL, NULL),
(5742, 1815, 'Điều chỉnh ghế sao cho chân có thể đạp phanh và ga dễ dàng, ngồi thẳng lưng, hai tay nắm vô lăng, tay trái nắm ở vị trí 9 đến 10 giờ và tay phải nắm ở vị trí từ 2 đến 4 giờ.', 1, NULL, NULL),
(5743, 1815, 'Ngồi sát vô lăng để dễ quan sát hoặc ngồi tự do, không cần điều chỉnh ghế.', 0, NULL, NULL),
(5744, 1815, 'Ngồi ngả người về phía sau nhiều để thư giãn, chân trái để ở vị trí chân ga, hai tay nắm vô lăng ở vị trí bất kỳ.', 0, NULL, NULL),
