(5852, 1852, 'Quan sát, phát tín hiệu, nhường đường cho các xe đang chạy trên đường cao tốc, khi đủ điều kiện an toàn thì tăng tốc độ cho xe nhập vào làn đường cao tốc, nếu có làn đường tăng tốc thì phải cho xe chạy trên làn đường đó trước khi cho xe nhập vào làn của đường cao tốc.', 1, NULL, NULL),
(5853, 1852, 'Phát tín hiệu, quan sát các xe đang chạy phía trước, nếu bảo đảm các điều kiện an toàn thì tăng tốc độ cho xe nhập ngay vào làn đường cao tốc.', 0, NULL, NULL),
(5854, 1852, 'Phát tín hiệu và lái xe nhập vào làn đường tăng tốc, quan sát các xe phía sau đang chạy trên đường cao tốc, khi đủ điều kiện an toàn thì giảm tốc độ, từ từ cho xe nhập vào làn đường cao tốc.', 0, NULL, NULL),
(5855, 1853, 'Quan sát phía trước để tìm biển báo chỉ dẫn \"lối ra đường cao tốc\", kiểm tra tình trạng giao thông phía sau và bên phải, nếu bảo đảm điều kiện an toàn thì phát tín hiệu và điều khiển xe chuyển dần sang làn bên phải, nếu có làn đường giảm tốc thì phải cho xe di chuyển trên làn đường đó trước khi ra khỏi đường cao tốc.', 1, NULL, NULL),
(5856, 1853, 'Quan sát phía trước để tìm biển báo chỉ dẫn \"lối ra đường cao tốc\", trường hợp vượt qua \"lối ra đường cao tốc\" thì phát tín hiệu, di chuyển sang làn đường giảm tốc và lùi xe quay trở lại.', 0, NULL, NULL),
(5857, 1854, 'Xe gặp sự cố, tai nạn hoặc trường hợp khẩn cấp không thể di chuyển bình thường.', 1, NULL, NULL),
(5858, 1854, 'Để nghỉ ngơi, đi vệ sinh, chụp ảnh, làm việc riêng...', 0, NULL, NULL),
(5859, 1854, 'Cả hai ý trên.', 0, NULL, NULL),
(5860, 1855, 'Giữ khoảng cách an toàn, tránh đi vào vị trí điểm mù của xe kéo rơ moóc, bật xi nhan trái đồng thời kết hợp đèn, còi xin vượt.', 0, NULL, NULL),
(5861, 1855, 'Khi xe kéo rơ moóc đã có tín hiệu cho vượt (không có chướng ngại vật phía trước và xe đi ngược chiều), thấy đủ điều kiện an toàn thì vượt dứt khoát, không di chuyển song song bên cạnh xe kéo rơ moóc.', 0, NULL, NULL),
(5862, 1855, 'Khi vượt qua, phải quan sát gương chiếu hậu bên phải nếu có khoảng trống an toàn mới được cho xe chạy vào làn của mình, tắt xi nhan và tiếp tục hành trình.', 0, NULL, NULL),
(5863, 1855, 'Cả ba ý trên.', 1, NULL, NULL),
(5864, 1856, 'Nhả bàn đạp ga, về số thấp, đạp phanh chân với mức độ phù hợp để giảm tốc độ.', 1, NULL, NULL),
(5865, 1856, 'Nhả bàn đạp ga, về số N đạp phanh chân và kéo phanh tay để giảm tốc độ.', 0, NULL, NULL),
(5866, 1857, 'Quan sát, giảm tốc độ, phát tín hiệu, nhường đường cho xe trên đường chính từ bất kỳ hướng nào tới.', 1, NULL, NULL),
(5867, 1857, 'Nháy đèn, bấm còi để xe đi trên đường chính biết và tăng tốc độ cho xe đi ra đường chính.', 0, NULL, NULL),
(5868, 1857, 'Quan sát xe đang đi trên đường chính, nếu là xe có kích thước lớn hơn thì nhường đường, xe có kích thước nhỏ hơn thì tăng tốc độ cho xe đi ra đường chính.', 0, NULL, NULL),
(5869, 1858, 'Giảm tốc độ để bảo đảm an toàn với xe phía trước và sử dụng điện thoại để liên lạc.', 0, NULL, NULL),
(5870, 1858, 'Giảm tốc độ để dừng xe ở nơi cho phép sau đó sử dụng điện thoại để liên lạc.', 1, NULL, NULL),
