(5917, 1871, 'Ý 1 và ý 2.', 1, NULL, NULL),
(5918, 1872, 'Là loại kính an toàn, kính nhiều lớp, đúng quy cách, không rạn nứt, bảo đảm hình ảnh quan sát rõ ràng, không bị méo mó.', 1, NULL, NULL),
(5919, 1872, 'Là loại kính trong suốt, không rạn nứt, bảo đảm tầm nhìn cho người điều khiển về phía trước mặt và hai bên.', 0, NULL, NULL),
(5920, 1873, 'Bánh xe phải có kết cấu chắc chắn, lắp đặt đúng quy cách của nhà sản xuât.', 0, NULL, NULL),
(5921, 1873, 'Lốp phải đủ số lượng, đủ áp suất, không phồng rộp, đúng cỡ lốp của nhà sản xuất hoặc tài liệu kỹ thuật quy định; lốp trên cùng một trục của xe sử dụng trong điều kiện hoạt động bình thường phải cùng kiểu loại.', 0, NULL, NULL),
(5922, 1873, 'Cả hai ý trên.', 1, NULL, NULL),
(5923, 1874, 'Bảo đảm cho xe chuyển hướng chính xác, điều khiển nhẹ nhàng, an toàn ở mọi vận tốc và tải trọng trong phạm vi tính năng kỹ thuật cho phép của xe.', 0, NULL, NULL),
(5924, 1874, 'Khi hoạt động các cơ cấu chuyển động của hệ thống lái không được va chạm với bất kỳ bộ phận nào của xe; khi quay vô lăng lái về bên phải và bên trái thì không được có sự khác biệt đáng kể về lực tác động lên vành tay lái.', 0, NULL, NULL),
(5925, 1874, 'Cả hai ý trên.', 1, NULL, NULL),
(5926, 1875, 'Bảo dưỡng ô tô thường xuyên làm cho ô tô luôn luôn có tính năng kỹ thuật tốt, giảm cường độ hao mòn của các chi tiết, kéo dài tuổi thọ của xe.', 0, NULL, NULL),
(5927, 1875, 'Ngăn ngừa và phát hiện kịp thời các hư hỏng và sai lệch kỹ thuật để khắc phục, giữ gìn được hình thức bên ngoài.', 0, NULL, NULL),
(5928, 1875, 'Cả hai ý trên.', 1, NULL, NULL),
(5929, 1876, 'Hết nhiên liệu, lõi lọc nhiên liệu bị tắc, lọc khí bị tắc, nhiên liệu lẫn không khí, tạp chất.', 1, NULL, NULL),
(5930, 1876, 'Hết nhiên liệu, lõi lọc nhiên liệu bị tắc, lọc khí bị tắc, nhiên liệu lẫn không khí, không có tia lửa điện.', 0, NULL, NULL);
