(7067, 2245, 'Từ 22 giờ ngày hôm trước đến 05 giờ ngày hôm sau.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7068, 2245, 'Từ 05 giờ đến 22 giờ.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7069, 2245, 'Từ 23 giờ ngày hôm trước đến 05 giờ sáng hôm sau.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7070, 2246, 'Chỉ bật đèn chiếu xa (đèn pha).', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7071, 2246, 'Bật đèn chiếu xa (đèn pha) khi đường vắng, bật đèn chiếu gần (đèn cốt) khi có xe đi ngược chiều.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7072, 2246, 'Chỉ bật đèn chiếu gần (đèn cốt).', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7073, 2247, 'Dùng tay cầm và sử dụng điện thoại hoặc thiết bị điện tử khác.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7074, 2247, 'Chỉ được chở người trên thùng xe ô tô chở hàng trong trường hợp chở người đi làm nhiệm vụ cứu nạn, cứu hộ, phòng, chống thiên tai, dịch bệnh hoặc thực hiện nhiệm vụ khẩn cấp.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7075, 2248, 'Trên cầu hẹp có một làn đường; nơi đường giao nhau, đường bộ giao nhau cùng mức với đường sắt; khi gặp xe ưu tiên.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7076, 2248, 'Trên cầu có từ 02 làn xe trở lên.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7077, 2248, 'Trên đường có 02 làn đường được phân chia làn bằng vạch kẻ nét đứt.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7078, 2249, 'Ở phần đường dành cho người đi bộ qua đường, trên cầu, đầu cầu, gầm cầu vượt, ngầm.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7079, 2249, 'Tại nơi đường bộ giao nhau cùng mức với đường sắt, đường hẹp, đường dốc, đoạn đường cong tầm nhìn bị che khuất, trên đường cao tốc, trong hầm đường bộ, trên đường một chiều.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7080, 2249, 'Cả hai ý trên.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7081, 2250, 'Phải quan sát, bảo đảm khoảng cách an toàn với xe phía sau.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7082, 2250, 'Giảm tốc độ và có tín hiệu báo hướng rẽ.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7083, 2250, 'Chuyển dần sang làn gần nhất với hướng rẽ. Khi bảo đảm an toàn, không gây trở ngại cho người và phương tiện khác mới được chuyển hướng.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7084, 2250, 'Cả ba ý trên.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7085, 2251, 'Khi bắt đầu chuyển làn đường.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7086, 2251, 'Trước khi thay đổi làn đường.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7087, 2251, 'Sau khi thay đổi làn đường.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7088, 2252, 'Trên miệng cống thoát nước, miệng hầm của đường điện thoại, điện cao thế, chỗ dành riêng cho xe chữa cháy lấy nước.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7089, 2252, 'Trong phạm vi an toàn của đường sắt.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7090, 2252, 'Cả hai ý trên.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7091, 2253, 'Được phép.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7092, 2253, 'Nếu phương tiện được kéo, đẩy có khối lượng nhỏ hơn phương tiện của mình.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7093, 2253, 'Tùy trường hợp.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7094, 2253, 'Không được phép.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7095, 2254, 'Buông cả hai tay; đứng, nằm trên xe điều khiển xe; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7096, 2254, 'Chở tối đa hai người phía sau khi chở người bệnh đi cấp cứu, áp giải người có hành vi vi phạm pháp luật, trẻ em dưới 12 tuổi và người già yếu hoặc người khuyết tật.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7097, 2255, 'Buông cả hai tay; sử dụng xe để kéo, đẩy xe khác, vật khác; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy.', 1, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7098, 2255, 'Sử dụng xe để chở người hoặc hàng hóa; để chân chạm xuống đất khi khởi hành.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7099, 2255, 'Đội mũ bảo hiểm; chạy xe đúng tốc độ quy định và chấp hành đúng quy tắc giao thông đường bộ.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7100, 2255, 'Chở người ngồi sau dưới 16 tuổi.', 0, '2025-06-04 01:38:20', '2025-06-04 01:38:20'),
(7101, 2256, 'Mang, vác vật cồng kềnh.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7102, 2256, 'Bám, kéo hoặc đẩy các phương tiện khác.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7103, 2256, 'Dùng tay cầm điện thoại hoặc các thiết bị điện tử khác.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7104, 2256, 'Ý 1 và ý 2.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7105, 2257, 'Được phép.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7106, 2257, 'Được bám trong trường hợp phương tiện của mình bị hỏng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7107, 2257, 'Được kéo, đẩy trong trường hợp phương tiện khác bị hỏng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7108, 2257, 'Không được phép.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7109, 2258, 'Đội mũ bảo hiểm theo đúng quy chuẩn kỹ thuật quốc gia và cài quai đúng quy cách.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7110, 2258, 'Người lái xe phải đội mũ bảo hiểm, người được chở trên xe không nhất thiết phải đội mũ bảo hiểm.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7111, 2258, 'Phải đội mũ bảo hiểm nhưng không nhất thiết phải cài quai.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7112, 2259, 'Chở người bệnh đi cấp cứu; áp giải người có hành vi vi phạm pháp luật; trẻ em dưới 12 tuổi; người già yếu hoặc người khuyết tật.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7113, 2259, 'Người đã uống rượu, bia; người trong cơ thể có chất ma tuý.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7114, 2259, 'Cả hai ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7115, 2260, 'Đi xe dàn hàng ngang; buông cả hai tay.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7116, 2260, 'Sử dụng xe để kéo, đẩy xe khác, vật khác, dẫn dắt vật nuôi, mang, vác và chở vật cồng kềnh; chở người đứng trên xe, giá đèo hàng hoặc ngồi trên tay lái; xếp hàng hóa trên xe quá giới hạn quy định.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7117, 2260, 'Ngồi về một bên điều khiển xe; đứng, nằm trên xe điều khiển xe; thay người lái xe khi xe đang chạy; quay người về phía sau để điều khiển xe hoặc bịt mắt điều khiển xe; sử dụng chân chống hoặc vật khác quệt xuống đường khi xe đang chạy.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7118, 2260, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7119, 2261, 'Đi xe dàn hàng ngang; đi xe vào phần đường dành cho người đi bộ và phương tiện khác.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7120, 2261, 'Sử dụng ô, thiết bị âm thanh, trừ thiết bị trợ thính.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7121, 2261, 'Cả hai ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7122, 2262, 'Đi trên phần đường, làn đường quy định, chấp hành hiệu lệnh của người điều khiển giao thông, đèn tín hiệu giao thông.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7123, 2262, 'Đi xe dàn hàng ngang, đi xe vào phần đường dành cho người đi bộ.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7124, 2262, 'Cả hai ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7125, 2263, 'Được sử dụng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7126, 2263, 'Chỉ người ngồi sau được sử dụng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7127, 2263, 'Không được sử dụng.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7128, 2263, 'Được sử dụng nếu không có áo mưa.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7129, 2264, 'Chỉ được phép nếu cả hai đội mũ bảo hiểm.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7130, 2264, 'Không được phép.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7131, 2264, 'Chỉ được thực hiện trên đường vắng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7132, 2265, 'Không bị xử phạt chỉ bị nhắc nhở.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7133, 2265, 'Người được chở không bị xử phạt, chỉ xử phạt người điều khiển xe mô tô, xe gắn máy.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7134, 2265, 'Người được chở bị xử phạt, không xử phạt người điều khiển xe mô tô, xe gắn máy.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7135, 2265, 'Xử phạt cả người điều khiển và người được chở trên xe mô tô, xe gắn máy.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7136, 2266, 'Phải đội mũ bảo hiểm theo đúng quy chuẩn kỹ thuật quốc gia và cài quai đúng quy cách, không sử dụng ô, điện thoại di động, thiết bị âm thanh (trừ thiết bị trợ thính).', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7137, 2266, 'Phải đội mũ bảo hiểm khi trời mưa gió hoặc trời quá nắng; có thể sử dụng ô, điện thoại di động, thiết bị âm thanh nhưng phải bảo đảm an toàn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7138, 2266, 'Phải đội mũ bảo hiểm khi cảm thấy mất an toàn giao thông hoặc khi chuẩn bị di chuyển quãng đường xa.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7139, 2267, 'Xe thô sơ, người đi bộ xuống trước, xe cơ giới, xe máy chuyên dùng xuống sau.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7140, 2267, 'Xe cơ giới, xe máy chuyên dùng xuống trước, xe thô sơ, người đi bộ xuống sau.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7141, 2267, 'Xe cơ giới, xe thô sơ xuống trước, xe máy chuyên dùng, người đi bộ xuống sau.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7142, 2268, 'Chỉ được báo hiệu bằng còi.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7143, 2268, 'Phải báo hiệu bằng cả còi và đèn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7144, 2268, 'Chỉ được báo hiệu bằng đèn.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7145, 2269, 'Tăng tốc độ và ra hiệu cho xe sau vượt, không được gây trở ngại cho xe xin vượt.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7146, 2269, 'Giảm tốc độ, có tín hiệu rẽ phải để báo hiệu cho người điều khiển phương tiện tham gia giao thông đường bộ phía sau biết được vượt và đi sát về bên phải của phần đường xe chạy cho đến khi xe sau đã vượt qua, không được cản trở đối với xe xin vượt.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7147, 2269, 'Cho xe đi sát về bên trái của phần đường xe chạy và ra hiệu cho xe sau vượt, không được gây trở ngại cho xe xin vượt.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7148, 2270, 'Giảm tốc độ và cho xe đi về bên phải theo chiều xe chạy của mình.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7149, 2270, 'Một trong hai xe phải dừng lại cho xe kia đi qua mới được đi.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7150, 2270, 'Tăng tốc độ, cho xe đi về bên phải theo chiều xe chạy của mình để nhanh chóng vượt qua.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7151, 2271, 'Nơi đường hẹp chỉ đủ cho một xe chạy và có chỗ tránh xe thì xe nào ở gần chỗ tránh hơn phải vào vị trí tránh, nhường đường cho xe đi ngược chiều.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7152, 2271, 'Xe xuống dốc phải nhường đường cho xe lên dốc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7153, 2271, 'Xe có chướng ngại vật phía trước phải nhường đường cho xe không có chướng ngại vật phía trước.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7154, 2271, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7155, 2272, 'Quan sát, giảm tốc độ hoặc dừng lại để bảo đảm an toàn.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7156, 2272, 'Đi sang làn đường của xe ngược chiều để mở rộng tầm nhìn và vượt xe khác.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7157, 2272, 'Cho xe đi sát bên phải làn đường, bật tín hiệu báo hiệu để vượt bên phải xe khác.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7158, 2273, 'Nhường đường cho xe đi ở bên phải mình tới.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7159, 2273, 'Nhường đường cho xe đi ở bên trái mình tới.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7160, 2273, 'Nhường đường cho xe đi trên đường ưu tiên hoặc đường chính từ bất kỳ hướng nào tới.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7161, 2274, 'Nhường đường cho xe đi đến từ bên phải.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7162, 2274, 'Nhường đường cho xe đi đến từ bên trái.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7163, 2274, 'Không phải nhường đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7164, 2275, 'Phải nhường đường cho xe đi đến từ bên phải.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7165, 2275, 'Xe báo hiệu xin đường trước, xe đó được đi trước.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7166, 2275, 'Phải nhường đường cho xe đi đến từ bên trái.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7167, 2276, 'Xe chữa cháy của Cảnh sát phòng cháy, chữa cháy và cứu nạn, cứu hộ và xe chữa cháy của các lực lượng khác; xe của lực lượng quân sự, công an và kiểm sát; đoàn xe có xe Cảnh sát giao thông dẫn đường; xe cứu thương; xe hộ đê không có tín hiệu ưu tiên theo quy định.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7168, 2276, 'Xe ưu tiên gồm xe chữa cháy của Cảnh sát phòng cháy, chữa cháy và cứu nạn, cứu hộ và xe chữa cháy của các lực lượng khác được huy động đi làm nhiệm vụ chữa cháy; xe của lực lượng quân sự, công an và kiểm sát đi làm nhiệm vụ khẩn cấp; đoàn xe có xe Cảnh sát giao thông dẫn đường; xe cứu thương đi làm nhiệm vụ cấp cứu; xe hộ đê đi làm nhiệm vụ; xe đi làm nhiệm vụ cứu nạn, cứu hộ, khắc phục sự cố thiên tai, dịch bệnh hoặc xe đi làm nhiệm vụ trong tình trạng khẩn cấp theo quy định của pháp luật; đoàn xe tang.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7169, 2276, 'Xe ô tô, xe máy, đoàn xe đang diễu hành có tổ chức có báo tín hiệu xin vượt bằng còi và đèn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7170, 2277, 'Giảm tốc độ, đi sát lề đường bên phải hoặc dừng lại để nhường đường.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7171, 2277, 'Tăng tốc độ và đi sát lề đường bên phải để nhường đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7172, 2277, 'Giảm tốc độ, đi sát lề đường bên trái để nhường đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7173, 2278, 'Không được vượt.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7174, 2278, 'Được phép vượt ở phần đường dành cho người đi bộ qua đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7175, 2278, 'Được vượt khi bảo đảm an toàn.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7176, 2279, 'Không được vượt.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7177, 2279, 'Được vượt khi đang đi trên cầu.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7178, 2279, 'Được phép vượt khi đi qua nơi giao nhau có ít phương tiện cùng tham gia giao thông.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7179, 2279, 'Được vượt khi bảo đảm an toàn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7180, 2280, 'Dừng lại về bên phải đường của mình, trước vạch dừng xe và quan sát hai phía, khi không có phương tiện giao thông đường sắt tới mới được đi qua.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7181, 2280, 'Quan sát hai phía, khi không có phương tiện giao thông đường sắt tới thì nhanh chóng đi qua.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7182, 2280, 'Dừng lại khoảng cách tối thiểu 3 mét tính từ ray đường sắt gần nhất, khi không có phương tiện giao thông đường sắt tới thì nhanh chóng đi qua.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7183, 2281, 'Dừng lại về bên trái đường của mình, trước vạch dừng xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7184, 2281, 'Dừng lại giữa đường của mình, trước vạch dừng xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7185, 2281, 'Dừng lại về bên phải đường của mình, trước vạch dừng xe.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7186, 2282, 'Hiệu lệnh của nhân viên gác chắn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7187, 2282, 'Đèn đỏ sáng nhấp nháy, chuông kêu.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7188, 2282, 'Chắn đường bộ đang dịch chuyển hoặc đã đóng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7189, 2282, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7190, 2283, 'Xe cơ giới, xe máy chuyên dùng phải bật đèn chiếu gần; xe thô sơ phải bật đèn hoặc có vật phát sáng báo hiệu; không dừng xe, đỗ xe trong hầm đường bộ; trường hợp gặp sự cố kỹ thuật hoặc bất khả kháng khác buộc phải dừng xe, đỗ xe, người lái xe, người điều khiển xe máy chuyên dùng phải đưa xe vào vị trí dừng xe, đỗ xe khẩn cấp, nếu không di chuyển được, phải có báo hiệu bằng đèn khẩn cấp và đặt biển hoặc đèn cảnh báo về phía sau xe khoảng cách bảo đảm an toàn.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7191, 2283, 'Xe cơ giới, xe máy chuyên dùng phải bật đèn chiếu xa; được dừng xe, đỗ xe khi cần thiết.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7192, 2283, 'Phải cho xe chạy trên một làn đường và chỉ chuyển làn ở nơi được phép; được quay đầu xe, lùi xe khi cần thiết.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7193, 2284, 'Có báo hiệu cảnh báo nguy hiểm hoặc có chướng ngại vật trên đường; chuyển hướng xe chạy hoặc tầm nhìn bị hạn chế.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7194, 2284, 'Nơi cầu, cống hẹp, đập tràn, đường ngầm, hầm chui, hầm đường bộ; có vật nuôi đi trên đường hoặc chăn thả ở ven đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7195, 2284, 'Điểm dừng xe, đỗ xe trên đường bộ có khách đang lên, xuống xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7196, 2284, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7197, 2285, 'Xe phía trước có tín hiệu rẽ trái hoặc đang rẽ trái hoặc khi xe chuyên dùng đang làm việc trên đường mà không thể vượt bên trái.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7198, 2285, 'Xe phía trước đang đi sát lề đường bên trái.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7199, 2285, 'Cả hai ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7200, 2286, 'Giảm tốc độ, có tín hiệu rẽ phải để báo hiệu cho người điều khiển phương tiện tham gia giao thông đường bộ phía sau biết được vượt và đi sát về bên phải của phần đường xe chạy cho đến khi xe sau đã vượt qua, không được cản trở đối với xe xin vượt.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7201, 2286, 'Lái xe vào lề đường bên trái và giảm tốc độ để xe phía sau vượt qua, không được gây trở ngại đối với xe xin vượt.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7202, 2286, 'Tăng tốc độ, đi sát về bên phải của phần đường xe chạy cho đến khi xe sau đã vượt qua.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7203, 2287, 'Xe máy chuyên dùng có tốc độ thiết kế nhỏ hơn tốc độ tối thiểu quy định đối với đường cao tốc, xe chở người bốn bánh có gắn động cơ, xe chở hàng bốn bánh có gắn động cơ, xe mô tô, xe gắn máy, các loại xe tương tự xe mô tô, xe gắn máy, xe thô sơ, người đi bộ.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7204, 2287, 'Xe máy chuyên dùng có tốc độ thiết kế lớn hơn tốc độ tối thiểu quy định đối với đường cao tốc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7205, 2287, 'Xe ô tô và xe máy chuyên dùng có tốc độ thiết kế lớn hơn 80 km/h.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7206, 2288, '16 tuổi.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7207, 2288, '17 tuổi', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7208, 2288, '18 tuổi.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7209, 2289, 'Xe mô tô hai bánh có dung tích xi-lanh đến 125 cm3 .', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7210, 2289, 'Xe gắn máy.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7211, 2289, 'Xe ô tô chở người đến 08 chỗ (không kể chỗ của người lái xe); xe ô tô tải và ô tô chuyên dùng có khối lượng toàn bộ theo thiết kế đến 3.500 kg; các loại xe ô tô quy định cho giấy phép lái xe hạng B kéo rơ moóc có khối lượng toàn bộ theo thiết kế đến 750 kg.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7212, 2289, 'Cả ba ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7213, 2290, 'Xe mô tô hai bánh có dung tích xi-lanh 125 cm3 hoặc có công suất động cơ điện đến 11 kW.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7214, 2290, 'Xe mô tô ba bánh.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7215, 2290, 'Cả hai ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7216, 2291, 'Xe mô tô hai bánh có dung tích xi-lanh đến 125 cm3 hoặc có công suất động cơ điện đến 11 kW.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7217, 2291, 'Xe mô tô ba bánh.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7218, 2291, 'Cả hai ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7219, 2292, 'Xe mô tô hai bánh có dung tích xi-lanh đến 125 cm3 hoặc có công suất động cơ điện đến 11 kW.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7220, 2292, 'Xe mô tô hai bánh có dung tích xi-lanh trên 125 cm3 hoặc có công suất động cơ điện trên 11 kW.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7221, 2292, 'Cả hai ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7222, 2293, 'Phải đủ tuổi, sức khỏe theo quy định của pháp luật; có giấy phép lái xe đang còn điểm, còn hiệu lực phù hợp với loại xe đang điều khiển do cơ quan có thẩm quyền cấp (trừ người lái xe gắn máy).', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7223, 2293, 'Phải là người đứng tên trong đăng ký xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7224, 2293, 'Cả hai ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7225, 2294, 'Chứng nhận đăng ký xe hoặc bản sao Chứng nhận đăng ký xe có chứng thực kèm bản gốc giấy tờ xác nhận của tổ chức tín dụng, chi nhánh ngân hàng nước ngoài còn hiệu lực trong trường hợp xe đang được thế chấp tại tổ chức tín dụng, chi nhánh ngân hàng nước ngoài.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7226, 2294, 'Giấy phép lái xe phù hợp với loại xe đang điều khiển; chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường đối với xe cơ giới theo quy định của pháp luật; chứng nhận bảo hiểm bắt buộc trách nhiệm dân sự của chủ xe cơ giới.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7227, 2294, 'Trường hợp các giấy tờ nêu trên đã được tích hợp vào tài khoản định danh điện tử thì việc xuất trình, kiểm tra có thể thực hiện thông qua tài khoản định danh điện tử.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7228, 2294, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7229, 2295, 'Không được phục hồi.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7230, 2295, 'Được phục hồi đủ 12 điểm, nếu không bị trừ điểm trong thời hạn 12 tháng từ ngày bị trừ điểm gần nhất.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7231, 2296, 'Không vi phạm pháp luật trật tự, an toàn giao thông đường bộ trong thời gian 12 tháng kể từ ngày bị trừ hết điểm.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7232, 2296, 'Sau thời hạn ít nhất là 06 tháng kể từ ngày bị trừ hết điểm, người có phép lái xe được tham gia kiểm tra nội dung kiến thức pháp luật về trật tự, an toàn giao thông đường bộ theo quy định, có kết quả đạt yêu cầu thì được phục hồi đủ 12 điểm.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7233, 2296, 'Cả hai ý trên.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7234, 2297, 'Tiếp tục chịu trách nhiệm của chủ xe.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7235, 2297, 'Không chịu trách nhiệm sau khi đã chuyển nhượng, trao đổi, tặng, cho.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7236, 2298, '60 km/h.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7237, 2298, '50 km/h.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7238, 2298, '40 km/h.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7239, 2299, '60 km/h.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7240, 2299, '50 km/h.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7241, 2299, '40 km/h.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7242, 2300, 'Xe ô tô chở người đến 28 chỗ không kể chỗ của người lái xe (trừ xe buýt); ô tô tải có trọng tải không lớn hơn 3,5 tấn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7243, 2300, 'Xe ô tô chở người trên 28 chỗ không kể chỗ người lái xe (trừ xe buýt); ô tô tải có trọng tải trên 3,5 tấn (trừ ô tô xi téc).', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7244, 2300, 'Xe buýt; ô tô đầu kéo kéo sơ mi rơ moóc (trừ ô tô đầu kéo kéo sơ mi rơ moóc xi téc); xe mô tô; ô tô chuyên dùng (trừ ô tô trộn vữa, ô tô trộn bê tông lưu động).', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7245, 2300, 'Ô tô kéo rơ moóc; ô tô kéo xe khác; ô tô trộn vữa, ô tô trộn bê tông lưu động, ô tô xi téc, ô tô đầu kéo kéo sơ mi rơ moóc xi téc, ô tô kéo theo rơ moóc xi téc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7246, 2301, 'Xe ô tô chở người đến 28 chỗ không kể chỗ của người lái xe (trừ xe buýt); ô tô tải có trọng tải không lớn hơn 3,5 tấn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7247, 2301, 'Xe ô tô chở người trên 28 chỗ không kể chỗ người lái xe (trừ xe buýt); ô tô tải có trọng tải trên 3,5 tấn (trừ ô tô xi téc).', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7248, 2301, 'Xe buýt; ô tô đầu kéo kéo sơ mi rơ moóc (trừ ô tô đầu kéo kéo sơ mi rơ moóc xi téc); xe mô tô; ô tô chuyên dùng (trừ ô tô trộn vữa, ô tô trộn bê tông lưu động).', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7249, 2301, 'Ô tô kéo rơ moóc; ô tô kéo xe khác; ô tô trộn vữa, ô tô trộn bê tông lưu động, ô tô xi téc, ô tô đầu kéo kéo sơ mi rơ moóc xi téc, ô tô kéo theo rơ moóc xi téc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7250, 2302, 'Gặp biển báo nguy hiểm và cảnh báo trên đường.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7251, 2302, 'Gặp biển chỉ dẫn trên đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21');
INSERT INTO `quiz_options` (`id`, `quiz_id`, `option_text`, `is_correct`, `created_at`, `updated_at`) VALUES
(7252, 2302, 'Gặp biển báo hết mọi lệnh cấm.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7253, 2302, 'Gặp biển báo hết hạn chế tốc độ tối đa cho phép.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7254, 2303, 'Tăng tốc độ để nhanh chóng vượt qua xe buýt.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7255, 2303, 'Quan sát, giảm tốc độ đi qua xe buýt hoặc dừng lại để bảo đảm an toàn.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7256, 2304, 'Kiểm tra điều kiện bảo đảm an toàn của xe trước khi tham gia giao thông đường bộ; mang đủ giấy tờ theo quy định của pháp luật.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7257, 2304, 'Kiểm tra việc sắp xếp hàng hóa bảo đảm an toàn; không chở quá số người, chở hành lý, hàng hoá vượt quá khối lượng cho phép hoặc vượt quá khổ giới hạn của xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7258, 2304, 'Cả hai ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7259, 2305, 'Luôn tuân thủ pháp luật về trật tự, an toàn giao thông đường bộ, nhường nhịn và giúp đỡ người khác.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7260, 2305, 'Đi nhanh, vượt đèn đỏ nếu không có lực lượng Công an.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7261, 2305, 'Bấm còi và nháy đèn liên tục để cảnh báo xe khác.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7262, 2305, 'Tránh nhường đường để đi nhanh hơn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7263, 2306, 'Là sự hiểu biết và chấp hành nghiêm chỉnh pháp luật về giao thông, là ý thức trách nhiệm với cộng đồng khi tham gia giao thông.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7264, 2306, 'Là sự tôn trọng, nhường nhịn, giúp đỡ và ứng xử có văn hóa giữa những người tham gia giao thông với nhau.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7265, 2306, 'Cả hai ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7266, 2307, 'Là thiếu văn hóa giao thông, vi phạm pháp luật về trật tự, an toàn giao thông đường bộ.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7267, 2307, 'Là thiếu văn hóa giao thông.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7268, 2308, 'Hiểu biết và chấp hành nghiêm chỉnh pháp luật về giao thông đường bộ; có ý thức trách nhiệm với cộng đồng khi tham gia giao thông; tôn trọng, nhường nhịn, giúp đỡ và ứng xử có văn hóa với những người cùng tham gia giao thông.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7269, 2308, 'Điều khiển xe vượt quá tốc độ, đi không đúng làn đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7270, 2309, 'Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; đội mũ bảo hiểm đúng quy chuẩn kỹ thuật quốc gia, cài quai đúng quy cách.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7271, 2309, 'Điều khiển xe đi trên phần đường, làn đường có ít phương tiện tham gia giao thông.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7272, 2309, 'Điều khiển xe và đội mũ bảo hiểm ở nơi có biển báo bắt buộc đội mũ bảo hiểm.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7273, 2310, 'Điều khiển xe đi bên phải theo chiều đi của mình; đi đúng phần đường, làn đường quy định; dừng, đỗ xe đúng nơi quy định; đã uống rượu, bia thì không lái xe.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7274, 2310, 'Điều khiển xe đi trên phần đường, làn đường có ít phương tiện giao thông; dừng xe, đỗ xe ở nơi thuận tiện hoặc theo yêu cầu của hành khách, của người thân.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7275, 2310, 'Dừng và đỗ xe ở nơi thuận tiện cho việc chuyên chở hành khách và giao nhận hàng hóa; sử dụng ít rượu, bia thì có thể lái xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7276, 2311, 'Chỉ bấm còi khi thật sự cần thiết, không bấm còi liên tục hoặc kéo dài, sử dụng còi với mức âm lượng theo quy định.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7277, 2311, 'Bấm còi liên tục để các xe khác nhường đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7278, 2311, 'Bấm còi to khi đi qua khu vực đông dân cư.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7279, 2311, 'Không cần dùng còi, tránh gây tiếng ồn là văn minh.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7280, 2312, 'Dừng ngay phương tiện, cảnh báo nguy hiểm, giữ nguyên hiện trường, trợ giúp người bị nạn và báo tin cho cơ quan Công an, cơ sở khám bệnh, chữa bệnh.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7281, 2312, 'Ở lại hiện trường vụ tai nạn giao thông đường bộ cho đến khi người của cơ quan Công an đến, trừ trường hợp phải đi cấp cứu, đưa người bị nạn đi cấp cứu hoặc xét thấy bị đe dọa đến tính mạng, sức khỏe nhưng phải đến trình báo ngay cơ quan Công an, Ủy ban nhân dân nơi gần nhất.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7282, 2312, 'Cung cấp thông tin xác định danh tính về bản thân, người liên quan đến vụ tai nạn giao thông đường bộ và thông tin liên quan của vụ tai nạn giao thông đường bộ cho cơ quan có thẩm quyền.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7283, 2312, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7284, 2313, 'Giúp đỡ, cứu chữa kịp thời người bị nạn; báo tin ngay cho cơ quan Công an, cơ sở khám bệnh, chữa bệnh hoặc Ủy ban nhân dân nơi gần nhất; tham gia bảo vệ hiện trường; tham gia bảo vệ tài sản của người bị nạn; cung cấp thông tin liên quan về vụ tai nạn theo yêu cầu của cơ quan có thẩm quyền.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7285, 2313, 'Chụp lại hình ảnh vụ tai nạn (nếu có thiết bị ghi hình) và nhanh chóng rời khỏi hiện trường vụ tai nạn.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7286, 2314, 'Cho xe lấn sang làn ngược chiều để nhanh chóng thoát khỏi nơi ùn tắc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7287, 2314, 'Điều khiển xe trên vỉa hè để nhanh chóng thoát khỏi nơi ùn tắc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7288, 2314, 'Kiên nhẫn tuân thủ hướng dẫn của người điều khiển giao thông hoặc tín hiệu đèn giao thông, di chuyển trên đúng phần đường bên phải theo chiều đi, nhường đường cho các phương tiện đi ngược chiều.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7289, 2315, 'Giữ tay ga ở mức độ phù hợp, sử dụng phanh trước và phanh sau để giảm tốc độ.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7290, 2315, 'Nhả hết tay ga, tắt động cơ, sử dụng phanh trước và phanh sau để giảm tốc độ.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7291, 2315, 'Sử dụng phanh trước để giảm tốc độ kết hợp với tắt chìa khóa điện của xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7292, 2316, 'Quan sát cẩn thận các chướng ngại vật và báo hiệu bằng coi, đèn; giảm tốc độ tới mức cần thiết, về số thấp và thực hiện quay vòng với tốc độ phù hợp với bán kính cong của đường vòng.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7293, 2316, 'Quan sát cẩn thận các chướng ngại vật và báo hiệu bằng còi, đèn; tăng tốc để nhanh chóng qua đường vòng và giảm tốc độ sau khi qua đường vòng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7294, 2317, 'Khi có chuông báo hoặc thanh chắn đã hạ xuống, người lái xe phải dừng xe tạm thời đúng khoảng cách an toàn, kéo phanh tay nếu đường dốc hoặc phải chờ lâu.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7295, 2317, 'Khi không có chuông báo hoặc thanh chắn không hạ xuống, người lái xe cần phải quan sát nếu thấy đủ điều kiện an toàn thì về số thấp, tăng ga nhẹ và không thay đổi số trong quá trình vượt qua đường sắt để tránh động cơ chết máy cho xe cho vượt qua.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7296, 2317, 'Cả hai ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7297, 2318, 'Xăng và dầu diesel.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7298, 2318, 'Xăng sinh học và khí sinh học.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7299, 2318, 'Ý 1 và ý 2.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7300, 2319, 'Bảo dưỡng xe theo định kỳ và có kế hoạch lộ trình trước khi xe chạy.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7301, 2319, 'Kiểm tra áp suất lốp theo quy định và chạy xe với tốc độ phù hợp với tình trạng mặt đường và mật độ giao thông trên đường.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7302, 2319, 'Cả hai ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7303, 2320, 'Tăng tốc độ, chạy gần xe trước, nhìn đèn hậu để định hướng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7304, 2320, 'Giảm tốc độ, chạy cách xa xe trước với khoảng cách an toàn, bật đèn sương mù và đèn chiếu gần.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7305, 2320, 'Tăng tốc độ, bật đèn pha vượt qua xe chạy trước.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7306, 2321, 'Giảm tốc độ, giữ vững tay lái, nhìn chếch sang lề đường bên phải.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7307, 2321, 'Bật đèn pha chiếu xa và giữ nguyên tốc độ.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7308, 2321, 'Tăng tốc độ, bật đèn pha đối diện xe phía trước.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7309, 2322, 'Sử dụng phanh trước.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7310, 2322, 'Sử dụng phanh sau.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7311, 2322, 'Giảm hết ga, sử dụng đồng thời cả phanh sau và phanh trước.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7312, 2323, 'Giảm tốc độ để bảo đảm an toàn với xe phía trước và sử dụng điện thoại để liên lạc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7313, 2323, 'Giảm tốc độ để dừng xe ở nơi cho phép sau đó sử dụng điện thoại để liên lạc.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7314, 2323, 'Tăng tốc độ để cách xa xe phía sau và sử dụng điện thoại để liên lạc.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7315, 2324, 'Sử dụng còi.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7316, 2324, 'Phanh đồng thời cả phanh trước và phanh sau.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7317, 2324, 'Chỉ sử dụng phanh trước.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7318, 2325, 'Bật tín hiệu báo rẽ trước khi quay đầu, từ từ giảm tốc độ đến mức có thể dừng lại.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7319, 2325, 'Chỉ quay đầu xe tại những nơi được phép quay đầu.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7320, 2325, 'Quan sát an toàn các phương tiện tới từ phía trước, phía sau, hai bên đồng thời nhường đường cho xe từ bên phải và phía trước đi tới.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7321, 2325, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7322, 2326, 'Để điều khiển xe chạy về phía trước.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7323, 2326, 'Để điều tiết công suất động cơ qua đó điều khiển tốc độ của xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7324, 2326, 'Để điều khiển xe chạy lùi.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7325, 2326, 'Ý 1 và ý 2.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7326, 2327, 'Để quan sát an toàn phía bên trái khi chuẩn bị rẽ trái.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7327, 2327, 'Để quan sát an toàn phía bên phải khi chuẩn bị rẽ phải.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7328, 2327, 'Để quan sát an toàn phía sau của bên trái và bên phải trước khi chuyển hướng.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7329, 2327, 'Để quan sát an toàn phía trước cả bên trái và bên phải trước khi chuyển hướng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7330, 2328, 'Tăng ga thật mạnh, giảm ga từ từ.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7331, 2328, 'Tăng ga thật mạnh, giảm ga thật nhanh.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7332, 2328, 'Tăng ga từ từ, giảm ga thật nhanh.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7333, 2328, 'Tăng ga từ từ, giảm ga từ từ.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7334, 2329, 'Đi ở tốc độ thấp, quan sát liên tục khoảng cách từ 05 m đến 10 m phía trước để điều chỉnh sớm hướng di chuyển.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7335, 2329, 'Trong quá trình di chuyển không nên dùng phanh trước tránh làm khóa bánh dẫn hướng.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7336, 2329, 'Không được lắc người sang trái hoặc phải nhiều, trọng tâm cơ thể cần trùng với trọng tâm của xe.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7337, 2329, 'Cả ba ý trên.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7338, 2330, 'Biển 1.', 0, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
(7339, 2330, 'Biển 2 và biển 3.', 1, '2025-06-04 01:38:21', '2025-06-04 01:38:21'),
