(17, 'Hạng A1', 1000000.00, 0, 0.00, 0.00, 0.00, 0.000, 'Hạng A1 lái xe mô tô hai bánh có dung tích xi-lanh đến 125cm³ hoặc có công suất động cơ điện đến 11kW.', '2025-07-12 13:50:14', '2025-07-31 13:14:05'),
(18, 'Hạng A', 1200000.00, 0, 0.00, 0.00, 0.00, 0.000, 'Hạng A lái xe mô tô hai bánh có dung tích xi-lanh trên 125cm³ hoặc có công suất động cơ điện trên 11kW và xe hạng A1.', '2025-07-12 13:50:48', '2025-07-31 13:14:16'),
