(20, 'Hạng B', 11000000.00, 1, 3.20, 4.00, 20.00, 810.000, 'Hạng B lái xe ô tô đến 08 chỗ (không kể lái xe); xe ô tô tải và ô tô chuyên dùng đến 3.500 kg; các loại xe ô tô hạng B có kéo rơ moóc đến 750 kg', '2025-07-12 13:55:38', '2025-07-31 13:13:42'),
(21, 'Hạng C1', 12000000.00, 1, 3.20, 4.00, 20.00, 810.000, 'Hạng C1 lái xe ô tô tải và ô tô chuyên dùng trên 3.500 kg đến 7.500 kg; các loại xe hạng C1 có kéo rơ moóc đến 750 kg; các loại xe hạng B', '2025-07-12 13:56:04', '2025-07-31 13:14:58'),
(22, 'Hạng C', 13000000.00, 1, 3.20, 4.00, 20.00, 810.000, 'Hạng C lái xe ô tô tải và ô tô chuyên dùng trên 7.500 kg; các loại xe hạng C kéo rơ moóc đến 750 kg; các loại xe hạng B và hạng C1', '2025-07-12 13:56:25', '2025-07-31 13:15:10'),
(23, 'Hạng D1', 14000000.00, 1, 3.20, 4.00, 20.00, 810.000, 'Hạng D1 lái xe ô tô trên 08 chỗ đến 16 chỗ (không kể lái xe), các loại xe hạng D1 kéo rơ moóc đến 750 kg; các loại xe hạng B, C1, C', '2025-07-12 13:56:47', '2025-07-31 13:15:20'),
