INSERT INTO `traffic_signs` (`id`, `type`, `code`, `name`, `image`, `description`, `created_at`, `updated_at`) VALUES
(192, 1, 'P.101', 'Đường cấm', 'bienbao/P.101.webp', 'Biển báo đường cấm tất cả các loại phương tiện tham gia giao thông đi lại cả hai hướng, trừ xe ưu tiên theo luật định.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(193, 1, 'P.102', 'Cấm đi ngược chiều', 'bienbao/P.102.webp', 'Biển báo đường cấm tất cả các loại phương tiện tham gia giao thông đi vào theo chiều đặt biển.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(194, 1, 'P.103a', 'Cấm ô tô', 'bienbao/P.103a.webp', 'Biển báo đường cấm tất cả các loại xe cơ giới kể cả mô tô 3 bánh có thùng đi qua, trừ xe mô tô 2 bánh, xe gắn máy (kể cả xe máy điện) và các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(195, 1, 'P.103b', 'Cấm ô tô rẽ phải', 'bienbao/P.103b.webp', 'Biển báo đường cấm xe ô tô rẽ phải ( kể cả xe mô tô ba bánh), trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(196, 1, 'P.103c', 'Cấm ô tô rẽ trái', 'bienbao/P.103c.webp', 'Biển báo đường cấm xe ô tô rẽ trái và cũng không được phép quay đầu xe, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(197, 1, 'P.104', 'Cấm mô tô', 'bienbao/P.104.webp', 'Biển báo đường cấm tất cả các loại mô tô đi qua, trừ các loại xe mô tô được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(198, 1, 'P.105', 'Cấm ô tô và mô tô', 'bienbao/P.105.webp', 'Biển báo đường cấm tất cả xe cơ giới và xe mô tô đi qua trừ xe gắn máy và xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(199, 1, 'P.106a', 'Cấm ô tô tải', 'bienbao/P.106a.webp', 'Biển báo đường cấm tất cả các loại xe ô tô tải trừ các xe được ưu tiên theo Luật Giao thông đường bộ, hiệu lực cấm đối với cả máy kéo và xe máy chuyên dùng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(200, 1, 'P.106b', 'Cấm ô tô tải theo trọng lượng', 'bienbao/P.106b.webp', 'Trọng lượng được tính theo tấn ghi trên biển', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(201, 1, 'P.106c', 'Cấm ô tô tải chở hàng nguy hiểm', 'bienbao/P.106c.webp', 'Biển báo P.106c đường cấm tất cả các loại xe ô tô tải chở hàng nguy hiểm.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(202, 1, 'P.107', 'Cấm ô tô khách và ô tô tải', 'bienbao/P.107.webp', 'Biển báo đường cấm xe ô tô khách và các loại xe ô tô tải, kể cả máy kéo và xe máy chuyên dùng đi qua, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(203, 1, 'P.107a', 'Cấm ô tô khách', 'bienbao/P.107a.webp', 'Biển báo đường cấm ôtô chở khách đi qua trừ các xe ưu tiên theo quy định. Biển này không cấm xe buýt.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(204, 1, 'P.107b', 'Cấm xe taxi', 'bienbao/P.107b.webp', 'Biển báo đường cấm ôtô taxi đi lại. Trường hợp cấm xe ôtô taxi theo giờ thì đặt biển phụ ghi giờ cấm.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(205, 1, 'P.108', 'Cấm ôtô kéo rơ moóc', 'bienbao/P.108.webp', 'Biển báo đường cấm tất cả các loại xe cơ giới kéo theo rơ moóc kể cả xe mô tô, máy kéo, xe ô tô khách kéo theo rơ moóc đi qua, trừ loại xe ô tô sơ mi rơ moóc và các xe được ưu tiên theo Luật Giao thông đường bộ (có kéo theo rơ moóc).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(206, 1, 'P.108a', 'Cấm xe sơ-mi rơ-moóc', 'bienbao/P.108a.webp', 'Biển báo đường cấm các loại xe sơ-mi-rơ-moóc và các xe kéo rơ- moóc trừ các xe được ưu tiên (có dạng xe sơ-mi-rơ-moóc hoặc có kéo theo rơ-moóc) theo quy định.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(207, 1, 'P.109', 'Cấm máy kéo', 'bienbao/P.109.webp', 'Biển báo đường cấm tất cả các loại máy kéo, kể cả máy kéo bánh hơi và bánh xích đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(208, 1, 'P.110a', 'Cấm xe đạp', 'bienbao/P.110a.webp', 'Biển báo đường cấm xe đạp đi qua. Biển không có giá trị cấm những người dắt xe đạp.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(209, 1, 'P.110b', 'Cấm xe đạp thồ', 'bienbao/P.110b.webp', 'Biển báo đường cấm xe đạp thồ đi qua. Biển không có giá trị cấm người dắt loại xe này.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(210, 1, 'P.111a', 'Cấm xe gắn máy', 'bienbao/P.111a.webp', 'Biển báo đường cấm xe gắn máy đi qua. Biển không có giá trị cấm đối với xe đạp.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(211, 1, 'P.112', 'Cấm người đi bộ', 'bienbao/P.112.webp', 'Biển báo đường cấm người đi bộ qua lại.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(212, 1, 'P.113', 'Cấm xe người kéo, đẩy', 'bienbao/P.113.webp', 'Biển báo đường cấm xe người kéo đẩy đi qua. Biển không có giá trị cấm những xe nôi của trẻ em và phương tiện chuyên dùng để đi lại của những người khuyết tật.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(213, 1, 'P.114', 'Cấm xe súc vật kéo', 'bienbao/P.114.webp', 'Biển báo đường cấm súc vậtấtt vận tải hàng hóa hoặc hành khách dù kéo xe hay chở trên lưng đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(214, 1, 'P.115', 'Hạn chế trọng lượng xe', 'bienbao/P.115.webp', 'Biển báo đường cấm các loại phương tiện giao thông đường bộ kể cả các xe được ưu tiên theo Luật Giao thông đường bộ có trọng lượng toàn bộ (cả xe và hàng) vượt quá trị số ghi trên biển tính bằng tấn đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(215, 1, 'P.116', 'Hạn chế trọng lượng trên trục xe', 'bienbao/P.116.webp', 'Biển báo đường cấm các loại phương tiện giao thông đường bộ, kể cả các xe được ưu tiên theo Luật Giao thông đường bộ có trọng lượng toàn bộ (cả xe và hàng) phân bố trên một trục bất kỳ của xe vượt quá trị số ghi trên biển tính bằng tấn đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(216, 1, 'P.117', 'Hạn chế chiều cao', 'bienbao/P.117.webp', 'Biển có hiệu lực cấm các loại phương tiện giao thông đường bộ đi qua, kể cả các xe được ưu tiên theo Luật Giao thông đường bộ có chiều cao (tính đến điểm cao nhất cả xe và hàng hóa) vượt quá trị số ghi trên biển tính bằng mét đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(217, 1, 'P.118', 'Hạn chế chiều ngang', 'bienbao/P.118.webp', 'Biển có hiệu lực cấm các loại phương tiện giao thông đường bộ kể cả các xe được ưu tiên theo Luật Giao thông đường bộ có chiều ngang (cả xe và hàng hóa) vượt quá trị số ghi trên Biển tính bằng mét đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(218, 1, 'P.119', 'Hạn chế chiều dài ô tô', 'bienbao/P.119.webp', 'Biển báo đường cấm các loại xe (cơ giới và thô sơ), kể cả các xe được ưu tiên theo Luật Giao thông đường bộ, có độ dài toàn bộ (cả xe và hàng) vượt quá trị số ghi trên biển tính bằng mét đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(219, 1, 'P.120', 'Hạn chế chiều dài ô tô kéo moóc', 'bienbao/P.120.webp', 'Biển báo đường cấm các loại phương tiện giao thông đường bộ kéo theo rơ moóc kể cả ô tô sơ mi rơ moóc và các xe được ưu tiên theo Luật Giao thông đường bộ kéo theo rơ moóc có độ dài toàn bộ (cả xe, rơ moóc và hàng) vượt quá trị số ghi trên biển đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(220, 1, 'P.121', 'Cự ly tối thiểu giữa hai xe', 'bienbao/P.121.webp', 'Biển báo xe ô tô phải đi cách nhau một khoảng tối thiểu. Biển có hiệu lực cấm các xe ô tô không được đi cách nhau với cự ly nhỏ hơn trị số ghi trên biển tính bằng mét, kể cả các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(221, 1, 'P.123a', 'Cấm rẽ trái', 'bienbao/P.123a.webp', 'Biển báo đường cấm các loại phương tiện giao thông đường bộ (xe cơ giới và xe thô sơ) rẽ trái, trừ các xe được ưu tiên theo Luật Giao thông đường bộ. Biển không có giá trị cấm quay đầu xe.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(222, 1, 'P.123b', 'Cấm rẽ phải', 'bienbao/P.123b.webp', 'Biển báo đường cấm các loại phương tiện giao thông đường bộ (xe cơ giới và xe thô sơ) rẽ phải, trừ các xe được ưu tiên theo Luật Giao thông đường bộ. Biển không có giá trị cấm quay đầu xe.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(223, 1, 'P.124a', 'Cấm quay đầu xe', 'bienbao/P.124a.webp', 'Biển báo đường cấm các loại phương tiện giao thông đường bộ quay đầu xe theo kiểu chữ U, trừ các xe được ưu tiên theo Luật Giao thông đường bộ. Biển không có giá trị cấm rẽ trái để sang hướng đường khác.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(224, 1, 'P.124b', 'Cấm ô tô quay đầu', 'bienbao/P.124b.webp', 'Biển báo đường cấm xe ô tô và xe mô tô 3 bánh quay đầu xe theo kiểu chữ U, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(225, 1, 'P.124c', 'Cấm rẽ trái và quay đầu xe', 'bienbao/P.124c.webp', 'Biển báo cấm các loại xe rẽ trái đồng thời cấm quay đầu, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(226, 1, 'P.124d', 'Cấm rẽ phải và quay đầu xe', 'bienbao/P.124d.webp', 'Biển báo cấm các loại xe rẽ phải đồng thời cấm quay đầu, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(227, 1, 'P.124e', 'Cấm ô tô rẽ trái và quay xe', 'bienbao/P.124e.webp', 'Biển báo cấm xe ôtô rẽ trái và đồng thời cấm quay đầu phải, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(228, 1, 'P.124f', 'Cấm ô tô rẽ phải và quay xe', 'bienbao/P.124f.webp', 'Biển báo cấm xe ôtô rẽ phải và đồng thời cấm quay đầu phải, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(229, 1, 'P.125', 'Cấm vượt', 'bienbao/P.125.webp', 'Biển có hiệu lực cấm tất cả các loại xe cơ giới vượt nhau, kể cả các xe được ưu tiên theo Luật Giao thông đường bộ. được phép vượt xe mô tô 2 bánh, xe gắn máy.&#xB;Biển hết hiệu lực cấm khi có biển số DP.133 “Hết cấm vượt” hoặc đến chỗ có biển số DP.135 “Hết tất cả các lệnh cấm” nếu đồng thời có nhiều biển cấm khác hết tác dụng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(230, 1, 'P.126', 'Cấm ôtô tải vượt', 'bienbao/P.126.webp', 'Biển có hiệu lực cấm các loại ôtô tải có khối lượng chuyên chở (theo Giấy chứng nhận kiểm định an toàn kỹ thuật và bảo vệ môi trường phương tiện giao thông cơ giới đường bộ) lớn hơn 3.500 kg (3,5 tấn) kể cả các xe được ưu tiên theo quy định vượt xe cơ giới khác. được phép vượt xe máy 2 bánh, xe gắn máy. Biển không có giá trị cấm các loại xe cơ giới khác vượt nhau và vượt xe ô tô tải.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(231, 1, 'P.127', 'Tốc độ tối đa cho phép', 'bienbao/P.127.webp', 'Biển có hiệu lực cấm tất cả các loại xe cơ giới đường bộ chạy với tốc độ tối đa vượt quá trị số ghi trên Biển (tính bằng km/h), trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(232, 1, 'P.127a', 'Tốc độ tối đa cho phép về ban đêm', 'bienbao/P.127a.webp', 'Biển có hiệu lực cấm tất cả các loại xe cơ giới đường bộ chạy ban đêm với tốc độ tối đa vượt quá trị số ghi trên biển (tính bằng km/h), trừ một số trường hợp ưu tiên được quy định.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(233, 1, 'P.127b', 'Tốc độ tối đa trên từng làn đường', 'bienbao/P.127b.webp', 'Biển ghép tốc độ tối đa cho phép trên từng làn đường', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(234, 1, 'P.127c', 'Tốc độ tối đa phương tiện trên từng làn đường', 'bienbao/P.127c.webp', 'Biển ghép tốc độ tối đa cho phép theo phương tiện, trên từng làn đường', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(235, 1, 'P.127d', 'Biển hết hạn chế tốc độ tối đa', 'bienbao/P.127d.webp', 'Biển hết hạn chế tốc độ tối đa cho phép theo biển ghép', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(236, 1, 'P.128', 'Cấm bóp còi', 'bienbao/P.128.webp', 'Biển báo cấm các loại xe cơ giới sử dụng còi.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(237, 1, 'P.129', 'Kiểm tra', 'bienbao/P.129.webp', 'Biển báo nơi đặt trạm kiểm tra, các loại phương tiện vận tải qua đó phải dừng lại để làm thủ tục kiểm tra, kiểm soát theo quy định.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(238, 1, 'P.130', 'Cấm dừng và đỗ xe', 'bienbao/P.130.webp', 'Biển có hiệu lực cấm các loại xe cơ giới đường bộ dừng và đỗ lại ở phía đường có đặt biển,', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(239, 1, 'P.131a', 'Cấm đỗ xe', 'bienbao/P.131a.webp', 'Biển số 131a có hiệu lực cấm các loại xe cơ giới đỗ ở phía đường có đặt biển vào bất kể ngày nào.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(240, 1, 'P.131b', 'Cấm đỗ xe ngày lẻ', 'bienbao/P.131b.webp', 'Biển có hiệu lực cấm các loại xe cơ giới đỗ ở phía đường có đặt biển vào những ngày lẻ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(241, 1, 'P.131c', 'Cấm đỗ xe ngày chẵn', 'bienbao/P.131c.webp', 'Biển có hiệu lực cấm các loại xe cơ giới đỗ ở phía đường có đặt biển vào những ngày chẵn.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(242, 1, 'P.132', 'Nhường cho xe ngược chiều qua đường hẹp', 'bienbao/P.132.webp', 'Biển báo cho các loại phương tiện giao thông đường bộ (cơ giới và thô sơ), kể cả các xe được ưu tiên theo Luật Giao thông đường bộ đi theo chiều nhìn thấy biển phải nhường đường cho các loại xe cơ giới đi theo chiều ngược lại khi đi qua các đoạn đường và cầu hẹp.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(243, 1, 'DP.133', 'Hết cấm vượt', 'bienbao/DP.133.webp', 'Biển báo cho người lái xe biết hiệu lực của biển số P.125 “Cấm vượt” và biển số P.126 “Cấm ô tô tải vượt” hết tác dụng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(244, 1, 'DP.134', 'Hết hạn chế tốc độ tối đa', 'bienbao/DP.134.webp', 'Biển báo cho người lái xe biết hiệu lực của biển số P.127 “Hạn chế tốc độ tối đa” hết tác dụng. Kể từ biển này, các xe được phép chạy với tốc độ tối đa đã quy định trong Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(245, 1, 'DP.135', 'Hết tất cả các lệnh cấm', 'bienbao/DP.135.webp', 'Biển báo cho người lái xe biết hiệu lực của biển số P.121 “Cự ly tối thiểu giữa hai xe” và các biển từ biển số P.125 đến P.131 (a, b, c) được đặt trước đó cùng hết tác dụng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(246, 1, 'P.136', 'Cấm đi thẳng', 'bienbao/P.136.webp', 'Biển được đặt trước nơi đường giao nhau và có hiệu lực cấm tất cả các loại phương tiện giao thông đường bộ (cơ giới và thô sơ) đi thẳng ở nơi đường giao nhau.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(247, 1, 'P.137', 'Cấm rẽ trái và rẽ phải', 'bienbao/P.137.webp', 'Biển được đặt trước nơi đường giao nhau và có hiệu lực cấm tất cả các loại phương tiện giao thông đường bộ (cơ giới và thô sơ) rẽ trái và rẽ phải ở nơi đường giao nhau.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(248, 1, 'P.138', 'Cấm đi thẳng và rẽ trái', 'bienbao/P.138.webp', 'Biển được đặt trước nơi đường giao nhau và có hiệu lực cấm tất cả các loại phương tiện giao thông đường bộ (cơ giới và thô sơ) đi thẳng và rẽ trái ở nơi đường giao nhau.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(249, 1, 'P.139', 'Cấm đi thẳng và rẽ phải', 'bienbao/P.139.webp', 'Biển được đặt trước nơi đường giao nhau và có hiệu lực cấm tất cả các loại phương tiện giao thông đường bộ (cơ giới và thô sơ) đi thẳng và rẽ phải ở nơi đường giao nhau.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(250, 1, 'P.140', 'Cấm xe công nông và các loại xe tương tự', 'bienbao/P.140.webp', 'Biển báo đường cấm tất cả các loại xe công nông và các loại xe tương tự đi qua.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(251, 1, 'S.508a', 'Biển cấm theo giờ', 'bienbao/S.508a.webp', 'Khi cần báo hiệu cấm các loại phương tiện giao thông đường bộ theo giờ trong thành phố, thị xã phải đặt biển phụ số S508(a,b) dưới biển cấm và có chú thích bằng tiếng Việt, phụ đề tiếng Anh trong biển này.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(252, 1, 'S.508b', 'Biển cấm theo giờ', 'bienbao/S.508b.webp', 'Khi cần báo hiệu cấm các loại phương tiện giao thông đường bộ theo giờ trong thành phố, thị xã phải đặt biển phụ số S508(a,b) dưới biển cấm và có chú thích bằng tiếng Việt, phụ đề tiếng Anh trong biển này.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(253, 2, 'W.201a', 'Chỗ ngoặt nguy hiểm bên trái', 'bienbao/W.201a.webp', 'Biển báo đường sắp đến chỗ ngoặt nguy hiểm.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(254, 2, 'W.201b', 'Chỗ ngoặt nguy hiểm bên phải', 'bienbao/W.201b.webp', 'Biển báo đường sắp đến chỗ ngoặt nguy hiểm.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(255, 2, 'W.201c', 'Chỗ ngoặt nguy hiểm có nguy cơ lật bên phải', 'bienbao/W.201c.webp', 'Biển số W.201c chỗ ngoặt nguy hiểm có nguy cơ lật xe bên phải khi đường cong vòng sang trái.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(256, 2, 'W.201d', 'Chỗ ngoặt nguy hiểm có nguy cơ lật bên trái', 'bienbao/W.201d.webp', 'Biển số W.201d chỗ ngoặt nguy hiểm có nguy cơ lật xe bên trái khi đường cong vòng bên phải.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(257, 2, 'W.202a', 'Nhiều chỗ ngoặt nguy hiểm liên tiếp', 'bienbao/W.202a.webp', 'Biển báo sắp đến đoạn đường ngoặt liên tiếp (có từ 3 đoạn cong ngược chiều nhau) rất nguy hiểm, người lái xe cần giảm tốc độ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(258, 2, 'W.202b', 'Nhiều chỗ ngoặt nguy hiểm liên tiếp', 'bienbao/W.202b.webp', 'Biển báo sắp đến đoạn đường ngoặt liên tiếp (có từ 3 đoạn cong ngược chiều nhau) rất nguy hiểm, người lái xe cần giảm tốc độ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(259, 2, 'W.203a', 'Đường bị hẹp cả hai bên', 'bienbao/W.203a.webp', 'Biển báo sắp đến chỗ một đoạn đường bị hẹp đột ngột.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(260, 2, 'W.203b', 'Đường bị hẹp bên trái', 'bienbao/W.203b.webp', 'Biển báo sắp đến chỗ một đoạn đường bị hẹp đột ngột.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(261, 2, 'W.203c', 'Đường bị hẹp bên phải', 'bienbao/W.203c.webp', 'Biển báo sắp đến chỗ một đoạn đường bị hẹp đột ngột.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(262, 2, 'W.204', 'Đường hai chiều', 'bienbao/W.204.webp', 'Biển báo hiệu sắp đến đoạn đường chỉ có một làn đường mà tạm thời (đường do sửa chữa hoặc có trở ngại ở một phía đường mà phải tổ chức đi lại cho phương tiện cả hai chiều trên phía đường còn lại) hay thường xuyên các chiều xe đi và về vẫn phải dùng chung. Khi qua đoạn đường này, lái xe cần thận trọng với xe phía chiều ngược lại.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(263, 2, 'W.205a', 'Nơi giao nhau của đường đồng cấp', 'bienbao/W.205a.webp', 'Biển báo hiệu sắp đến nơi giao nhau của các tuyến đường cùng cấp (không có đường nào ưu tiên) trên cùng một mặt bằng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(264, 2, 'W.205b', 'Nơi giao nhau của đường đồng cấp', 'bienbao/W.205b.webp', 'Biển báo hiệu sắp đến nơi giao nhau của các tuyến đường cùng cấp (không có đường nào ưu tiên) trên cùng một mặt bằng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(265, 2, 'W.205c', 'Nơi giao nhau của đường đồng cấp', 'bienbao/W.205c.webp', 'Biển báo hiệu sắp đến nơi giao nhau của các tuyến đường cùng cấp (không có đường nào ưu tiên) trên cùng một mặt bằng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(266, 2, 'W.205d', 'Nơi giao nhau của đường đồng cấp', 'bienbao/W.205d.webp', 'Biển báo hiệu sắp đến nơi giao nhau của các tuyến đường cùng cấp (không có đường nào ưu tiên) trên cùng một mặt bằng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(267, 2, 'W.205e', 'Nơi giao nhau của đường đồng cấp', 'bienbao/W.205e.webp', 'Biển báo hiệu sắp đến nơi giao nhau của các tuyến đường cùng cấp (không có đường nào ưu tiên) trên cùng một mặt bằng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(268, 2, 'W.206', 'Giao nhau chạy theo vòng xuyến', 'bienbao/W.206.webp', 'Biển báo hiệu nơi giao nhau có bố trí đảo an toàn ở giữa điểm giao, các loại xe qua điểm giao vòng trái phải đi vòng xuyến qua đảo an toàn.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(269, 2, 'W.207a', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207a.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(270, 2, 'W.207b', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207b.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(271, 2, 'W.207c', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207c.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(272, 2, 'W.207d', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207d.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(273, 2, 'W.207e', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207e.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(274, 2, 'W.207f', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207f.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(275, 2, 'W.207g', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207g.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(276, 2, 'W.207h', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207h.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(277, 2, 'W.207i', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207i.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(278, 2, 'W.207k', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207k.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(279, 2, 'W.207l', 'Giao nhau với đường không ưu tiên', 'bienbao/W.207l.webp', 'Biển báo hiệu đường ưu tiên sắp đến nơi giao nhau với đường không ưu tiên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(280, 2, 'W.208', 'Giao nhau với đường ưu tiên', 'bienbao/W.208.webp', 'Biển báo hiệu đường không đươc ưu tiên sắp đến nơi giao nhau với đường ưu tiên (biển được đặt trên đường không ưu tiên). Các xe đi trên đường có đặt biển này phải nhường đường cho xe đi trên đường ưu tiên khi qua nơi giao nhau, trừ các loại xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(281, 2, 'W.209', 'Giao nhau có tín hiệu đèn', 'bienbao/W.209.webp', 'Biển báo hiệu nơi giao nhau có sự điều khiển giao thông bằng tín hiệu đèn.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(282, 2, 'W.210', 'Giao nhau với đường sắt có rào chắn', 'bienbao/W.210.webp', 'Biển báo hiệu sắp đến chỗ giao nhau giữa đường bộ và đường sắt có rào chắn kín hay nửa kín ở cả hai bên đường sắt và có nhân viên ngành đường sắt điều khiển giao thông.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(283, 2, 'W.211a', 'Giao nhau với đường sắt không có rào chắn', 'bienbao/W.211a.webp', 'Biển báo hiệu sắp đến chỗ giao nhau giữa đường bộ và đường sắt hoặc đường bộ và đường sắt có từng đoạn đi chung với nhau không có rào chắn, không có người điều khiển giao thông.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(284, 2, 'W.211b', 'Giao nhau với đường tàu điện', 'bienbao/W.211b.webp', 'Biển báo hiệu sắp đến chỗ giao nhau cùng mức giữa đường bộ với đường tàu điện.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(285, 2, 'W.212', 'Cầu hẹp', 'bienbao/W.212.webp', 'Biển báo hiệu sắp đến cầu hẹp (loại cầu có chiều rộng lòng cầu nhỏ hơn hoặc bằng 4,5 m). Khi qua cầu này, lái xe phải đi chậm, quan sát, nhường nhau và dừng lại chờ ở hai đầu cầu.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(286, 2, 'W.213', 'Cầu tạm', 'bienbao/W.213.webp', 'Biển báo hiệu sắp đến cầu tạm (loại cầu được làm để sử dụng tạm thời cho xe qua lại). Khi gặp biển này lái xe cần thận trọng và lưu ý sau mỗi trận mưa lũ hoặc khi nước ngập nhất thiết không qua cầu.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(287, 2, 'W.214', 'Cầu xoay-cầu cất', 'bienbao/W.214.webp', 'Biển báo hiệu sắp đến cầu xoay, cầu cất (loại cầu trong từng thời gian có cắt giao thông đường bộ để cho tàu thuyền qua lại). Các phương tiện đi trên đường bộ phải chờ đợi.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(288, 2, 'W.215a', 'Kè, vực sâu phía trước', 'bienbao/W.215a.webp', 'Biển báo hiệu sắp đến những chỗ có kè, vực sâu hoặc bờ sông áp sát đường, lái xe cần đề phòng tình huống nguy hiểm vượt kè, tụt xuống vực sâu (thường xảy ra ở những chỗ nguy hiểm).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(289, 2, 'W.215b', 'Kè, vực sâu bên đường phía bên phải', 'bienbao/W.215b.webp', 'Biển báo hiệu sắp đến những chỗ có kè, vực sâu hoặc bờ sông áp sát đường, lái xe cần đề phòng tình huống nguy hiểm vượt kè, tụt xuống vực sâu (thường xảy ra ở những chỗ nguy hiểm).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(290, 2, 'W.215c', 'Kè, vực sâu bên đường phía bên trái', 'bienbao/W.215c.webp', 'Biển báo hiệu sắp đến những chỗ có kè, vực sâu hoặc bờ sông áp sát đường, lái xe cần đề phòng tình huống nguy hiểm vượt kè, tụt xuống vực sâu (thường xảy ra ở những chỗ nguy hiểm).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(291, 2, 'W.216a', 'Đường ngầm', 'bienbao/W.216a.webp', 'Biển báo hiệu sắp đến chỗ có đường ngầm (đường tràn), đoạn đường vượt qua sông, suối, khe cạn mà nước có thể tràn qua thường xuyên hoặc khi có lũ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(292, 2, 'W.216b', 'Đường ngầm có nguy cơ lũ quét', 'bienbao/W.216b.webp', 'Biển báo hiệu sắp đến chỗ có đường ngầm (đường tràn), đoạn đường vượt qua sông, suối, khe cạn thường xuyên có lũ quét.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(293, 2, 'W.217', 'Bến phà', 'bienbao/W.217.webp', 'Biển báo hiệu sắp đến bến phà. Người tham gia giao thông đường bộ phải tuân theo nội quy bến phà.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(294, 2, 'W.218', 'Cửa chui', 'bienbao/W.218.webp', 'Biển báo hiệu sắp đến chỗ đường có cổng chui, kiểu cổng tò vò chắn ngang như cổng đường hầm, cổng thành, cầu vượt đường bộ dạng cầu vòm...', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(295, 2, 'W.219', 'Dốc xuống nguy hiểm', 'bienbao/W.219.webp', 'Biển báo hiệu sắp đến chỗ dốc xuống nguy hiểm. Trị số ghi trong biển chỉ độ dốc thực tế tính bằng %.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(296, 2, 'W.220', 'Dốc lên nguy hiểm', 'bienbao/W.220.webp', 'Biển báo hiệu sắp đến chỗ dốc lên nguy hiểm. Trị số ghi trong biển chỉ độ dốc thực tế tính bằng %.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(297, 2, 'W.221a', 'Đường ổ gà, sống trâu', 'bienbao/W.221a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(298, 2, 'W.221b', 'Đường có gồ giảm tốc', 'bienbao/W.221b.webp', 'Biển số W.221b báo hiệu đoạn “Đường có gồ giảm tốc” để cảnh báo xe đi chậm trước khi qua những điểm có gồ giảm tốc phía trước hoặc những vị trí tiếp giáp với đầu cầu, cống bị lún, võng;', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(299, 2, 'W.222a', 'Đường trơn', 'bienbao/W.222a.webp', 'Biển báo hiệu sắp đến đoạn đường có thể xảy ra trơn trượt đặc biệt là khi thời tiết xấu, mưa phùn. Lái xe cần tránh hãm phanh, tăng ga, sang số đột ngột hoặc cho xe chạy với tốc độ cao.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(300, 2, 'W.222b', 'Lề đường nguy hiểm', 'bienbao/W.222b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(301, 2, 'W.223a', 'Vách núi nguy hiểm', 'bienbao/W.223a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(302, 2, 'W.223b', 'Vách núi nguy hiểm', 'bienbao/W.223b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(303, 2, 'W.224', 'Đường người đi bộ cắt ngang', 'bienbao/W.224.webp', 'Biển báo hiệu sắp đến phần đường ngang dành cho người đi bộ. Gặp biển này các lái xe phải nhường đường cho người đi bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(304, 2, 'W.225', 'Trẻ em', 'bienbao/W.225.webp', 'Biển báo hiệu gần đến đoạn đường thường có trẻ em đi ngang qua hoặc tụ tập trên đường như ở vườn trẻ, trường học, câu lạc bộ đi ra. Chiều dài của đoạn đường này có thể được chỉ dẫn bằng biển phụ số 501 “Phạm vi tác dụng của biển” đặt bên dưới biển chính.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(305, 2, 'W.226', 'Đường người đi xe đạp cắt ngang', 'bienbao/W.226.webp', 'Biển báo hiệu gần đến chỗ thường có người đi xe đạp từ những đường nhỏ cắt ngang qua hoặc từ đường dành cho xe đạp đi nhập vào đường ô tô.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(306, 2, 'W.227', 'Công trường', 'bienbao/W.227.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(307, 2, 'W.228a', 'Đá lở', 'bienbao/W.228a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(308, 2, 'W.228b', 'Đá lở', 'bienbao/W.228b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
