(310, 2, 'W.228d', 'Nền đường yếu', 'bienbao/W.228d.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(311, 2, 'W.229', 'Dải máy bay lên xuống', 'bienbao/W.229.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(312, 2, 'W.230', 'Gia súc', 'bienbao/W.230.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(313, 2, 'W.231', 'Thú rừng vượt qua đường', 'bienbao/W.231.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(314, 2, 'W.232', 'Gió ngang', 'bienbao/W.232.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(315, 2, 'W.233', 'Nguy hiểm khác', 'bienbao/W.233.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(316, 2, 'W.234', 'Giao nhau với đường hai chiều', 'bienbao/W.234.webp', 'Biển báo hiệu trên đường một chiều sắp đến chỗ giao nhau với đường hai chiều.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(317, 2, 'W.235', 'Đường đôi', 'bienbao/W.235.webp', 'Biển báo hiệu sắp đến đoạn đường đôi (chiều đi và chiều về phân biệt rõ ràng bằng giải phân cách cứng).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(318, 2, 'W.236', 'Hết đường đôi', 'bienbao/W.236.webp', 'Biển báo hiệu sắp kết thúc đoạn đường đôi (đoạn đường hết giải phân cách cứng).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(319, 2, 'W.237', 'Đường có độ vòng lớn', 'bienbao/W.237.webp', 'Biển báo hiệu sắp đến chiếc cầu có độ vồng rất lớn ảnh hưởng tới tầm nhìn.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(320, 2, 'W.238', 'Đường cao tốc phía trước', 'bienbao/W.238.webp', 'Biển báo hiệu sắp đến đường cao tốc.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(321, 2, 'W.239', 'Đường cáp điện ở phía trên', 'bienbao/W.239.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(322, 2, 'W.240', 'Đường hầm phía trước', 'bienbao/W.240.webp', 'Biển báo hiệu sắp tới đường hầm (đường chạy hai chiều xe mà chiếu sáng lại không tốt).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(323, 2, 'W.241', 'Ùn tắc giao thông', 'bienbao/W.241.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(324, 2, 'W.242a', 'Nơi đường sắt giao vuông góc với đường bộ', 'bienbao/W.242a.webp', 'Biển W.242a báo hiệu chỗ giao nhau chỉ có một đường sắt cắt ngang đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(325, 2, 'W.242b', 'Nơi 2 đường sắt giao nhau với đường bộ', 'bienbao/W.242b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(326, 2, 'W.243a', 'Nơi đường sắt giao không vuông góc với đường bộ', 'bienbao/W.243a.webp', 'Đặt cách ray đường sắt gần nhất 50m', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(327, 2, 'W.243b', 'Nơi đường sắt giao không vuông góc với đường bộ', 'bienbao/W.243b.webp', 'Đặt cách ray đường sắt gần nhất 100m', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(328, 2, 'W.243c', 'Nơi đường sắt giao không vuông góc với đường bộ', 'bienbao/W.243c.webp', 'Đặt cách ray đường sắt gần nhất 150m', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(329, 2, 'W.244', 'Đoạn đường hay xảy ra tai nạn', 'bienbao/W.244.webp', 'Biển báo hiệu đoạn đường phía trước thường xảy ra tai nạn để lái xe cần đặc biệt chú ý.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(330, 2, 'W.245a', 'Đi chậm', 'bienbao/W.245a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(331, 2, 'W.245b', 'Đi chậm', 'bienbao/W.245b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(332, 2, 'W.246a', 'Chú ý chướng ngại vật', 'bienbao/W.246a.webp', 'Biển báo hiệu phía trước có chướng ngại vật. người lái xe cần giảm tốc độ đi vòng tránh sang hai bên.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(333, 2, 'W.246b', 'Chú ý chướng ngại vật', 'bienbao/W.246b.webp', 'Biển báo hiệu phía trước có chướng ngại vật. người lái xe cần giảm tốc độ đi vòng tránh sang bên trái.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(334, 2, 'W.246c', 'Chú ý chướng ngại vật', 'bienbao/W.246c.webp', 'Biển báo hiệu phía trước có chướng ngại vật. người lái xe cần giảm tốc độ đi vòng tránh sang bên phải.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(335, 2, 'W.247', 'Chú ý xe đỗ', 'bienbao/W.247.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(336, 3, 'R.122', 'Dừng lại', 'bienbao/R.122.webp', 'Biển báo hiệu buộc các xe cơ giới và thô sơ kể cả xe được ưu tiên theo quy định phải dừng lại. Chỉ được phép đi nếu có người điều khiển giao thông hoặc đèn cờ cho phép đi. Nếu không thì chỉ được phép đi khi trên đường không còn nguy cơ gây mất an toàn giao thông.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(337, 3, 'R.301a', 'Các xe chỉ được đi thẳng', 'bienbao/R.301a.webp', 'Được đặt trước ngã ba, ngã tư. Các xe chỉ được đi thẳng ở khu vực ngã ba, ngã tư.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(338, 3, 'R.301b', 'Các xe chỉ được rẽ phải', 'bienbao/R.301b.webp', 'Được đặt sau ngã ba, ngã tư. Các xe chỉ được rẽ phải ở khu vực trước mặt biển.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(339, 3, 'R.301c', 'Các xe chỉ được rẽ trái', 'bienbao/R.301c.webp', 'Được đặt sau ngã ba, ngã tư. Các xe chỉ được rẽ trái ở khu vực trước mặt biển.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(340, 3, 'R.301d', 'Các xe chỉ được rẽ phải', 'bienbao/R.301d.webp', 'Được đặt trước ngã ba, ngã tư. Các xe chỉ được rẽ phải ở phạm vi ngã ba, ngã tư đằng sau mặt biển.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(341, 3, 'R.301e', 'Các xe chỉ được rẽ trái', 'bienbao/R.301e.webp', 'Được đặt trước ngã ba, ngã tư. Các xe chỉ được rẽ trái ở phạm vi ngã ba, ngã tư đằng sau mặt biển.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(342, 3, 'R.301f', 'Các xe chỉ được đi thẳng và rẽ phải', 'bienbao/R.301f.webp', 'Được đặt trước ngã ba, ngã tư. Các xe chỉ được phép đi thẳng hay rẽ phải ở khu vực sau mặt biển.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(343, 3, 'R.301g', 'Các xe chỉ được đi thẳng và rẽ trái', 'bienbao/R.301g.webp', 'Được đặt trước ngã ba, ngã tư. Các xe chỉ được phép đi thẳng hay rẽ trái ở khu vực sau mặt biển và được phép quay đầu xe để đi theo hướng ngược lại.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(344, 3, 'R.301h', 'Các xe chỉ được rẽ trái và phải', 'bienbao/R.301h.webp', 'Được đặt sau ngã ba, ngã tư. Các xe chỉ được phép rẽ trái, quay đầu hoặc rẽ phải ở khu vực ngã ba, ngã tư trước mặt biển.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(345, 3, 'R.302a', 'Hướng phải đi vòng chướng ngại vật', 'bienbao/R.302a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(346, 3, 'R.302b', 'Hướng phải đi vòng chướng ngại vật', 'bienbao/R.302b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(347, 3, 'R.302c', 'Hướng phải đi vòng chướng ngại vật', 'bienbao/R.302c.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(348, 3, 'R.303', 'Nơi giao nhau chạy theo vòng xuyến', 'bienbao/R.303.webp', 'Biển có hiệu lực bắt buộc các xe muốn chuyển hướng phải chạy vòng theo đảo an toàn theo hướng mũi tên tại nơi đường giao nhau (ngã ba, ngã tư).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(349, 3, 'R.304', 'Đường dành cho xe thô sơ', 'bienbao/R.304.webp', 'Biển báo đường dành cho xe thô sơ (kể cả xe của người khuyết tật) và người đi bộ, bắt buộc phải đi theo đường dành riêng này, cấm phương tiện giao thông cơ giới kể cả các xe được ưu tiên theo Luật Giao thông đường bộ đi vào đường đã đặt biển này, trừ trường hợp đi cắt ngang qua nhưng phải bảo đảm tuyệt đối an toàn cho người đi bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(350, 3, 'R.305', 'Đường dành cho người đi bộ', 'bienbao/R.305.webp', 'Biển báo đường dành riêng cho người đi bộ.Các phương tiện giao thông đường bộ kể cả xe được ưu tiên theo Luật Giao thông đường bộ không được phép đi vào, trừ trường hợp đi cắt ngang qua, nhưng phải bảo đảm tuyệt đối an toàn cho người đi bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(351, 3, 'R.306', 'Tốc độ tối thiểu cho phép', 'bienbao/R.306.webp', 'Biển báo tốc độ tối thiểu cho phép. Biển có hiệu lực bắt buộc các loại xe cơ giới chạy với tốc độ không nhỏ hơn trị số ghi trên biển trong điều kiện giao thông thuận lợi và an toàn. Các loại xe có tốc độ tối đa theo quy định của nhà sản xuất không đạt tốc độ tối thiểu đã ghi trên biển không được phép đi vào đường này.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(352, 3, 'R.307', 'Hết hạn chế tốc độ tối thiểu', 'bienbao/R.307.webp', 'Biển báo hết đoạn đường hạn chế tốc độ tối thiểu. Kể từ biển này các xe được phép chạy chậm hơn trị số ghi trên biển nhưng không được gây cản trở các xe khác.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(353, 3, 'R.308a', 'Tuyến đường cầu vượt cắt qua', 'bienbao/R.308a.webp', 'Biển số R.308a báo cho người lái xe chỉ được đi thẳng hoặc rẽ trái trên cầu vượt.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(354, 3, 'R.308b', 'Tuyến đường cầu vượt cắt qua', 'bienbao/R.308b.webp', 'Biển số R.308b báo cho người lái xe chỉ được đi thẳng hoặc rẽ phải trên cầu vượt.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(355, 3, 'R.309', 'Ấn còi', 'bienbao/R.309.webp', 'Biển báo lệnh cho người lái xe phải bấm còi.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(356, 3, 'R.310a', 'Hướng đi phải theo cho xe chở hàng nguy hiểm', 'bienbao/R.310a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(357, 3, 'R.310b', 'Hướng đi phải theo cho xe chở hàng nguy hiểm', 'bienbao/R.310b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(358, 3, 'R.310c', 'Hướng đi phải theo cho xe chở hàng nguy hiểm', 'bienbao/R.310c.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(359, 3, 'R.403a', 'Đường dành cho ôtô', 'bienbao/R.403a.webp', 'Biển báo hiệu bắt đầu đường dành cho các loại ôtô đi lại.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(360, 3, 'R.403b', 'Đường dành cho ôtô, xe máy', 'bienbao/R.403b.webp', 'Biển báo hiệu bắt đầu đường dành cho các loại ôtô, xe máy (kể cả xe gắn máy).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(361, 3, 'R.404a', 'Hết đoạn đường dành cho ôtô', 'bienbao/R.404a.webp', 'Đến hết đoạn đường dành cho ôtô đi lại', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(362, 3, 'R.404b', 'Hết đoạn đường dành cho ôtô và xe máy', 'bienbao/R.404b.webp', 'Đến hết đoạn đường dành cho ôtô, xe máy đi lại', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(363, 3, 'R.411', 'Hướng đi trên mỗi làn đường phải theo', 'bienbao/R.411.webp', 'Biển báo hiệu cho người tham gia giao thông biết số lượng làn đường trên mặt đường và hướng đi trên mỗi làn đường theo vạch kẻ đường.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(364, 3, 'R.412a', 'Làn đường dành cho xe khách', 'bienbao/R.412a.webp', 'Biển báo hiệu làn đường dành riêng cho ôtô khách (kể cả ôtô buýt).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(365, 3, 'R.412b', 'Làn đường dành cho xe con', 'bienbao/R.412b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(366, 3, 'R.412c', 'Làn đường dành cho xe tải', 'bienbao/R.412c.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(367, 3, 'R.412d', 'Làn đường dành cho xe mô tô', 'bienbao/R.412d.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(368, 3, 'R.412f', 'Làn đường dành cho xe ô tô', 'bienbao/R.412f.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(369, 3, 'R.413i', 'Kết thúc làn đường dành cho xe khách', 'bienbao/R.413i.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(370, 3, 'R.413j', 'Kết thúc làn đường dành cho xe con', 'bienbao/R.413j.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(371, 3, 'R.413k', 'Kết thúc làn đường dành cho xe tải', 'bienbao/R.413k.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(372, 3, 'R.413l', 'Kết thúc làn đường dành cho xe mô tô', 'bienbao/R.413l.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(373, 3, 'R.413n', 'Kết thúc làn đường dành cho xe ô tô', 'bienbao/R.413n.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(374, 3, 'R.415', 'Biển gộp làn đường theo phương tiện', 'bienbao/R.415.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(375, 3, 'R.420', 'Bắt đầu khu dân cư', 'bienbao/R.420.webp', 'Biển báo hiệu bắt đầu đoạn đường vào phạm vi khu đông dân cư. Biển có tác dụng báo cho người tham gia giao thông biết phạm vi phải tuân theo những quy định đi đường được áp dụng ở khu đông dân cư.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(376, 3, 'R.421', 'Hết khu đông dân cư', 'bienbao/R.421.webp', 'Biển báo hiệu hết đoạn đường qua phạm vi khu đông dân cư. Biển có tác dụng báo cho người tham gia giao thông biết phạm vi phải tuân theo những quy định đi đường được áp dụng ở khu đông dân cư đã hết hiệu lực.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(377, 3, 'R.E,9a', 'Cấm đỗ xe trong khu vực', 'bienbao/R.E,9a.webp', 'Biển báo Cấm đỗ xe trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(378, 3, 'R.E,9b', 'Cấm đỗ xe theo giờ trong khu vực', 'bienbao/R.E,9b.webp', 'Biển báo Cấm đỗ xe theo giờ trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(379, 3, 'R.E,9c', 'Khu vực đỗ xe', 'bienbao/R.E,9c.webp', 'Biển báo khu vực đỗ xe trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(380, 3, 'R.E,9d', 'Hạn chế tốc độ tối đa trong khu vực', 'bienbao/R.E,9d.webp', 'Để quy định hạn chế tốc độ tối đa trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(381, 3, 'R.E,10a', 'Hết cấm đỗ xe trong khu vực', 'bienbao/R.E,10a.webp', 'Để báo hiệu hết cấm đỗ xe trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(382, 3, 'R.E,10b', 'Hết cấm đỗ xe theo giờ trong khu vực', 'bienbao/R.E,10b.webp', 'Để báo hiệu hết cấm đỗ xe theo giờ trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(383, 3, 'R.E,10c', 'Hết khu vực đỗ xe', 'bienbao/R.E,10c.webp', 'Để quy định hết khu vực đỗ xe trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(384, 3, 'R.E,10d', 'Hết hạn chế tốc độ tối đa trong khu vực', 'bienbao/R.E,10d.webp', 'Để quy định hết hạn chế tốc độ tối đa trong khu vực có hiệu lực cho tất cả các tuyến đường trong một khu vực (hiệu lực cho cả khu vực).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(385, 3, 'R.E,11a', 'Báo hiệu có hầm chui', 'bienbao/R.E,11a.webp', 'Chỉ dẫn đoạn đường qua hầm có áp dụng quy định giao thông riêng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(386, 3, 'R.E,11b', 'Kết thúc hầm chui', 'bienbao/R.E,11b.webp', 'Chỉ dẫn hết đoạn đường qua hầm, các quy định giao thông riêng không còn áp dụng.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(387, 4, 'I.401', 'Bắt đầu đường ưu tiên', 'bienbao/I.401.webp', 'Biển chỉ dẫn các phương tiện trên trục đường chính được ưu tiên đi trước ở nơi đường giao nhau, các phương tiện từ đường nhánh ra phải dừng lại nhường đường cho phương tiện trên đường chính đi trước, trừ các xe được ưu tiên theo Luật Giao thông đường bộ.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(388, 4, 'I.402', 'Hết đường ưu tiên', 'bienbao/I.402.webp', 'Biển chỉ dẫn đã hết đoạn đường ưu tiên. Trên đoạn đường tiếp theo, các xe đi đúng với tốc độ quy định, qua nơi giao nhau ưu tiên bên phải.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(389, 4, 'I.405a', 'Đường cụt', 'bienbao/I.405a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(390, 4, 'I.405b', 'Đường cụt', 'bienbao/I.405b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(391, 4, 'I.405c', 'Đường cụt', 'bienbao/I.405c.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(392, 4, 'I.406', 'Được ưu tiên qua đường hẹp', 'bienbao/I.406.webp', 'Biển chỉ dẫn có quyền được ưu tiên đi trước trên đoạn đường hẹp khi gặp xe đi ngược chiều, trừ trường hợp trên hướng đi ngược chiều có phương tiện đã đi vào phạm vi đường hẹp thì xe đi theo chiều ưu tiên cũng phải nhường đường.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(393, 4, 'I.407a', 'Đường một chiều', 'bienbao/I.407a.webp', 'Chỉ cho phép các loại phương tiệngiao thông đi vào theo chiều mũi tên chỉ, cấm quay đầu ngược lại (trừ các xe được quyền ưu tiên theo Luật Giao thông đường bộ).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(394, 4, 'I.407b', 'Đường một chiều', 'bienbao/I.407b.webp', 'Chỉ cho phép các loại phương tiệngiao thông đi vào theo chiều mũi tên chỉ, cấm quay đầu ngược lại (trừ các xe được quyền ưu tiên theo Luật Giao thông đường bộ).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(395, 4, 'I.407c', 'Đường một chiều', 'bienbao/I.407c.webp', 'Chỉ cho phép các loại phương tiệngiao thông đi vào theo chiều mũi tên chỉ, cấm quay đầu ngược lại (trừ các xe được quyền ưu tiên theo Luật Giao thông đường bộ).', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(396, 4, 'I.408', 'Nơi đỗ xe', 'bienbao/I.408.webp', 'Biển chỉ dẫn những nơi được phép đỗ xe, những bãi đỗ xe, bến xe v.v...', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(397, 4, 'I.408a', 'Nơi đỗ xe một phần trên hè phố', 'bienbao/I.408a.webp', 'Biển chỉ dẫn những nơi được phép đỗ xe một phần trên hè phố rộng, phải đặt biển số. Xe phải đổ từ 1⁄2 thân xe trở lên trên hè phố.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(398, 4, 'I.409', 'Chỗ quay xe', 'bienbao/I.409.webp', 'Biển chỉ dẫn vị trí được phép quay đầu xe kiểu chữ U. Biển không cấm rẽ trái', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(399, 4, 'I.410', 'Khu vực quay xe', 'bienbao/I.410.webp', 'Biển chỉ dẫn khu vực được phép quay đầu xe kiểu chữ U. Biển không cấm rẽ trái.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(400, 4, 'I.413a', 'Đường phía trước có làn đường dành cho ô tô khách', 'bienbao/I.413a.webp', 'Biển chỉ dẫn đường có làn đường dành riêng cho xe ô tô khách theo chiều ngược lại. Biển được đặt ở ngã ba, ngã tư đầu đường một chiều mà hướng ngược chiều có xe ô tô khách được phép chạy.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(401, 4, 'I.413b', 'Rẽ ra đường có làn dành cho xe khách', 'bienbao/I.413b.webp', 'Biển chỉ dẫn ở ngã ba, ngã tư rẽ phải hoặc rẽ trái là rẽ ra đường có làn đường dành cho xe ô tô khách.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(402, 4, 'I.413c', 'Rẽ ra đường có làn dành cho xe khách', 'bienbao/I.413c.webp', 'Biển chỉ dẫn ở ngã ba, ngã tư rẽ phải hoặc rẽ trái là rẽ ra đường có làn đường dành cho xe ô tô khách.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(403, 4, 'I.418', 'Lối đi ở những chỗ cấm rẽ', 'bienbao/I.418.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(404, 4, 'I.423a', 'Đường người đi bộ sang ngang', 'bienbao/I.423a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(405, 4, 'I.437', 'Đường cao tốc', 'bienbao/I.437.webp', 'Để chỉ dẫn bắt đầu đường cao tốc, đặt biển số I.437 “Đường cao tốc”.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(406, 4, 'I.444', 'Xe kéo moóc', 'bienbao/I.444.webp', 'Biển này đặt trên nóc buồng lái của xe kéo moóc', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(407, 4, 'I.446', 'Nơi đỗ xe dành cho người tàn tật', 'bienbao/I.446.webp', 'Biển chỉ dẫn vị trí thiết bị chuyên dùng cho người tàn tật.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(408, 4, 'I.447a', 'Cầu vượt liên thông', 'bienbao/I.447a.webp', 'Biển được đặt trước khi vào cầu vượt . Biển chỉ dẫn tại cầu vượt liên thông xe có thể đi thẳng hoặc theo chỉ dẫn trên hình vẽ để rẽ trái hay rẽ phải.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(409, 4, 'I.447b', 'Cầu vượt liên thông', 'bienbao/I.447b.webp', 'Biển được đặt trước khi vào cầu vượt . Biển chỉ dẫn tại cầu vượt liên thông xe có thể đi thẳng hoặc theo chỉ dẫn trên hình vẽ để rẽ trái hay rẽ phải.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(410, 4, 'I.448', 'Làn đường cứu nạn hay làn thoát xe khẩn cấp', 'bienbao/I.448.webp', 'Biển chỉ dẫn gồm 3 cặp biển ở các cự ly 2 km, 1 km và 300 m nhằm chỉ dẫn cho ngƣời tham gia giao thông biết vị trí và khoảng cách có làn cứu nạn.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(411, 4, 'I.449', 'Biển tên đường', 'bienbao/I.449.webp', 'Biển báo tên đƣờng cho các tuyến đƣờng đối ngoại.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(412, 5, 'S.501', 'Phạm vi tác dụng của biển', 'bienbao/S.501.webp', 'Biển được đặt dưới các loại biển báo nguy hiểm, biển báo cấm hoặc hạn chế. Biển thông báo chiều dài đoạn đường nguy hiểm hay đoạn đường phải thi hành lệnh cấm hoặc hạn chế.', '2025-04-17 21:36:46', '2025-04-17 21:36:46');
INSERT INTO `traffic_signs` (`id`, `type`, `code`, `name`, `image`, `description`, `created_at`, `updated_at`) VALUES
(413, 5, 'S.502', 'Khoảng cách đến đối tượng báo hiệu', 'bienbao/S.502.webp', 'Biển được đặt dưới các loại biển báo nguy hiểm, biển báo cấm hoặc hạn chế, biển hiệu lệnh và biển chỉ dẫn . Biển thông báo khoảng cách thực tế từ vị trí đặt biển đến đối tượng báo hiệu ở phía trước.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(414, 5, 'S.503a', 'Hướng tác dụng của biển', 'bienbao/S.503a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(415, 5, 'S.503b', 'Hướng tác dụng của biển', 'bienbao/S.503b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(416, 5, 'S.503c', 'Hướng tác dụng của biển', 'bienbao/S.503c.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(417, 5, 'S.503d', 'Hướng tác dụng của biển', 'bienbao/S.503d.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(418, 5, 'S.503e', 'Hướng tác dụng của biển', 'bienbao/S.503e.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(419, 5, 'S.503f', 'Hướng tác dụng của biển', 'bienbao/S.503f.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(420, 5, 'S.504', 'Làn đường', 'bienbao/S.504.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(421, 5, 'S.506a', 'Hướng đường ưu tiên', 'bienbao/S.506a.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(422, 5, 'S.506b', 'Hướng đường ưu tiên', 'bienbao/S.506b.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(423, 6, 'Vạch 1.1', 'Vạch phân chia hai chiều xe chạy (vạch tim đường), dạng vạch đơn, đứt nét', 'bienbao/Vạch 1.1.webp', 'Áp dụng: dùng để phân chia hai chiều xe chạy ngược chiều nhau ở những đoạn đường có từ 2 làn xe trở lên, không có dải phân cách giữa. Xe được phép cắt qua để sử dụng làn ngược chiều từ cả hai phía.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(424, 6, 'Vạch 1.2', 'Vạch phân chia hai chiều xe chạy (vạch tim đường), dạng vạch đơn, nét liền', 'bienbao/Vạch 1.2.webp', 'Áp dụng: dùng để phân chia hai chiều xe chạy cho đường có 2 hoặc 3 làn xe, không có dải phân cách giữa; xe không được lấn làn, không được đè lên vạch.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(425, 6, 'Vạch 1.3', 'Vạch phân chia hai chiều xe chạy ngược chiều (vạch tim đường), dạng vạch đôi, nét liền', 'bienbao/Vạch 1.3.webp', 'Dùng để phân chia hai chiều xe chạy cho đường có từ 4 làn xe trở lên, không có dải phân cách giữa, xe không được lấn làn, không được đè lên vạch. - Trường hợp các đường có 2 hoặc 3 làn xe, dùng để nhấn mạnh sự nguy hiểm.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(426, 6, 'Vạch 1.4', 'Vạch phân chia hai chiều xe chạy, dạng vạch đôi gồm một vạch nét liền, một vạch nét đứt', 'bienbao/Vạch 1.4.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(427, 6, 'Vạch 1.5', 'Vạch xác định ranh giới làn đường có thể thay đổi hướng xe chạy', 'bienbao/Vạch 1.5.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(428, 6, 'Vạch 2.1', 'Vạch phân chia các làn xe cùng chiều, dạng vạch đơn, đứt nét', 'bienbao/Vạch 2.1.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(429, 6, 'Vạch 2.2', 'Vạch phân chia các làn xe cùng chiều, dạng vạch đơn, liền nét.', 'bienbao/Vạch 2.2.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(430, 6, 'Vạch 7.6', 'Vạch chỉ dẫn sắp đến chỗ có bố trí vạch đi bộ qua đường', 'bienbao/Vạch 7.6.webp', NULL, '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(431, 6, 'Vạch 7.8', 'Vạch xác định khoảng cách xe trên đường.', 'bienbao/Vạch 7.8.webp', 'Vạch 7.8 là vạch dùng để xác định khoảng cách trên đường, giúp cho lái xe biết cần phải giãn cách cự ly để đảm bảo an toàn với xe chạy phía trước. Vạch thường được sử dụng trên đường ôtô cao tốc.', '2025-04-17 21:36:46', '2025-04-17 21:36:46'),
(432, 6, 'Vạch 9.2', 'Vạch quy định vị trí dừng đỗ của phương tiện giao thông công cộng trên đường', 'bienbao/Vạch 9.2.webp', 'Vạch 9.2 quy định vị trí dừng xe của các phương tiện vận tải hành khách công cộng trên đường như xe buýt, xe tắc xi ...', '2025-04-17 21:36:46', '2025-04-17 21:36:46');
